window.KJV1769_STRONG_BOOKS["Isa"] = {"osis":"Isa","book":"이사야","verses":{"1:1":{"text":"The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.","words":[["H2377","The vision",0,10],["H3470","of Isaiah",11,20],["H1121","the son",21,28],["H0531","of Amoz",29,36],["H2372","which he saw",38,50],["H3063","concerning Judah",51,67],["H3389","and Jerusalem",68,81],["H3117","in the days",82,93],["H5818","of Uzziah",94,103],["H3147","Jotham",105,111],["H0271","Ahaz",113,117],["H3169","and Hezekiah",119,131],["H4428","kings",133,138],["H3063","of Judah",139,147]]},"1:2":{"text":"Hear, O heavens, and give ear, O earth: for the LORD hath spoken, I have nourished and brought up children, and they have rebelled against me.","words":[["H8085","Hear",0,4],["H8064","O heavens",6,15],["H0238","and give ear",17,29],["H0776","O earth",31,38],["H3068","for the LORD",40,52],["H1696","hath spoken",53,64],["H1431","I have nourished",66,82],["H7311","and brought up",83,97],["H1121","children",98,106],["H6586","and they have rebelled",108,130]]},"1:3":{"text":"The ox knoweth his owner, and the ass his master's crib: but Israel doth not know, my people doth not consider.","words":[["H7794","The ox",0,6],["H3045","knoweth",7,14],["H7069","his owner",15,24],["H2543","and the ass",26,37],["H1167","his master's",38,50],["H0018","crib",51,55],["H3478","but Israel",57,67],["H3045","doth not know",68,81],["H5971","my people",83,92],["H0995","doth not consider",93,110]]},"1:4":{"text":"Ah sinful nation, a people laden with iniquity, a seed of evildoers, children that are corrupters: they have forsaken the LORD, they have provoked the Holy One of Israel unto anger, they are gone away backward.","words":[["H1945","Ah",0,2],["H2398","sinful",3,9],["H1471","nation",10,16],["H5971","a people",18,26],["H3515","laden",27,32],["H5771","with iniquity",33,46],["H2233","a seed",48,54],["H7489","of evildoers",55,67],["H1121","children",69,77],["H7843","that are corrupters",78,97],["H5800","they have forsaken",99,117],["H0853","",-1,-1],["H3068","the LORD",118,126],["H5006","they have provoked",128,146],["H0853","",-1,-1],["H6918","the Holy One",147,159],["H3478","of Israel",160,169],["H5006","unto anger",170,180],["H2114","they are gone away",182,200],["H0268","backward",201,209]]},"1:5":{"text":"Why should ye be stricken any more? ye will revolt more and more: the whole head is sick, and the whole heart faint.","words":[["H5221","Why should ye be stricken",0,25],["H5627","any more? ye will revolt",26,50],["H3254","more and more",51,64],["H7218","the whole head",66,80],["H2483","is sick",81,88],["H3824","and the whole heart",90,109],["H1742","faint",110,115]]},"1:6":{"text":"From the sole of the foot even unto the head there is no soundness in it; but wounds, and bruises, and putrifying sores: they have not been closed, neither bound up, neither mollified with ointment.","words":[["H3709","From the sole",0,13],["H7272","of the foot",14,25],["H7218","even unto the head",26,44],["H4974","there is no soundness",45,66],["H6482","in it; but wounds",67,84],["H2250","and bruises",86,97],["H2961","and putrifying",99,113],["H4347","sores",114,119],["H2115","they have not been closed",121,146],["H2280","neither bound up",148,164],["H7401","neither mollified",166,183],["H8081","with ointment",184,197]]},"1:7":{"text":"Your country is desolate, your cities are burned with fire: your land, strangers devour it in your presence, and it is desolate, as overthrown by strangers.","words":[["H0776","Your country",0,12],["H8077","is desolate",13,24],["H5892","your cities",26,37],["H8313","are burned",38,48],["H0784","with fire",49,58],["H0127","your land",60,69],["H2114","strangers",71,80],["H0398","devour",81,87],["H8077","it in your presence, and it is desolate",88,127],["H4114","as overthrown",129,142],["H2114","by strangers",143,155]]},"1:8":{"text":"And the daughter of Zion is left as a cottage in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.","words":[["H1323","And the daughter",0,16],["H6726","of Zion",17,24],["H3498","is left",25,32],["H5521","as a cottage",33,45],["H3754","in a vineyard",46,59],["H4412","as a lodge",61,71],["H4750","in a garden of cucumbers",72,96],["H5341","as a besieged",98,111],["H5892","city",112,116]]},"1:9":{"text":"Except the LORD of hosts had left unto us a very small remnant, we should have been as Sodom, and we should have been like unto Gomorrah.","words":[["H3884","Except",0,6],["H3068","the LORD",7,15],["H6635","of hosts",16,24],["H3498","had left",25,33],["H4592","unto us a very small",34,54],["H8300","remnant",55,62],["H1961","we should have been",64,83],["H5467","as Sodom",84,92],["H1819","and we should have been like",94,122],["H6017","unto Gomorrah",123,136]]},"1:10":{"text":"Hear the word of the LORD, ye rulers of Sodom; give ear unto the law of our God, ye people of Gomorrah.","words":[["H8085","Hear",0,4],["H1697","the word",5,13],["H3068","of the LORD",14,25],["H7101","ye rulers",27,36],["H5467","of Sodom",37,45],["H0238","give ear",47,55],["H8451","unto the law",56,68],["H0430","of our God",69,79],["H5971","ye people",81,90],["H6017","of Gomorrah",91,102]]},"1:11":{"text":"To what purpose is the multitude of your sacrifices unto me? saith the LORD: I am full of the burnt offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he goats.","words":[["H4100","To what",0,7],["H7230","purpose is the multitude",8,32],["H2077","of your sacrifices",33,51],["H0559","unto me? saith",52,66],["H3068","the LORD",67,75],["H7646","I am full",77,86],["H5930","of the burnt offerings",87,109],["H0352","of rams",110,117],["H2459","and the fat",119,130],["H4806","of fed beasts",131,144],["H2654","and I delight",146,159],["H1818","not in the blood",160,176],["H6499","of bullocks",177,188],["H3532","or of lambs",190,201],["H6260","or of he goats",203,217]]},"1:12":{"text":"When ye come to appear before me, who hath required this at your hand, to tread my courts?","words":[["H0935","When ye come",0,12],["H7200","to appear",13,22],["H6440","before",23,29],["H1245","me, who hath required",30,51],["H3027","this at your hand",52,69],["H7429","to tread",71,79],["H2691","my courts",80,89]]},"1:13":{"text":"Bring no more vain oblations; incense is an abomination unto me; the new moons and sabbaths, the calling of assemblies, I cannot away with; it is iniquity, even the solemn meeting.","words":[["H0935","Bring",0,5],["H3254","no more",6,13],["H7723","vain",14,18],["H4503","oblations",19,28],["H7004","incense",30,37],["H8441","is an abomination",38,55],["H2320","unto me; the new moons",56,78],["H7676","and sabbaths",79,91],["H7121","the calling",93,104],["H4744","of assemblies",105,118],["H3201","I cannot away with",120,138],["H0205","it is iniquity",140,154],["H6116","even the solemn meeting",156,179]]},"1:14":{"text":"Your new moons and your appointed feasts my soul hateth: they are a trouble unto me; I am weary to bear them.","words":[["H2320","Your new moons",0,14],["H4150","and your appointed feasts",15,40],["H5315","my soul",41,48],["H8130","hateth",49,55],["H2960","they are a trouble",57,75],["H3811","unto me; I am weary",76,95],["H5375","to bear",96,103]]},"1:15":{"text":"And when ye spread forth your hands, I will hide mine eyes from you: yea, when ye make many prayers, I will not hear: your hands are full of blood.","words":[["H6566","And when ye spread forth",0,24],["H3709","your hands",25,35],["H5956","I will hide",37,48],["H5869","mine eyes",49,58],["H7235","from you: yea, when ye make many",59,91],["H8605","prayers",92,99],["H8085","I will not hear",101,116],["H3027","your hands",118,128],["H4390","are full",129,137],["H1818","of blood",138,146]]},"1:16":{"text":"Wash you, make you clean; put away the evil of your doings from before mine eyes; cease to do evil;","words":[["H7364","Wash",0,4],["H2135","you, make you clean",5,24],["H5493","put away",26,34],["H7455","the evil",35,43],["H4611","of your doings",44,58],["H5048","from before",59,70],["H5869","mine eyes",71,80],["H2308","cease",82,87],["H7489","to do evil",88,98]]},"1:17":{"text":"Learn to do well; seek judgment, relieve the oppressed, judge the fatherless, plead for the widow.","words":[["H3925","Learn",0,5],["H3190","to do well",6,16],["H1875","seek",18,22],["H4941","judgment",23,31],["H0833","relieve",33,40],["H2541","the oppressed",41,54],["H8199","judge",56,61],["H3490","the fatherless",62,76],["H7378","plead",78,83],["H0490","for the widow",84,97]]},"1:18":{"text":"Come now, and let us reason together, saith the LORD: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.","words":[["H3212","Come now",0,8],["H3198","and let us reason together",10,36],["H0559","saith",38,43],["H3068","the LORD",44,52],["H2399","though your sins",54,70],["H8144","be as scarlet",71,84],["H3835","they shall be as white",86,108],["H7950","as snow",109,116],["H0119","though they be red",118,136],["H8438","like crimson",137,149],["H6785","they shall be as wool",151,172]]},"1:19":{"text":"If ye be willing and obedient, ye shall eat the good of the land:","words":[["H0014","If ye be willing",0,16],["H8085","and obedient",17,29],["H0398","ye shall eat",31,43],["H2898","the good",44,52],["H0776","of the land",53,64]]},"1:20":{"text":"But if ye refuse and rebel, ye shall be devoured with the sword: for the mouth of the LORD hath spoken it.","words":[["H3985","But if ye refuse",0,16],["H4784","and rebel",17,26],["H0398","ye shall be devoured",28,48],["H2719","with the sword",49,63],["H6310","for the mouth",65,78],["H3068","of the LORD",79,90],["H1696","hath spoken",91,102]]},"1:21":{"text":"How is the faithful city become an harlot! it was full of judgment; righteousness lodged in it; but now murderers.","words":[["H0539","How is the faithful",0,19],["H7151","city",20,24],["H2181","become an harlot",25,41],["H4392","it was full",43,54],["H4941","of judgment",55,66],["H6664","righteousness",68,81],["H3885","lodged",82,88],["H7523","in it; but now murderers",89,113]]},"1:22":{"text":"Thy silver is become dross, thy wine mixed with water:","words":[["H3701","Thy silver",0,10],["H5509","is become dross",11,26],["H5435","thy wine",28,36],["H4107","mixed",37,42],["H4325","with water",43,53]]},"1:23":{"text":"Thy princes are rebellious, and companions of thieves: every one loveth gifts, and followeth after rewards: they judge not the fatherless, neither doth the cause of the widow come unto them.","words":[["H8269","Thy princes",0,11],["H5637","are rebellious",12,26],["H2270","and companions",28,42],["H1590","of thieves",43,53],["H0157","every one loveth",55,71],["H7810","gifts",72,77],["H7291","and followeth",79,92],["H8021","after rewards",93,106],["H8199","they judge",108,118],["H3490","not the fatherless",119,137],["H7379","neither doth the cause",139,161],["H0490","of the widow",162,174],["H0935","come",175,179]]},"1:24":{"text":"Therefore saith the Lord, the LORD of hosts, the mighty One of Israel, Ah, I will ease me of mine adversaries, and avenge me of mine enemies:","words":[["H5002","Therefore saith",0,15],["H0113","the Lord",16,24],["H3068","the LORD",26,34],["H6635","of hosts",35,43],["H0046","the mighty One",45,59],["H3478","of Israel",60,69],["H1945","Ah",71,73],["H5162","I will ease",75,86],["H6862","me of mine adversaries",87,109],["H5358","and avenge",111,121],["H0341","me of mine enemies",122,140]]},"1:25":{"text":"And I will turn my hand upon thee, and purely purge away thy dross, and take away all thy tin:","words":[["H7725","And I will turn",0,15],["H3027","my hand",16,23],["H1253","upon thee, and purely",24,45],["H6884","purge away",46,56],["H5509","thy dross",57,66],["H5493","and take away",68,81],["H0913","all thy tin",82,93]]},"1:26":{"text":"And I will restore thy judges as at the first, and thy counsellors as at the beginning: afterward thou shalt be called, The city of righteousness, the faithful city.","words":[["H7725","And I will restore",0,18],["H8199","thy judges",19,29],["H7223","as at the first",30,45],["H3289","and thy counsellors",47,66],["H8462","as at the beginning",67,86],["H0310","afterward",88,97],["H7121","thou shalt be called",98,118],["H5892","The city",120,128],["H6664","of righteousness",129,145],["H0539","the faithful",147,159],["H7151","city",160,164]]},"1:27":{"text":"Zion shall be redeemed with judgment, and her converts with righteousness.","words":[["H6726","Zion",0,4],["H6299","shall be redeemed",5,22],["H4941","with judgment",23,36],["H7725","and her converts",38,54],["H6666","with righteousness",55,73]]},"1:28":{"text":"And the destruction of the transgressors and of the sinners shall be together, and they that forsake the LORD shall be consumed.","words":[["H7667","And the destruction",0,19],["H6586","of the transgressors",20,40],["H2400","and of the sinners",41,59],["H3162","shall be together",60,77],["H5800","and they that forsake",79,100],["H3068","the LORD",101,109],["H3615","shall be consumed",110,127]]},"1:29":{"text":"For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.","words":[["H0954","For they shall be ashamed",0,25],["H0352","of the oaks",26,37],["H2530","which ye have desired",38,59],["H2659","and ye shall be confounded",61,87],["H1593","for the gardens",88,103],["H0977","that ye have chosen",104,123]]},"1:30":{"text":"For ye shall be as an oak whose leaf fadeth, and as a garden that hath no water.","words":[["H0424","For ye shall be as an oak",0,25],["H5929","whose leaf",26,36],["H5034","fadeth",37,43],["H1593","and as a garden",45,60],["H4325","that hath no water",61,79]]},"1:31":{"text":"And the strong shall be as tow, and the maker of it as a spark, and they shall both burn together, and none shall quench them.","words":[["H2634","And the strong",0,14],["H5296","shall be as tow",15,30],["H6467","and the maker",32,45],["H5213","of it as a spark",46,62],["H8147","and they shall both",64,83],["H1197","burn",84,88],["H3162","together",89,97],["H3518","and none shall quench",99,120]]},"2:1":{"text":"The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.","words":[["H1697","The word",0,8],["H3470","that Isaiah",9,20],["H1121","the son",21,28],["H0531","of Amoz",29,36],["H2372","saw",37,40],["H3063","concerning Judah",41,57],["H3389","and Jerusalem",58,71]]},"2:2":{"text":"And it shall come to pass in the last days, that the mountain of the LORD'S house shall be established in the top of the mountains, and shall be exalted above the hills; and all nations shall flow unto it.","words":[["H0319","And it shall come to pass in the last",0,37],["H3117","days",38,42],["H2022","that the mountain",44,61],["H3068","of the LORD'S",62,75],["H1004","house",76,81],["H3559","shall be established",82,102],["H7218","in the top",103,113],["H2022","of the mountains",114,130],["H5375","and shall be exalted",132,152],["H1389","above the hills",153,168],["H1471","and all nations",170,185],["H5102","shall flow",186,196]]},"2:3":{"text":"And many people shall go and say, Come ye, and let us go up to the mountain of the LORD, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for out of Zion shall go forth the law, and the word of the LORD from Jerusalem.","words":[["H7227","And many",0,8],["H5971","people",9,15],["H1980","shall go",16,24],["H0559","and say",25,32],["H3212","Come",34,38],["H5927","ye, and let us go up",39,59],["H2022","to the mountain",60,75],["H3068","of the LORD",76,87],["H1004","to the house",89,101],["H0430","of the God",102,112],["H3290","of Jacob",113,121],["H3384","and he will teach",123,140],["H1870","us of his ways",141,155],["H3212","and we will walk",157,173],["H0734","in his paths",174,186],["H6726","for out of Zion",188,203],["H3318","shall go forth",204,218],["H8451","the law",219,226],["H1697","and the word",228,240],["H3068","of the LORD",241,252],["H3389","from Jerusalem",253,267]]},"2:4":{"text":"And he shall judge among the nations, and shall rebuke many people: and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up sword against nation, neither shall they learn war any more.","words":[["H8199","And he shall judge",0,18],["H1471","among the nations",19,36],["H3198","and shall rebuke",38,54],["H7227","many",55,59],["H5971","people",60,66],["H3807","and they shall beat",68,87],["H2719","their swords",88,100],["H0855","into plowshares",101,116],["H2595","and their spears",118,134],["H4211","into pruninghooks",135,152],["H1471","nation",154,160],["H5375","shall not lift up",161,178],["H2719","sword",179,184],["H1471","against nation",185,199],["H3925","neither shall they learn",201,225],["H4421","war",226,229]]},"2:5":{"text":"O house of Jacob, come ye, and let us walk in the light of the LORD.","words":[["H1004","O house",0,7],["H3290","of Jacob",8,16],["H3212","come",18,22],["H3212","ye, and let us walk",23,42],["H0216","in the light",43,55],["H3068","of the LORD",56,67]]},"2:6":{"text":"Therefore thou hast forsaken thy people the house of Jacob, because they be replenished from the east, and are soothsayers like the Philistines, and they please themselves in the children of strangers.","words":[["H5203","Therefore thou hast forsaken",0,28],["H5971","thy people",29,39],["H1004","the house",40,49],["H3290","of Jacob",50,58],["H4390","because they be replenished",60,87],["H6924","from the east",88,101],["H6049","and are soothsayers",103,122],["H6430","like the Philistines",123,143],["H5606","and they please",145,160],["H3206","themselves in the children",161,187],["H5237","of strangers",188,200]]},"2:7":{"text":"Their land also is full of silver and gold, neither is there any end of their treasures; their land is also full of horses, neither is there any end of their chariots:","words":[["H0776","Their land",0,10],["H4390","also is full",11,23],["H3701","of silver",24,33],["H2091","and gold",34,42],["H7097","neither is there any end",44,68],["H0214","of their treasures",69,87],["H0776","their land",89,99],["H4390","is also full",100,112],["H5483","of horses",113,122],["H7097","neither is there any end",124,148],["H4818","of their chariots",149,166]]},"2:8":{"text":"Their land also is full of idols; they worship the work of their own hands, that which their own fingers have made:","words":[["H0776","Their land",0,10],["H4390","also is full",11,23],["H0457","of idols",24,32],["H7812","they worship",34,46],["H4639","the work",47,55],["H3027","of their own hands",56,74],["H0676","that which their own fingers",76,104],["H6213","have made",105,114]]},"2:9":{"text":"And the mean man boweth down, and the great man humbleth himself: therefore forgive them not.","words":[["H0120","And the mean man",0,16],["H7817","boweth down",17,28],["H0376","and the great man",30,47],["H8213","humbleth",48,56],["H5375","himself: therefore forgive",57,83]]},"2:10":{"text":"Enter into the rock, and hide thee in the dust, for fear of the LORD, and for the glory of his majesty.","words":[["H0935","Enter",0,5],["H6697","into the rock",6,19],["H2934","and hide",21,29],["H6083","thee in the dust",30,46],["H6440","for",48,51],["H6343","fear",52,56],["H3068","of the LORD",57,68],["H1926","and for the glory",70,87],["H1347","of his majesty",88,102]]},"2:11":{"text":"The lofty looks of man shall be humbled, and the haughtiness of men shall be bowed down, and the LORD alone shall be exalted in that day.","words":[["H1365","The lofty",0,9],["H5869","looks",10,15],["H0120","of man",16,22],["H8213","shall be humbled",23,39],["H7312","and the haughtiness",41,60],["H0582","of men",61,67],["H7817","shall be bowed down",68,87],["H3068","and the LORD",89,101],["H7682","alone shall be exalted",102,124],["H3117","in that day",125,136]]},"2:12":{"text":"For the day of the LORD of hosts shall be upon every one that is proud and lofty, and upon every one that is lifted up; and he shall be brought low:","words":[["H3117","For the day",0,11],["H3068","of the LORD",12,23],["H6635","of hosts",24,32],["H1343","shall be upon every one that is proud",33,70],["H7311","and lofty",71,80],["H5375","and upon every one that is lifted up",82,118],["H8213","and he shall be brought low",120,147]]},"2:13":{"text":"And upon all the cedars of Lebanon, that are high and lifted up, and upon all the oaks of Bashan,","words":[["H0730","And upon all the cedars",0,23],["H3844","of Lebanon",24,34],["H7311","that are high",36,49],["H5375","and lifted up",50,63],["H0437","and upon all the oaks",65,86],["H1316","of Bashan",87,96]]},"2:14":{"text":"And upon all the high mountains, and upon all the hills that are lifted up,","words":[["H7311","And upon all the high",0,21],["H2022","mountains",22,31],["H1389","and upon all the hills",33,55],["H5375","that are lifted up",56,74]]},"2:15":{"text":"And upon every high tower, and upon every fenced wall,","words":[["H1364","And upon every high",0,19],["H4026","tower",20,25],["H1219","and upon every fenced",27,48],["H2346","wall",49,53]]},"2:16":{"text":"And upon all the ships of Tarshish, and upon all pleasant pictures.","words":[["H0591","And upon all the ships",0,22],["H8659","of Tarshish",23,34],["H2532","and upon all pleasant",36,57],["H7914","pictures",58,66]]},"2:17":{"text":"And the loftiness of man shall be bowed down, and the haughtiness of men shall be made low: and the LORD alone shall be exalted in that day.","words":[["H1365","And the loftiness",0,17],["H0120","of man",18,24],["H7817","shall be bowed down",25,44],["H7312","and the haughtiness",46,65],["H0582","of men",66,72],["H8213","shall be made low",73,90],["H3068","and the LORD",92,104],["H7682","alone shall be exalted",105,127],["H3117","in that day",128,139]]},"2:18":{"text":"And the idols he shall utterly abolish.","words":[["H0457","And the idols",0,13],["H3632","he shall utterly",14,30],["H2498","abolish",31,38]]},"2:19":{"text":"And they shall go into the holes of the rocks, and into the caves of the earth, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.","words":[["H0935","And they shall go",0,17],["H4631","into the holes",18,32],["H6697","of the rocks",33,45],["H4247","and into the caves",47,65],["H6083","of the earth",66,78],["H6440","for",80,83],["H6343","fear",84,88],["H3068","of the LORD",89,100],["H1926","and for the glory",102,119],["H1347","of his majesty",120,134],["H6965","when he ariseth",136,151],["H6206","to shake terribly",152,169],["H0776","the earth",170,179]]},"2:20":{"text":"In that day a man shall cast his idols of silver, and his idols of gold, which they made each one for himself to worship, to the moles and to the bats;","words":[["H3117","In that day",0,11],["H0120","a man",12,17],["H7993","shall cast",18,28],["H0457","his idols",29,38],["H3701","of silver",39,48],["H0457","and his idols",50,63],["H2091","of gold",64,71],["H6213","which they made each one for himself",73,109],["H7812","to worship",110,120],["H2661","to the moles",122,134],["H6512","to the moles",122,134],["H5847","and to the bats",135,150]]},"2:21":{"text":"To go into the clefts of the rocks, and into the tops of the ragged rocks, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.","words":[["H0935","To go",0,5],["H5366","into the clefts",6,21],["H6697","of the rocks",22,34],["H5585","and into the tops",36,53],["H5553","of the ragged rocks",54,73],["H6440","for",75,78],["H6343","fear",79,83],["H3068","of the LORD",84,95],["H1926","and for the glory",97,114],["H1347","of his majesty",115,129],["H6965","when he ariseth",131,146],["H6206","to shake terribly",147,164],["H0776","the earth",165,174]]},"2:22":{"text":"Cease ye from man, whose breath is in his nostrils: for wherein is he to be accounted of?","words":[["H2308","Cease",0,5],["H0120","ye from man",6,17],["H5397","whose breath",19,31],["H0639","is in his nostrils",32,50],["H2803","for wherein is he to be accounted of",52,88]]},"3:1":{"text":"For, behold, the Lord, the LORD of hosts, doth take away from Jerusalem and from Judah the stay and the staff, the whole stay of bread, and the whole stay of water,","words":[["H0113","For, behold, the Lord",0,21],["H3068","the LORD",23,31],["H6635","of hosts",32,40],["H5493","doth take away",42,56],["H3389","from Jerusalem",57,71],["H3063","and from Judah",72,86],["H4937","the stay",87,95],["H4938","and the staff",96,109],["H4937","the whole stay",111,125],["H3899","of bread",126,134],["H3605","and the whole",136,149],["H4937","stay",150,154],["H4325","of water",155,163]]},"3:2":{"text":"The mighty man, and the man of war, the judge, and the prophet, and the prudent, and the ancient,","words":[["H1368","The mighty man",0,14],["H0376","and the man",16,27],["H4421","of war",28,34],["H8199","the judge",36,45],["H5030","and the prophet",47,62],["H7080","and the prudent",64,79],["H2205","and the ancient",81,96]]},"3:3":{"text":"The captain of fifty, and the honourable man, and the counsellor, and the cunning artificer, and the eloquent orator.","words":[["H8269","The captain",0,11],["H2572","of fifty",12,20],["H5375","and the honourable",22,40],["H6440","man",41,44],["H3289","and the counsellor",46,64],["H2450","and the cunning",66,81],["H2791","artificer",82,91],["H0995","and the eloquent",93,109],["H3908","orator",110,116]]},"3:4":{"text":"And I will give children to be their princes, and babes shall rule over them.","words":[["H5414","And I will give",0,15],["H5288","children",16,24],["H8269","to be their princes",25,44],["H8586","and babes",46,55],["H4910","shall rule",56,66]]},"3:5":{"text":"And the people shall be oppressed, every one by another, and every one by his neighbour: the child shall behave himself proudly against the ancient, and the base against the honourable.","words":[["H5971","And the people",0,14],["H5065","shall be oppressed",15,33],["H0376","every one",35,44],["H0376","by another",45,55],["H0376","and every one",57,70],["H7453","by his neighbour",71,87],["H5288","the child",89,98],["H7292","shall behave himself proudly",99,127],["H2205","against the ancient",128,147],["H7034","and the base",149,161],["H3513","against the honourable",162,184]]},"3:6":{"text":"When a man shall take hold of his brother of the house of his father, saying, Thou hast clothing, be thou our ruler, and let this ruin be under thy hand:","words":[["H0376","When a man",0,10],["H8610","shall take hold",11,26],["H0251","of his brother",27,41],["H1004","of the house",42,54],["H0001","of his father",55,68],["H8071","saying, Thou hast clothing",70,96],["H7101","be thou our ruler",98,115],["H4384","and let this ruin",117,134],["H3027","be under thy hand",135,152]]},"3:7":{"text":"In that day shall he swear, saying, I will not be an healer; for in my house is neither bread nor clothing: make me not a ruler of the people.","words":[["H3117","In that day",0,11],["H5375","shall he swear",12,26],["H0559","saying",28,34],["H2280","I will not be an healer",36,59],["H1004","for in my house",61,76],["H3899","is neither bread",77,93],["H8071","nor clothing",94,106],["H7760","make",108,112],["H7101","me not a ruler",113,127],["H5971","of the people",128,141]]},"3:8":{"text":"For Jerusalem is ruined, and Judah is fallen: because their tongue and their doings are against the LORD, to provoke the eyes of his glory.","words":[["H3389","For Jerusalem",0,13],["H3782","is ruined",14,23],["H3063","and Judah",25,34],["H5307","is fallen",35,44],["H3956","because their tongue",46,66],["H4611","and their doings",67,83],["H3068","are against the LORD",84,104],["H4784","to provoke",106,116],["H5869","the eyes",117,125],["H3519","of his glory",126,138]]},"3:9":{"text":"The shew of their countenance doth witness against them; and they declare their sin as Sodom, they hide it not. Woe unto their soul! for they have rewarded evil unto themselves.","words":[["H1971","The shew",0,8],["H6440","of their countenance",9,29],["H6030","doth witness against them",30,55],["H5046","and they declare",57,73],["H2403","their sin",74,83],["H5467","as Sodom",84,92],["H3582","they hide",94,103],["H0188","it not. Woe",104,115],["H5315","unto their soul",116,131],["H1580","for they have rewarded",133,155],["H7451","evil",156,160]]},"3:10":{"text":"Say ye to the righteous, that it shall be well with him: for they shall eat the fruit of their doings.","words":[["H0559","Say",0,3],["H6662","ye to the righteous",4,23],["H2896","that it shall be well",25,46],["H0398","with him: for they shall eat",47,75],["H6529","the fruit",76,85],["H4611","of their doings",86,101]]},"3:11":{"text":"Woe unto the wicked! it shall be ill with him: for the reward of his hands shall be given him.","words":[["H0188","Woe",0,3],["H7563","unto the wicked",4,19],["H7451","it shall be ill",21,36],["H1576","with him: for the reward",37,61],["H3027","of his hands",62,74],["H6213","shall be given",75,89]]},"3:12":{"text":"As for my people, children are their oppressors, and women rule over them. O my people, they which lead thee cause thee to err, and destroy the way of thy paths.","words":[["H5971","As for my people",0,16],["H5953","children",18,26],["H5065","are their oppressors",27,47],["H0802","and women",49,58],["H4910","rule",59,63],["H5971","over them. O my people",64,86],["H0833","they which lead",88,103],["H8582","thee cause thee to err",104,126],["H1104","and destroy",128,139],["H1870","the way",140,147],["H0734","of thy paths",148,160]]},"3:13":{"text":"The LORD standeth up to plead, and standeth to judge the people.","words":[["H3068","The LORD",0,8],["H5324","standeth up",9,20],["H7378","to plead",21,29],["H5975","and standeth",31,43],["H1777","to judge",44,52],["H5971","the people",53,63]]},"3:14":{"text":"The LORD will enter into judgment with the ancients of his people, and the princes thereof: for ye have eaten up the vineyard; the spoil of the poor is in your houses.","words":[["H3068","The LORD",0,8],["H0935","will enter",9,19],["H4941","into judgment",20,33],["H2205","with the ancients",34,51],["H5971","of his people",52,65],["H8269","and the princes",67,82],["H1197","thereof: for ye have eaten up",83,112],["H3754","the vineyard",113,125],["H1500","the spoil",127,136],["H6041","of the poor",137,148],["H1004","is in your houses",149,166]]},"3:15":{"text":"What mean ye that ye beat my people to pieces, and grind the faces of the poor? saith the Lord GOD of hosts.","words":[["H1792","What mean ye that ye beat",0,25],["H5971","my people",26,35],["H1792","to pieces",36,45],["H2912","and grind",47,56],["H6440","the faces",57,66],["H6041","of the poor",67,78],["H5002","saith",80,85],["H0136","the Lord",86,94],["H3069","GOD",95,98],["H6635","of hosts",99,107]]},"3:16":{"text":"Moreover the LORD saith, Because the daughters of Zion are haughty, and walk with stretched forth necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet:","words":[["H3068","Moreover the LORD",0,17],["H0559","saith",18,23],["H3282","Because",25,32],["H1323","the daughters",33,46],["H6726","of Zion",47,54],["H1361","are haughty",55,66],["H3212","and walk",68,76],["H5186","with stretched forth",77,97],["H1627","necks",98,103],["H8265","and wanton",104,114],["H5869","eyes",115,119],["H1980","walking",121,128],["H2952","and mincing",129,140],["H3212","as they go",141,151],["H5913","and making a tinkling",153,174],["H7272","with their feet",175,190]]},"3:17":{"text":"Therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and the LORD will discover their secret parts.","words":[["H0136","Therefore the Lord",0,18],["H5596","will smite with a scab",19,41],["H6936","the crown of the head",42,63],["H1323","of the daughters",64,80],["H6726","of Zion",81,88],["H3068","and the LORD",90,102],["H6168","will discover",103,116],["H6596","their secret parts",117,135]]},"3:18":{"text":"In that day the Lord will take away the bravery of their tinkling ornaments about their feet, and their cauls, and their round tires like the moon,","words":[["H3117","In that day",0,11],["H0136","the Lord",12,20],["H5493","will take away",21,35],["H8597","the bravery",36,47],["H5914","of their tinkling ornaments",48,75],["H7636","about their feet, and their cauls",76,109],["H7720","and their round tires like the moon",111,146]]},"3:19":{"text":"The chains, and the bracelets, and the mufflers,","words":[["H5188","The chains",0,10],["H8285","and the bracelets",12,29],["H7479","and the mufflers",31,47]]},"3:20":{"text":"The bonnets, and the ornaments of the legs, and the headbands, and the tablets, and the earrings,","words":[["H6287","The bonnets",0,11],["H6807","and the ornaments of the legs",13,42],["H7196","and the headbands",44,61],["H5315","and the tablets",63,78],["H1004","and the tablets",63,78],["H3908","and the earrings",80,96]]},"3:21":{"text":"The rings, and nose jewels,","words":[["H2885","The rings",0,9],["H0639","and nose",11,19],["H5141","jewels",20,26]]},"3:22":{"text":"The changeable suits of apparel, and the mantles, and the wimples, and the crisping pins,","words":[["H4254","The changeable suits of apparel",0,31],["H4595","and the mantles",33,48],["H4304","and the wimples",50,65],["H2754","and the crisping pins",67,88]]},"3:23":{"text":"The glasses, and the fine linen, and the hoods, and the vails.","words":[["H1549","The glasses",0,11],["H5466","and the fine linen",13,31],["H6797","and the hoods",33,46],["H7289","and the vails",48,61]]},"3:24":{"text":"And it shall come to pass, that instead of sweet smell there shall be stink; and instead of a girdle a rent; and instead of well set hair baldness; and instead of a stomacher a girding of sackcloth; and burning instead of beauty.","words":[["H1314","And it shall come to pass, that instead of sweet smell",0,54],["H4716","there shall be stink",55,75],["H2290","and instead of a girdle",77,100],["H5364","a rent",101,107],["H4639","and instead of well set",109,132],["H4748","hair",133,137],["H7144","baldness",138,146],["H6614","and instead of a stomacher",148,174],["H4228","a girding",175,184],["H8242","of sackcloth",185,197],["H3587","and burning",199,210],["H3308","instead of beauty",211,228]]},"3:25":{"text":"Thy men shall fall by the sword, and thy mighty in the war.","words":[["H4962","Thy men",0,7],["H5307","shall fall",8,18],["H2719","by the sword",19,31],["H1369","and thy mighty",33,47],["H4421","in the war",48,58]]},"3:26":{"text":"And her gates shall lament and mourn; and she being desolate shall sit upon the ground.","words":[["H6607","And her gates",0,13],["H0578","shall lament",14,26],["H0056","and mourn",27,36],["H5352","and she being desolate",38,60],["H3427","shall sit",61,70],["H0776","upon the ground",71,86]]},"4:1":{"text":"And in that day seven women shall take hold of one man, saying, We will eat our own bread, and wear our own apparel: only let us be called by thy name, to take away our reproach.","words":[["H3117","And in that day",0,15],["H7651","seven",16,21],["H0802","women",22,27],["H2388","shall take hold",28,43],["H0259","of one",44,50],["H0376","man",51,54],["H0559","saying",56,62],["H0398","We will eat",64,75],["H3899","our own bread",76,89],["H3847","and wear",91,99],["H8071","our own apparel",100,115],["H7121","only let us be called",117,138],["H8034","by thy name",139,150],["H0622","to take away",152,164],["H2781","our reproach",165,177]]},"4:2":{"text":"In that day shall the branch of the LORD be beautiful and glorious, and the fruit of the earth shall be excellent and comely for them that are escaped of Israel.","words":[["H3117","In that day",0,11],["H6780","shall the branch",12,28],["H3068","of the LORD",29,40],["H6643","be beautiful",41,53],["H3519","and glorious",54,66],["H6529","and the fruit",68,81],["H0776","of the earth",82,94],["H1347","shall be excellent",95,113],["H8597","and comely for",114,128],["H6413","them that are escaped",129,150],["H3478","of Israel",151,160]]},"4:3":{"text":"And it shall come to pass, that he that is left in Zion, and he that remaineth in Jerusalem, shall be called holy, even every one that is written among the living in Jerusalem:","words":[["H7604","And it shall come to pass, that he that is left",0,47],["H6726","in Zion",48,55],["H3498","and he that remaineth",57,78],["H3389","in Jerusalem",79,91],["H0559","shall be called",93,108],["H6918","holy",109,113],["H3789","even every one that is written",115,145],["H2416","among the living",146,162],["H3389","in Jerusalem",163,175]]},"4:4":{"text":"When the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof by the spirit of judgment, and by the spirit of burning.","words":[["H0136","When the Lord",0,13],["H7364","shall have washed away",14,36],["H6675","the filth",37,46],["H1323","of the daughters",47,63],["H6726","of Zion",64,71],["H1740","and shall have purged",73,94],["H1818","the blood",95,104],["H3389","of Jerusalem",105,117],["H7130","from the midst",118,132],["H7307","thereof by the spirit",133,154],["H4941","of judgment",155,166],["H7307","and by the spirit",168,185],["H1197","of burning",186,196]]},"4:5":{"text":"And the LORD will create upon every dwelling place of mount Zion, and upon her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night: for upon all the glory shall be a defence.","words":[["H3068","And the LORD",0,12],["H1254","will create",13,24],["H4349","upon every dwelling place",25,50],["H2022","of mount",51,59],["H6726","Zion",60,64],["H4744","and upon her assemblies",66,89],["H6051","a cloud",91,98],["H6227","and smoke",99,108],["H3119","by day",109,115],["H5051","and the shining",117,132],["H3852","of a flaming",133,145],["H0784","fire",146,150],["H3915","by night",151,159],["H3519","for upon all the glory",161,183],["H2646","shall be a defence",184,202]]},"4:6":{"text":"And there shall be a tabernacle for a shadow in the daytime from the heat, and for a place of refuge, and for a covert from storm and from rain.","words":[["H5521","And there shall be a tabernacle",0,31],["H6738","for a shadow",32,44],["H3119","in the daytime",45,59],["H2721","from the heat",60,73],["H4268","and for a place of refuge",75,100],["H4563","and for a covert",102,118],["H2230","from storm",119,129],["H4306","and from rain",130,143]]},"5:1":{"text":"Now will I sing to my wellbeloved a song of my beloved touching his vineyard. My wellbeloved hath a vineyard in a very fruitful hill:","words":[["H7891","Now will I sing",0,15],["H3039","to my wellbeloved",16,33],["H7892","a song",34,40],["H1730","of my beloved",41,54],["H3754","touching his vineyard",55,76],["H3039","My wellbeloved",78,92],["H3754","hath a vineyard",93,108],["H1121","in a very fruitful",109,127],["H8081","in a very fruitful",109,127],["H7161","hill",128,132]]},"5:2":{"text":"And he fenced it, and gathered out the stones thereof, and planted it with the choicest vine, and built a tower in the midst of it, and also made a winepress therein: and he looked that it should bring forth grapes, and it brought forth wild grapes.","words":[["H5823","And he fenced",0,13],["H5619","it, and gathered out the stones",14,45],["H5193","thereof, and planted",46,66],["H8321","it with the choicest vine",67,92],["H1129","and built",94,103],["H4026","a tower",104,111],["H8432","in the midst",112,124],["H2672","of it, and also made",125,145],["H3342","a winepress",146,157],["H6960","therein: and he looked",158,180],["H6213","that it should bring forth",181,207],["H6025","grapes",208,214],["H6213","and it brought forth",216,236],["H0891","wild grapes",237,248]]},"5:3":{"text":"And now, O inhabitants of Jerusalem, and men of Judah, judge, I pray you, betwixt me and my vineyard.","words":[["H3427","And now, O inhabitants",0,22],["H3389","of Jerusalem",23,35],["H0376","and men",37,44],["H3063","of Judah",45,53],["H8199","judge",55,60],["H3754","I pray you, betwixt me and my vineyard",62,100]]},"5:4":{"text":"What could have been done more to my vineyard, that I have not done in it? wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes?","words":[["H6213","What could have been done",0,25],["H3754","more to my vineyard",26,45],["H6213","that I have not done",47,67],["H4069","in it? wherefore",68,84],["H6960","when I looked",86,99],["H6213","that it should bring forth",100,126],["H6025","grapes",127,133],["H6213","brought it forth",135,151],["H0891","wild grapes",152,163]]},"5:5":{"text":"And now go to; I will tell you what I will do to my vineyard: I will take away the hedge thereof, and it shall be eaten up; and break down the wall thereof, and it shall be trodden down:","words":[["H3045","And now go to; I will tell",0,26],["H6213","you what I will do",27,45],["H3754","to my vineyard",46,60],["H5493","I will take away",62,78],["H4881","the hedge",79,88],["H1197","thereof, and it shall be eaten up",89,122],["H6555","and break down",124,138],["H1447","the wall",139,147],["H4823","thereof, and it shall be trodden down",148,185]]},"5:6":{"text":"And I will lay it waste: it shall not be pruned, nor digged; but there shall come up briers and thorns: I will also command the clouds that they rain no rain upon it.","words":[["H7896","And I will lay",0,14],["H1326","it waste",15,23],["H2168","it shall not be pruned",25,47],["H5737","nor digged",49,59],["H5927","but there shall come up",61,84],["H8068","briers",85,91],["H7898","and thorns",92,102],["H6680","I will also command",104,123],["H5645","the clouds",124,134],["H4305","that they rain",135,149],["H4306","no rain",150,157]]},"5:7":{"text":"For the vineyard of the LORD of hosts is the house of Israel, and the men of Judah his pleasant plant: and he looked for judgment, but behold oppression; for righteousness, but behold a cry.","words":[["H3754","For the vineyard",0,16],["H3068","of the LORD",17,28],["H6635","of hosts",29,37],["H1004","is the house",38,50],["H3478","of Israel",51,60],["H0376","and the men",62,73],["H3063","of Judah",74,82],["H8191","his pleasant",83,95],["H5194","plant",96,101],["H6960","and he looked",103,116],["H4941","for judgment",117,129],["H4939","but behold oppression",131,152],["H6666","for righteousness",154,171],["H6818","but behold a cry",173,189]]},"5:8":{"text":"Woe unto them that join house to house, that lay field to field, till there be no place, that they may be placed alone in the midst of the earth!","words":[["H1945","Woe",0,3],["H5060","unto them that join",4,23],["H1004","house",24,29],["H1004","to house",30,38],["H7126","that lay",40,48],["H7704","field",49,54],["H7704","to field",55,63],["H0657","till there be no",65,81],["H4725","place",82,87],["H3427","that they may be placed",89,112],["H7130","alone in the midst",113,131],["H0776","of the earth",132,144]]},"5:9":{"text":"In mine ears said the LORD of hosts, Of a truth many houses shall be desolate, even great and fair, without inhabitant.","words":[["H0241","In mine ears",0,12],["H3068","said the LORD",13,26],["H6635","of hosts",27,35],["H3808","Of a truth",37,47],["H7227","many",48,52],["H1004","houses",53,59],["H8047","shall be desolate",60,77],["H1419","even great",79,89],["H2896","and fair",90,98],["H3427","without inhabitant",100,118]]},"5:10":{"text":"Yea, ten acres of vineyard shall yield one bath, and the seed of an homer shall yield an ephah.","words":[["H3588","Yea",0,3],["H6235","ten",5,8],["H6776","acres",9,14],["H3754","of vineyard",15,26],["H6213","shall yield",27,38],["H0259","one",39,42],["H1324","bath",43,47],["H2233","and the seed",49,61],["H2563","of an homer",62,73],["H6213","shall yield",74,85],["H0374","an ephah",86,94]]},"5:11":{"text":"Woe unto them that rise up early in the morning, that they may follow strong drink; that continue until night, till wine inflame them!","words":[["H1945","Woe",0,3],["H7925","unto them that rise up early",4,32],["H1242","in the morning",33,47],["H7291","that they may follow",49,69],["H7941","strong drink",70,82],["H0309","that continue",84,97],["H5399","until night",98,109],["H3196","till wine",111,120],["H1814","inflame",121,128]]},"5:12":{"text":"And the harp, and the viol, the tabret, and pipe, and wine, are in their feasts: but they regard not the work of the LORD, neither consider the operation of his hands.","words":[["H3658","And the harp",0,12],["H5035","and the viol",14,26],["H8596","the tabret",28,38],["H2485","and pipe",40,48],["H3196","and wine",50,58],["H4960","are in their feasts",60,79],["H5027","but they regard",81,96],["H6467","not the work",97,109],["H3068","of the LORD",110,121],["H7200","neither consider",123,139],["H4639","the operation",140,153],["H3027","of his hands",154,166]]},"5:13":{"text":"Therefore my people are gone into captivity, because they have no knowledge: and their honourable men are famished, and their multitude dried up with thirst.","words":[["H5971","Therefore my people",0,19],["H1540","are gone into captivity",20,43],["H1847","because they have no knowledge",45,75],["H3519","and their honourable",77,97],["H4962","men",98,101],["H7458","are famished",102,114],["H1995","and their multitude",116,135],["H6704","dried up",136,144],["H6772","with thirst",145,156]]},"5:14":{"text":"Therefore hell hath enlarged herself, and opened her mouth without measure: and their glory, and their multitude, and their pomp, and he that rejoiceth, shall descend into it.","words":[["H7585","Therefore hell",0,14],["H7337","hath enlarged",15,28],["H5315","herself",29,36],["H6473","and opened",38,48],["H6310","her mouth",49,58],["H2706","without measure",59,74],["H1926","and their glory",76,91],["H1995","and their multitude",93,112],["H7588","and their pomp",114,128],["H5938","and he that rejoiceth",130,151],["H3381","shall descend",153,166]]},"5:15":{"text":"And the mean man shall be brought down, and the mighty man shall be humbled, and the eyes of the lofty shall be humbled:","words":[["H0120","And the mean man",0,16],["H7817","shall be brought down",17,38],["H0376","and the mighty man",40,58],["H8213","shall be humbled",59,75],["H5869","and the eyes",77,89],["H1364","of the lofty",90,102],["H8213","shall be humbled",103,119]]},"5:16":{"text":"But the LORD of hosts shall be exalted in judgment, and God that is holy shall be sanctified in righteousness.","words":[["H3068","But the LORD",0,12],["H6635","of hosts",13,21],["H1361","shall be exalted",22,38],["H4941","in judgment",39,50],["H0410","and God",52,59],["H6918","that is holy",60,72],["H6942","shall be sanctified",73,92],["H6666","in righteousness",93,109]]},"5:17":{"text":"Then shall the lambs feed after their manner, and the waste places of the fat ones shall strangers eat.","words":[["H3532","Then shall the lambs",0,20],["H7462","feed",21,25],["H1699","after their manner",26,44],["H2723","and the waste places",46,66],["H4220","of the fat ones",67,82],["H1481","shall strangers",83,98],["H0398","eat",99,102]]},"5:18":{"text":"Woe unto them that draw iniquity with cords of vanity, and sin as it were with a cart rope:","words":[["H1945","Woe",0,3],["H4900","unto them that draw",4,23],["H5771","iniquity",24,32],["H2256","with cords",33,43],["H7723","of vanity",44,53],["H2403","and sin",55,62],["H5699","as it were with a cart",63,85],["H5688","rope",86,90]]},"5:19":{"text":"That say, Let him make speed, and hasten his work, that we may see it: and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!","words":[["H0559","That say",0,8],["H4116","Let him make speed",10,28],["H2363","and hasten",30,40],["H4639","his work",41,49],["H7200","that we may see",51,66],["H6098","it: and let the counsel",67,90],["H6918","of the Holy One",91,106],["H3478","of Israel",107,116],["H7126","draw nigh",117,126],["H0935","and come",127,135],["H3045","that we may know",137,153]]},"5:20":{"text":"Woe unto them that call evil good, and good evil; that put darkness for light, and light for darkness; that put bitter for sweet, and sweet for bitter!","words":[["H1945","Woe",0,3],["H0559","unto them that call",4,23],["H7451","evil",24,28],["H2896","good",29,33],["H2896","and good",35,43],["H7451","evil",44,48],["H7760","that put",50,58],["H2822","darkness",59,67],["H0216","for light",68,77],["H0216","and light",79,88],["H2822","for darkness",89,101],["H7760","that put",103,111],["H4751","bitter",112,118],["H4966","for sweet",119,128],["H4966","and sweet",130,139],["H4751","for bitter",140,150]]},"5:21":{"text":"Woe unto them that are wise in their own eyes, and prudent in their own sight!","words":[["H1945","Woe",0,3],["H2450","unto them that are wise",4,27],["H5869","in their own eyes",28,45],["H0995","and prudent",47,58],["H6440","in their own sight",59,77]]},"5:22":{"text":"Woe unto them that are mighty to drink wine, and men of strength to mingle strong drink:","words":[["H1945","Woe",0,3],["H1368","unto them that are mighty",4,29],["H8354","to drink",30,38],["H3196","wine",39,43],["H0582","and men",45,52],["H2428","of strength",53,64],["H4537","to mingle",65,74],["H7941","strong drink",75,87]]},"5:23":{"text":"Which justify the wicked for reward, and take away the righteousness of the righteous from him!","words":[["H6663","Which justify",0,13],["H7563","the wicked",14,24],["H6118","for",25,28],["H7810","reward",29,35],["H5493","and take away",37,50],["H6666","the righteousness",51,68],["H6662","of the righteous",69,85]]},"5:24":{"text":"Therefore as the fire devoureth the stubble, and the flame consumeth the chaff, so their root shall be as rottenness, and their blossom shall go up as dust: because they have cast away the law of the LORD of hosts, and despised the word of the Holy One of Israel.","words":[["H0784","Therefore as the fire",0,21],["H0398","devoureth",22,31],["H7179","the stubble",32,43],["H3956","and the flame",45,58],["H3852","and the flame",45,58],["H7503","consumeth",59,68],["H2842","the chaff",69,78],["H8328","so their root",80,93],["H4716","shall be as rottenness",94,116],["H6525","and their blossom",118,135],["H5927","shall go up",136,147],["H0080","as dust",148,155],["H3988","because they have cast away",157,184],["H8451","the law",185,192],["H3068","of the LORD",193,204],["H6635","of hosts",205,213],["H5006","and despised",215,227],["H0565","the word",228,236],["H6918","of the Holy One",237,252],["H3478","of Israel",253,262]]},"5:25":{"text":"Therefore is the anger of the LORD kindled against his people, and he hath stretched forth his hand against them, and hath smitten them: and the hills did tremble, and their carcases were torn in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still.","words":[["H0639","Therefore is the anger",0,22],["H3068","of the LORD",23,34],["H2734","kindled",35,42],["H5971","against his people",43,61],["H5186","and he hath stretched forth",63,90],["H3027","his hand",91,99],["H5221","against them, and hath smitten",100,130],["H2022","them: and the hills",131,150],["H7264","did tremble",151,162],["H5038","and their carcases",164,182],["H5478","were torn",183,192],["H7130","in the midst",193,205],["H2351","of the streets",206,220],["H0639","For all this his anger",222,244],["H7725","is not turned away",245,263],["H3027","but his hand",265,277],["H5186","is stretched out",278,294]]},"5:26":{"text":"And he will lift up an ensign to the nations from far, and will hiss unto them from the end of the earth: and, behold, they shall come with speed swiftly:","words":[["H5375","And he will lift up",0,19],["H5251","an ensign",20,29],["H1471","to the nations",30,44],["H7350","from far",45,53],["H8319","and will hiss",55,68],["H7097","unto them from the end",69,91],["H0776","of the earth",92,104],["H0935","and, behold, they shall come",106,134],["H4120","with speed",135,145],["H7031","swiftly",146,153]]},"5:27":{"text":"None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken:","words":[["H5889","None shall be weary",0,19],["H3782","nor stumble",20,31],["H5123","among them; none shall slumber",32,62],["H3462","nor sleep",63,72],["H0232","neither shall the girdle",74,98],["H2504","of their loins",99,113],["H6605","be loosed",114,123],["H8288","nor the latchet",125,140],["H5275","of their shoes",141,155],["H5423","be broken",156,165]]},"5:28":{"text":"Whose arrows are sharp, and all their bows bent, their horses' hoofs shall be counted like flint, and their wheels like a whirlwind:","words":[["H2671","Whose arrows",0,12],["H8150","are sharp",13,22],["H7198","and all their bows",24,42],["H1869","bent",43,47],["H5483","their horses'",49,62],["H6541","hoofs",63,68],["H2803","shall be counted",69,85],["H6862","like flint",86,96],["H1534","and their wheels",98,114],["H5492","like a whirlwind",115,131]]},"5:29":{"text":"Their roaring shall be like a lion, they shall roar like young lions: yea, they shall roar, and lay hold of the prey, and shall carry it away safe, and none shall deliver it.","words":[["H7581","Their roaring",0,13],["H3833","shall be like a lion",14,34],["H7580","they shall roar",36,51],["H7580","they shall roar",36,51],["H3715","like young lions",52,68],["H5098","yea, they shall roar",70,90],["H0270","and lay hold",92,104],["H2964","of the prey",105,116],["H6403","and shall carry it away safe",118,146],["H5337","and none shall deliver",148,170]]},"5:30":{"text":"And in that day they shall roar against them like the roaring of the sea: and if one look unto the land, behold darkness and sorrow, and the light is darkened in the heavens thereof.","words":[["H3117","And in that day",0,15],["H5098","they shall roar",16,31],["H5100","against them like the roaring",32,61],["H3220","of the sea",62,72],["H5027","and if one look",74,89],["H0776","unto the land",90,103],["H2822","behold darkness",105,120],["H6862","and sorrow",121,131],["H0216","and the light",133,146],["H2821","is darkened",147,158],["H6183","in the heavens",159,173]]},"6:1":{"text":"In the year that king Uzziah died I saw also the Lord sitting upon a throne, high and lifted up, and his train filled the temple.","words":[["H8141","In the year",0,11],["H4428","that king",12,21],["H5818","Uzziah",22,28],["H4194","died",29,33],["H7200","I saw",34,39],["H0853","also",40,44],["H0136","the Lord",45,53],["H3427","sitting",54,61],["H3678","upon a throne",62,75],["H7311","high",77,81],["H5375","and lifted up",82,95],["H7757","and his train",97,110],["H4392","filled",111,117],["H0853","",-1,-1],["H1964","the temple",118,128]]},"6:2":{"text":"Above it stood the seraphims: each one had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he did fly.","words":[["H4605","Above",0,5],["H5975","it stood",6,14],["H8314","the seraphims",15,28],["H0259","each one",30,38],["H8337","had six",39,46],["H3671","wings",47,52],["H8147","with twain",54,64],["H3680","he covered",65,75],["H6440","his face",76,84],["H8147","and with twain",86,100],["H3680","he covered",101,111],["H7272","his feet",112,120],["H8147","and with twain",122,136],["H5774","he did fly",137,147]]},"6:3":{"text":"And one cried unto another, and said, Holy, holy, holy, is the LORD of hosts: the whole earth is full of his glory.","words":[["H7121","And one cried",0,13],["H0559","unto another, and said",14,36],["H6918","Holy",38,42],["H6918","holy",44,48],["H6918","holy",50,54],["H3068","is the LORD",56,67],["H6635","of hosts",68,76],["H0776","the whole earth",78,93],["H4393","is full",94,101],["H3519","of his glory",102,114]]},"6:4":{"text":"And the posts of the door moved at the voice of him that cried, and the house was filled with smoke.","words":[["H0520","And the posts",0,13],["H5592","of the door",14,25],["H5128","moved",26,31],["H6963","at the voice",32,44],["H7121","of him that cried",45,62],["H1004","and the house",64,77],["H4390","was filled",78,88],["H6227","with smoke",89,99]]},"6:5":{"text":"Then said I, Woe is me! for I am undone; because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for mine eyes have seen the King, the LORD of hosts.","words":[["H0559","Then said",0,9],["H0188","I, Woe",10,16],["H1820","is me! for I am undone",17,39],["H0376","because I am a man",41,59],["H2931","of unclean",60,70],["H8193","lips",71,75],["H3427","and I dwell",77,88],["H8432","in the midst",89,101],["H5971","of a people",102,113],["H2931","of unclean",114,124],["H8193","lips",125,129],["H5869","for mine eyes",131,144],["H7200","have seen",145,154],["H4428","the King",155,163],["H3068","the LORD",165,173],["H6635","of hosts",174,182]]},"6:6":{"text":"Then flew one of the seraphims unto me, having a live coal in his hand, which he had taken with the tongs from off the altar:","words":[["H5774","Then flew",0,9],["H0259","one",10,13],["H8314","of the seraphims",14,30],["H7531","unto me, having a live coal",31,58],["H3027","in his hand",59,70],["H3947","which he had taken",72,90],["H4457","with the tongs",91,105],["H4196","from off the altar",106,124]]},"6:7":{"text":"And he laid it upon my mouth, and said, Lo, this hath touched thy lips; and thine iniquity is taken away, and thy sin purged.","words":[["H5060","And he laid",0,11],["H6310","it upon my mouth",12,28],["H0559","and said",30,38],["H5060","Lo, this hath touched",40,61],["H8193","thy lips",62,70],["H5771","and thine iniquity",72,90],["H5493","is taken away",91,104],["H2403","and thy sin",106,117],["H3722","purged",118,124]]},"6:8":{"text":"Also I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then said I, Here am I; send me.","words":[["H8085","Also I heard",0,12],["H6963","the voice",13,22],["H0136","of the Lord",23,34],["H0559","saying",36,42],["H7971","Whom shall I send",44,61],["H3212","and who will go",63,78],["H0559","for us? Then said",79,96],["H7971","I, Here am I; send",97,115]]},"6:9":{"text":"And he said, Go, and tell this people, Hear ye indeed, but understand not; and see ye indeed, but perceive not.","words":[["H0559","And he said",0,11],["H3212","Go",13,15],["H0559","and tell",17,25],["H5971","this people",26,37],["H8085","Hear",39,43],["H8085","ye indeed",44,53],["H0995","but understand",55,69],["H7200","not; and see",70,82],["H7200","ye indeed",83,92],["H3045","but perceive",94,106]]},"6:10":{"text":"Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and convert, and be healed.","words":[["H3820","Make the heart",0,14],["H5971","of this people",15,29],["H8080","fat",30,33],["H0241","and make their ears",35,54],["H3513","heavy",55,60],["H8173","and shut",62,70],["H5869","their eyes",71,81],["H7200","lest they see",83,96],["H5869","with their eyes",97,112],["H8085","and hear",114,122],["H0241","with their ears",123,138],["H0995","and understand",140,154],["H3824","with their heart",155,171],["H7725","and convert",173,184],["H7495","and be healed",186,199]]},"6:11":{"text":"Then said I, Lord, how long? And he answered, Until the cities be wasted without inhabitant, and the houses without man, and the land be utterly desolate,","words":[["H0559","Then said",0,9],["H0136","I, Lord",10,17],["H0559","how long? And he answered",19,44],["H5892","Until the cities",46,62],["H7582","be wasted",63,72],["H3427","without inhabitant",73,91],["H1004","and the houses",93,107],["H0120","without man",108,119],["H0127","and the land",121,133],["H8077","be utterly",134,144],["H7582","desolate",145,153]]},"6:12":{"text":"And the LORD have removed men far away, and there be a great forsaking in the midst of the land.","words":[["H3068","And the LORD",0,12],["H7368","have removed",13,25],["H0120","men",26,29],["H7368","far away",30,38],["H7227","and there be a great",40,60],["H5805","forsaking",61,70],["H7130","in the midst",71,83],["H0776","of the land",84,95]]},"6:13":{"text":"But yet in it shall be a tenth, and it shall return, and shall be eaten: as a teil tree, and as an oak, whose substance is in them, when they cast their leaves: so the holy seed shall be the substance thereof.","words":[["H6224","But yet in it shall be a tenth",0,30],["H7725","and it shall return",32,51],["H1197","and shall be eaten",53,71],["H0424","as a teil tree",73,87],["H0437","and as an oak",89,102],["H4678","whose substance",104,119],["H7995","is in them, when they cast",120,146],["H6944","their leaves: so the holy",147,172],["H2233","seed",173,177],["H4678","shall be the substance",178,200]]},"7:1":{"text":"And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up toward Jerusalem to war against it, but could not prevail against it.","words":[["H3117","And it came to pass in the days",0,31],["H0271","of Ahaz",32,39],["H1121","the son",40,47],["H3147","of Jotham",48,57],["H1121","the son",59,66],["H5818","of Uzziah",67,76],["H4428","king",78,82],["H3063","of Judah",83,91],["H7526","that Rezin",93,103],["H4428","the king",104,112],["H0758","of Syria",113,121],["H6492","and Pekah",123,132],["H1121","the son",133,140],["H7425","of Remaliah",141,152],["H4428","king",154,158],["H3478","of Israel",159,168],["H5927","went up",170,177],["H3389","toward Jerusalem",178,194],["H4421","to war",195,201],["H3201","against it, but could",202,223],["H3898","not prevail",224,235]]},"7:2":{"text":"And it was told the house of David, saying, Syria is confederate with Ephraim. And his heart was moved, and the heart of his people, as the trees of the wood are moved with the wind.","words":[["H5046","And it was told",0,15],["H1004","the house",16,25],["H1732","of David",26,34],["H0559","saying",36,42],["H0758","Syria",44,49],["H5117","is confederate",50,64],["H0669","with Ephraim",65,77],["H3824","And his heart",79,92],["H5128","was moved",93,102],["H3824","and the heart",104,117],["H5971","of his people",118,131],["H6086","as the trees",133,145],["H3293","of the wood",146,157],["H5128","are moved",158,167],["H6440","with",168,172],["H7307","the wind",173,181]]},"7:3":{"text":"Then said the LORD unto Isaiah, Go forth now to meet Ahaz, thou, and Shearjashub thy son, at the end of the conduit of the upper pool in the highway of the fuller's field;","words":[["H0559","Then said",0,9],["H3068","the LORD",10,18],["H3470","unto Isaiah",19,30],["H3318","Go forth",32,40],["H7125","now to meet",41,52],["H0271","Ahaz",53,57],["H7610","thou, and Shearjashub",59,80],["H1121","thy son",81,88],["H7097","at the end",90,100],["H8585","of the conduit",101,115],["H5945","of the upper",116,128],["H1295","pool",129,133],["H4546","in the highway",134,148],["H3526","of the fuller's",149,164],["H7704","field",165,170]]},"7:4":{"text":"And say unto him, Take heed, and be quiet; fear not, neither be fainthearted for the two tails of these smoking firebrands, for the fierce anger of Rezin with Syria, and of the son of Remaliah.","words":[["H0559","And say",0,7],["H8104","unto him, Take heed",8,27],["H8252","and be quiet",29,41],["H3372","fear",43,47],["H7401","not, neither be fainthearted",48,76],["H3824","not, neither be fainthearted",48,76],["H8147","for the two",77,88],["H2180","tails",89,94],["H6226","of these smoking",95,111],["H0181","firebrands",112,122],["H2750","for the fierce",124,138],["H0639","anger",139,144],["H7526","of Rezin",145,153],["H0758","with Syria",154,164],["H1121","and of the son",166,180],["H7425","of Remaliah",181,192]]},"7:5":{"text":"Because Syria, Ephraim, and the son of Remaliah, have taken evil counsel against thee, saying,","words":[["H0758","Because Syria",0,13],["H0669","Ephraim",15,22],["H1121","and the son",24,35],["H7425","of Remaliah",36,47],["H7451","have taken evil",49,64],["H3289","counsel",65,72],["H0559","against thee, saying",73,93]]},"7:6":{"text":"Let us go up against Judah, and vex it, and let us make a breach therein for us, and set a king in the midst of it, even the son of Tabeal:","words":[["H5927","Let us go up",0,12],["H3063","against Judah",13,26],["H6973","and vex",28,35],["H1234","it, and let us make a breach",36,64],["H4427","therein for us, and set",65,88],["H4428","a king",89,95],["H8432","in the midst",96,108],["H1121","of it, even the son",109,128],["H2870","of Tabeal",129,138]]},"7:7":{"text":"Thus saith the Lord GOD, It shall not stand, neither shall it come to pass.","words":[["H3541","Thus",0,4],["H0559","saith",5,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6965","It shall not stand",25,43]]},"7:8":{"text":"For the head of Syria is Damascus, and the head of Damascus is Rezin; and within threescore and five years shall Ephraim be broken, that it be not a people.","words":[["H7218","For the head",0,12],["H0758","of Syria",13,21],["H1834","is Damascus",22,33],["H7218","and the head",35,47],["H1834","of Damascus",48,59],["H7526","is Rezin",60,68],["H8346","and within threescore",70,91],["H2568","and five",92,100],["H8141","years",101,106],["H0669","shall Ephraim",107,120],["H2865","be broken",121,130],["H5971","that it be not a people",132,155]]},"7:9":{"text":"And the head of Ephraim is Samaria, and the head of Samaria is Remaliah's son. If ye will not believe, surely ye shall not be established.","words":[["H7218","And the head",0,12],["H0669","of Ephraim",13,23],["H8111","is Samaria",24,34],["H7218","and the head",36,48],["H8111","of Samaria",49,59],["H7425","is Remaliah's",60,73],["H1121","son",74,77],["H0539","If ye will not believe",79,101],["H0539","surely ye shall not be established",103,137]]},"7:10":{"text":"Moreover the LORD spake again unto Ahaz, saying,","words":[["H3068","Moreover the LORD",0,17],["H1696","spake",18,23],["H3254","again",24,29],["H0271","unto Ahaz",30,39],["H0559","saying",41,47]]},"7:11":{"text":"Ask thee a sign of the LORD thy God; ask it either in the depth, or in the height above.","words":[["H7592","Ask",0,3],["H0226","thee a sign",4,15],["H3068","of the LORD",16,27],["H0430","thy God",28,35],["H7592","ask",37,40],["H6009","it either in the depth",41,63],["H1361","or in the height",65,81],["H4605","above",82,87]]},"7:12":{"text":"But Ahaz said, I will not ask, neither will I tempt the LORD.","words":[["H0271","But Ahaz",0,8],["H0559","said",9,13],["H7592","I will not ask",15,29],["H5254","neither will I tempt",31,51],["H0853","",-1,-1],["H3068","the LORD",52,60]]},"7:13":{"text":"And he said, Hear ye now, O house of David; Is it a small thing for you to weary men, but will ye weary my God also?","words":[["H0559","And he said",0,11],["H8085","Hear",13,17],["H1004","ye now, O house",18,33],["H1732","of David",34,42],["H4592","Is it a small thing",44,63],["H3811","for you to weary",64,80],["H0582","men",81,84],["H3811","but will ye weary",86,103],["H0430","my God",104,110]]},"7:14":{"text":"Therefore the Lord himself shall give you a sign; Behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.","words":[["H0136","Therefore the Lord",0,18],["H5414","himself shall give",19,37],["H0226","you a sign",38,48],["H5959","Behold, a virgin",50,66],["H2030","shall conceive",67,81],["H3205","and bear",83,91],["H1121","a son",92,97],["H7121","and shall call",99,113],["H8034","his name",114,122],["H0410","Immanuel",123,131],["H6005","Immanuel",123,131]]},"7:15":{"text":"Butter and honey shall he eat, that he may know to refuse the evil, and choose the good.","words":[["H2529","Butter",0,6],["H1706","and honey",7,16],["H0398","shall he eat",17,29],["H3045","that he may know",31,47],["H3988","to refuse",48,57],["H7451","the evil",58,66],["H0977","and choose",68,78],["H2896","the good",79,87]]},"7:16":{"text":"For before the child shall know to refuse the evil, and choose the good, the land that thou abhorrest shall be forsaken of both her kings.","words":[["H5288","For before the child",0,20],["H3045","shall know",21,31],["H3988","to refuse",32,41],["H7451","the evil",42,50],["H0977","and choose",52,62],["H2896","the good",63,71],["H0127","the land",73,81],["H6973","that thou abhorrest",82,101],["H6440","shall be",102,110],["H5800","forsaken",111,119],["H8147","of both",120,127],["H4428","her kings",128,137]]},"7:17":{"text":"The LORD shall bring upon thee, and upon thy people, and upon thy father's house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.","words":[["H3068","The LORD",0,8],["H0935","shall bring",9,20],["H5971","upon thee, and upon thy people",21,51],["H0001","and upon thy father's",53,74],["H1004","house",75,80],["H3117","days",82,86],["H0935","that have not come",87,105],["H3117","from the day",107,119],["H0669","that Ephraim",120,132],["H5493","departed",133,141],["H3063","from Judah",142,152],["H4428","even the king",154,167],["H0804","of Assyria",168,178]]},"7:18":{"text":"And it shall come to pass in that day, that the LORD shall hiss for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.","words":[["H3117","And it shall come to pass in that day",0,37],["H3068","that the LORD",39,52],["H8319","shall hiss",53,63],["H2070","for the fly",64,75],["H7097","that is in the uttermost part",76,105],["H2975","of the rivers",106,119],["H4714","of Egypt",120,128],["H1682","and for the bee",130,145],["H0776","that is in the land",146,165],["H0804","of Assyria",166,176]]},"7:19":{"text":"And they shall come, and shall rest all of them in the desolate valleys, and in the holes of the rocks, and upon all thorns, and upon all bushes.","words":[["H0935","And they shall come",0,19],["H5117","and shall rest",21,35],["H1327","all of them in the desolate",36,63],["H5158","valleys",64,71],["H5357","and in the holes",73,89],["H5553","of the rocks",90,102],["H5285","and upon all thorns",104,123],["H5097","and upon all bushes",125,144]]},"7:20":{"text":"In the same day shall the Lord shave with a razor that is hired, namely, by them beyond the river, by the king of Assyria, the head, and the hair of the feet: and it shall also consume the beard.","words":[["H3117","In the same day",0,15],["H0136","shall the Lord",16,30],["H1548","shave",31,36],["H8593","with a razor",37,49],["H7917","that is hired",50,63],["H5676","namely, by them beyond",65,87],["H5104","the river",88,97],["H4428","by the king",99,110],["H0804","of Assyria",111,121],["H7218","the head",123,131],["H8181","and the hair",133,145],["H7272","of the feet",146,157],["H5595","and it shall also consume",159,184],["H2206","the beard",185,194]]},"7:21":{"text":"And it shall come to pass in that day, that a man shall nourish a young cow, and two sheep;","words":[["H3117","And it shall come to pass in that day",0,37],["H0376","that a man",39,49],["H2421","shall nourish",50,63],["H1241","a young",64,71],["H5697","cow",72,75],["H8147","and two",77,84],["H6629","sheep",85,90]]},"7:22":{"text":"And it shall come to pass, for the abundance of milk that they shall give he shall eat butter: for butter and honey shall every one eat that is left in the land.","words":[["H7230","And it shall come to pass, for the abundance",0,44],["H2461","of milk",45,52],["H6213","that they shall give",53,73],["H0398","he shall eat",74,86],["H2529","butter",87,93],["H2529","for butter",95,105],["H1706","and honey",106,115],["H0398","shall every one eat",116,135],["H3498","that is left",136,148],["H7130","in",149,151],["H0776","the land",152,160]]},"7:23":{"text":"And it shall come to pass in that day, that every place shall be, where there were a thousand vines at a thousand silverlings, it shall even be for briers and thorns.","words":[["H3117","And it shall come to pass in that day",0,37],["H4725","that every place",39,55],["H0505","shall be, where there were a thousand",56,93],["H1612","vines",94,99],["H0505","at a thousand",100,113],["H3701","silverlings",114,125],["H8068","it shall even be for briers",127,154],["H7898","and thorns",155,165]]},"7:24":{"text":"With arrows and with bows shall men come thither; because all the land shall become briers and thorns.","words":[["H2671","With arrows",0,11],["H7198","and with bows",12,25],["H0935","shall men come",26,40],["H0776","thither; because all the land",41,70],["H8068","shall become briers",71,90],["H7898","and thorns",91,101]]},"7:25":{"text":"And on all hills that shall be digged with the mattock, there shall not come thither the fear of briers and thorns: but it shall be for the sending forth of oxen, and for the treading of lesser cattle.","words":[["H2022","And on all hills",0,16],["H5737","that shall be digged",17,37],["H4576","with the mattock",38,54],["H0935","there shall not come thither",56,84],["H3374","the fear",85,93],["H8068","of briers",94,103],["H7898","and thorns",104,114],["H4916","but it shall be for the sending forth",116,153],["H7794","of oxen",154,161],["H4823","and for the treading",163,183],["H7716","of lesser cattle",184,200]]},"8:1":{"text":"Moreover the LORD said unto me, Take thee a great roll, and write in it with a man's pen concerning Mahershalalhashbaz.","words":[["H3068","Moreover the LORD",0,17],["H0559","said",18,22],["H3947","unto me, Take",23,36],["H1419","thee a great",37,49],["H1549","roll",50,54],["H3789","and write",56,65],["H0582","in it with a man's",66,84],["H2747","pen",85,88],["H4122","concerning Mahershalalhashbaz",89,118]]},"8:2":{"text":"And I took unto me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.","words":[["H5749","And I took",0,10],["H0539","unto me faithful",11,27],["H5707","witnesses",28,37],["H5749","to record",38,47],["H0223","Uriah",49,54],["H3548","the priest",55,65],["H2148","and Zechariah",67,80],["H1121","the son",81,88],["H3000","of Jeberechiah",89,103]]},"8:3":{"text":"And I went unto the prophetess; and she conceived, and bare a son. Then said the LORD to me, Call his name Mahershalalhashbaz.","words":[["H7126","And I went",0,10],["H5031","unto the prophetess",11,30],["H2029","and she conceived",32,49],["H3205","and bare",51,59],["H1121","a son",60,65],["H0559","Then said",67,76],["H3068","the LORD",77,85],["H7121","to me, Call",86,97],["H8034","his name",98,106],["H4122","Mahershalalhashbaz",107,125]]},"8:4":{"text":"For before the child shall have knowledge to cry, My father, and my mother, the riches of Damascus and the spoil of Samaria shall be taken away before the king of Assyria.","words":[["H5288","For before the child",0,20],["H3045","shall have knowledge",21,41],["H7121","to cry",42,48],["H0001","My father",50,59],["H0517","and my mother",61,74],["H2428","the riches",76,86],["H1834","of Damascus",87,98],["H7998","and the spoil",99,112],["H8111","of Samaria",113,123],["H5375","shall be taken away",124,143],["H6440","before",144,150],["H4428","the king",151,159],["H0804","of Assyria",160,170]]},"8:5":{"text":"The LORD spake also unto me again, saying,","words":[["H3068","The LORD",0,8],["H1696","spake",9,14],["H3254","also unto me again",15,33],["H0559","saying",35,41]]},"8:6":{"text":"Forasmuch as this people refuseth the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah's son;","words":[["H3282","Forasmuch",0,9],["H5971","as this people",10,24],["H3988","refuseth",25,33],["H4325","the waters",34,44],["H7975","of Shiloah",45,55],["H1980","that go",56,63],["H0328","softly",64,70],["H4885","and rejoice",72,83],["H7526","in Rezin",84,92],["H7425","and Remaliah's",93,107],["H1121","son",108,111]]},"8:7":{"text":"Now therefore, behold, the Lord bringeth up upon them the waters of the river, strong and many, even the king of Assyria, and all his glory: and he shall come up over all his channels, and go over all his banks:","words":[["H0136","Now therefore, behold, the Lord",0,31],["H5927","bringeth up",32,43],["H4325","upon them the waters",44,64],["H5104","of the river",65,77],["H6099","strong",79,85],["H7227","and many",86,94],["H4428","even the king",96,109],["H0804","of Assyria",110,120],["H3519","and all his glory",122,139],["H5927","and he shall come up",141,161],["H0650","over all his channels",162,183],["H1980","and go over",185,196],["H1415","all his banks",197,210]]},"8:8":{"text":"And he shall pass through Judah; he shall overflow and go over, he shall reach even to the neck; and the stretching out of his wings shall fill the breadth of thy land, O Immanuel.","words":[["H2498","And he shall pass",0,17],["H3063","through Judah",18,31],["H7857","he shall overflow",33,50],["H5674","and go over",51,62],["H5060","he shall reach",64,78],["H6677","even to the neck",79,95],["H4298","and the stretching out",97,119],["H3671","of his wings",120,132],["H4393","shall fill",133,143],["H7341","the breadth",144,155],["H0776","of thy land",156,167],["H6005","O Immanuel",169,179],["H0410","O Immanuel",169,179]]},"8:9":{"text":"Associate yourselves, O ye people, and ye shall be broken in pieces; and give ear, all ye of far countries: gird yourselves, and ye shall be broken in pieces; gird yourselves, and ye shall be broken in pieces.","words":[["H7489","Associate",0,9],["H5971","yourselves, O ye people",10,33],["H2865","and ye shall be broken in pieces",35,67],["H0238","and give ear",69,81],["H3605","all",83,86],["H4801","ye of far",87,96],["H0776","countries",97,106],["H0247","gird",108,112],["H2865","yourselves, and ye shall be broken in pieces",113,157],["H0247","gird",159,163],["H2865","yourselves, and ye shall be broken in pieces",164,208]]},"8:10":{"text":"Take counsel together, and it shall come to nought; speak the word, and it shall not stand: for God is with us.","words":[["H5779","Take",0,4],["H6098","counsel",5,12],["H5779","together",13,21],["H6565","and it shall come to nought",23,50],["H1696","speak",52,57],["H1697","the word",58,66],["H6965","and it shall not stand",68,90],["H0410","for God",92,99]]},"8:11":{"text":"For the LORD spake thus to me with a strong hand, and instructed me that I should not walk in the way of this people, saying,","words":[["H3068","For the LORD",0,12],["H0559","spake",13,18],["H2393","thus to me with a strong",19,43],["H3027","hand",44,48],["H3256","and instructed",50,64],["H3212","me that I should not walk",65,90],["H1870","in the way",91,101],["H5971","of this people",102,116],["H0559","saying",118,124]]},"8:12":{"text":"Say ye not, A confederacy, to all them to whom this people shall say, A confederacy; neither fear ye their fear, nor be afraid.","words":[["H0559","Say",0,3],["H7195","ye not, A confederacy",4,25],["H5971","to all them to whom this people",27,58],["H0559","shall say",59,68],["H7195","A confederacy",70,83],["H3372","neither fear",85,97],["H4172","ye their fear",98,111],["H6206","nor be afraid",113,126]]},"8:13":{"text":"Sanctify the LORD of hosts himself; and let him be your fear, and let him be your dread.","words":[["H6942","Sanctify",0,8],["H3068","the LORD",9,17],["H6635","of hosts",18,26],["H4172","himself; and let him be your fear",27,60],["H6206","and let him be your dread",62,87]]},"8:14":{"text":"And he shall be for a sanctuary; but for a stone of stumbling and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.","words":[["H4720","And he shall be for a sanctuary",0,31],["H0068","but for a stone",33,48],["H5063","of stumbling",49,61],["H6697","and for a rock",62,76],["H4383","of offence",77,87],["H8147","to both",88,95],["H1004","the houses",96,106],["H3478","of Israel",107,116],["H6341","for a gin",118,127],["H4170","and for a snare",128,143],["H3427","to the inhabitants",144,162],["H3389","of Jerusalem",163,175]]},"8:15":{"text":"And many among them shall stumble, and fall, and be broken, and be snared, and be taken.","words":[["H7227","And many",0,8],["H3782","among them shall stumble",9,33],["H5307","and fall",35,43],["H7665","and be broken",45,58],["H3369","and be snared",60,73],["H3920","and be taken",75,87]]},"8:16":{"text":"Bind up the testimony, seal the law among my disciples.","words":[["H6887","Bind up",0,7],["H8584","the testimony",8,21],["H2856","seal",23,27],["H8451","the law",28,35],["H3928","among my disciples",36,54]]},"8:17":{"text":"And I will wait upon the LORD, that hideth his face from the house of Jacob, and I will look for him.","words":[["H2442","And I will wait",0,15],["H3068","upon the LORD",16,29],["H5641","that hideth",31,42],["H6440","his face",43,51],["H1004","from the house",52,66],["H3290","of Jacob",67,75],["H6960","and I will look",77,92]]},"8:18":{"text":"Behold, I and the children whom the LORD hath given me are for signs and for wonders in Israel from the LORD of hosts, which dwelleth in mount Zion.","words":[["H3206","Behold, I and the children",0,26],["H3068","whom the LORD",27,40],["H5414","hath given",41,51],["H0226","me are for signs",52,68],["H4159","and for wonders",69,84],["H3478","in Israel",85,94],["H3068","from the LORD",95,108],["H6635","of hosts",109,117],["H7931","which dwelleth",119,133],["H2022","in mount",134,142],["H6726","Zion",143,147]]},"8:19":{"text":"And when they shall say unto you, Seek unto them that have familiar spirits, and unto wizards that peep, and that mutter: should not a people seek unto their God? for the living to the dead?","words":[["H0559","And when they shall say",0,23],["H1875","unto you, Seek",24,38],["H0178","unto them that have familiar spirits",39,75],["H3049","and unto wizards",77,93],["H6850","that peep",94,103],["H1897","and that mutter",105,120],["H5971","should not a people",122,141],["H1875","seek",142,146],["H0430","unto their God",147,161],["H2416","for the living",163,177],["H4191","to the dead",178,189]]},"8:20":{"text":"To the law and to the testimony: if they speak not according to this word, it is because there is no light in them.","words":[["H8451","To the law",0,10],["H8584","and to the testimony",11,31],["H0559","if they speak",33,46],["H1697","not according to this word",47,73],["H7837","it is because there is no light",75,106]]},"8:21":{"text":"And they shall pass through it, hardly bestead and hungry: and it shall come to pass, that when they shall be hungry, they shall fret themselves, and curse their king and their God, and look upward.","words":[["H5674","And they shall pass",0,19],["H7185","through it, hardly bestead",20,46],["H7457","and hungry",47,57],["H7456","and it shall come to pass, that when they shall be hungry",59,116],["H7107","they shall fret",118,133],["H7043","themselves, and curse",134,155],["H4428","their king",156,166],["H0430","and their God",167,180],["H6437","and look",182,190],["H4605","upward",191,197]]},"8:22":{"text":"And they shall look unto the earth; and behold trouble and darkness, dimness of anguish; and they shall be driven to darkness.","words":[["H5027","And they shall look",0,19],["H0776","unto the earth",20,34],["H6869","and behold trouble",36,54],["H2825","and darkness",55,67],["H4588","dimness",69,76],["H6695","of anguish",77,87],["H5080","and they shall be driven",89,113],["H0653","to darkness",114,125]]},"9:1":{"text":"Nevertheless the dimness shall not be such as was in her vexation, when at the first he lightly afflicted the land of Zebulun and the land of Naphtali, and afterward did more grievously afflict her by the way of the sea, beyond Jordan, in Galilee of the nations.","words":[["H4155","Nevertheless the dimness",0,24],["H4164","shall not be such as was in her vexation",25,65],["H6256","when",67,71],["H7223","at the first",72,84],["H7043","he lightly afflicted",85,105],["H0776","the land",106,114],["H2074","of Zebulun",115,125],["H0776","and the land",126,138],["H5321","of Naphtali",139,150],["H0314","and afterward",152,165],["H3513","did more grievously afflict",166,193],["H1870","her by the way",194,208],["H3220","of the sea",209,219],["H5676","beyond",221,227],["H3383","Jordan",228,234],["H1551","in Galilee",236,246],["H1471","of the nations",247,261]]},"9:2":{"text":"The people that walked in darkness have seen a great light: they that dwell in the land of the shadow of death, upon them hath the light shined.","words":[["H5971","The people",0,10],["H1980","that walked",11,22],["H2822","in darkness",23,34],["H7200","have seen",35,44],["H1419","a great",45,52],["H0216","light",53,58],["H3427","they that dwell",60,75],["H0776","in the land",76,87],["H6757","of the shadow of death",88,110],["H0216","upon them hath the light",112,136],["H5050","shined",137,143]]},"9:3":{"text":"Thou hast multiplied the nation, and not increased the joy: they joy before thee according to the joy in harvest, and as men rejoice when they divide the spoil.","words":[["H7235","Thou hast multiplied",0,20],["H1471","the nation",21,31],["H1431","and not increased",33,50],["H8057","the joy",51,58],["H8055","they joy",60,68],["H6440","before",69,75],["H8057","thee according to the joy",76,101],["H7105","in harvest",102,112],["H1523","and as men rejoice",114,132],["H2505","when they divide",133,149],["H7998","the spoil",150,159]]},"9:4":{"text":"For thou hast broken the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, as in the day of Midian.","words":[["H2865","For thou hast broken",0,20],["H5923","the yoke",21,29],["H5448","of his burden",30,43],["H4294","and the staff",45,58],["H7926","of his shoulder",59,74],["H7626","the rod",76,83],["H5065","of his oppressor",84,100],["H3117","as in the day",102,115],["H4080","of Midian",116,125]]},"9:5":{"text":"For every battle of the warrior is with confused noise, and garments rolled in blood; but this shall be with burning and fuel of fire.","words":[["H5430","For every battle",0,16],["H5431","of the warrior",17,31],["H7494","is with confused noise",32,54],["H8071","and garments",56,68],["H1556","rolled",69,75],["H1818","in blood",76,84],["H8316","but this shall be with burning",86,116],["H3980","and fuel",117,125],["H0784","of fire",126,133]]},"9:6":{"text":"For unto us a child is born, unto us a son is given: and the government shall be upon his shoulder: and his name shall be called Wonderful, Counsellor, The mighty God, The everlasting Father, The Prince of Peace.","words":[["H3206","For unto us a child",0,19],["H3205","is born",20,27],["H1121","unto us a son",29,42],["H5414","is given",43,51],["H4951","and the government",53,71],["H7926","shall be upon his shoulder",72,98],["H8034","and his name",100,112],["H7121","shall be called",113,128],["H6382","Wonderful",129,138],["H3289","Counsellor",140,150],["H1368","The mighty",152,162],["H0410","God",163,166],["H5703","The everlasting",168,183],["H0001","Father",184,190],["H8269","The Prince",192,202],["H7965","of Peace",203,211]]},"9:7":{"text":"Of the increase of his government and peace there shall be no end, upon the throne of David, and upon his kingdom, to order it, and to establish it with judgment and with justice from henceforth even for ever. The zeal of the LORD of hosts will perform this.","words":[["H4766","Of the increase",0,15],["H4951","of his government",16,33],["H7965","and peace",34,43],["H7093","there shall be no end",44,65],["H3678","upon the throne",67,82],["H1732","of David",83,91],["H4467","and upon his kingdom",93,113],["H3559","to order",115,123],["H5582","it, and to establish",124,144],["H4941","it with judgment",145,161],["H6666","and with justice",162,178],["H5704","from henceforth even for",179,203],["H5769","ever",204,208],["H7068","The zeal",210,218],["H3068","of the LORD",219,230],["H6635","of hosts",231,239],["H6213","will perform",240,252]]},"9:8":{"text":"The Lord sent a word into Jacob, and it hath lighted upon Israel.","words":[["H0136","The Lord",0,8],["H7971","sent",9,13],["H1697","a word",14,20],["H3290","into Jacob",21,31],["H5307","and it hath lighted",33,52],["H3478","upon Israel",53,64]]},"9:9":{"text":"And all the people shall know, even Ephraim and the inhabitant of Samaria, that say in the pride and stoutness of heart,","words":[["H5971","And all the people",0,18],["H3045","shall know",19,29],["H0669","even Ephraim",31,43],["H3427","and the inhabitant",44,62],["H8111","of Samaria",63,73],["H0559","that say",75,83],["H1346","in the pride",84,96],["H1433","and stoutness",97,110],["H3824","of heart",111,119]]},"9:10":{"text":"The bricks are fallen down, but we will build with hewn stones: the sycomores are cut down, but we will change them into cedars.","words":[["H3843","The bricks",0,10],["H5307","are fallen down",11,26],["H1129","but we will build",28,45],["H1496","with hewn stones",46,62],["H8256","the sycomores",64,77],["H1438","are cut down",78,90],["H2498","but we will change",92,110],["H0730","them into cedars",111,127]]},"9:11":{"text":"Therefore the LORD shall set up the adversaries of Rezin against him, and join his enemies together;","words":[["H3068","Therefore the LORD",0,18],["H7682","shall set up",19,31],["H6862","the adversaries",32,47],["H7526","of Rezin",48,56],["H5526","against him, and join",57,78],["H0341","his enemies",79,90],["H5526","together",91,99]]},"9:12":{"text":"The Syrians before, and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still.","words":[["H0758","The Syrians",0,11],["H6924","before",12,18],["H6430","and the Philistines",20,39],["H0268","behind",40,46],["H0398","and they shall devour",48,69],["H3478","Israel",70,76],["H6310","with open mouth",77,92],["H0639","For all this his anger",94,116],["H7725","is not turned away",117,135],["H3027","but his hand",137,149],["H5186","is stretched out still",150,172]]},"9:13":{"text":"For the people turneth not unto him that smiteth them, neither do they seek the LORD of hosts.","words":[["H5971","For the people",0,14],["H7725","turneth",15,22],["H5221","not unto him that smiteth",23,48],["H1875","them, neither do they seek",49,75],["H3068","the LORD",76,84],["H6635","of hosts",85,93]]},"9:14":{"text":"Therefore the LORD will cut off from Israel head and tail, branch and rush, in one day.","words":[["H3068","Therefore the LORD",0,18],["H3772","will cut off",19,31],["H3478","from Israel",32,43],["H7218","head",44,48],["H2180","and tail",49,57],["H3712","branch",59,65],["H0100","and rush",66,74],["H0259","in one",76,82],["H3117","day",83,86]]},"9:15":{"text":"The ancient and honourable, he is the head; and the prophet that teacheth lies, he is the tail.","words":[["H2205","The ancient",0,11],["H6440","and honourable",12,26],["H5375","and honourable",12,26],["H1931","he",28,30],["H7218","is the head",31,42],["H5030","and the prophet",44,59],["H3384","that teacheth",60,73],["H8267","lies",74,78],["H2180","he is the tail",80,94]]},"9:16":{"text":"For the leaders of this people cause them to err; and they that are led of them are destroyed.","words":[["H0833","For the leaders",0,15],["H5971","of this people",16,30],["H8582","cause them to err",31,48],["H0833","and they that are led",50,71],["H1104","of them are destroyed",72,93]]},"9:17":{"text":"Therefore the Lord shall have no joy in their young men, neither shall have mercy on their fatherless and widows: for every one is an hypocrite and an evildoer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand is stretched out still.","words":[["H0136","Therefore the Lord",0,18],["H8055","shall have no joy",19,36],["H0970","in their young men",37,55],["H7355","neither shall have mercy",57,81],["H3490","on their fatherless",82,101],["H0490","and widows",102,112],["H2611","for every one is an hypocrite",114,143],["H7489","and an evildoer",144,159],["H6310","and every mouth",161,176],["H1696","speaketh",177,185],["H5039","folly",186,191],["H0639","For all this his anger",193,215],["H7725","is not turned away",216,234],["H3027","but his hand",236,248],["H5186","is stretched out still",249,271]]},"9:18":{"text":"For wickedness burneth as the fire: it shall devour the briers and thorns, and shall kindle in the thickets of the forest, and they shall mount up like the lifting up of smoke.","words":[["H7564","For wickedness",0,14],["H1197","burneth",15,22],["H0784","as the fire",23,34],["H0398","it shall devour",36,51],["H8068","the briers",52,62],["H7898","and thorns",63,73],["H3341","and shall kindle",75,91],["H5442","in the thickets",92,107],["H3293","of the forest",108,121],["H0055","and they shall mount up",123,146],["H1348","like the lifting up",147,166],["H6227","of smoke",167,175]]},"9:19":{"text":"Through the wrath of the LORD of hosts is the land darkened, and the people shall be as the fuel of the fire: no man shall spare his brother.","words":[["H5678","Through the wrath",0,17],["H3068","of the LORD",18,29],["H6635","of hosts",30,38],["H0776","is the land",39,50],["H6272","darkened",51,59],["H5971","and the people",61,75],["H3980","shall be as the fuel",76,96],["H0784","of the fire",97,108],["H0376","no man",110,116],["H2550","shall spare",117,128],["H0251","his brother",129,140]]},"9:20":{"text":"And he shall snatch on the right hand, and be hungry; and he shall eat on the left hand, and they shall not be satisfied: they shall eat every man the flesh of his own arm:","words":[["H1504","And he shall snatch",0,19],["H3225","on the right hand",20,37],["H7457","and be hungry",39,52],["H0398","and he shall eat",54,70],["H8040","on the left hand",71,87],["H7646","and they shall not be satisfied",89,120],["H0398","they shall eat",122,136],["H0376","every man",137,146],["H1320","the flesh",147,156],["H2220","of his own arm",157,171]]},"9:21":{"text":"Manasseh, Ephraim; and Ephraim, Manasseh: and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.","words":[["H4519","Manasseh",0,8],["H0669","Ephraim",10,17],["H0669","and Ephraim",19,30],["H4519","Manasseh",32,40],["H3162","and they together",42,59],["H3063","shall be against Judah",60,82],["H0639","For all this his anger",84,106],["H7725","is not turned away",107,125],["H3027","but his hand",127,139],["H5186","is stretched out still",140,162]]},"10:1":{"text":"Woe unto them that decree unrighteous decrees, and that write grievousness which they have prescribed;","words":[["H1945","Woe",0,3],["H2710","unto them that decree",4,25],["H0205","unrighteous",26,37],["H2711","decrees",38,45],["H3789","and that write",47,61],["H5999","grievousness",62,74],["H3789","which they have prescribed",75,101]]},"10:2":{"text":"To turn aside the needy from judgment, and to take away the right from the poor of my people, that widows may be their prey, and that they may rob the fatherless!","words":[["H5186","To turn aside",0,13],["H1800","the needy",14,23],["H1779","from judgment",24,37],["H1497","and to take away",39,55],["H4941","the right",56,65],["H6041","from the poor",66,79],["H5971","of my people",80,92],["H0490","that widows",94,105],["H7998","may be their prey",106,123],["H0962","and that they may rob",125,146],["H3490","the fatherless",147,161]]},"10:3":{"text":"And what will ye do in the day of visitation, and in the desolation which shall come from far? to whom will ye flee for help? and where will ye leave your glory?","words":[["H6213","And what will ye do",0,19],["H3117","in the day",20,30],["H6486","of visitation",31,44],["H7722","and in the desolation",46,67],["H0935","which shall come",68,84],["H4801","from far",85,93],["H5127","to whom will ye flee",95,115],["H5833","for help",116,124],["H5800","and where will ye leave",126,149],["H3519","your glory",150,160]]},"10:4":{"text":"Without me they shall bow down under the prisoners, and they shall fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.","words":[["H1115","Without me they shall",0,21],["H3766","bow down",22,30],["H0616","under the prisoners",31,50],["H5307","and they shall fall",52,71],["H2026","under the slain",72,87],["H0639","For all this his anger",89,111],["H7725","is not turned away",112,130],["H3027","but his hand",132,144],["H5186","is stretched out still",145,167]]},"10:5":{"text":"O Assyrian, the rod of mine anger, and the staff in their hand is mine indignation.","words":[["H1945","O",0,1],["H0804","Assyrian",2,10],["H7626","the rod",12,19],["H0639","of mine anger",20,33],["H4294","and the staff",35,48],["H3027","in their hand",49,62],["H2195","is mine indignation",63,82]]},"10:6":{"text":"I will send him against an hypocritical nation, and against the people of my wrath will I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.","words":[["H7971","I will send",0,11],["H2611","him against an hypocritical",12,39],["H1471","nation",40,46],["H5971","and against the people",48,70],["H5678","of my wrath",71,82],["H6680","will I give him a charge",83,107],["H7997","to take",109,116],["H7998","the spoil",117,126],["H0962","and to take",128,139],["H0957","the prey",140,148],["H7760","and to tread them down",150,172],["H4823","and to tread them down",150,172],["H2563","like the mire",173,186],["H2351","of the streets",187,201]]},"10:7":{"text":"Howbeit he meaneth not so, neither doth his heart think so; but it is in his heart to destroy and cut off nations not a few.","words":[["H1819","Howbeit he meaneth",0,18],["H3824","not so, neither doth his heart",19,49],["H2803","think",50,55],["H3824","so; but it is in his heart",56,82],["H8045","to destroy",83,93],["H3772","and cut off",94,105],["H1471","nations",106,113],["H4592","not a few",114,123]]},"10:8":{"text":"For he saith, Are not my princes altogether kings?","words":[["H0559","For he saith",0,12],["H8269","Are not my princes",14,32],["H3162","altogether",33,43],["H4428","kings",44,49]]},"10:9":{"text":"Is not Calno as Carchemish? is not Hamath as Arpad? is not Samaria as Damascus?","words":[["H3641","Is not Calno",0,12],["H3751","as Carchemish",13,26],["H2574","is not Hamath",28,41],["H0774","as Arpad",42,50],["H8111","is not Samaria",52,66],["H1834","as Damascus",67,78]]},"10:10":{"text":"As my hand hath found the kingdoms of the idols, and whose graven images did excel them of Jerusalem and of Samaria;","words":[["H3027","As my hand",0,10],["H4672","hath found",11,21],["H4467","the kingdoms",22,34],["H0457","of the idols",35,47],["H6456","and whose graven images",49,72],["H3389","did excel them of Jerusalem",73,100],["H8111","and of Samaria",101,115]]},"10:11":{"text":"Shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her idols?","words":[["H6213","Shall I not, as I have done",0,27],["H8111","unto Samaria",28,40],["H0457","and her idols",41,54],["H6213","so do",56,61],["H3389","to Jerusalem",62,74],["H6091","and her idols",75,88]]},"10:12":{"text":"Wherefore it shall come to pass, that when the Lord hath performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks.","words":[["H0136","Wherefore it shall come to pass, that when the Lord",0,51],["H1214","hath performed",52,66],["H4639","his whole work",67,81],["H2022","upon mount",82,92],["H6726","Zion",93,97],["H3389","and on Jerusalem",98,114],["H6485","I will punish",116,129],["H6529","the fruit",130,139],["H1433","of the stout",140,152],["H3824","heart",153,158],["H4428","of the king",159,170],["H0804","of Assyria",171,181],["H8597","and the glory",183,196],["H7312","of his high",197,208],["H5869","looks",209,214]]},"10:13":{"text":"For he saith, By the strength of my hand I have done it, and by my wisdom; for I am prudent: and I have removed the bounds of the people, and have robbed their treasures, and I have put down the inhabitants like a valiant man:","words":[["H0559","For he saith",0,12],["H3581","By the strength",14,29],["H3027","of my hand",30,40],["H6213","I have done",41,52],["H2451","it, and by my wisdom",53,73],["H0995","for I am prudent",75,91],["H5493","and I have removed",93,111],["H1367","the bounds",112,122],["H5971","of the people",123,136],["H8154","and have robbed",138,153],["H6259","their treasures",154,169],["H6264","their treasures",154,169],["H3381","and I have put down",171,190],["H3427","the inhabitants",191,206],["H0047","like a valiant",207,221],["H3524","like a valiant",207,221]]},"10:14":{"text":"And my hand hath found as a nest the riches of the people: and as one gathereth eggs that are left, have I gathered all the earth; and there was none that moved the wing, or opened the mouth, or peeped.","words":[["H3027","And my hand",0,11],["H4672","hath found",12,22],["H7064","as a nest",23,32],["H2428","the riches",33,43],["H5971","of the people",44,57],["H0622","and as one gathereth",59,79],["H1000","eggs",80,84],["H5800","that are left",85,98],["H0622","have I gathered",100,115],["H0776","all the earth",116,129],["H5074","and there was none that moved",131,160],["H3671","the wing",161,169],["H6475","or opened",171,180],["H6310","the mouth",181,190],["H6850","or peeped",192,201]]},"10:15":{"text":"Shall the axe boast itself against him that heweth therewith? or shall the saw magnify itself against him that shaketh it? as if the rod should shake itself against them that lift it up, or as if the staff should lift up itself, as if it were no wood.","words":[["H1631","Shall the axe",0,13],["H6286","boast",14,19],["H2672","itself against him that heweth",20,50],["H4883","therewith? or shall the saw",51,78],["H1431","magnify",79,86],["H5130","itself against him that shaketh",87,118],["H7626","it? as if the rod",119,136],["H5130","should shake",137,149],["H7311","itself against them that lift it up",150,185],["H4294","or as if the staff",187,205],["H7311","should lift up",206,220],["H6086","itself, as if it were no wood",221,250]]},"10:16":{"text":"Therefore shall the Lord, the Lord of hosts, send among his fat ones leanness; and under his glory he shall kindle a burning like the burning of a fire.","words":[["H0113","Therefore shall the Lord",0,24],["H0136","the Lord",26,34],["H3068","the Lord",26,34],["H6635","of hosts",35,43],["H7971","send",45,49],["H4924","among his fat ones",50,68],["H7332","leanness",69,77],["H3519","and under his glory",79,98],["H3344","he shall kindle",99,114],["H3350","a burning",115,124],["H0784","like the burning of a fire",125,151]]},"10:17":{"text":"And the light of Israel shall be for a fire, and his Holy One for a flame: and it shall burn and devour his thorns and his briers in one day;","words":[["H0216","And the light",0,13],["H3478","of Israel",14,23],["H0784","shall be for a fire",24,43],["H6918","and his Holy One",45,61],["H3852","for a flame",62,73],["H1197","and it shall burn",75,92],["H0398","and devour",93,103],["H7898","his thorns",104,114],["H8068","and his briers",115,129],["H0259","in one",130,136],["H3117","day",137,140]]},"10:18":{"text":"And shall consume the glory of his forest, and of his fruitful field, both soul and body: and they shall be as when a standardbearer fainteth.","words":[["H3615","And shall consume",0,17],["H3519","the glory",18,27],["H3293","of his forest",28,41],["H3759","and of his fruitful field",43,68],["H5315","both soul",70,79],["H1320","and body",80,88],["H5263","and they shall be as when a standardbearer",90,132],["H4549","fainteth",133,141]]},"10:19":{"text":"And the rest of the trees of his forest shall be few, that a child may write them.","words":[["H7605","And the rest",0,12],["H6086","of the trees",13,25],["H3293","of his forest",26,39],["H4557","shall be few",40,52],["H5288","that a child",54,66],["H3789","may write",67,76]]},"10:20":{"text":"And it shall come to pass in that day, that the remnant of Israel, and such as are escaped of the house of Jacob, shall no more again stay upon him that smote them; but shall stay upon the LORD, the Holy One of Israel, in truth.","words":[["H3117","And it shall come to pass in that day",0,37],["H7605","that the remnant",39,55],["H3478","of Israel",56,65],["H6413","and such as are escaped",67,90],["H1004","of the house",91,103],["H3290","of Jacob",104,112],["H3254","shall no more again",114,133],["H8172","stay",134,138],["H5221","upon him that smote",139,158],["H8172","them; but shall stay",159,179],["H3068","upon the LORD",180,193],["H6918","the Holy One",195,207],["H3478","of Israel",208,217],["H0571","in truth",219,227]]},"10:21":{"text":"The remnant shall return, even the remnant of Jacob, unto the mighty God.","words":[["H7605","The remnant",0,11],["H7725","shall return",12,24],["H7605","even the remnant",26,42],["H3290","of Jacob",43,51],["H1368","unto the mighty",53,68],["H0410","God",69,72]]},"10:22":{"text":"For though thy people Israel be as the sand of the sea, yet a remnant of them shall return: the consumption decreed shall overflow with righteousness.","words":[["H5971","For though thy people",0,21],["H3478","Israel",22,28],["H2344","be as the sand",29,43],["H3220","of the sea",44,54],["H7605","yet a remnant",56,69],["H7725","of them shall return",70,90],["H3631","the consumption",92,107],["H2782","decreed",108,115],["H7857","shall overflow",116,130],["H6666","with righteousness",131,149]]},"10:23":{"text":"For the Lord GOD of hosts shall make a consumption, even determined, in the midst of all the land.","words":[["H0136","For the Lord",0,12],["H3069","GOD",13,16],["H6635","of hosts",17,25],["H6213","shall make",26,36],["H3617","a consumption",37,50],["H2782","even determined",52,67],["H7130","in the midst",69,81],["H0776","of all the land",82,97]]},"10:24":{"text":"Therefore thus saith the Lord GOD of hosts, O my people that dwellest in Zion, be not afraid of the Assyrian: he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6635","of hosts",34,42],["H5971","O my people",44,55],["H3427","that dwellest",56,69],["H6726","in Zion",70,77],["H3372","be not afraid",79,92],["H0804","of the Assyrian",93,108],["H5221","he shall smite",110,124],["H7626","thee with a rod",125,140],["H5375","and shall lift up",142,159],["H4294","his staff",160,169],["H1870","against thee, after the manner",170,200],["H4714","of Egypt",201,209]]},"10:25":{"text":"For yet a very little while, and the indignation shall cease, and mine anger in their destruction.","words":[["H4213","For yet a very",0,14],["H4592","little while",15,27],["H2195","and the indignation",29,48],["H3615","shall cease",49,60],["H0639","and mine anger",62,76],["H8399","in their destruction",77,97]]},"10:26":{"text":"And the LORD of hosts shall stir up a scourge for him according to the slaughter of Midian at the rock of Oreb: and as his rod was upon the sea, so shall he lift it up after the manner of Egypt.","words":[["H3068","And the LORD",0,12],["H6635","of hosts",13,21],["H5782","shall stir up",22,35],["H7752","a scourge",36,45],["H4347","for him according to the slaughter",46,80],["H4080","of Midian",81,90],["H6697","at the rock",91,102],["H6159","of Oreb",103,110],["H4294","and as his rod",112,126],["H3220","was upon the sea",127,143],["H5375","so shall he lift it up",145,167],["H1870","after the manner",168,184],["H4714","of Egypt",185,193]]},"10:27":{"text":"And it shall come to pass in that day, that his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of the anointing.","words":[["H3117","And it shall come to pass in that day",0,37],["H5448","that his burden",39,54],["H5493","shall be taken away",55,74],["H7926","from off thy shoulder",75,96],["H5923","and his yoke",98,110],["H6677","from off thy neck",111,128],["H5923","and the yoke",130,142],["H2254","shall be destroyed",143,161],["H6440","because",162,169],["H8081","of the anointing",170,186]]},"10:28":{"text":"He is come to Aiath, he is passed to Migron; at Michmash he hath laid up his carriages:","words":[["H0935","He is come",0,10],["H5857","to Aiath",11,19],["H5674","he is passed",21,33],["H4051","to Migron",34,43],["H4363","at Michmash",45,56],["H6485","he hath laid up",57,72],["H3627","his carriages",73,86]]},"10:29":{"text":"They are gone over the passage: they have taken up their lodging at Geba; Ramah is afraid; Gibeah of Saul is fled.","words":[["H5674","They are gone over",0,18],["H4569","the passage",19,30],["H4411","they have taken up their lodging",32,64],["H1387","at Geba",65,72],["H7414","Ramah",74,79],["H2729","is afraid",80,89],["H1390","Gibeah",91,97],["H7586","of Saul",98,105],["H5127","is fled",106,113]]},"10:30":{"text":"Lift up thy voice, O daughter of Gallim: cause it to be heard unto Laish, O poor Anathoth.","words":[["H6670","Lift up",0,7],["H6963","thy voice",8,17],["H1323","O daughter",19,29],["H1530","of",30,32],["H1554","Gallim",33,39],["H7181","cause it to be heard",41,61],["H3919","unto Laish",62,72],["H6041","O poor",74,80],["H6068","Anathoth",81,89]]},"10:31":{"text":"Madmenah is removed; the inhabitants of Gebim gather themselves to flee.","words":[["H4088","Madmenah",0,8],["H5074","is removed",9,19],["H3427","the inhabitants",21,36],["H1374","of Gebim",37,45],["H5756","gather themselves to flee",46,71]]},"10:32":{"text":"As yet shall he remain at Nob that day: he shall shake his hand against the mount of the daughter of Zion, the hill of Jerusalem.","words":[["H5975","As yet shall he remain",0,22],["H5011","at Nob",23,29],["H3117","that day",30,38],["H5130","he shall shake",40,54],["H3027","his hand",55,63],["H2022","against the mount",64,81],["H1323","of the daughter",82,97],["H1004","of the daughter",82,97],["H6726","of Zion",98,105],["H1389","the hill",107,115],["H3389","of Jerusalem",116,128]]},"10:33":{"text":"Behold, the Lord, the LORD of hosts, shall lop the bough with terror: and the high ones of stature shall be hewn down, and the haughty shall be humbled.","words":[["H0113","Behold, the Lord",0,16],["H3068","the LORD",18,26],["H6635","of hosts",27,35],["H5586","shall lop",37,46],["H6288","the bough",47,56],["H4637","with terror",57,68],["H7311","and the high ones",70,87],["H6967","of stature",88,98],["H1438","shall be hewn down",99,117],["H1364","and the haughty",119,134],["H8213","shall be humbled",135,151]]},"10:34":{"text":"And he shall cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.","words":[["H5362","And he shall cut down",0,21],["H5442","the thickets",22,34],["H3293","of the forest",35,48],["H1270","with iron",49,58],["H3844","and Lebanon",60,71],["H5307","shall fall",72,82],["H0117","by a mighty one",83,98]]},"11:1":{"text":"And there shall come forth a rod out of the stem of Jesse, and a Branch shall grow out of his roots:","words":[["H3318","And there shall come forth",0,26],["H2415","a rod",27,32],["H1503","out of the stem",33,48],["H3448","of Jesse",49,57],["H5342","and a Branch",59,71],["H6509","shall grow",72,82],["H8328","out of his roots",83,99]]},"11:2":{"text":"And the spirit of the LORD shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the LORD;","words":[["H7307","And the spirit",0,14],["H3068","of the LORD",15,26],["H5117","shall rest",27,37],["H7307","upon him, the spirit",38,58],["H2451","of wisdom",59,68],["H0998","and understanding",69,86],["H7307","the spirit",88,98],["H6098","of counsel",99,109],["H1369","and might",110,119],["H7307","the spirit",121,131],["H1847","of knowledge",132,144],["H3374","and of the fear",145,160],["H3068","of the LORD",161,172]]},"11:3":{"text":"And shall make him of quick understanding in the fear of the LORD: and he shall not judge after the sight of his eyes, neither reprove after the hearing of his ears:","words":[["H7306","And shall make him of quick understanding",0,41],["H3374","in the fear",42,53],["H3068","of the LORD",54,65],["H8199","and he shall not judge",67,89],["H4758","after the sight",90,105],["H5869","of his eyes",106,117],["H3198","neither reprove",119,134],["H4926","after the hearing",135,152],["H0241","of his ears",153,164]]},"11:4":{"text":"But with righteousness shall he judge the poor, and reprove with equity for the meek of the earth: and he shall smite the earth with the rod of his mouth, and with the breath of his lips shall he slay the wicked.","words":[["H6664","But with righteousness",0,22],["H8199","shall he judge",23,37],["H1800","the poor",38,46],["H3198","and reprove",48,59],["H4334","with equity",60,71],["H6035","for the meek",72,84],["H0776","of the earth",85,97],["H5221","and he shall smite",99,117],["H0776","the earth",118,127],["H7626","with the rod",128,140],["H6310","of his mouth",141,153],["H7307","and with the breath",155,174],["H8193","of his lips",175,186],["H4191","shall he slay",187,200],["H7563","the wicked",201,211]]},"11:5":{"text":"And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins.","words":[["H6664","And righteousness",0,17],["H0232","shall be the girdle",18,37],["H4975","of his loins",38,50],["H0530","and faithfulness",52,68],["H0232","the girdle",69,79],["H2504","of his reins",80,92]]},"11:6":{"text":"The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.","words":[["H2061","The wolf",0,8],["H1481","also shall dwell",9,25],["H3532","with the lamb",26,39],["H5246","and the leopard",41,56],["H7257","shall lie down",57,71],["H1423","with the kid",72,84],["H5695","and the calf",86,98],["H3715","and the young lion",99,117],["H4806","and the fatling",118,133],["H3162","together",134,142],["H6996","and a little",144,156],["H5288","child",157,162],["H5090","shall lead",163,173]]},"11:7":{"text":"And the cow and the bear shall feed; their young ones shall lie down together: and the lion shall eat straw like the ox.","words":[["H6510","And the cow",0,11],["H1677","and the bear",12,24],["H7462","shall feed",25,35],["H3206","their young ones",37,53],["H7257","shall lie down",54,68],["H3162","together",69,77],["H0738","and the lion",79,91],["H0398","shall eat",92,101],["H8401","straw",102,107],["H1241","like the ox",108,119]]},"11:8":{"text":"And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the cockatrice' den.","words":[["H3243","And the sucking child",0,21],["H8173","shall play",22,32],["H2352","on the hole",33,44],["H6620","of the asp",45,55],["H1580","and the weaned child",57,77],["H1911","shall put",78,87],["H3027","his hand",88,96],["H6848","on the cockatrice'",97,115],["H3975","den",116,119]]},"11:9":{"text":"They shall not hurt nor destroy in all my holy mountain: for the earth shall be full of the knowledge of the LORD, as the waters cover the sea.","words":[["H7489","They shall not hurt",0,19],["H7843","nor destroy",20,31],["H6944","in all my holy",32,46],["H2022","mountain",47,55],["H0776","for the earth",57,70],["H4390","shall be full",71,84],["H1844","of the knowledge",85,101],["H3068","of the LORD",102,113],["H4325","as the waters",115,128],["H3680","cover",129,134],["H3220","the sea",135,142]]},"11:10":{"text":"And in that day there shall be a root of Jesse, which shall stand for an ensign of the people; to it shall the Gentiles seek: and his rest shall be glorious.","words":[["H3117","And in that day",0,15],["H8328","there shall be a root",16,37],["H3448","of Jesse",38,46],["H5975","which shall stand",48,65],["H5251","for an ensign",66,79],["H5971","of the people",80,93],["H1471","to it shall the Gentiles",95,119],["H1875","seek",120,124],["H4496","and his rest",126,138],["H3519","shall be glorious",139,156]]},"11:11":{"text":"And it shall come to pass in that day, that the Lord shall set his hand again the second time to recover the remnant of his people, which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.","words":[["H3117","And it shall come to pass in that day",0,37],["H0136","that the Lord",39,52],["H3254","shall set",53,62],["H3027","his hand",63,71],["H3254","again",72,77],["H8145","the second time",78,93],["H7069","to recover",94,104],["H7605","the remnant",105,116],["H5971","of his people",117,130],["H7604","which shall be left",132,151],["H0804","from Assyria",153,165],["H4714","and from Egypt",167,181],["H6624","and from Pathros",183,199],["H3568","and from Cush",201,214],["H5867","and from Elam",216,229],["H8152","and from Shinar",231,246],["H2574","and from Hamath",248,263],["H0339","and from the islands",265,285],["H3220","of the sea",286,296]]},"11:12":{"text":"And he shall set up an ensign for the nations, and shall assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.","words":[["H5375","And he shall set up",0,19],["H5251","an ensign",20,29],["H1471","for the nations",30,45],["H0622","and shall assemble",47,65],["H1760","the outcasts",66,78],["H3478","of Israel",79,88],["H6908","and gather together",90,109],["H5310","the dispersed",110,123],["H3063","of Judah",124,132],["H0702","from the four",133,146],["H3671","corners",147,154],["H0776","of the earth",155,167]]},"11:13":{"text":"The envy also of Ephraim shall depart, and the adversaries of Judah shall be cut off: Ephraim shall not envy Judah, and Judah shall not vex Ephraim.","words":[["H7068","The envy",0,8],["H0669","also of Ephraim",9,24],["H5493","shall depart",25,37],["H6887","and the adversaries",39,58],["H3063","of Judah",59,67],["H3772","shall be cut off",68,84],["H0669","Ephraim",86,93],["H7065","shall not envy",94,108],["H3063","Judah",109,114],["H3063","and Judah",116,125],["H6887","shall not vex",126,139],["H0669","Ephraim",140,147]]},"11:14":{"text":"But they shall fly upon the shoulders of the Philistines toward the west; they shall spoil them of the east together: they shall lay their hand upon Edom and Moab; and the children of Ammon shall obey them.","words":[["H5774","But they shall fly",0,18],["H3802","upon the shoulders",19,37],["H6430","of the Philistines",38,56],["H3220","toward the west",57,72],["H0962","they shall spoil",74,90],["H1121","them",91,95],["H6924","of the east",96,107],["H3162","together",108,116],["H4916","they shall lay",118,132],["H3027","their hand",133,143],["H0123","upon Edom",144,153],["H4124","and Moab",154,162],["H1121","and the children",164,180],["H5983","of Ammon",181,189],["H4928","shall obey",190,200]]},"11:15":{"text":"And the LORD shall utterly destroy the tongue of the Egyptian sea; and with his mighty wind shall he shake his hand over the river, and shall smite it in the seven streams, and make men go over dryshod.","words":[["H3068","And the LORD",0,12],["H2763","shall utterly destroy",13,34],["H3956","the tongue",35,45],["H4714","of the Egyptian",46,61],["H3220","sea",62,65],["H5868","and with his mighty",67,86],["H7307","wind",87,91],["H5130","shall he shake",92,106],["H3027","his hand",107,115],["H5104","over the river",116,130],["H5221","and shall smite",132,147],["H7651","it in the seven",148,163],["H5158","streams",164,171],["H1869","and make men go over",173,193],["H5275","dryshod",194,201]]},"11:16":{"text":"And there shall be an highway for the remnant of his people, which shall be left, from Assyria; like as it was to Israel in the day that he came up out of the land of Egypt.","words":[["H4546","And there shall be an highway",0,29],["H7605","for the remnant",30,45],["H5971","of his people",46,59],["H0834","which",61,66],["H7604","shall be left",67,80],["H0804","from Assyria",82,94],["H3478","like as it was to Israel",96,120],["H3117","in the day",121,131],["H5927","that he came up",132,147],["H0776","out of the land",148,163],["H4714","of Egypt",164,172]]},"12:1":{"text":"And in that day thou shalt say, O LORD, I will praise thee: though thou wast angry with me, thine anger is turned away, and thou comfortedst me.","words":[["H3117","And in that day",0,15],["H0559","thou shalt say",16,30],["H3068","O LORD",32,38],["H3034","I will praise",40,53],["H0599","thee: though thou wast angry",54,82],["H0639","with me, thine anger",83,103],["H7725","is turned away",104,118],["H5162","and thou comfortedst",120,140]]},"12:2":{"text":"Behold, God is my salvation; I will trust, and not be afraid: for the LORD JEHOVAH is my strength and my song; he also is become my salvation.","words":[["H0410","Behold, God",0,11],["H3444","is my salvation",12,27],["H0982","I will trust",29,41],["H6342","and not be afraid",43,60],["H3050","for the LORD",62,74],["H3068","JEHOVAH",75,82],["H5797","is my strength",83,97],["H2176","and my song",98,109],["H3444","he also is become my salvation",111,141]]},"12:3":{"text":"Therefore with joy shall ye draw water out of the wells of salvation.","words":[["H8342","Therefore with joy",0,18],["H7579","shall ye draw",19,32],["H4325","water",33,38],["H4599","out of the wells",39,55],["H3444","of salvation",56,68]]},"12:4":{"text":"And in that day shall ye say, Praise the LORD, call upon his name, declare his doings among the people, make mention that his name is exalted.","words":[["H3117","And in that day",0,15],["H0559","shall ye say",16,28],["H3034","Praise",30,36],["H3068","the LORD",37,45],["H7121","call",47,51],["H8034","upon his name",52,65],["H3045","declare",67,74],["H5949","his doings",75,85],["H5971","among the people",86,102],["H2142","make mention",104,116],["H8034","that his name",117,130],["H7682","is exalted",131,141]]},"12:5":{"text":"Sing unto the LORD; for he hath done excellent things: this is known in all the earth.","words":[["H2167","Sing",0,4],["H3068","unto the LORD",5,18],["H6213","for he hath done",20,36],["H1348","excellent things",37,53],["H3045","this is known",55,68],["H3045","this is known",55,68],["H0776","in all the earth",69,85]]},"12:6":{"text":"Cry out and shout, thou inhabitant of Zion: for great is the Holy One of Israel in the midst of thee.","words":[["H6670","Cry out",0,7],["H7442","and shout",8,17],["H3427","thou inhabitant",19,34],["H6726","of Zion",35,42],["H1419","for great",44,53],["H6918","is the Holy One",54,69],["H3478","of Israel",70,79],["H7130","in the midst",80,92]]},"13:1":{"text":"The burden of Babylon, which Isaiah the son of Amoz did see.","words":[["H4853","The burden",0,10],["H0894","of Babylon",11,21],["H3470","which Isaiah",23,35],["H1121","the son",36,43],["H0531","of Amoz",44,51],["H2372","did see",52,59]]},"13:2":{"text":"Lift ye up a banner upon the high mountain, exalt the voice unto them, shake the hand, that they may go into the gates of the nobles.","words":[["H5375","Lift ye up",0,10],["H5251","a banner",11,19],["H8192","upon the high",20,33],["H2022","mountain",34,42],["H7311","exalt",44,49],["H6963","the voice",50,59],["H5130","unto them, shake",60,76],["H3027","the hand",77,85],["H0935","that they may go",87,103],["H6607","into the gates",104,118],["H5081","of the nobles",119,132]]},"13:3":{"text":"I have commanded my sanctified ones, I have also called my mighty ones for mine anger, even them that rejoice in my highness.","words":[["H6680","I have commanded",0,16],["H6942","my sanctified ones",17,35],["H7121","I have also called",37,55],["H1368","my mighty ones",56,70],["H0639","for mine anger",71,85],["H5947","even them that rejoice",87,109],["H1346","in my highness",110,124]]},"13:4":{"text":"The noise of a multitude in the mountains, like as of a great people; a tumultuous noise of the kingdoms of nations gathered together: the LORD of hosts mustereth the host of the battle.","words":[["H6963","The noise",0,9],["H1995","of a multitude",10,24],["H2022","in the mountains",25,41],["H1823","like as",43,50],["H7227","of a great",51,61],["H5971","people",62,68],["H7588","a tumultuous",70,82],["H6963","noise",83,88],["H4467","of the kingdoms",89,104],["H1471","of nations",105,115],["H0622","gathered together",116,133],["H3068","the LORD",135,143],["H6635","of hosts",144,152],["H6485","mustereth",153,162],["H6635","the host",163,171],["H4421","of the battle",172,185]]},"13:5":{"text":"They come from a far country, from the end of heaven, even the LORD, and the weapons of his indignation, to destroy the whole land.","words":[["H0935","They come",0,9],["H4801","from a far",10,20],["H0776","country",21,28],["H7097","from the end",30,42],["H8064","of heaven",43,52],["H3068","even the LORD",54,67],["H3627","and the weapons",69,84],["H2195","of his indignation",85,103],["H2254","to destroy",105,115],["H0776","the whole land",116,130]]},"13:6":{"text":"Howl ye; for the day of the LORD is at hand; it shall come as a destruction from the Almighty.","words":[["H3213","Howl",0,4],["H3117","ye; for the day",5,20],["H3068","of the LORD",21,32],["H7138","is at hand",33,43],["H0935","it shall come",45,58],["H7701","as a destruction",59,75],["H7706","from the Almighty",76,93]]},"13:7":{"text":"Therefore shall all hands be faint, and every man's heart shall melt:","words":[["H3027","Therefore shall all hands",0,25],["H7503","be faint",26,34],["H0582","and every man's",36,51],["H3824","heart",52,57],["H4549","shall melt",58,68]]},"13:8":{"text":"And they shall be afraid: pangs and sorrows shall take hold of them; they shall be in pain as a woman that travaileth: they shall be amazed one at another; their faces shall be as flames.","words":[["H0926","And they shall be afraid",0,24],["H6735","pangs",26,31],["H2256","and sorrows",32,43],["H0270","shall take hold",44,59],["H2342","of them; they shall be in pain",60,90],["H3205","as a woman that travaileth",91,117],["H8539","they shall be amazed",119,139],["H0376","one",140,143],["H7453","at another",144,154],["H6440","their faces",156,167],["H3851","shall be as flames",168,186]]},"13:9":{"text":"Behold, the day of the LORD cometh, cruel both with wrath and fierce anger, to lay the land desolate: and he shall destroy the sinners thereof out of it.","words":[["H3117","Behold, the day",0,15],["H3068","of the LORD",16,27],["H0935","cometh",28,34],["H0394","cruel",36,41],["H5678","both with wrath",42,57],["H2740","and fierce",58,68],["H0639","anger",69,74],["H7760","to lay",76,82],["H0776","the land",83,91],["H8047","desolate",92,100],["H8045","and he shall destroy",102,122],["H2400","the sinners",123,134]]},"13:10":{"text":"For the stars of heaven and the constellations thereof shall not give their light: the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.","words":[["H3556","For the stars",0,13],["H8064","of heaven",14,23],["H3685","and the constellations",24,46],["H1984","thereof shall not give",47,69],["H0216","their light",70,81],["H8121","the sun",83,90],["H2821","shall be darkened",91,108],["H3318","in his going forth",109,127],["H3394","and the moon",129,141],["H0216","shall not cause her light",142,167],["H5050","to shine",168,176]]},"13:11":{"text":"And I will punish the world for their evil, and the wicked for their iniquity; and I will cause the arrogancy of the proud to cease, and will lay low the haughtiness of the terrible.","words":[["H6485","And I will punish",0,17],["H8398","the world",18,27],["H7451","for their evil",28,42],["H7563","and the wicked",44,58],["H5771","for their iniquity",59,77],["H1347","and I will cause the arrogancy",79,109],["H2086","of the proud",110,122],["H7673","to cease",123,131],["H8213","and will lay low",133,149],["H1346","the haughtiness",150,165],["H6184","of the terrible",166,181]]},"13:12":{"text":"I will make a man more precious than fine gold; even a man than the golden wedge of Ophir.","words":[["H0582","I will make a man",0,17],["H3365","more precious",18,31],["H6337","than fine gold",32,46],["H0120","even a man",48,58],["H3800","than the golden wedge",59,80],["H0211","of Ophir",81,89]]},"13:13":{"text":"Therefore I will shake the heavens, and the earth shall remove out of her place, in the wrath of the LORD of hosts, and in the day of his fierce anger.","words":[["H7264","Therefore I will shake",0,22],["H8064","the heavens",23,34],["H0776","and the earth",36,49],["H7493","shall remove",50,62],["H4725","out of her place",63,79],["H5678","in the wrath",81,93],["H3068","of the LORD",94,105],["H6635","of hosts",106,114],["H3117","and in the day",116,130],["H2740","of his fierce",131,144],["H0639","anger",145,150]]},"13:14":{"text":"And it shall be as the chased roe, and as a sheep that no man taketh up: they shall every man turn to his own people, and flee every one into his own land.","words":[["H5080","And it shall be as the chased",0,29],["H6643","roe",30,33],["H6629","and as a sheep",35,49],["H6908","that no man taketh up",50,71],["H0376","they shall every man",73,93],["H6437","turn",94,98],["H5971","to his own people",99,116],["H5127","and flee",118,126],["H0376","every one",127,136],["H0776","into his own land",137,154]]},"13:15":{"text":"Every one that is found shall be thrust through; and every one that is joined unto them shall fall by the sword.","words":[["H4672","Every one that is found",0,23],["H1856","shall be thrust through",24,47],["H5595","and every one that is joined",49,77],["H5307","unto them shall fall",78,98],["H2719","by the sword",99,111]]},"13:16":{"text":"Their children also shall be dashed to pieces before their eyes; their houses shall be spoiled, and their wives ravished.","words":[["H5768","Their children",0,14],["H7376","also shall be dashed to pieces",15,45],["H5869","before their eyes",46,63],["H1004","their houses",65,77],["H8155","shall be spoiled",78,94],["H0802","and their wives",96,111],["H7901","ravished",112,120],["H7693","ravished",112,120]]},"13:17":{"text":"Behold, I will stir up the Medes against them, which shall not regard silver; and as for gold, they shall not delight in it.","words":[["H5782","Behold, I will stir up",0,22],["H4074","the Medes",23,32],["H2803","against them, which shall not regard",33,69],["H3701","silver",70,76],["H2091","and as for gold",78,93],["H2654","they shall not delight",95,117]]},"13:18":{"text":"Their bows also shall dash the young men to pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.","words":[["H7198","Their bows",0,10],["H7376","also shall dash",11,26],["H5288","the young men",27,40],["H7376","to pieces",41,50],["H7355","and they shall have no pity",52,79],["H6529","on the fruit",80,92],["H0990","of the womb",93,104],["H5869","their eye",106,115],["H2347","shall not spare",116,131],["H1121","children",132,140]]},"13:19":{"text":"And Babylon, the glory of kingdoms, the beauty of the Chaldees' excellency, shall be as when God overthrew Sodom and Gomorrah.","words":[["H0894","And Babylon",0,11],["H6643","the glory",13,22],["H4467","of kingdoms",23,34],["H8597","the beauty",36,46],["H3778","of the Chaldees'",47,63],["H1347","excellency",64,74],["H0430","shall be as when God",76,96],["H4114","overthrew",97,106],["H5467","Sodom",107,112],["H6017","and Gomorrah",113,125]]},"13:20":{"text":"It shall never be inhabited, neither shall it be dwelt in from generation to generation: neither shall the Arabian pitch tent there; neither shall the shepherds make their fold there.","words":[["H5331","It shall never",0,14],["H3427","be inhabited",15,27],["H7931","neither shall it be dwelt",29,54],["H1755","in from generation",55,73],["H1755","to generation",74,87],["H6163","neither shall the Arabian",89,114],["H0167","pitch tent",115,125],["H7462","there; neither shall the shepherds",126,160],["H7257","make their fold",161,176]]},"13:21":{"text":"But wild beasts of the desert shall lie there; and their houses shall be full of doleful creatures; and owls shall dwell there, and satyrs shall dance there.","words":[["H6728","But wild beasts of the desert",0,29],["H7257","shall lie",30,39],["H1004","there; and their houses",40,63],["H4390","shall be full",64,77],["H0255","of doleful creatures",78,98],["H1323","and owls",100,108],["H3284","and owls",100,108],["H7931","shall dwell",109,120],["H8163","there, and satyrs",121,138],["H7540","shall dance",139,150]]},"13:22":{"text":"And the wild beasts of the islands shall cry in their desolate houses, and dragons in their pleasant palaces: and her time is near to come, and her days shall not be prolonged.","words":[["H0338","And the wild beasts of the islands",0,34],["H6030","shall cry",35,44],["H0490","in their desolate houses",45,69],["H8577","and dragons",71,82],["H6027","in their pleasant",83,100],["H1964","palaces",101,108],["H6256","and her time",110,122],["H7138","is near",123,130],["H0935","to come",131,138],["H3117","and her days",140,152],["H4900","shall not be prolonged",153,175]]},"14:1":{"text":"For the LORD will have mercy on Jacob, and will yet choose Israel, and set them in their own land: and the strangers shall be joined with them, and they shall cleave to the house of Jacob.","words":[["H3068","For the LORD",0,12],["H7355","will have mercy",13,28],["H3290","on Jacob",29,37],["H0977","and will yet choose",39,58],["H3478","Israel",59,65],["H3240","and set",67,74],["H0127","them in their own land",75,97],["H1616","and the strangers",99,116],["H3867","shall be joined",117,132],["H5596","with them, and they shall cleave",133,165],["H1004","to the house",166,178],["H3290","of Jacob",179,187]]},"14:2":{"text":"And the people shall take them, and bring them to their place: and the house of Israel shall possess them in the land of the LORD for servants and handmaids: and they shall take them captives, whose captives they were; and they shall rule over their oppressors.","words":[["H5971","And the people",0,14],["H3947","shall take",15,25],["H0935","them, and bring",26,41],["H4725","them to their place",42,61],["H1004","and the house",63,76],["H3478","of Israel",77,86],["H5157","shall possess",87,100],["H0127","them in the land",101,117],["H3068","of the LORD",118,129],["H5650","for servants",130,142],["H8198","and handmaids",143,156],["H7617","and they shall take them captives",158,191],["H7617","whose captives",193,207],["H7287","they were; and they shall rule",208,238],["H5065","over their oppressors",239,260]]},"14:3":{"text":"And it shall come to pass in the day that the LORD shall give thee rest from thy sorrow, and from thy fear, and from the hard bondage wherein thou wast made to serve,","words":[["H3117","And it shall come to pass in the day",0,36],["H3068","that the LORD",37,50],["H5117","shall give thee rest",51,71],["H6090","from thy sorrow",72,87],["H7267","and from thy fear",89,106],["H7186","and from the hard",108,125],["H5656","bondage",126,133],["H5647","wherein thou wast made to serve",134,165]]},"14:4":{"text":"That thou shalt take up this proverb against the king of Babylon, and say, How hath the oppressor ceased! the golden city ceased!","words":[["H5375","That thou shalt take up",0,23],["H4912","this proverb",24,36],["H4428","against the king",37,53],["H0894","of Babylon",54,64],["H0559","and say",66,73],["H5065","How hath the oppressor",75,97],["H7673","ceased",98,104],["H4062","the golden city",106,121],["H7673","ceased",122,128]]},"14:5":{"text":"The LORD hath broken the staff of the wicked, and the sceptre of the rulers.","words":[["H3068","The LORD",0,8],["H7665","hath broken",9,20],["H4294","the staff",21,30],["H7563","of the wicked",31,44],["H7626","and the sceptre",46,61],["H4910","of the rulers",62,75]]},"14:6":{"text":"He who smote the people in wrath with a continual stroke, he that ruled the nations in anger, is persecuted, and none hindereth.","words":[["H5221","He who smote",0,12],["H5971","the people",13,23],["H5678","in wrath",24,32],["H1115","with a continual",33,49],["H5627","with a continual",33,49],["H4347","stroke",50,56],["H7287","he that ruled",58,71],["H1471","the nations",72,83],["H0639","in anger",84,92],["H4783","is persecuted",94,107],["H1097","and none",109,117],["H2820","hindereth",118,127]]},"14:7":{"text":"The whole earth is at rest, and is quiet: they break forth into singing.","words":[["H0776","The whole earth",0,15],["H5117","is at rest",16,26],["H8252","and is quiet",28,40],["H6476","they break forth",42,58],["H7440","into singing",59,71]]},"14:8":{"text":"Yea, the fir trees rejoice at thee, and the cedars of Lebanon, saying, Since thou art laid down, no feller is come up against us.","words":[["H1265","Yea, the fir trees",0,18],["H8055","rejoice",19,26],["H0730","at thee, and the cedars",27,50],["H3844","of Lebanon",51,61],["H7901","saying, Since thou art laid down",63,95],["H3772","no feller",97,106],["H5927","is come up",107,117]]},"14:9":{"text":"Hell from beneath is moved for thee to meet thee at thy coming: it stirreth up the dead for thee, even all the chief ones of the earth; it hath raised up from their thrones all the kings of the nations.","words":[["H7585","Hell",0,4],["H7264","from beneath is moved",5,26],["H7125","for thee to meet",27,43],["H0935","thee at thy coming",44,62],["H5782","it stirreth up",64,78],["H7496","the dead",79,87],["H6260","for thee, even all the chief ones",88,121],["H0776","of the earth",122,134],["H6965","it hath raised up",136,153],["H3678","from their thrones",154,172],["H4428","all the kings",173,186],["H1471","of the nations",187,201]]},"14:10":{"text":"All they shall speak and say unto thee, Art thou also become weak as we? art thou become like unto us?","words":[["H6030","All they shall speak",0,20],["H0559","and say",21,28],["H2470","unto thee, Art thou also become weak",29,65],["H4911","as we? art thou become like",66,93]]},"14:11":{"text":"Thy pomp is brought down to the grave, and the noise of thy viols: the worm is spread under thee, and the worms cover thee.","words":[["H1347","Thy pomp",0,8],["H3381","is brought down",9,24],["H7585","to the grave",25,37],["H1998","and the noise",39,52],["H5035","of thy viols",53,65],["H7415","the worm",67,75],["H3331","is spread",76,85],["H8438","under thee, and the worms",86,111],["H4374","cover",112,117]]},"14:12":{"text":"How art thou fallen from heaven, O Lucifer, son of the morning! how art thou cut down to the ground, which didst weaken the nations!","words":[["H5307","How art thou fallen",0,19],["H8064","from heaven",20,31],["H1966","O Lucifer",33,42],["H1121","son",44,47],["H7837","of the morning",48,62],["H3213","of the morning",48,62],["H1438","how art thou cut down",64,85],["H0776","to the ground",86,99],["H2522","which didst weaken",101,119],["H1471","the nations",120,131]]},"14:13":{"text":"For thou hast said in thine heart, I will ascend into heaven, I will exalt my throne above the stars of God: I will sit also upon the mount of the congregation, in the sides of the north:","words":[["H0559","For thou hast said",0,18],["H3824","in thine heart",19,33],["H5927","I will ascend",35,48],["H8064","into heaven",49,60],["H7311","I will exalt",62,74],["H3678","my throne",75,84],["H4605","above",85,90],["H3556","the stars",91,100],["H0410","of God",101,107],["H3427","I will sit",109,119],["H2022","also upon the mount",120,139],["H4150","of the congregation",140,159],["H3411","in the sides",161,173],["H6828","of the north",174,186]]},"14:14":{"text":"I will ascend above the heights of the clouds; I will be like the most High.","words":[["H5927","I will ascend",0,13],["H1116","above the heights",14,31],["H5645","of the clouds",32,45],["H1819","I will be like",47,61],["H5945","the most High",62,75]]},"14:15":{"text":"Yet thou shalt be brought down to hell, to the sides of the pit.","words":[["H3381","Yet thou shalt be brought down",0,30],["H7585","to hell",31,38],["H3411","to the sides",40,52],["H0953","of the pit",53,63]]},"14:16":{"text":"They that see thee shall narrowly look upon thee, and consider thee, saying, Is this the man that made the earth to tremble, that did shake kingdoms;","words":[["H7200","They that see",0,13],["H7688","thee shall narrowly look",14,38],["H0995","upon thee, and consider",39,62],["H0376","thee, saying, Is this the man",63,92],["H0776","that made the earth",93,112],["H7264","to tremble",113,123],["H7493","that did shake",125,139],["H4467","kingdoms",140,148]]},"14:17":{"text":"That made the world as a wilderness, and destroyed the cities thereof; that opened not the house of his prisoners?","words":[["H7760","That made",0,9],["H8398","the world",10,19],["H4057","as a wilderness",20,35],["H2040","and destroyed",37,50],["H5892","the cities",51,61],["H6605","thereof; that opened",62,82],["H1004","not the house",83,96],["H0615","of his prisoners",97,113]]},"14:18":{"text":"All the kings of the nations, even all of them, lie in glory, every one in his own house.","words":[["H4428","All the kings",0,13],["H1471","of the nations",14,28],["H7901","even all of them, lie",30,51],["H3519","in glory",52,60],["H0376","every one",62,71],["H1004","in his own house",72,88]]},"14:19":{"text":"But thou art cast out of thy grave like an abominable branch, and as the raiment of those that are slain, thrust through with a sword, that go down to the stones of the pit; as a carcase trodden under feet.","words":[["H7993","But thou art cast out",0,21],["H6913","of thy grave",22,34],["H8581","like an abominable",35,53],["H5342","branch",54,60],["H3830","and as the raiment",62,80],["H2026","of those that are slain",81,104],["H2944","thrust through",106,120],["H2719","with a sword",121,133],["H3381","that go down",135,147],["H0068","to the stones",148,161],["H0953","of the pit",162,172],["H6297","as a carcase",174,186],["H0947","trodden under feet",187,205]]},"14:20":{"text":"Thou shalt not be joined with them in burial, because thou hast destroyed thy land, and slain thy people: the seed of evildoers shall never be renowned.","words":[["H3161","Thou shalt not be joined",0,24],["H6900","with them in burial",25,44],["H7843","because thou hast destroyed",46,73],["H0776","thy land",74,82],["H2026","and slain",84,93],["H5971","thy people",94,104],["H2233","the seed",106,114],["H7489","of evildoers",115,127],["H5769","shall never",128,139],["H7121","be renowned",140,151]]},"14:21":{"text":"Prepare slaughter for his children for the iniquity of their fathers; that they do not rise, nor possess the land, nor fill the face of the world with cities.","words":[["H3559","Prepare",0,7],["H4293","slaughter",8,17],["H1121","for his children",18,34],["H5771","for the iniquity",35,51],["H0001","of their fathers",52,68],["H1077","that they do not",70,86],["H6965","rise",87,91],["H3423","nor possess",93,104],["H0776","the land",105,113],["H4390","nor fill",115,123],["H6440","the face",124,132],["H8398","of the world",133,145],["H6145","with cities",146,157],["H5892","with cities",146,157]]},"14:22":{"text":"For I will rise up against them, saith the LORD of hosts, and cut off from Babylon the name, and remnant, and son, and nephew, saith the LORD.","words":[["H6965","For I will rise up",0,18],["H5002","against them, saith",19,38],["H3068","the LORD",39,47],["H6635","of hosts",48,56],["H3772","and cut off",58,69],["H0894","from Babylon",70,82],["H8034","the name",83,91],["H7605","and remnant",93,104],["H5209","and son",106,113],["H5220","and nephew",115,125],["H5002","saith",127,132],["H3068","the LORD",133,141]]},"14:23":{"text":"I will also make it a possession for the bittern, and pools of water: and I will sweep it with the besom of destruction, saith the LORD of hosts.","words":[["H7760","I will also make",0,16],["H4180","it a possession",17,32],["H7090","for the bittern",33,48],["H0098","and pools",50,59],["H4325","of water",60,68],["H2894","and I will sweep",70,86],["H4292","it with the besom",87,104],["H8045","of destruction",105,119],["H5002","saith",121,126],["H3068","the LORD",127,135],["H6635","of hosts",136,144]]},"14:24":{"text":"The LORD of hosts hath sworn, saying, Surely as I have thought, so shall it come to pass; and as I have purposed, so shall it stand:","words":[["H3068","The LORD",0,8],["H6635","of hosts",9,17],["H7650","hath sworn",18,28],["H0559","saying",30,36],["H1819","Surely as I have thought",38,62],["H3289","so shall it come to pass; and as I have purposed",64,112],["H6965","so shall it stand",114,131]]},"14:25":{"text":"That I will break the Assyrian in my land, and upon my mountains tread him under foot: then shall his yoke depart from off them, and his burden depart from off their shoulders.","words":[["H7665","That I will break",0,17],["H0804","the Assyrian",18,30],["H0776","in my land",31,41],["H2022","and upon my mountains",43,64],["H0947","tread him under foot",65,85],["H5923","then shall his yoke",87,106],["H5493","depart",107,113],["H5448","from off them, and his burden",114,143],["H5493","depart",144,150],["H7926","from off their shoulders",151,175]]},"14:26":{"text":"This is the purpose that is purposed upon the whole earth: and this is the hand that is stretched out upon all the nations.","words":[["H6098","This is the purpose",0,19],["H3289","that is purposed",20,36],["H0776","upon the whole earth",37,57],["H3027","and this is the hand",59,79],["H5186","that is stretched out",80,101],["H1471","upon all the nations",102,122]]},"14:27":{"text":"For the LORD of hosts hath purposed, and who shall disannul it? and his hand is stretched out, and who shall turn it back?","words":[["H3068","For the LORD",0,12],["H6635","of hosts",13,21],["H3289","hath purposed",22,35],["H6565","and who shall disannul",37,59],["H3027","it? and his hand",60,76],["H5186","is stretched out",77,93],["H7725","and who shall turn it back",95,121]]},"14:28":{"text":"In the year that king Ahaz died was this burden.","words":[["H8141","In the year",0,11],["H4428","that king",12,21],["H0271","Ahaz",22,26],["H4194","died",27,31],["H4853","was this burden",32,47]]},"14:29":{"text":"Rejoice not thou, whole Palestina, because the rod of him that smote thee is broken: for out of the serpent's root shall come forth a cockatrice, and his fruit shall be a fiery flying serpent.","words":[["H8055","Rejoice",0,7],["H6429","not thou, whole Palestina",8,33],["H7626","because the rod",35,50],["H5221","of him that smote",51,68],["H7665","thee is broken",69,83],["H5175","for out of the serpent's",85,109],["H8328","root",110,114],["H3318","shall come forth",115,131],["H6848","a cockatrice",132,144],["H6529","and his fruit",146,159],["H8314","shall be a fiery",160,176],["H5774","flying",177,183],["H8314","serpent",184,191]]},"14:30":{"text":"And the firstborn of the poor shall feed, and the needy shall lie down in safety: and I will kill thy root with famine, and he shall slay thy remnant.","words":[["H1060","And the firstborn",0,17],["H1800","of the poor",18,29],["H7462","shall feed",30,40],["H0034","and the needy",42,55],["H7257","shall lie down",56,70],["H0983","in safety",71,80],["H4191","and I will kill",82,97],["H8328","thy root",98,106],["H7458","with famine",107,118],["H2026","and he shall slay",120,137],["H7611","thy remnant",138,149]]},"14:31":{"text":"Howl, O gate; cry, O city; thou, whole Palestina, art dissolved: for there shall come from the north a smoke, and none shall be alone in his appointed times.","words":[["H3213","Howl",0,4],["H8179","O gate",6,12],["H2199","cry",14,17],["H5892","O city",19,25],["H6429","thou, whole Palestina",27,48],["H4127","art dissolved",50,63],["H0935","for there shall come",65,85],["H6828","from the north",86,100],["H6227","a smoke",101,108],["H0909","and none shall be alone",110,133],["H4151","in his appointed times",134,156]]},"14:32":{"text":"What shall one then answer the messengers of the nation? That the LORD hath founded Zion, and the poor of his people shall trust in it.","words":[["H6030","What shall one then answer",0,26],["H4397","the messengers",27,41],["H1471","of the nation",42,55],["H3068","That the LORD",57,70],["H3245","hath founded",71,83],["H6726","Zion",84,88],["H6041","and the poor",90,102],["H5971","of his people",103,116],["H2620","shall trust",117,128]]},"15:1":{"text":"The burden of Moab. Because in the night Ar of Moab is laid waste, and brought to silence; because in the night Kir of Moab is laid waste, and brought to silence;","words":[["H4853","The burden",0,10],["H4124","of Moab",11,18],["H3915","Because in the night",20,40],["H6144","Ar",41,43],["H4124","of Moab",44,51],["H7703","is laid waste",52,65],["H1820","and brought to silence",67,89],["H3915","because in the night",91,111],["H7024","Kir",112,115],["H4124","of Moab",116,123],["H7703","is laid waste",124,137],["H1820","and brought to silence",139,161]]},"15:2":{"text":"He is gone up to Bajith, and to Dibon, the high places, to weep: Moab shall howl over Nebo, and over Medeba: on all their heads shall be baldness, and every beard cut off.","words":[["H5927","He is gone up",0,13],["H1006","to Bajith",14,23],["H1769","and to Dibon",25,37],["H1116","the high places",39,54],["H1065","to weep",56,63],["H4124","Moab",65,69],["H3213","shall howl",70,80],["H5015","over Nebo",81,90],["H4311","and over Medeba",92,107],["H7218","on all their heads",109,127],["H7144","shall be baldness",128,145],["H2206","and every beard",147,162],["H1438","cut off",163,170]]},"15:3":{"text":"In their streets they shall gird themselves with sackcloth: on the tops of their houses, and in their streets, every one shall howl, weeping abundantly.","words":[["H2351","In their streets",0,16],["H2296","they shall gird",17,32],["H8242","themselves with sackcloth",33,58],["H1406","on the tops",60,71],["H7339","of their houses, and in their streets",72,109],["H3213","every one shall howl",111,131],["H1065","weeping",133,140],["H3381","abundantly",141,151]]},"15:4":{"text":"And Heshbon shall cry, and Elealeh: their voice shall be heard even unto Jahaz: therefore the armed soldiers of Moab shall cry out; his life shall be grievous unto him.","words":[["H2809","And Heshbon",0,11],["H2199","shall cry",12,21],["H0500","and Elealeh",23,34],["H6963","their voice",36,47],["H8085","shall be heard",48,62],["H3096","even unto Jahaz",63,78],["H2502","therefore the armed soldiers",80,108],["H4124","of Moab",109,116],["H7321","shall cry out",117,130],["H5315","his life",132,140],["H3415","shall be grievous",141,158]]},"15:5":{"text":"My heart shall cry out for Moab; his fugitives shall flee unto Zoar, an heifer of three years old: for by the mounting up of Luhith with weeping shall they go it up; for in the way of Horonaim they shall raise up a cry of destruction.","words":[["H3820","My heart",0,8],["H2199","shall cry out",9,22],["H4124","for Moab",23,31],["H1280","his fugitives",33,46],["H6820","shall flee unto Zoar",47,67],["H5697","an heifer",69,78],["H7992","of three years old",79,97],["H4608","for by the mounting up",99,121],["H3872","of Luhith",122,131],["H1065","with weeping",132,144],["H5927","shall they go it up",145,164],["H1870","for in the way",166,180],["H2773","of Horonaim",181,192],["H5782","they shall raise up",193,212],["H2201","a cry",213,218],["H7667","of destruction",219,233]]},"15:6":{"text":"For the waters of Nimrim shall be desolate: for the hay is withered away, the grass faileth, there is no green thing.","words":[["H4325","For the waters",0,14],["H5249","of Nimrim",15,24],["H4923","shall be desolate",25,42],["H2682","for the hay",44,55],["H3001","is withered away",56,72],["H1877","the grass",74,83],["H3615","faileth",84,91],["H3418","there is no green thing",93,116]]},"15:7":{"text":"Therefore the abundance they have gotten, and that which they have laid up, shall they carry away to the brook of the willows.","words":[["H3502","Therefore the abundance",0,23],["H6213","they have gotten",24,40],["H6486","and that which they have laid up",42,74],["H5375","shall they carry away",76,97],["H5158","to the brook",98,110],["H6155","of the willows",111,125]]},"15:8":{"text":"For the cry is gone round about the borders of Moab; the howling thereof unto Eglaim, and the howling thereof unto Beerelim.","words":[["H2201","For the cry",0,11],["H5362","is gone round about",12,31],["H1366","the borders",32,43],["H4124","of Moab",44,51],["H3215","the howling",53,64],["H0097","thereof unto Eglaim",65,84],["H3215","and the howling",86,101],["H0879","thereof unto Beerelim",102,123]]},"15:9":{"text":"For the waters of Dimon shall be full of blood: for I will bring more upon Dimon, lions upon him that escapeth of Moab, and upon the remnant of the land.","words":[["H4325","For the waters",0,14],["H1775","of Dimon",15,23],["H4390","shall be full",24,37],["H1818","of blood",38,46],["H7896","for I will bring",48,64],["H3254","more",65,69],["H1775","upon Dimon",70,80],["H0738","lions",82,87],["H6413","upon him that escapeth",88,110],["H4124","of Moab",111,118],["H7611","and upon the remnant",120,140],["H0127","of the land",141,152]]},"16:1":{"text":"Send ye the lamb to the ruler of the land from Sela to the wilderness, unto the mount of the daughter of Zion.","words":[["H7971","Send",0,4],["H3733","ye the lamb",5,16],["H4910","to the ruler",17,29],["H0776","of the land",30,41],["H5554","from Sela",42,51],["H4057","to the wilderness",52,69],["H2022","unto the mount",71,85],["H1323","of the daughter",86,101],["H6726","of Zion",102,109]]},"16:2":{"text":"For it shall be, that, as a wandering bird cast out of the nest, so the daughters of Moab shall be at the fords of Arnon.","words":[["H5074","For it shall be, that, as a wandering",0,37],["H5775","bird",38,42],["H7971","cast out",43,51],["H7064","of the nest",52,63],["H1323","so the daughters",65,81],["H4124","of Moab",82,89],["H4569","shall be at the fords",90,111],["H0769","of Arnon",112,120]]},"16:3":{"text":"Take counsel, execute judgment; make thy shadow as the night in the midst of the noonday; hide the outcasts; bewray not him that wandereth.","words":[["H0935","Take",0,4],["H6098","counsel",5,12],["H6213","execute",14,21],["H6415","judgment",22,30],["H7896","make",32,36],["H6738","thy shadow",37,47],["H3915","as the night",48,60],["H8432","in the midst",61,73],["H6672","of the noonday",74,88],["H5641","hide",90,94],["H5080","the outcasts",95,107],["H1540","bewray",109,115],["H5074","not him that wandereth",116,138]]},"16:4":{"text":"Let mine outcasts dwell with thee, Moab; be thou a covert to them from the face of the spoiler: for the extortioner is at an end, the spoiler ceaseth, the oppressors are consumed out of the land.","words":[["H5080","Let mine outcasts",0,17],["H1481","dwell",18,23],["H4124","with thee, Moab",24,39],["H1933","be",41,43],["H5643","thou a covert",44,57],["H6440","to them from the face",58,79],["H7703","of the spoiler",80,94],["H4160","for the extortioner",96,115],["H0656","is at an end",116,128],["H7701","the spoiler",130,141],["H3615","ceaseth",142,149],["H7429","the oppressors",151,165],["H8552","are consumed",166,178],["H0776","out of the land",179,194]]},"16:5":{"text":"And in mercy shall the throne be established: and he shall sit upon it in truth in the tabernacle of David, judging, and seeking judgment, and hasting righteousness.","words":[["H2617","And in mercy",0,12],["H3678","shall the throne",13,29],["H3559","be established",30,44],["H3427","and he shall sit",46,62],["H0571","upon it in truth",63,79],["H0168","in the tabernacle",80,97],["H1732","of David",98,106],["H8199","judging",108,115],["H1875","and seeking",117,128],["H4941","judgment",129,137],["H4106","and hasting",139,150],["H6664","righteousness",151,164]]},"16:6":{"text":"We have heard of the pride of Moab; he is very proud: even of his haughtiness, and his pride, and his wrath: but his lies shall not be so.","words":[["H8085","We have heard",0,13],["H1347","of the pride",14,26],["H4124","of Moab",27,34],["H3966","he is very",36,46],["H1341","proud",47,52],["H1346","even of his haughtiness",54,77],["H1347","and his pride",79,92],["H5678","and his wrath",94,107],["H0907","but his lies",109,121]]},"16:7":{"text":"Therefore shall Moab howl for Moab, every one shall howl: for the foundations of Kirhareseth shall ye mourn; surely they are stricken.","words":[["H4124","Therefore shall Moab",0,20],["H3213","howl",21,25],["H4124","for Moab",26,34],["H3213","every one shall howl",36,56],["H0808","for the foundations",58,77],["H7025","of Kirhareseth",78,92],["H1897","shall ye mourn",93,107],["H5218","surely they are stricken",109,133]]},"16:8":{"text":"For the fields of Heshbon languish, and the vine of Sibmah: the lords of the heathen have broken down the principal plants thereof, they are come even unto Jazer, they wandered through the wilderness: her branches are stretched out, they are gone over the sea.","words":[["H7709","For the fields",0,14],["H2809","of Heshbon",15,25],["H0535","languish",26,34],["H1612","and the vine",36,48],["H7643","of Sibmah",49,58],["H1167","the lords",60,69],["H1471","of the heathen",70,84],["H1986","have broken down",85,101],["H8291","the principal plants",102,122],["H5060","thereof, they are come",123,145],["H3270","even unto Jazer",146,161],["H8582","they wandered",163,176],["H4057","through the wilderness",177,199],["H7976","her branches",201,213],["H5203","are stretched out",214,231],["H5674","they are gone over",233,251],["H3220","the sea",252,259]]},"16:9":{"text":"Therefore I will bewail with the weeping of Jazer the vine of Sibmah: I will water thee with my tears, O Heshbon, and Elealeh: for the shouting for thy summer fruits and for thy harvest is fallen.","words":[["H1058","Therefore I will bewail",0,23],["H1065","with the weeping",24,40],["H3270","of Jazer",41,49],["H1612","the vine",50,58],["H7643","of Sibmah",59,68],["H7301","I will water",70,82],["H1832","thee with my tears",83,101],["H2809","O Heshbon",103,112],["H0500","and Elealeh",114,125],["H1959","for the shouting",127,143],["H7019","for thy summer fruits",144,165],["H7105","and for thy harvest",166,185],["H5307","is fallen",186,195]]},"16:10":{"text":"And gladness is taken away, and joy out of the plentiful field; and in the vineyards there shall be no singing, neither shall there be shouting: the treaders shall tread out no wine in their presses; I have made their vintage shouting to cease.","words":[["H8057","And gladness",0,12],["H0622","is taken away",13,26],["H1524","and joy",28,35],["H3759","out of the plentiful field",36,62],["H3754","and in the vineyards",64,84],["H7442","there shall be no singing",85,110],["H7321","neither shall there be shouting",112,143],["H1869","the treaders",145,157],["H1869","shall tread out",158,173],["H3196","no wine",174,181],["H3342","in their presses",182,198],["H1959","I have made their vintage shouting",200,234],["H7673","to cease",235,243]]},"16:11":{"text":"Wherefore my bowels shall sound like an harp for Moab, and mine inward parts for Kirharesh.","words":[["H4578","Wherefore my bowels",0,19],["H1993","shall sound",20,31],["H3658","like an harp",32,44],["H4124","for Moab",45,53],["H7130","and mine inward parts",55,76],["H7025","for Kirharesh",77,90]]},"16:12":{"text":"And it shall come to pass, when it is seen that Moab is weary on the high place, that he shall come to his sanctuary to pray; but he shall not prevail.","words":[["H7200","And it shall come to pass, when it is seen",0,42],["H4124","that Moab",43,52],["H3811","is weary",53,61],["H1116","on the high place",62,79],["H0935","that he shall come",81,99],["H4720","to his sanctuary",100,116],["H6419","to pray",117,124],["H3201","but he shall not prevail",126,150]]},"16:13":{"text":"This is the word that the LORD hath spoken concerning Moab since that time.","words":[["H1697","This is the word",0,16],["H3068","that the LORD",17,30],["H1696","hath spoken",31,42],["H4124","concerning Moab",43,58],["H0227","since that time",59,74]]},"16:14":{"text":"But now the LORD hath spoken, saying, Within three years, as the years of an hireling, and the glory of Moab shall be contemned, with all that great multitude; and the remnant shall be very small and feeble.","words":[["H3068","But now the LORD",0,16],["H1696","hath spoken",17,28],["H0559","saying",30,36],["H7969","Within three",38,50],["H8141","years",51,56],["H8141","as the years",58,70],["H7916","of an hireling",71,85],["H3519","and the glory",87,100],["H4124","of Moab",101,108],["H7034","shall be contemned",109,127],["H7227","with all that great",129,148],["H1995","multitude",149,158],["H7605","and the remnant",160,175],["H4592","shall be very",176,189],["H4213","small",190,195],["H3808","and feeble",196,206],["H3524","and feeble",196,206]]},"17:1":{"text":"The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.","words":[["H4853","The burden",0,10],["H1834","of Damascus",11,22],["H1834","Behold, Damascus",24,40],["H5493","is taken away",41,54],["H5892","from being a city",55,72],["H4654","and it shall be a ruinous",74,99],["H4596","heap",100,104]]},"17:2":{"text":"The cities of Aroer are forsaken: they shall be for flocks, which shall lie down, and none shall make them afraid.","words":[["H5892","The cities",0,10],["H6177","of Aroer",11,19],["H5800","are forsaken",20,32],["H5739","they shall be for flocks",34,58],["H7257","which shall lie down",60,80],["H2729","and none shall make them afraid",82,113]]},"17:3":{"text":"The fortress also shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria: they shall be as the glory of the children of Israel, saith the LORD of hosts.","words":[["H4013","The fortress",0,12],["H7673","also shall cease",13,29],["H0669","from Ephraim",30,42],["H4467","and the kingdom",44,59],["H1834","from Damascus",60,73],["H7605","and the remnant",75,90],["H0758","of Syria",91,99],["H3519","they shall be as the glory",101,127],["H1121","of the children",128,143],["H3478","of Israel",144,153],["H5002","saith",155,160],["H3068","the LORD",161,169],["H6635","of hosts",170,178]]},"17:4":{"text":"And in that day it shall come to pass, that the glory of Jacob shall be made thin, and the fatness of his flesh shall wax lean.","words":[["H3117","And in that day",0,15],["H3519","it shall come to pass, that the glory",16,53],["H3290","of Jacob",54,62],["H1809","shall be made thin",63,81],["H4924","and the fatness",83,98],["H1320","of his flesh",99,111],["H7329","shall wax lean",112,126]]},"17:5":{"text":"And it shall be as when the harvestman gathereth the corn, and reapeth the ears with his arm; and it shall be as he that gathereth ears in the valley of Rephaim.","words":[["H7105","And it shall be as when the harvestman",0,38],["H0622","gathereth",39,48],["H7054","the corn",49,57],["H7114","and reapeth",59,70],["H7641","the ears",71,79],["H2220","with his arm",80,92],["H3950","and it shall be as he that gathereth",94,130],["H7641","ears",131,135],["H6010","in the valley",136,149],["H7497","of Rephaim",150,160]]},"17:6":{"text":"Yet gleaning grapes shall be left in it, as the shaking of an olive tree, two or three berries in the top of the uppermost bough, four or five in the outmost fruitful branches thereof, saith the LORD God of Israel.","words":[["H5955","Yet gleaning grapes",0,19],["H7604","shall be left",20,33],["H5363","in it, as the shaking",34,55],["H2132","of an olive tree",56,72],["H8147","two",74,77],["H7969","or three",78,86],["H1620","berries",87,94],["H7218","in the top",95,105],["H0534","of the uppermost bough",106,128],["H0702","four",130,134],["H2568","or five",135,142],["H6509","in the outmost fruitful",143,166],["H5585","branches",167,175],["H5002","thereof, saith",176,190],["H3068","the LORD",191,199],["H0430","God",200,203],["H3478","of Israel",204,213]]},"17:7":{"text":"At that day shall a man look to his Maker, and his eyes shall have respect to the Holy One of Israel.","words":[["H3117","At that day",0,11],["H0120","shall a man",12,23],["H8159","look",24,28],["H6213","to his Maker",29,41],["H5869","and his eyes",43,55],["H7200","shall have respect",56,74],["H6918","to the Holy",75,86],["H3478","One of Israel",87,100]]},"17:8":{"text":"And he shall not look to the altars, the work of his hands, neither shall respect that which his fingers have made, either the groves, or the images.","words":[["H8159","And he shall not look",0,21],["H4196","to the altars",22,35],["H4639","the work",37,45],["H3027","of his hands",46,58],["H7200","neither shall respect",60,81],["H0676","that which his fingers",82,104],["H6213","have made",105,114],["H0842","either the groves",116,133],["H2553","or the images",135,148]]},"17:9":{"text":"In that day shall his strong cities be as a forsaken bough, and an uppermost branch, which they left because of the children of Israel: and there shall be desolation.","words":[["H3117","In that day",0,11],["H4581","shall his strong",12,28],["H5892","cities",29,35],["H5800","be as a forsaken",36,52],["H2793","bough",53,58],["H0534","and an uppermost branch",60,83],["H5800","which they left",85,100],["H6440","because",101,108],["H1121","of the children",109,124],["H3478","of Israel",125,134],["H8077","and there shall be desolation",136,165]]},"17:10":{"text":"Because thou hast forgotten the God of thy salvation, and hast not been mindful of the rock of thy strength, therefore shalt thou plant pleasant plants, and shalt set it with strange slips:","words":[["H7911","Because thou hast forgotten",0,27],["H0430","the God",28,35],["H3468","of thy salvation",36,52],["H2142","and hast not been mindful",54,79],["H6697","of the rock",80,91],["H4581","of thy strength",92,107],["H5193","therefore shalt thou plant",109,135],["H5282","pleasant",136,144],["H5194","plants",145,151],["H2232","and shalt set",153,166],["H2114","it with strange",167,182],["H2156","slips",183,188]]},"17:11":{"text":"In the day shalt thou make thy plant to grow, and in the morning shalt thou make thy seed to flourish: but the harvest shall be a heap in the day of grief and of desperate sorrow.","words":[["H3117","In the day",0,10],["H5194","shalt thou make thy plant",11,36],["H7735","to grow",37,44],["H1242","and in the morning",46,64],["H2233","shalt thou make thy seed",65,89],["H6524","to flourish",90,101],["H7105","but the harvest",103,118],["H5067","shall be a heap",119,134],["H3117","in the day",135,145],["H2470","of grief",146,154],["H0605","and of desperate",155,171],["H3511","sorrow",172,178]]},"17:12":{"text":"Woe to the multitude of many people, which make a noise like the noise of the seas; and to the rushing of nations, that make a rushing like the rushing of mighty waters!","words":[["H1945","Woe",0,3],["H1995","to the multitude",4,20],["H7227","of many",21,28],["H5971","people",29,35],["H1993","which make a noise",37,55],["H1993","like the noise",56,70],["H3220","of the seas",71,82],["H7588","and to the rushing",84,102],["H3816","of nations",103,113],["H7582","that make a rushing like the rushing",115,151],["H3524","of mighty",152,161],["H4325","waters",162,168]]},"17:13":{"text":"The nations shall rush like the rushing of many waters: but God shall rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like a rolling thing before the whirlwind.","words":[["H3816","The nations",0,11],["H7582","shall rush",12,22],["H7588","like the rushing",23,39],["H7227","of many",40,47],["H4325","waters",48,54],["H1605","but God shall rebuke",56,76],["H5127","them, and they shall flee",77,102],["H4801","far off",103,110],["H7291","and shall be chased",112,131],["H4671","as the chaff",132,144],["H2022","of the mountains",145,161],["H6440","before",162,168],["H7307","the wind",169,177],["H1534","and like a rolling thing",179,203],["H6440","before",204,210],["H5492","the whirlwind",211,224]]},"17:14":{"text":"And behold at eveningtide trouble; and before the morning he is not. This is the portion of them that spoil us, and the lot of them that rob us.","words":[["H6256","And behold at eveningtide",0,25],["H6153","And behold at eveningtide",0,25],["H1091","trouble",26,33],["H1242","and before the morning",35,57],["H2506","he is not. This is the portion",58,88],["H8154","of them that spoil",89,107],["H1486","us, and the lot",108,123],["H0962","of them that rob",124,140]]},"18:1":{"text":"Woe to the land shadowing with wings, which is beyond the rivers of Ethiopia:","words":[["H1945","Woe",0,3],["H0776","to the land",4,15],["H6767","shadowing",16,25],["H3671","with wings",26,36],["H5676","which is beyond",38,53],["H5104","the rivers",54,64],["H3568","of Ethiopia",65,76]]},"18:2":{"text":"That sendeth ambassadors by the sea, even in vessels of bulrushes upon the waters, saying, Go, ye swift messengers, to a nation scattered and peeled, to a people terrible from their beginning hitherto; a nation meted out and trodden down, whose land the rivers have spoiled!","words":[["H7971","That sendeth",0,12],["H6735","ambassadors",13,24],["H3220","by the sea",25,35],["H3627","even in vessels",37,52],["H1573","of bulrushes",53,65],["H6440","upon",66,70],["H4325","the waters",71,81],["H3212","saying, Go",83,93],["H7031","ye swift",95,103],["H4397","messengers",104,114],["H1471","to a nation",116,127],["H4900","scattered",128,137],["H4178","and peeled",138,148],["H5971","to a people",150,161],["H3372","terrible",162,170],["H1973","from their beginning hitherto",171,200],["H1471","a nation",202,210],["H6978","meted out",211,220],["H4001","and trodden down",221,237],["H0776","whose land",239,249],["H5104","the rivers",250,260],["H0958","have spoiled",261,273]]},"18:3":{"text":"All ye inhabitants of the world, and dwellers on the earth, see ye, when he lifteth up an ensign on the mountains; and when he bloweth a trumpet, hear ye.","words":[["H3427","All ye inhabitants",0,18],["H8398","of the world",19,31],["H7931","and dwellers",33,45],["H0776","on the earth",46,58],["H7200","see",60,63],["H5375","ye, when he lifteth up",64,86],["H5251","an ensign",87,96],["H2022","on the mountains",97,113],["H8628","and when he bloweth",115,134],["H7782","a trumpet",135,144],["H8085","hear",146,150]]},"18:4":{"text":"For so the LORD said unto me, I will take my rest, and I will consider in my dwelling place like a clear heat upon herbs, and like a cloud of dew in the heat of harvest.","words":[["H3541","For so",0,6],["H3068","the LORD",7,15],["H0559","said",16,20],["H8252","unto me, I will take my rest",21,49],["H5027","and I will consider",51,70],["H4349","in my dwelling place",71,91],["H6703","like a clear",92,104],["H2527","heat",105,109],["H0216","upon herbs",110,120],["H5645","and like a cloud",122,138],["H2919","of dew",139,145],["H2527","in the heat",146,157],["H7105","of harvest",158,168]]},"18:5":{"text":"For afore the harvest, when the bud is perfect, and the sour grape is ripening in the flower, he shall both cut off the sprigs with pruning hooks, and take away and cut down the branches.","words":[["H6440","For afore",0,9],["H7105","the harvest",10,21],["H6525","when the bud",23,35],["H8552","is perfect",36,46],["H1155","and the sour grape",48,66],["H1580","is ripening",67,78],["H5328","in the flower",79,92],["H3772","he shall both cut off",94,115],["H2150","the sprigs",116,126],["H4211","with pruning hooks",127,145],["H5493","and take away",147,160],["H8456","and cut down",161,173],["H5189","the branches",174,186]]},"18:6":{"text":"They shall be left together unto the fowls of the mountains, and to the beasts of the earth: and the fowls shall summer upon them, and all the beasts of the earth shall winter upon them.","words":[["H5800","They shall be left",0,18],["H3162","together",19,27],["H5861","unto the fowls",28,42],["H2022","of the mountains",43,59],["H0929","and to the beasts",61,78],["H0776","of the earth",79,91],["H5861","and the fowls",93,106],["H6972","shall summer",107,119],["H0929","upon them, and all the beasts",120,149],["H0776","of the earth",150,162],["H2778","shall winter",163,175]]},"18:7":{"text":"In that time shall the present be brought unto the LORD of hosts of a people scattered and peeled, and from a people terrible from their beginning hitherto; a nation meted out and trodden under foot, whose land the rivers have spoiled, to the place of the name of the LORD of hosts, the mount Zion.","words":[["H6256","In that time",0,12],["H7862","shall the present",13,30],["H2986","be brought",31,41],["H3068","unto the LORD",42,55],["H6635","of hosts",56,64],["H5971","of a people",65,76],["H4900","scattered",77,86],["H4178","and peeled",87,97],["H5971","and from a people",99,116],["H3372","terrible",117,125],["H1973","from their beginning hitherto",126,155],["H1471","a nation",157,165],["H6978","meted out",166,175],["H4001","and trodden under foot",176,198],["H0776","whose land",200,210],["H5104","the rivers",211,221],["H0958","have spoiled",222,234],["H4725","to the place",236,248],["H8034","of the name",249,260],["H3068","of the LORD",261,272],["H6635","of hosts",273,281],["H2022","the mount",283,292],["H6726","Zion",293,297]]},"19:1":{"text":"The burden of Egypt. Behold, the LORD rideth upon a swift cloud, and shall come into Egypt: and the idols of Egypt shall be moved at his presence, and the heart of Egypt shall melt in the midst of it.","words":[["H4853","The burden",0,10],["H4714","of Egypt",11,19],["H3068","Behold, the LORD",21,37],["H7392","rideth",38,44],["H7031","upon a swift",45,57],["H5645","cloud",58,63],["H0935","and shall come",65,79],["H4714","into Egypt",80,90],["H0457","and the idols",92,105],["H4714","of Egypt",106,114],["H5128","shall be moved",115,129],["H6440","at his presence",130,145],["H3824","and the heart",147,160],["H4714","of Egypt",161,169],["H4549","shall melt",170,180],["H7130","in the midst",181,193]]},"19:2":{"text":"And I will set the Egyptians against the Egyptians: and they shall fight every one against his brother, and every one against his neighbour; city against city, and kingdom against kingdom.","words":[["H5526","And I will set",0,14],["H4714","the Egyptians",15,28],["H4714","against the Egyptians",29,50],["H3898","and they shall fight",52,72],["H0376","every one",73,82],["H0251","against his brother",83,102],["H0376","and every one",104,117],["H7453","against his neighbour",118,139],["H5892","city",141,145],["H5892","against city",146,158],["H4467","and kingdom",160,171],["H4467","against kingdom",172,187]]},"19:3":{"text":"And the spirit of Egypt shall fail in the midst thereof; and I will destroy the counsel thereof: and they shall seek to the idols, and to the charmers, and to them that have familiar spirits, and to the wizards.","words":[["H7307","And the spirit",0,14],["H4714","of Egypt",15,23],["H1238","shall fail",24,34],["H7130","in the midst",35,47],["H1104","thereof; and I will destroy",48,75],["H6098","the counsel",76,87],["H1875","thereof: and they shall seek",88,116],["H0457","to the idols",117,129],["H0328","and to the charmers",131,150],["H0178","and to them that have familiar spirits",152,190],["H3049","and to the wizards",192,210]]},"19:4":{"text":"And the Egyptians will I give over into the hand of a cruel lord; and a fierce king shall rule over them, saith the Lord, the LORD of hosts.","words":[["H0853","And",0,3],["H4714","the Egyptians",4,17],["H5534","will I give over",18,34],["H3027","into the hand",35,48],["H7186","of a cruel",49,59],["H0113","lord",60,64],["H5794","and a fierce",66,78],["H4428","king",79,83],["H4910","shall rule",84,94],["H5002","over them, saith",95,111],["H0113","the Lord",112,120],["H3068","the LORD",122,130],["H6635","of hosts",131,139]]},"19:5":{"text":"And the waters shall fail from the sea, and the river shall be wasted and dried up.","words":[["H4325","And the waters",0,14],["H5405","shall fail",15,25],["H3220","from the sea",26,38],["H5104","and the river",40,53],["H2717","shall be wasted",54,69],["H3001","and dried up",70,82]]},"19:6":{"text":"And they shall turn the rivers far away; and the brooks of defence shall be emptied and dried up: the reeds and flags shall wither.","words":[["H2186","And they shall turn",0,19],["H5104","the rivers",20,30],["H2186","far away",31,39],["H2975","and the brooks",41,55],["H4693","of defence",56,66],["H1809","shall be emptied",67,83],["H2717","and dried up",84,96],["H7070","the reeds",98,107],["H5488","and flags",108,117],["H7060","shall wither",118,130]]},"19:7":{"text":"The paper reeds by the brooks, by the mouth of the brooks, and every thing sown by the brooks, shall wither, be driven away, and be no more.","words":[["H6169","The paper reeds",0,15],["H2975","by the brooks",16,29],["H6310","by the mouth",31,43],["H2975","of the brooks",44,57],["H4218","and every thing sown",59,79],["H2975","by the brooks",80,93],["H3001","shall wither",95,107],["H5086","be driven away",109,123]]},"19:8":{"text":"The fishers also shall mourn, and all they that cast angle into the brooks shall lament, and they that spread nets upon the waters shall languish.","words":[["H1771","The fishers",0,11],["H0578","also shall mourn",12,28],["H7993","and all they that cast",30,52],["H2443","angle",53,58],["H2975","into the brooks",59,74],["H0056","shall lament",75,87],["H6566","and they that spread",89,109],["H4365","nets",110,114],["H6440","upon",115,119],["H4325","the waters",120,130],["H0535","shall languish",131,145]]},"19:9":{"text":"Moreover they that work in fine flax, and they that weave networks, shall be confounded.","words":[["H5647","Moreover they that work",0,23],["H8305","in fine",24,31],["H6593","flax",32,36],["H0707","and they that weave",38,57],["H2355","networks",58,66],["H0954","shall be confounded",68,87]]},"19:10":{"text":"And they shall be broken in the purposes thereof, all that make sluices and ponds for fish.","words":[["H1792","And they shall be broken",0,24],["H8356","in the purposes",25,40],["H6213","thereof, all that make",41,63],["H7938","sluices",64,71],["H0099","and ponds",72,81],["H5315","for fish",82,90]]},"19:11":{"text":"Surely the princes of Zoan are fools, the counsel of the wise counsellors of Pharaoh is become brutish: how say ye unto Pharaoh, I am the son of the wise, the son of ancient kings?","words":[["H8269","Surely the princes",0,18],["H6814","of Zoan",19,26],["H0191","are fools",27,36],["H6098","the counsel",38,49],["H2450","of the wise",50,61],["H3289","counsellors",62,73],["H6547","of Pharaoh",74,84],["H1197","is become brutish",85,102],["H0559","how say",104,111],["H6547","ye unto Pharaoh",112,127],["H1121","I am the son",129,141],["H2450","of the wise",142,153],["H1121","the son",155,162],["H6924","of ancient",163,173],["H4428","kings",174,179]]},"19:12":{"text":"Where are they? where are thy wise men? and let them tell thee now, and let them know what the LORD of hosts hath purposed upon Egypt.","words":[["H0335","Where",0,5],["H0645","are they? where",6,21],["H2450","are thy wise",22,34],["H5046","men? and let them tell",35,57],["H3045","thee now, and let them know",58,85],["H3068","what the LORD",86,99],["H6635","of hosts",100,108],["H3289","hath purposed",109,122],["H4714","upon Egypt",123,133]]},"19:13":{"text":"The princes of Zoan are become fools, the princes of Noph are deceived; they have also seduced Egypt, even they that are the stay of the tribes thereof.","words":[["H8269","The princes",0,11],["H6814","of Zoan",12,19],["H2973","are become fools",20,36],["H8269","the princes",38,49],["H5297","of Noph",50,57],["H5377","are deceived",58,70],["H8582","they have also seduced",72,94],["H4714","Egypt",95,100],["H6438","even they that are the stay",102,129],["H7626","of the tribes",130,143]]},"19:14":{"text":"The LORD hath mingled a perverse spirit in the midst thereof: and they have caused Egypt to err in every work thereof, as a drunken man staggereth in his vomit.","words":[["H3068","The LORD",0,8],["H4537","hath mingled",9,21],["H5773","a perverse",22,32],["H7307","spirit",33,39],["H7130","in the midst",40,52],["H4714","thereof: and they have caused Egypt",53,88],["H8582","to err",89,95],["H4639","in every work",96,109],["H7910","thereof, as a drunken",110,131],["H8582","man staggereth",132,146],["H6892","in his vomit",147,159]]},"19:15":{"text":"Neither shall there be any work for Egypt, which the head or tail, branch or rush, may do.","words":[["H4639","Neither shall there be any work",0,31],["H4714","for Egypt",32,41],["H7218","which the head",43,57],["H2180","or tail",58,65],["H3712","branch",67,73],["H0100","or rush",74,81],["H6213","may do",83,89]]},"19:16":{"text":"In that day shall Egypt be like unto women: and it shall be afraid and fear because of the shaking of the hand of the LORD of hosts, which he shaketh over it.","words":[["H3117","In that day",0,11],["H4714","shall Egypt",12,23],["H0802","be like unto women",24,42],["H2729","and it shall be afraid",44,66],["H6342","and fear",67,75],["H6440","because",76,83],["H8573","of the shaking",84,98],["H3027","of the hand",99,110],["H3068","of the LORD",111,122],["H6635","of hosts",123,131],["H5130","which he shaketh",133,149]]},"19:17":{"text":"And the land of Judah shall be a terror unto Egypt, every one that maketh mention thereof shall be afraid in himself, because of the counsel of the LORD of hosts, which he hath determined against it.","words":[["H0127","And the land",0,12],["H3063","of Judah",13,21],["H2283","shall be a terror",22,39],["H4714","unto Egypt",40,50],["H2142","every one that maketh mention",52,81],["H6342","thereof shall be afraid",82,105],["H6440","in himself, because",106,125],["H6098","of the counsel",126,140],["H3068","of the LORD",141,152],["H6635","of hosts",153,161],["H3289","which he hath determined",163,187]]},"19:18":{"text":"In that day shall five cities in the land of Egypt speak the language of Canaan, and swear to the LORD of hosts; one shall be called, The city of destruction.","words":[["H3117","In that day",0,11],["H2568","shall five",12,22],["H5892","cities",23,29],["H0776","in the land",30,41],["H4714","of Egypt",42,50],["H1696","speak",51,56],["H8193","the language",57,69],["H3667","of Canaan",70,79],["H7650","and swear",81,90],["H3068","to the LORD",91,102],["H6635","of hosts",103,111],["H0259","one",113,116],["H0559","shall be called",117,132],["H5892","The city",134,142],["H2041","of destruction",143,157]]},"19:19":{"text":"In that day shall there be an altar to the LORD in the midst of the land of Egypt, and a pillar at the border thereof to the LORD.","words":[["H3117","In that day",0,11],["H4196","shall there be an altar",12,35],["H3068","to the LORD",36,47],["H8432","in the midst",48,60],["H0776","of the land",61,72],["H4714","of Egypt",73,81],["H4676","and a pillar",83,95],["H0681","at",96,98],["H1366","the border",99,109],["H3068","thereof to the LORD",110,129]]},"19:20":{"text":"And it shall be for a sign and for a witness unto the LORD of hosts in the land of Egypt: for they shall cry unto the LORD because of the oppressors, and he shall send them a saviour, and a great one, and he shall deliver them.","words":[["H0226","And it shall be for a sign",0,26],["H5707","and for a witness",27,44],["H3068","unto the LORD",45,58],["H6635","of hosts",59,67],["H0776","in the land",68,79],["H4714","of Egypt",80,88],["H6817","for they shall cry",90,108],["H3068","unto the LORD",109,122],["H6440","because",123,130],["H3905","of the oppressors",131,148],["H7971","and he shall send",150,167],["H3467","them a saviour",168,182],["H7227","and a great one",184,199],["H5337","and he shall deliver",201,221]]},"19:21":{"text":"And the LORD shall be known to Egypt, and the Egyptians shall know the LORD in that day, and shall do sacrifice and oblation; yea, they shall vow a vow unto the LORD, and perform it.","words":[["H3068","And the LORD",0,12],["H3045","shall be known",13,27],["H4714","to Egypt",28,36],["H4714","and the Egyptians",38,55],["H3045","shall know",56,66],["H3068","the LORD",67,75],["H3117","in that day",76,87],["H5647","and shall do",89,101],["H2077","sacrifice",102,111],["H4503","and oblation",112,124],["H5087","yea, they shall vow",126,145],["H5088","a vow",146,151],["H3068","unto the LORD",152,165],["H7999","and perform",167,178]]},"19:22":{"text":"And the LORD shall smite Egypt: he shall smite and heal it: and they shall return even to the LORD, and he shall be intreated of them, and shall heal them.","words":[["H3068","And the LORD",0,12],["H5062","shall smite",13,24],["H4714","Egypt",25,30],["H5062","he shall smite",32,46],["H7495","and heal",47,55],["H7725","it: and they shall return",56,81],["H3068","even to the LORD",82,98],["H6279","and he shall be intreated",100,125],["H7495","of them, and shall heal",126,149]]},"19:23":{"text":"In that day shall there be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria, and the Egyptians shall serve with the Assyrians.","words":[["H3117","In that day",0,11],["H4546","shall there be a highway",12,36],["H4714","out of Egypt",37,49],["H0804","to Assyria",50,60],["H0804","and the Assyrian",62,78],["H0935","shall come",79,89],["H4714","into Egypt",90,100],["H4714","and the Egyptian",102,118],["H0804","into Assyria",119,131],["H4714","and the Egyptians",133,150],["H5647","shall serve",151,162],["H0804","with the Assyrians",163,181]]},"19:24":{"text":"In that day shall Israel be the third with Egypt and with Assyria, even a blessing in the midst of the land:","words":[["H3117","In that day",0,11],["H3478","shall Israel",12,24],["H7992","be the third",25,37],["H4714","with Egypt",38,48],["H0804","and with Assyria",49,65],["H1293","even a blessing",67,82],["H7130","in the midst",83,95],["H0776","of the land",96,107]]},"19:25":{"text":"Whom the LORD of hosts shall bless, saying, Blessed be Egypt my people, and Assyria the work of my hands, and Israel mine inheritance.","words":[["H3068","Whom the LORD",0,13],["H6635","of hosts",14,22],["H1288","shall bless",23,34],["H0559","saying",36,42],["H1288","Blessed",44,51],["H4714","be Egypt",52,60],["H5971","my people",61,70],["H0804","and Assyria",72,83],["H4639","the work",84,92],["H3027","of my hands",93,104],["H3478","and Israel",106,116],["H5159","mine inheritance",117,133]]},"20:1":{"text":"In the year that Tartan came unto Ashdod, (when Sargon the king of Assyria sent him,) and fought against Ashdod, and took it;","words":[["H8141","In the year",0,11],["H8661","that Tartan",12,23],["H0935","came",24,28],["H0795","unto Ashdod",29,40],["H5623","(when Sargon",42,54],["H4428","the king",55,63],["H0804","of Assyria",64,74],["H7971","sent",75,79],["H3898","him,) and fought",80,96],["H0795","against Ashdod",97,111],["H3920","and took",113,121]]},"20:2":{"text":"At the same time spake the LORD by Isaiah the son of Amoz, saying, Go and loose the sackcloth from off thy loins, and put off thy shoe from thy foot. And he did so, walking naked and barefoot.","words":[["H6256","At the same time",0,16],["H1696","spake",17,22],["H3068","the LORD",23,31],["H3027","by",32,34],["H3470","Isaiah",35,41],["H1121","the son",42,49],["H0531","of Amoz",50,57],["H0559","saying",59,65],["H3212","Go",67,69],["H6605","and loose",70,79],["H8242","the sackcloth",80,93],["H4975","from off thy loins",94,112],["H2502","and put off",114,125],["H5275","thy shoe",126,134],["H7272","from thy foot",135,148],["H6213","And he did so",150,163],["H1980","walking",165,172],["H6174","naked",173,178],["H3182","and barefoot",179,191]]},"20:3":{"text":"And the LORD said, Like as my servant Isaiah hath walked naked and barefoot three years for a sign and wonder upon Egypt and upon Ethiopia;","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5650","Like as my servant",19,37],["H3470","Isaiah",38,44],["H1980","hath walked",45,56],["H6174","naked",57,62],["H3182","and barefoot",63,75],["H7969","three",76,81],["H8141","years",82,87],["H0226","for a sign",88,98],["H4159","and wonder",99,109],["H4714","upon Egypt",110,120],["H3568","and upon Ethiopia",121,138]]},"20:4":{"text":"So shall the king of Assyria lead away the Egyptians prisoners, and the Ethiopians captives, young and old, naked and barefoot, even with their buttocks uncovered, to the shame of Egypt.","words":[["H4428","So shall the king",0,17],["H0804","of Assyria",18,28],["H5090","lead away",29,38],["H4714","the Egyptians",39,52],["H7628","prisoners",53,62],["H3568","and the Ethiopians",64,82],["H1546","captives",83,91],["H5288","young",93,98],["H2205","and old",99,106],["H6174","naked",108,113],["H3182","and barefoot",114,126],["H8357","even with their buttocks",128,152],["H2834","uncovered",153,162],["H6172","to the shame",164,176],["H4714","of Egypt",177,185]]},"20:5":{"text":"And they shall be afraid and ashamed of Ethiopia their expectation, and of Egypt their glory.","words":[["H2865","And they shall be afraid",0,24],["H0954","and ashamed",25,36],["H3568","of Ethiopia",37,48],["H4007","their expectation",49,66],["H4714","and of Egypt",68,80],["H8597","their glory",81,92]]},"20:6":{"text":"And the inhabitant of this isle shall say in that day, Behold, such is our expectation, whither we flee for help to be delivered from the king of Assyria: and how shall we escape?","words":[["H3427","And the inhabitant",0,18],["H0339","of this isle",19,31],["H0559","shall say",32,41],["H3117","in that day",42,53],["H3541","Behold, such",55,67],["H4007","is our expectation",68,86],["H5127","whither we flee",88,103],["H5833","for help",104,112],["H5337","to be delivered",113,128],["H6440","from",129,133],["H4428","the king",134,142],["H0804","of Assyria",143,153],["H4422","and how shall we escape",155,178]]},"21:1":{"text":"The burden of the desert of the sea. As whirlwinds in the south pass through; so it cometh from the desert, from a terrible land.","words":[["H4853","The burden",0,10],["H4057","of the desert",11,24],["H3220","of the sea",25,35],["H5492","As whirlwinds",37,50],["H5045","in the south",51,63],["H2498","pass",64,68],["H0935","through; so it cometh",69,90],["H4057","from the desert",91,106],["H3372","from a terrible",108,123],["H0776","land",124,128]]},"21:2":{"text":"A grievous vision is declared unto me; the treacherous dealer dealeth treacherously, and the spoiler spoileth. Go up, O Elam: besiege, O Media; all the sighing thereof have I made to cease.","words":[["H7186","A grievous",0,10],["H2380","vision",11,17],["H5046","is declared",18,29],["H0898","unto me; the treacherous dealer",30,61],["H0898","dealeth treacherously",62,83],["H7703","and the spoiler",85,100],["H7703","spoileth",101,109],["H5927","Go up",111,116],["H5867","O Elam",118,124],["H6696","besiege",126,133],["H4074","O Media",135,142],["H0585","all the sighing",144,159],["H7673","thereof have I made to cease",160,188]]},"21:3":{"text":"Therefore are my loins filled with pain: pangs have taken hold upon me, as the pangs of a woman that travaileth: I was bowed down at the hearing of it; I was dismayed at the seeing of it.","words":[["H4975","Therefore are my loins",0,22],["H4390","filled",23,29],["H2479","with pain",30,39],["H6735","pangs",41,46],["H0270","have taken hold",47,62],["H6735","upon me, as the pangs",63,84],["H3205","of a woman that travaileth",85,111],["H5753","I was bowed down",113,129],["H8085","at the hearing",130,144],["H0926","of it; I was dismayed",145,166],["H7200","at the seeing",167,180]]},"21:4":{"text":"My heart panted, fearfulness affrighted me: the night of my pleasure hath he turned into fear unto me.","words":[["H3824","My heart",0,8],["H8582","panted",9,15],["H6427","fearfulness",17,28],["H1204","affrighted",29,39],["H5399","me: the night",40,53],["H2837","of my pleasure",54,68],["H7760","hath he turned",69,83],["H2731","into fear",84,93]]},"21:5":{"text":"Prepare the table, watch in the watchtower, eat, drink: arise, ye princes, and anoint the shield.","words":[["H6186","Prepare",0,7],["H7979","the table",8,17],["H6822","watch",19,24],["H6844","in the watchtower",25,42],["H0398","eat",44,47],["H8354","drink",49,54],["H6965","arise",56,61],["H8269","ye princes",63,73],["H4886","and anoint",75,85],["H4043","the shield",86,96]]},"21:6":{"text":"For thus hath the Lord said unto me, Go, set a watchman, let him declare what he seeth.","words":[["H0136","For thus hath the Lord",0,22],["H0559","said",23,27],["H3212","unto me, Go",28,39],["H5975","set",41,44],["H6822","a watchman",45,55],["H5046","let him declare",57,72],["H7200","what he seeth",73,86]]},"21:7":{"text":"And he saw a chariot with a couple of horsemen, a chariot of asses, and a chariot of camels; and he hearkened diligently with much heed:","words":[["H7200","And he saw",0,10],["H7393","a chariot",11,20],["H6776","with a couple",21,34],["H6571","of horsemen",35,46],["H7393","a chariot",48,57],["H2543","of asses",58,66],["H7393","and a chariot",68,81],["H1581","of camels",82,91],["H7181","and he hearkened",93,109],["H7182","diligently",110,120],["H7227","with much",121,130],["H7182","heed",131,135]]},"21:8":{"text":"And he cried, A lion: My lord, I stand continually upon the watchtower in the daytime, and I am set in my ward whole nights:","words":[["H7121","And he cried",0,12],["H0738","A lion",14,20],["H0136","My lord",22,29],["H5975","I stand",31,38],["H8548","continually",39,50],["H4707","upon the watchtower",51,70],["H3119","in the daytime",71,85],["H5324","and I am set",87,99],["H4931","in my ward",100,110],["H3915","whole nights",111,123]]},"21:9":{"text":"And, behold, here cometh a chariot of men, with a couple of horsemen. And he answered and said, Babylon is fallen, is fallen; and all the graven images of her gods he hath broken unto the ground.","words":[["H0935","And, behold, here cometh",0,24],["H7393","a chariot",25,34],["H0376","of men",35,41],["H6776","with a couple",43,56],["H6571","of horsemen",57,68],["H6030","And he answered",70,85],["H0559","and said",86,94],["H0894","Babylon",96,103],["H5307","is fallen",104,113],["H5307","is fallen",115,124],["H6456","and all the graven images",126,151],["H0430","of her gods",152,163],["H7665","he hath broken",164,178],["H0776","unto the ground",179,194]]},"21:10":{"text":"O my threshing, and the corn of my floor: that which I have heard of the LORD of hosts, the God of Israel, have I declared unto you.","words":[["H4098","O my threshing",0,14],["H1121","and the corn",16,28],["H1637","of my floor",29,40],["H8085","that which I have heard",42,65],["H3068","of the LORD",66,77],["H6635","of hosts",78,86],["H0430","the God",88,95],["H3478","of Israel",96,105],["H5046","have I declared",107,122]]},"21:11":{"text":"The burden of Dumah. He calleth to me out of Seir, Watchman, what of the night? Watchman, what of the night?","words":[["H4853","The burden",0,10],["H1746","of Dumah",11,19],["H7121","He calleth",21,31],["H8165","to me out of Seir",32,49],["H8104","Watchman",51,59],["H3915","what of the night",61,78],["H8104","Watchman",80,88],["H3915","what of the night",90,107]]},"21:12":{"text":"The watchman said, The morning cometh, and also the night: if ye will enquire, enquire ye: return, come.","words":[["H8104","The watchman",0,12],["H0559","said",13,17],["H1242","The morning",19,30],["H0857","cometh",31,37],["H3915","and also the night",39,57],["H1158","if ye will enquire",59,77],["H1158","enquire",79,86],["H7725","ye: return",87,97],["H0857","come",99,103]]},"21:13":{"text":"The burden upon Arabia. In the forest in Arabia shall ye lodge, O ye travelling companies of Dedanim.","words":[["H4853","The burden",0,10],["H6152","upon Arabia",11,22],["H3293","In the forest",24,37],["H6152","in Arabia",38,47],["H3885","shall ye lodge",48,62],["H0736","O ye travelling companies",64,89],["H1720","of Dedanim",90,100]]},"21:14":{"text":"The inhabitants of the land of Tema brought water to him that was thirsty, they prevented with their bread him that fled.","words":[["H3427","The inhabitants",0,15],["H0776","of the land",16,27],["H8485","of Tema",28,35],["H0857","brought",36,43],["H4325","water",44,49],["H7125","to him",50,56],["H6771","that was thirsty",57,73],["H6923","they prevented",75,89],["H3899","with their bread",90,106],["H5074","him that fled",107,120]]},"21:15":{"text":"For they fled from the swords, from the drawn sword, and from the bent bow, and from the grievousness of war.","words":[["H5074","For they fled",0,13],["H6440","from",14,18],["H2719","the swords",19,29],["H6440","from",31,35],["H5203","the drawn",36,45],["H2719","sword",46,51],["H6440","and from",53,61],["H1869","the bent",62,70],["H7198","bow",71,74],["H6440","and from",76,84],["H3514","the grievousness",85,101],["H4421","of war",102,108]]},"21:16":{"text":"For thus hath the Lord said unto me, Within a year, according to the years of an hireling, and all the glory of Kedar shall fail:","words":[["H0136","For thus hath the Lord",0,22],["H0559","said",23,27],["H8141","unto me, Within a year",28,50],["H8141","according to the years",52,74],["H7916","of an hireling",75,89],["H3519","and all the glory",91,108],["H6938","of Kedar",109,117],["H3615","shall fail",118,128]]},"21:17":{"text":"And the residue of the number of archers, the mighty men of the children of Kedar, shall be diminished: for the LORD God of Israel hath spoken it.","words":[["H7605","And the residue",0,15],["H4557","of the number",16,29],["H7198","of archers",30,40],["H1368","the mighty men",42,56],["H1121","of the children",57,72],["H6938","of Kedar",73,81],["H4591","shall be diminished",83,102],["H3068","for the LORD",104,116],["H0430","God",117,120],["H3478","of Israel",121,130],["H1696","hath spoken",131,142]]},"22:1":{"text":"The burden of the valley of vision. What aileth thee now, that thou art wholly gone up to the housetops?","words":[["H4853","The burden",0,10],["H1516","of the valley",11,24],["H2384","of vision",25,34],["H0645","What aileth thee now",36,56],["H5927","that thou art wholly gone up",58,86],["H1406","to the housetops",87,103]]},"22:2":{"text":"Thou that art full of stirs, a tumultuous city, a joyous city: thy slain men are not slain with the sword, nor dead in battle.","words":[["H4392","Thou that art full",0,18],["H8663","of stirs",19,27],["H1993","a tumultuous",29,41],["H5892","city",42,46],["H5947","a joyous",48,56],["H7151","city",57,61],["H2491","thy slain",63,72],["H2491","men are not slain",73,90],["H2719","with the sword",91,105],["H4191","nor dead",107,115],["H4421","in battle",116,125]]},"22:3":{"text":"All thy rulers are fled together, they are bound by the archers: all that are found in thee are bound together, which have fled from far.","words":[["H7101","All thy rulers",0,14],["H5074","are fled",15,23],["H3162","together",24,32],["H0631","they are bound",34,48],["H7198","by the archers",49,63],["H4672","all that are found",65,83],["H0631","in thee are bound",84,101],["H3162","together",102,110],["H1272","which have fled",112,127],["H7350","from far",128,136]]},"22:4":{"text":"Therefore said I, Look away from me; I will weep bitterly, labour not to comfort me, because of the spoiling of the daughter of my people.","words":[["H0559","Therefore said",0,14],["H8159","I, Look away",15,27],["H1065","from me; I will weep",28,48],["H4843","bitterly",49,57],["H0213","labour",59,65],["H5162","not to comfort",66,80],["H7701","me, because of the spoiling",81,108],["H1323","of the daughter",109,124],["H5971","of my people",125,137]]},"22:5":{"text":"For it is a day of trouble, and of treading down, and of perplexity by the Lord GOD of hosts in the valley of vision, breaking down the walls, and of crying to the mountains.","words":[["H3117","For it is a day",0,15],["H4103","of trouble",16,26],["H4001","and of treading down",28,48],["H3998","and of perplexity",50,67],["H0136","by the Lord",68,79],["H3069","GOD",80,83],["H6635","of hosts",84,92],["H1516","in the valley",93,106],["H2384","of vision",107,116],["H6979","breaking",118,126],["H7023","down the walls",127,141],["H7771","and of crying",143,156],["H2022","to the mountains",157,173]]},"22:6":{"text":"And Elam bare the quiver with chariots of men and horsemen, and Kir uncovered the shield.","words":[["H5867","And Elam",0,8],["H5375","bare",9,13],["H0827","the quiver",14,24],["H7393","with chariots",25,38],["H0120","of men",39,45],["H6571","and horsemen",46,58],["H7024","and Kir",60,67],["H6168","uncovered",68,77],["H4043","the shield",78,88]]},"22:7":{"text":"And it shall come to pass, that thy choicest valleys shall be full of chariots, and the horsemen shall set themselves in array at the gate.","words":[["H4005","And it shall come to pass, that thy choicest",0,44],["H6010","valleys",45,52],["H4390","shall be full",53,66],["H7393","of chariots",67,78],["H6571","and the horsemen",80,96],["H7896","shall set",97,106],["H7896","themselves in array",107,126],["H8179","at the gate",127,138]]},"22:8":{"text":"And he discovered the covering of Judah, and thou didst look in that day to the armour of the house of the forest.","words":[["H1540","And he discovered",0,17],["H4539","the covering",18,30],["H3063","of Judah",31,39],["H5027","and thou didst look",41,60],["H3117","in that day",61,72],["H5402","to the armour",73,86],["H1004","of the house",87,99],["H3293","of the forest",100,113]]},"22:9":{"text":"Ye have seen also the breaches of the city of David, that they are many: and ye gathered together the waters of the lower pool.","words":[["H7200","Ye have seen",0,12],["H1233","also the breaches",13,30],["H5892","of the city",31,42],["H1732","of David",43,51],["H7231","that they are many",53,71],["H6908","and ye gathered together",73,97],["H4325","the waters",98,108],["H8481","of the lower",109,121],["H1295","pool",122,126]]},"22:10":{"text":"And ye have numbered the houses of Jerusalem, and the houses have ye broken down to fortify the wall.","words":[["H5608","And ye have numbered",0,20],["H1004","the houses",21,31],["H3389","of Jerusalem",32,44],["H1004","and the houses",46,60],["H5422","have ye broken down",61,80],["H1219","to fortify",81,91],["H2346","the wall",92,100]]},"22:11":{"text":"Ye made also a ditch between the two walls for the water of the old pool: but ye have not looked unto the maker thereof, neither had respect unto him that fashioned it long ago.","words":[["H6213","Ye made",0,7],["H4724","also a ditch",8,20],["H2346","between the two walls",21,42],["H4325","for the water",43,56],["H3465","of the old",57,67],["H1295","pool",68,72],["H5027","but ye have not looked",74,96],["H6213","unto the maker",97,111],["H7200","thereof, neither had respect",112,140],["H3335","unto him that fashioned",141,164],["H7350","it long ago",165,176]]},"22:12":{"text":"And in that day did the Lord GOD of hosts call to weeping, and to mourning, and to baldness, and to girding with sackcloth:","words":[["H3117","And in that day",0,15],["H0136","did the Lord",16,28],["H3069","GOD",29,32],["H6635","of hosts",33,41],["H7121","call",42,46],["H1065","to weeping",47,57],["H4553","and to mourning",59,74],["H7144","and to baldness",76,91],["H2296","and to girding",93,107],["H8242","with sackcloth",108,122]]},"22:13":{"text":"And behold joy and gladness, slaying oxen, and killing sheep, eating flesh, and drinking wine: let us eat and drink; for to morrow we shall die.","words":[["H8342","And behold joy",0,14],["H8057","and gladness",15,27],["H2026","slaying",29,36],["H1241","oxen",37,41],["H7819","and killing",43,54],["H6629","sheep",55,60],["H0398","eating",62,68],["H1320","flesh",69,74],["H8354","and drinking",76,88],["H3196","wine",89,93],["H0398","let us eat",95,105],["H8354","and drink",106,115],["H4279","for to morrow",117,130],["H4191","we shall die",131,143]]},"22:14":{"text":"And it was revealed in mine ears by the LORD of hosts, Surely this iniquity shall not be purged from you till ye die, saith the Lord GOD of hosts.","words":[["H1540","And it was revealed",0,19],["H0241","in mine ears",20,32],["H3068","by the LORD",33,44],["H6635","of hosts",45,53],["H5771","Surely this iniquity",55,75],["H3722","shall not be purged",76,95],["H4191","from you till ye die",96,116],["H0559","saith",118,123],["H0136","the Lord",124,132],["H3069","GOD",133,136],["H6635","of hosts",137,145]]},"22:15":{"text":"Thus saith the Lord GOD of hosts, Go, get thee unto this treasurer, even unto Shebna, which is over the house, and say,","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6635","of hosts",24,32],["H3212","Go",34,36],["H0935","get",38,41],["H5532","thee unto this treasurer",42,66],["H7644","even unto Shebna",68,84],["H1004","which is over the house",86,109]]},"22:16":{"text":"What hast thou here? and whom hast thou here, that thou hast hewed thee out a sepulchre here, as he that heweth him out a sepulchre on high, and that graveth an habitation for himself in a rock?","words":[["H2672","What hast thou here? and whom hast thou here, that thou hast hewed thee out",0,75],["H6913","a sepulchre",76,87],["H6311","here",88,92],["H2672","as he that heweth him out",94,119],["H6913","a sepulchre",120,131],["H4791","on high",132,139],["H2710","and that graveth",141,157],["H4908","an habitation",158,171],["H5553","for himself in a rock",172,193]]},"22:17":{"text":"Behold, the LORD will carry thee away with a mighty captivity, and will surely cover thee.","words":[["H3068","Behold, the LORD",0,16],["H2904","will carry thee away",17,37],["H1397","with a mighty",38,51],["H2925","captivity",52,61],["H5844","and will surely",63,78],["H5844","cover",79,84]]},"22:18":{"text":"He will surely violently turn and toss thee like a ball into a large country: there shalt thou die, and there the chariots of thy glory shall be the shame of thy lord's house.","words":[["H6801","He will surely",0,14],["H6801","violently turn",15,29],["H6802","and toss",30,38],["H1754","thee like a ball",39,55],["H7342","into a large",56,68],["H3027","into a large",56,68],["H0776","country",69,76],["H4191","there shalt thou die",78,98],["H4818","and there the chariots",100,122],["H3519","of thy glory",123,135],["H7036","shall be the shame",136,154],["H0113","of thy lord's",155,168],["H1004","house",169,174]]},"22:19":{"text":"And I will drive thee from thy station, and from thy state shall he pull thee down.","words":[["H1920","And I will drive",0,16],["H4673","thee from thy station",17,38],["H4612","and from thy state",40,58],["H2040","shall he pull thee down",59,82]]},"22:20":{"text":"And it shall come to pass in that day, that I will call my servant Eliakim the son of Hilkiah:","words":[["H3117","And it shall come to pass in that day",0,37],["H7121","that I will call",39,55],["H5650","my servant",56,66],["H0471","Eliakim",67,74],["H1121","the son",75,82],["H2518","of Hilkiah",83,93]]},"22:21":{"text":"And I will clothe him with thy robe, and strengthen him with thy girdle, and I will commit thy government into his hand: and he shall be a father to the inhabitants of Jerusalem, and to the house of Judah.","words":[["H3847","And I will clothe",0,17],["H3801","him with thy robe",18,35],["H2388","and strengthen",37,51],["H0073","him with thy girdle",52,71],["H5414","and I will commit",73,90],["H4475","thy government",91,105],["H3027","into his hand",106,119],["H0001","and he shall be a father",121,145],["H3427","to the inhabitants",146,164],["H3389","of Jerusalem",165,177],["H1004","and to the house",179,195],["H3063","of Judah",196,204]]},"22:22":{"text":"And the key of the house of David will I lay upon his shoulder; so he shall open, and none shall shut; and he shall shut, and none shall open.","words":[["H4668","And the key",0,11],["H1004","of the house",12,24],["H1732","of David",25,33],["H5414","will I lay",34,44],["H7926","upon his shoulder",45,62],["H6605","so he shall open",64,80],["H5462","and none shall shut",82,101],["H5462","and he shall shut",103,120],["H6605","and none shall open",122,141]]},"22:23":{"text":"And I will fasten him as a nail in a sure place; and he shall be for a glorious throne to his father's house.","words":[["H8628","And I will fasten",0,17],["H3489","him as a nail",18,31],["H0539","in a sure",32,41],["H4725","place",42,47],["H3519","and he shall be for a glorious",49,79],["H3678","throne",80,86],["H0001","to his father's",87,102],["H1004","house",103,108]]},"22:24":{"text":"And they shall hang upon him all the glory of his father's house, the offspring and the issue, all vessels of small quantity, from the vessels of cups, even to all the vessels of flagons.","words":[["H8518","And they shall hang",0,19],["H3519","upon him all the glory",20,42],["H0001","of his father's",43,58],["H1004","house",59,64],["H6631","the offspring",66,79],["H6849","and the issue",80,93],["H3627","all vessels",95,106],["H6996","of small",107,115],["H3627","quantity, from the vessels",116,142],["H0101","of cups",143,150],["H3627","even to all the vessels",152,175],["H5035","of flagons",176,186]]},"22:25":{"text":"In that day, saith the LORD of hosts, shall the nail that is fastened in the sure place be removed, and be cut down, and fall; and the burden that was upon it shall be cut off: for the LORD hath spoken it.","words":[["H3117","In that day",0,11],["H5002","saith",13,18],["H3068","the LORD",19,27],["H6635","of hosts",28,36],["H3489","shall the nail",38,52],["H8628","that is fastened",53,69],["H0539","in the sure",70,81],["H4725","place",82,87],["H4185","be removed",88,98],["H1438","and be cut down",100,115],["H5307","and fall",117,125],["H4853","and the burden",127,141],["H3772","that was upon it shall be cut off",142,175],["H3068","for the LORD",177,189],["H1696","hath spoken",190,201]]},"23:1":{"text":"The burden of Tyre. Howl, ye ships of Tarshish; for it is laid waste, so that there is no house, no entering in: from the land of Chittim it is revealed to them.","words":[["H4853","The burden",0,10],["H6865","of Tyre",11,18],["H3213","Howl",20,24],["H0591","ye ships",26,34],["H8659","of Tarshish",35,46],["H7703","for it is laid waste",48,68],["H1004","so that there is no house",70,95],["H0935","no entering in",97,111],["H0776","from the land",113,126],["H3794","of Chittim",127,137],["H1540","it is revealed",138,152]]},"23:2":{"text":"Be still, ye inhabitants of the isle; thou whom the merchants of Zidon, that pass over the sea, have replenished.","words":[["H1826","Be still",0,8],["H3427","ye inhabitants",10,24],["H0339","of the isle",25,36],["H5503","thou whom the merchants",38,61],["H6721","of Zidon",62,70],["H5674","that pass over",72,86],["H3220","the sea",87,94],["H4390","have replenished",96,112]]},"23:3":{"text":"And by great waters the seed of Sihor, the harvest of the river, is her revenue; and she is a mart of nations.","words":[["H7227","And by great",0,12],["H4325","waters",13,19],["H2233","the seed",20,28],["H7883","of Sihor",29,37],["H7105","the harvest",39,50],["H2975","of the river",51,63],["H8393","is her revenue",65,79],["H5505","and she is a mart",81,98],["H1471","of nations",99,109]]},"23:4":{"text":"Be thou ashamed, O Zidon: for the sea hath spoken, even the strength of the sea, saying, I travail not, nor bring forth children, neither do I nourish up young men, nor bring up virgins.","words":[["H0954","Be thou ashamed",0,15],["H6721","O Zidon",17,24],["H3220","for the sea",26,37],["H0559","hath spoken",38,49],["H4581","even the strength",51,68],["H3220","of the sea",69,79],["H0559","saying",81,87],["H2342","I travail",89,98],["H3205","not, nor bring forth children",99,128],["H1431","neither do I nourish up",130,153],["H0970","young men",154,163],["H7311","nor bring up",165,177],["H1330","virgins",178,185]]},"23:5":{"text":"As at the report concerning Egypt, so shall they be sorely pained at the report of Tyre.","words":[["H8088","As at the report",0,16],["H4714","concerning Egypt",17,33],["H2342","so shall they be sorely pained",35,65],["H8088","at the report",66,79],["H6865","of Tyre",80,87]]},"23:6":{"text":"Pass ye over to Tarshish; howl, ye inhabitants of the isle.","words":[["H5674","Pass ye over",0,12],["H8659","to Tarshish",13,24],["H3213","howl",26,30],["H3427","ye inhabitants",32,46],["H0339","of the isle",47,58]]},"23:7":{"text":"Is this your joyous city, whose antiquity is of ancient days? her own feet shall carry her afar off to sojourn.","words":[["H5947","Is this your joyous",0,19],["H6927","city, whose antiquity",20,41],["H6924","is of ancient",42,55],["H3117","days",56,60],["H7272","her own feet",62,74],["H2986","shall carry",75,86],["H7350","her afar off",87,99],["H1481","to sojourn",100,110]]},"23:8":{"text":"Who hath taken this counsel against Tyre, the crowning city, whose merchants are princes, whose traffickers are the honourable of the earth?","words":[["H3289","Who hath taken this counsel",0,27],["H6865","against Tyre",28,40],["H5849","the crowning",42,54],["H5503","city, whose merchants",55,76],["H8269","are princes",77,88],["H3667","whose traffickers",90,107],["H3513","are the honourable",108,126],["H0776","of the earth",127,139]]},"23:9":{"text":"The LORD of hosts hath purposed it, to stain the pride of all glory, and to bring into contempt all the honourable of the earth.","words":[["H3068","The LORD",0,8],["H6635","of hosts",9,17],["H3289","hath purposed",18,31],["H2490","it, to stain",32,44],["H1347","the pride",45,54],["H6643","of all glory",55,67],["H7043","and to bring into contempt",69,95],["H3513","all the honourable",96,114],["H0776","of the earth",115,127]]},"23:10":{"text":"Pass through thy land as a river, O daughter of Tarshish: there is no more strength.","words":[["H5674","Pass",0,4],["H0776","through thy land",5,21],["H2975","as a river",22,32],["H1323","O daughter",34,44],["H8659","of Tarshish",45,56],["H4206","there is no more strength",58,83]]},"23:11":{"text":"He stretched out his hand over the sea, he shook the kingdoms: the LORD hath given a commandment against the merchant city, to destroy the strong holds thereof.","words":[["H5186","He stretched out",0,16],["H3027","his hand",17,25],["H3220","over the sea",26,38],["H7264","he shook",40,48],["H4467","the kingdoms",49,61],["H3068","the LORD",63,71],["H6680","hath given a commandment",72,96],["H3667","against the merchant",97,117],["H8045","city, to destroy",118,134],["H4581","the strong",135,145],["H4581","holds",146,151]]},"23:12":{"text":"And he said, Thou shalt no more rejoice, O thou oppressed virgin, daughter of Zidon: arise, pass over to Chittim; there also shalt thou have no rest.","words":[["H0559","And he said",0,11],["H3254","Thou shalt no more",13,31],["H5937","rejoice",32,39],["H6231","O thou oppressed",41,57],["H1330","virgin",58,64],["H1323","daughter",66,74],["H6721","of Zidon",75,83],["H6965","arise",85,90],["H5674","pass over",92,101],["H3794","to Chittim",102,112],["H5117","there also shalt thou have no rest",114,148]]},"23:13":{"text":"Behold the land of the Chaldeans; this people was not, till the Assyrian founded it for them that dwell in the wilderness: they set up the towers thereof, they raised up the palaces thereof; and he brought it to ruin.","words":[["H0776","Behold the land",0,15],["H3778","of the Chaldeans",16,32],["H5971","this people",34,45],["H0804","was not, till the Assyrian",46,72],["H3245","founded",73,80],["H6728","it for them that dwell in the wilderness",81,121],["H6965","they set up",123,134],["H0971","the towers",135,145],["H6209","thereof, they raised up",146,169],["H0759","the palaces",170,181],["H7760","thereof; and he brought",182,205],["H4654","it to ruin",206,216]]},"23:14":{"text":"Howl, ye ships of Tarshish: for your strength is laid waste.","words":[["H3213","Howl",0,4],["H0591","ye ships",6,14],["H8659","of Tarshish",15,26],["H4581","for your strength",28,45],["H7703","is laid waste",46,59]]},"23:15":{"text":"And it shall come to pass in that day, that Tyre shall be forgotten seventy years, according to the days of one king: after the end of seventy years shall Tyre sing as an harlot.","words":[["H3117","And it shall come to pass in that day",0,37],["H6865","that Tyre",39,48],["H7911","shall be forgotten",49,67],["H7657","seventy",68,75],["H8141","years",76,81],["H3117","according to the days",83,104],["H0259","of one",105,111],["H4428","king",112,116],["H7093","after the end",118,131],["H7657","of seventy",132,142],["H8141","years",143,148],["H6865","shall Tyre",149,159],["H7892","sing",160,164],["H2181","as an harlot",165,177]]},"23:16":{"text":"Take an harp, go about the city, thou harlot that hast been forgotten; make sweet melody, sing many songs, that thou mayest be remembered.","words":[["H3947","Take",0,4],["H3658","an harp",5,12],["H5437","go about",14,22],["H5892","the city",23,31],["H2181","thou harlot",33,44],["H7911","that hast been forgotten",45,69],["H3190","make sweet",71,81],["H5059","melody",82,88],["H7235","sing many",90,99],["H7892","songs",100,105],["H2142","that thou mayest be remembered",107,137]]},"23:17":{"text":"And it shall come to pass after the end of seventy years, that the LORD will visit Tyre, and she shall turn to her hire, and shall commit fornication with all the kingdoms of the world upon the face of the earth.","words":[["H7093","And it shall come to pass after the end",0,39],["H7657","of seventy",40,50],["H8141","years",51,56],["H3068","that the LORD",58,71],["H6485","will visit",72,82],["H6865","Tyre",83,87],["H7725","and she shall turn",89,107],["H0868","to her hire",108,119],["H2181","and shall commit fornication",121,149],["H4467","with all the kingdoms",150,171],["H0776","of the world",172,184],["H6440","upon the face",185,198],["H0127","of the earth",199,211]]},"23:18":{"text":"And her merchandise and her hire shall be holiness to the LORD: it shall not be treasured nor laid up; for her merchandise shall be for them that dwell before the LORD, to eat sufficiently, and for durable clothing.","words":[["H5504","And her merchandise",0,19],["H0868","and her hire",20,32],["H6944","shall be holiness",33,50],["H3068","to the LORD",51,62],["H0686","it shall not be treasured",64,89],["H2630","nor laid up",90,101],["H5504","for her merchandise",103,122],["H3427","shall be for them that dwell",123,151],["H6440","before",152,158],["H3068","the LORD",159,167],["H0398","to eat",169,175],["H7654","sufficiently",176,188],["H6266","and for durable",190,205],["H4374","clothing",206,214]]},"24:1":{"text":"Behold, the LORD maketh the earth empty, and maketh it waste, and turneth it upside down, and scattereth abroad the inhabitants thereof.","words":[["H3068","Behold, the LORD",0,16],["H0776","maketh the earth",17,33],["H1238","empty",34,39],["H1110","and maketh it waste",41,60],["H5753","and turneth",62,73],["H6440","it upside down",74,88],["H6327","and scattereth abroad",90,111],["H3427","the inhabitants",112,127]]},"24:2":{"text":"And it shall be, as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the lender, so with the borrower; as with the taker of usury, so with the giver of usury to him.","words":[["H5971","And it shall be, as with the people",0,35],["H3548","so with the priest",37,55],["H5650","as with the servant",57,76],["H0113","so with his master",78,96],["H8198","as with the maid",98,114],["H1404","so with her mistress",116,136],["H7069","as with the buyer",138,155],["H4376","so with the seller",157,175],["H3867","as with the lender",177,195],["H3867","so with the borrower",197,217],["H5383","as with the taker of usury",219,245],["H0834","so",247,249],["H5378","with the giver of usury",250,273]]},"24:3":{"text":"The land shall be utterly emptied, and utterly spoiled: for the LORD hath spoken this word.","words":[["H0776","The land",0,8],["H1238","shall be utterly",9,25],["H1238","emptied",26,33],["H0962","and utterly",35,46],["H0962","spoiled",47,54],["H3068","for the LORD",56,68],["H1696","hath spoken",69,80],["H1697","this word",81,90]]},"24:4":{"text":"The earth mourneth and fadeth away, the world languisheth and fadeth away, the haughty people of the earth do languish.","words":[["H0776","The earth",0,9],["H0056","mourneth",10,18],["H5034","and fadeth away",19,34],["H8398","the world",36,45],["H0535","languisheth",46,57],["H5034","and fadeth away",58,73],["H4791","the haughty",75,86],["H5971","people",87,93],["H0776","of the earth",94,106],["H0535","do languish",107,118]]},"24:5":{"text":"The earth also is defiled under the inhabitants thereof; because they have transgressed the laws, changed the ordinance, broken the everlasting covenant.","words":[["H0776","The earth",0,9],["H2610","also is defiled",10,25],["H3427","under the inhabitants",26,47],["H5674","thereof; because they have transgressed",48,87],["H8451","the laws",88,96],["H2498","changed",98,105],["H2706","the ordinance",106,119],["H6565","broken",121,127],["H5769","the everlasting",128,143],["H1285","covenant",144,152]]},"24:6":{"text":"Therefore hath the curse devoured the earth, and they that dwell therein are desolate: therefore the inhabitants of the earth are burned, and few men left.","words":[["H0423","Therefore hath the curse",0,24],["H0398","devoured",25,33],["H0776","the earth",34,43],["H3427","and they that dwell",45,64],["H0816","therein are desolate",65,85],["H3427","therefore the inhabitants",87,112],["H0776","of the earth",113,125],["H2787","are burned",126,136],["H4213","and few",138,145],["H0582","men",146,149],["H7604","left",150,154]]},"24:7":{"text":"The new wine mourneth, the vine languisheth, all the merryhearted do sigh.","words":[["H8492","The new wine",0,12],["H0056","mourneth",13,21],["H1612","the vine",23,31],["H0535","languisheth",32,43],["H8056","all the merryhearted",45,65],["H3820","all the merryhearted",45,65],["H0584","do sigh",66,73]]},"24:8":{"text":"The mirth of tabrets ceaseth, the noise of them that rejoice endeth, the joy of the harp ceaseth.","words":[["H4885","The mirth",0,9],["H8596","of tabrets",10,20],["H7673","ceaseth",21,28],["H7588","the noise",30,39],["H5947","of them that rejoice",40,60],["H2308","endeth",61,67],["H4885","the joy",69,76],["H3658","of the harp",77,88],["H7673","ceaseth",89,96]]},"24:9":{"text":"They shall not drink wine with a song; strong drink shall be bitter to them that drink it.","words":[["H8354","They shall not drink",0,20],["H3196","wine",21,25],["H7892","with a song",26,37],["H7941","strong drink",39,51],["H4843","shall be bitter",52,67],["H8354","to them that drink",68,86]]},"24:10":{"text":"The city of confusion is broken down: every house is shut up, that no man may come in.","words":[["H7151","The city",0,8],["H8414","of confusion",9,21],["H7665","is broken down",22,36],["H1004","every house",38,49],["H5462","is shut up",50,60],["H0935","that no man may come in",62,85]]},"24:11":{"text":"There is a crying for wine in the streets; all joy is darkened, the mirth of the land is gone.","words":[["H6682","There is a crying",0,17],["H3196","for wine",18,26],["H2351","in the streets",27,41],["H8057","all joy",43,50],["H6150","is darkened",51,62],["H4885","the mirth",64,73],["H0776","of the land",74,85],["H1540","is gone",86,93]]},"24:12":{"text":"In the city is left desolation, and the gate is smitten with destruction.","words":[["H5892","In the city",0,11],["H7604","is left",12,19],["H8047","desolation",20,30],["H8179","and the gate",32,44],["H3807","is smitten",45,55],["H7591","with destruction",56,72]]},"24:13":{"text":"When thus it shall be in the midst of the land among the people, there shall be as the shaking of an olive tree, and as the gleaning grapes when the vintage is done.","words":[["H7130","When thus it shall be in the midst",0,34],["H0776","of the land",35,46],["H8432","among",47,52],["H5971","the people",53,63],["H5363","there shall be as the shaking",65,94],["H2132","of an olive tree",95,111],["H5955","and as the gleaning grapes",113,139],["H1210","when the vintage",140,156],["H3615","is done",157,164]]},"24:14":{"text":"They shall lift up their voice, they shall sing for the majesty of the LORD, they shall cry aloud from the sea.","words":[["H5375","They shall lift up",0,18],["H6963","their voice",19,30],["H7442","they shall sing",32,47],["H1347","for the majesty",48,63],["H3068","of the LORD",64,75],["H6670","they shall cry aloud",77,97],["H3220","from the sea",98,110]]},"24:15":{"text":"Wherefore glorify ye the LORD in the fires, even the name of the LORD God of Israel in the isles of the sea.","words":[["H3513","Wherefore glorify",0,17],["H3068","ye the LORD",18,29],["H0217","in the fires",30,42],["H8034","even the name",44,57],["H3068","of the LORD",58,69],["H0430","God",70,73],["H3478","of Israel",74,83],["H0339","in the isles",84,96],["H3220","of the sea",97,107]]},"24:16":{"text":"From the uttermost part of the earth have we heard songs, even glory to the righteous. But I said, My leanness, my leanness, woe unto me! the treacherous dealers have dealt treacherously; yea, the treacherous dealers have dealt very treacherously.","words":[["H3671","From the uttermost part",0,23],["H0776","of the earth",24,36],["H8085","have we heard",37,50],["H2158","songs",51,56],["H6643","even glory",58,68],["H6662","to the righteous",69,85],["H0559","But I said",87,97],["H7334","My leanness",99,110],["H7334","my leanness",112,123],["H0188","woe",125,128],["H0898","unto me! the treacherous dealers",129,161],["H0898","have dealt treacherously",162,186],["H0898","yea, the treacherous dealers",188,216],["H0899","have dealt very",217,232],["H0898","treacherously",233,246]]},"24:17":{"text":"Fear, and the pit, and the snare, are upon thee, O inhabitant of the earth.","words":[["H6343","Fear",0,4],["H6354","and the pit",6,17],["H6341","and the snare",19,32],["H3427","are upon thee, O inhabitant",34,61],["H0776","of the earth",62,74]]},"24:18":{"text":"And it shall come to pass, that he who fleeth from the noise of the fear shall fall into the pit; and he that cometh up out of the midst of the pit shall be taken in the snare: for the windows from on high are open, and the foundations of the earth do shake.","words":[["H5127","And it shall come to pass, that he who fleeth",0,45],["H6963","from the noise",46,60],["H6343","of the fear",61,72],["H5307","shall fall",73,83],["H6354","into the pit",84,96],["H5927","and he that cometh up",98,119],["H8432","out of the midst",120,136],["H6354","of the pit",137,147],["H3920","shall be taken",148,162],["H6341","in the snare",163,175],["H0699","for the windows",177,192],["H4791","from on high",193,205],["H6605","are open",206,214],["H4146","and the foundations",216,235],["H0776","of the earth",236,248],["H7493","do shake",249,257]]},"24:19":{"text":"The earth is utterly broken down, the earth is clean dissolved, the earth is moved exceedingly.","words":[["H0776","The earth",0,9],["H7489","is utterly",10,20],["H7489","broken down",21,32],["H0776","the earth",34,43],["H6565","is clean",44,52],["H6565","dissolved",53,62],["H0776","the earth",64,73],["H4131","is moved",74,82],["H4131","exceedingly",83,94]]},"24:20":{"text":"The earth shall reel to and fro like a drunkard, and shall be removed like a cottage; and the transgression thereof shall be heavy upon it; and it shall fall, and not rise again.","words":[["H0776","The earth",0,9],["H5128","shall reel",10,20],["H5128","to and fro",21,31],["H7910","like a drunkard",32,47],["H5110","and shall be removed",49,69],["H4412","like a cottage",70,84],["H6588","and the transgression",86,107],["H3513","thereof shall be heavy",108,130],["H5307","upon it; and it shall fall",131,157],["H6965","and not rise",159,171],["H3254","again",172,177]]},"24:21":{"text":"And it shall come to pass in that day, that the LORD shall punish the host of the high ones that are on high, and the kings of the earth upon the earth.","words":[["H3117","And it shall come to pass in that day",0,37],["H3068","that the LORD",39,52],["H6485","shall punish",53,65],["H6635","the host",66,74],["H4791","of the high ones",75,91],["H4791","that are on high",92,108],["H4428","and the kings",110,123],["H0127","of the earth",124,136],["H0127","upon the earth",137,151]]},"24:22":{"text":"And they shall be gathered together, as prisoners are gathered in the pit, and shall be shut up in the prison, and after many days shall they be visited.","words":[["H0622","And they shall be gathered together",0,35],["H0616","as prisoners",37,49],["H0626","are gathered",50,62],["H0953","in the pit",63,73],["H5462","and shall be shut up",75,95],["H4525","in the prison",96,109],["H7230","and after many",111,125],["H3117","days",126,130],["H6485","shall they be visited",131,152]]},"24:23":{"text":"Then the moon shall be confounded, and the sun ashamed, when the LORD of hosts shall reign in mount Zion, and in Jerusalem, and before his ancients gloriously.","words":[["H3842","Then the moon",0,13],["H2659","shall be confounded",14,33],["H2535","and the sun",35,46],["H0954","ashamed",47,54],["H3068","when the LORD",56,69],["H6635","of hosts",70,78],["H4427","shall reign",79,90],["H2022","in mount",91,99],["H6726","Zion",100,104],["H3389","and in Jerusalem",106,122],["H2205","and before his ancients",124,147],["H3519","gloriously",148,158]]},"25:1":{"text":"O LORD, thou art my God; I will exalt thee, I will praise thy name; for thou hast done wonderful things; thy counsels of old are faithfulness and truth.","words":[["H3068","O LORD",0,6],["H0430","thou art my God",8,23],["H7311","I will exalt",25,37],["H3034","thee, I will praise",38,57],["H8034","thy name",58,66],["H6213","for thou hast done",68,86],["H6382","wonderful",87,96],["H6098","things; thy counsels",97,117],["H7350","of old",118,124],["H0530","are faithfulness",125,141],["H0544","and truth",142,151]]},"25:2":{"text":"For thou hast made of a city an heap; of a defenced city a ruin: a palace of strangers to be no city; it shall never be built.","words":[["H7760","For thou hast made",0,18],["H5892","of a city",19,28],["H1530","an heap",29,36],["H1219","of a defenced",38,51],["H7151","city",52,56],["H4654","a ruin",57,63],["H0759","a palace",65,73],["H2114","of strangers",74,86],["H5892","to be no city",87,100],["H5769","it shall never",102,116],["H1129","be built",117,125]]},"25:3":{"text":"Therefore shall the strong people glorify thee, the city of the terrible nations shall fear thee.","words":[["H5794","Therefore shall the strong",0,26],["H5971","people",27,33],["H3513","glorify",34,41],["H7151","thee, the city",42,56],["H6184","of the terrible",57,72],["H1471","nations",73,80],["H3372","shall fear",81,91]]},"25:4":{"text":"For thou hast been a strength to the poor, a strength to the needy in his distress, a refuge from the storm, a shadow from the heat, when the blast of the terrible ones is as a storm against the wall.","words":[["H4581","For thou hast been a strength",0,29],["H1800","to the poor",30,41],["H4581","a strength",43,53],["H0034","to the needy",54,66],["H6862","in his distress",67,82],["H4268","a refuge",84,92],["H2230","from the storm",93,107],["H6738","a shadow",109,117],["H2721","from the heat",118,131],["H7307","when the blast",133,147],["H6184","of the terrible ones",148,168],["H2230","is as a storm",169,182],["H7023","against the wall",183,199]]},"25:5":{"text":"Thou shalt bring down the noise of strangers, as the heat in a dry place; even the heat with the shadow of a cloud: the branch of the terrible ones shall be brought low.","words":[["H3665","Thou shalt bring down",0,21],["H7588","the noise",22,31],["H2114","of strangers",32,44],["H2721","as the heat",46,57],["H6724","in a dry place",58,72],["H2721","even the heat",74,87],["H6738","with the shadow",88,103],["H5645","of a cloud",104,114],["H2159","the branch",116,126],["H6184","of the terrible ones",127,147],["H6030","shall be brought low",148,168]]},"25:6":{"text":"And in this mountain shall the LORD of hosts make unto all people a feast of fat things, a feast of wines on the lees, of fat things full of marrow, of wines on the lees well refined.","words":[["H2022","And in this mountain",0,20],["H3068","shall the LORD",21,35],["H6635","of hosts",36,44],["H6213","make",45,49],["H5971","unto all people",50,65],["H4960","a feast",66,73],["H8081","of fat things",74,87],["H4960","a feast",89,96],["H8105","of wines on the lees",97,117],["H8081","of fat things",119,132],["H4229","full of marrow",133,147],["H8105","of wines on the lees",149,169],["H2212","well refined",170,182]]},"25:7":{"text":"And he will destroy in this mountain the face of the covering cast over all people, and the vail that is spread over all nations.","words":[["H1104","And he will destroy",0,19],["H2022","in this mountain",20,36],["H6440","the face",37,45],["H3875","of the covering",46,61],["H3874","cast over",62,71],["H5971","all people",72,82],["H4541","and the vail",84,96],["H5259","that is spread",97,111],["H1471","over all nations",112,128]]},"25:8":{"text":"He will swallow up death in victory; and the Lord GOD will wipe away tears from off all faces; and the rebuke of his people shall he take away from off all the earth: for the LORD hath spoken it.","words":[["H1104","He will swallow up",0,18],["H4194","death",19,24],["H5331","in victory",25,35],["H0136","and the Lord",37,49],["H3069","GOD",50,53],["H4229","will wipe away",54,68],["H1832","tears",69,74],["H6440","from off all faces",75,93],["H2781","and the rebuke",95,109],["H5971","of his people",110,123],["H5493","shall he take away",124,142],["H0776","from off all the earth",143,165],["H3068","for the LORD",167,179],["H1696","hath spoken",180,191]]},"25:9":{"text":"And it shall be said in that day, Lo, this is our God; we have waited for him, and he will save us: this is the LORD; we have waited for him, we will be glad and rejoice in his salvation.","words":[["H0559","And it shall be said",0,20],["H3117","in that day",21,32],["H0430","Lo, this is our God",34,53],["H6960","we have waited",55,69],["H3467","for him, and he will save",70,95],["H3068","us: this is the LORD",96,116],["H6960","we have waited",118,132],["H1523","for him, we will be glad",133,157],["H8055","and rejoice",158,169],["H3444","in his salvation",170,186]]},"25:10":{"text":"For in this mountain shall the hand of the LORD rest, and Moab shall be trodden down under him, even as straw is trodden down for the dunghill.","words":[["H2022","For in this mountain",0,20],["H3027","shall the hand",21,35],["H3068","of the LORD",36,47],["H5117","rest",48,52],["H4124","and Moab",54,62],["H1758","shall be trodden down",63,84],["H4963","under him, even as straw",85,109],["H1758","is trodden down",110,125],["H1119","for the dunghill",126,142],["H4087","for the dunghill",126,142],["H4325","for the dunghill",126,142]]},"25:11":{"text":"And he shall spread forth his hands in the midst of them, as he that swimmeth spreadeth forth his hands to swim: and he shall bring down their pride together with the spoils of their hands.","words":[["H6566","And he shall spread forth",0,25],["H3027","his hands",26,35],["H7130","in the midst",36,48],["H7811","of them, as he that swimmeth",49,77],["H6566","spreadeth forth",78,93],["H7811","his hands to swim",94,111],["H8213","and he shall bring down",113,136],["H1346","their pride",137,148],["H0698","together with the spoils",149,173],["H3027","of their hands",174,188]]},"25:12":{"text":"And the fortress of the high fort of thy walls shall he bring down, lay low, and bring to the ground, even to the dust.","words":[["H4013","And the fortress",0,16],["H4869","of the high fort",17,33],["H2346","of thy walls",34,46],["H7817","shall he bring down",47,66],["H8213","lay low",68,75],["H5060","and bring",77,86],["H0776","to the ground",87,100],["H6083","even to the dust",102,118]]},"26:1":{"text":"In that day shall this song be sung in the land of Judah; We have a strong city; salvation will God appoint for walls and bulwarks.","words":[["H3117","In that day",0,11],["H7892","shall this song",12,27],["H7891","be sung",28,35],["H0776","in the land",36,47],["H3063","of Judah",48,56],["H5797","We have a strong",58,74],["H5892","city",75,79],["H3444","salvation",81,90],["H7896","will God appoint",91,107],["H2346","for walls",108,117],["H2426","and bulwarks",118,130]]},"26:2":{"text":"Open ye the gates, that the righteous nation which keepeth the truth may enter in.","words":[["H6605","Open",0,4],["H8179","ye the gates",5,17],["H6662","that the righteous",19,37],["H1471","nation",38,44],["H8104","which keepeth",45,58],["H0529","the truth",59,68],["H0935","may enter in",69,81]]},"26:3":{"text":"Thou wilt keep him in perfect peace, whose mind is stayed on thee: because he trusteth in thee.","words":[["H5341","Thou wilt keep",0,14],["H7965","him in perfect",15,29],["H7965","peace",30,35],["H3336","whose mind",37,47],["H5564","is stayed",48,57],["H0982","on thee: because he trusteth",58,86]]},"26:4":{"text":"Trust ye in the LORD for ever: for in the LORD JEHOVAH is everlasting strength:","words":[["H0982","Trust",0,5],["H3068","ye in the LORD",6,20],["H5703","for ever",21,29],["H3050","for in the LORD",31,46],["H3068","JEHOVAH",47,54],["H5769","is everlasting",55,69],["H6697","strength",70,78]]},"26:5":{"text":"For he bringeth down them that dwell on high; the lofty city, he layeth it low; he layeth it low, even to the ground; he bringeth it even to the dust.","words":[["H7817","For he bringeth down",0,20],["H3427","them that dwell",21,36],["H4791","on high",37,44],["H7682","the lofty",46,55],["H7151","city",56,60],["H8213","he layeth it low",62,78],["H8213","he layeth it low",80,96],["H0776","even to the ground",98,116],["H5060","he bringeth",118,129],["H6083","it even to the dust",130,149]]},"26:6":{"text":"The foot shall tread it down, even the feet of the poor, and the steps of the needy.","words":[["H7272","The foot",0,8],["H7429","shall tread it down",9,28],["H7272","even the feet",30,43],["H6041","of the poor",44,55],["H6471","and the steps",57,70],["H1800","of the needy",71,83]]},"26:7":{"text":"The way of the just is uprightness: thou, most upright, dost weigh the path of the just.","words":[["H0734","The way",0,7],["H6662","of the just",8,19],["H4339","is uprightness",20,34],["H3477","thou, most upright",36,54],["H6424","dost weigh",56,66],["H4570","the path",67,75],["H6662","of the just",76,87]]},"26:8":{"text":"Yea, in the way of thy judgments, O LORD, have we waited for thee; the desire of our soul is to thy name, and to the remembrance of thee.","words":[["H0734","Yea, in the way",0,15],["H4941","of thy judgments",16,32],["H3068","O LORD",34,40],["H6960","have we waited",42,56],["H8378","for thee; the desire",57,77],["H5315","of our soul",78,89],["H8034","is to thy name",90,104],["H2143","and to the remembrance",106,128]]},"26:9":{"text":"With my soul have I desired thee in the night; yea, with my spirit within me will I seek thee early: for when thy judgments are in the earth, the inhabitants of the world will learn righteousness.","words":[["H5315","With my soul",0,12],["H0183","have I desired",13,27],["H3915","thee in the night",28,45],["H7307","yea, with my spirit",47,66],["H7130","within",67,73],["H7836","me will I seek thee early",74,99],["H4941","for when thy judgments",101,123],["H0776","are in the earth",124,140],["H3427","the inhabitants",142,157],["H8398","of the world",158,170],["H3925","will learn",171,181],["H6664","righteousness",182,195]]},"26:10":{"text":"Let favour be shewed to the wicked, yet will he not learn righteousness: in the land of uprightness will he deal unjustly, and will not behold the majesty of the LORD.","words":[["H2603","Let favour be shewed",0,20],["H7563","to the wicked",21,34],["H1077","yet will he not",36,51],["H3925","learn",52,57],["H6664","righteousness",58,71],["H0776","in the land",73,84],["H5229","of uprightness",85,99],["H5765","will he deal unjustly",100,121],["H1077","and will not",123,135],["H7200","behold",136,142],["H1348","the majesty",143,154],["H3068","of the LORD",155,166]]},"26:11":{"text":"LORD, when thy hand is lifted up, they will not see: but they shall see, and be ashamed for their envy at the people; yea, the fire of thine enemies shall devour them.","words":[["H3068","LORD",0,4],["H3027","when thy hand",6,19],["H7311","is lifted up",20,32],["H2372","they will not see",34,51],["H2372","but they shall see",53,71],["H0954","and be ashamed",73,87],["H7068","for their envy",88,102],["H5971","at the people",103,116],["H0784","yea, the fire",118,131],["H6862","of thine enemies",132,148],["H0398","shall devour",149,161]]},"26:12":{"text":"LORD, thou wilt ordain peace for us: for thou also hast wrought all our works in us.","words":[["H3068","LORD",0,4],["H8239","thou wilt ordain",6,22],["H7965","peace",23,28],["H6466","for us: for thou also hast wrought",29,63],["H4639","all our works",64,77]]},"26:13":{"text":"O LORD our God, other lords beside thee have had dominion over us: but by thee only will we make mention of thy name.","words":[["H3068","O LORD",0,6],["H0430","our God",7,14],["H0113","other lords",16,27],["H2108","beside",28,34],["H1166","thee have had dominion",35,57],["H2142","over us: but by thee only will we make mention",58,104],["H8034","of thy name",105,116]]},"26:14":{"text":"They are dead, they shall not live; they are deceased, they shall not rise: therefore hast thou visited and destroyed them, and made all their memory to perish.","words":[["H4191","They are dead",0,13],["H2421","they shall not live",15,34],["H7496","they are deceased",36,53],["H6965","they shall not rise",55,74],["H6485","therefore hast thou visited",76,103],["H8045","and destroyed",104,117],["H2143","them, and made all their memory",118,149],["H0006","to perish",150,159]]},"26:15":{"text":"Thou hast increased the nation, O LORD, thou hast increased the nation: thou art glorified: thou hadst removed it far unto all the ends of the earth.","words":[["H3254","Thou hast increased",0,19],["H1471","the nation",20,30],["H3068","O LORD",32,38],["H3254","thou hast increased",40,59],["H1471","the nation",60,70],["H3513","thou art glorified",72,90],["H7368","thou hadst removed it far",92,117],["H7099","unto all the ends",118,135],["H0776","of the earth",136,148]]},"26:16":{"text":"LORD, in trouble have they visited thee, they poured out a prayer when thy chastening was upon them.","words":[["H3068","LORD",0,4],["H6862","in trouble",6,16],["H6485","have they visited",17,34],["H6694","thee, they poured out",35,56],["H3908","a prayer",57,65],["H4148","when thy chastening",66,85]]},"26:17":{"text":"Like as a woman with child, that draweth near the time of her delivery, is in pain, and crieth out in her pangs; so have we been in thy sight, O LORD.","words":[["H3644","Like",0,4],["H2030","as a woman with child",5,26],["H7126","that draweth near",28,45],["H3205","the time of her delivery",46,70],["H2342","is in pain",72,82],["H2199","and crieth out",84,98],["H2256","in her pangs",99,111],["H6440","so have we been in thy sight",113,141],["H3068","O LORD",143,149]]},"26:18":{"text":"We have been with child, we have been in pain, we have as it were brought forth wind; we have not wrought any deliverance in the earth; neither have the inhabitants of the world fallen.","words":[["H2029","We have been with child",0,23],["H2342","we have been in pain",25,45],["H3644","we have as it were",47,65],["H3205","brought forth",66,79],["H7307","wind",80,84],["H6213","we have not wrought",86,105],["H3444","any deliverance",106,121],["H0776","in the earth",122,134],["H1077","neither",136,143],["H3427","have the inhabitants",144,164],["H8398","of the world",165,177],["H5307","fallen",178,184]]},"26:19":{"text":"Thy dead men shall live, together with my dead body shall they arise. Awake and sing, ye that dwell in dust: for thy dew is as the dew of herbs, and the earth shall cast out the dead.","words":[["H4191","Thy dead",0,8],["H2421","men shall live",9,23],["H5038","together with my dead body",25,51],["H6965","shall they arise",52,68],["H6974","Awake",70,75],["H7442","and sing",76,84],["H7931","ye that dwell",86,99],["H6083","in dust",100,107],["H2919","for thy dew",109,120],["H2919","is as the dew",121,134],["H0219","of herbs",135,143],["H0776","and the earth",145,158],["H5307","shall cast out",159,173],["H7496","the dead",174,182]]},"26:20":{"text":"Come, my people, enter thou into thy chambers, and shut thy doors about thee: hide thyself as it were for a little moment, until the indignation be overpast.","words":[["H3212","Come",0,4],["H5971","my people",6,15],["H0935","enter",17,22],["H2315","thou into thy chambers",23,45],["H5462","and shut",47,55],["H1817","thy doors",56,65],["H2247","about thee: hide",66,82],["H4592","thyself as it were for a little",83,114],["H7281","moment",115,121],["H2195","until the indignation",123,144],["H5674","be overpast",145,156]]},"26:21":{"text":"For, behold, the LORD cometh out of his place to punish the inhabitants of the earth for their iniquity: the earth also shall disclose her blood, and shall no more cover her slain.","words":[["H3068","For, behold, the LORD",0,21],["H3318","cometh out",22,32],["H4725","of his place",33,45],["H6485","to punish",46,55],["H3427","the inhabitants",56,71],["H0776","of the earth",72,84],["H5771","for their iniquity",85,103],["H0776","the earth",105,114],["H1540","also shall disclose",115,134],["H1818","her blood",135,144],["H3680","and shall no more cover",146,169],["H2026","her slain",170,179]]},"27:1":{"text":"In that day the LORD with his sore and great and strong sword shall punish leviathan the piercing serpent, even leviathan that crooked serpent; and he shall slay the dragon that is in the sea.","words":[["H3117","In that day",0,11],["H3068","the LORD",12,20],["H7186","with his sore",21,34],["H1419","and great",35,44],["H2389","and strong",45,55],["H2719","sword",56,61],["H6485","shall punish",62,74],["H3882","leviathan",75,84],["H1281","the piercing",85,97],["H5175","serpent",98,105],["H3882","even leviathan",107,121],["H6129","that crooked",122,134],["H5175","serpent",135,142],["H2026","and he shall slay",144,161],["H8577","the dragon",162,172],["H3220","that is in the sea",173,191]]},"27:2":{"text":"In that day sing ye unto her, A vineyard of red wine.","words":[["H3117","In that day",0,11],["H6031","sing",12,16],["H3754","ye unto her, A vineyard",17,40],["H2561","of red wine",41,52],["H2531","of red wine",41,52]]},"27:3":{"text":"I the LORD do keep it; I will water it every moment: lest any hurt it, I will keep it night and day.","words":[["H3068","I the LORD",0,10],["H5341","do keep",11,18],["H8248","it; I will water",19,35],["H7281","it every moment",36,51],["H6485","lest any hurt",53,66],["H5341","it, I will keep",67,82],["H3915","it night",83,91],["H3117","and day",92,99]]},"27:4":{"text":"Fury is not in me: who would set the briers and thorns against me in battle? I would go through them, I would burn them together.","words":[["H2534","Fury",0,4],["H5414","is not in me: who would set",5,32],["H8068","the briers",33,43],["H7898","and thorns",44,54],["H4421","against me in battle",55,75],["H6585","I would go",77,87],["H6702","through them, I would burn",88,114],["H3162","them together",115,128]]},"27:5":{"text":"Or let him take hold of my strength, that he may make peace with me; and he shall make peace with me.","words":[["H2388","Or let him take hold",0,20],["H4581","of my strength",21,35],["H6213","that he may make",37,53],["H7965","peace",54,59],["H6213","with me; and he shall make",60,86],["H7965","peace",87,92]]},"27:6":{"text":"He shall cause them that come of Jacob to take root: Israel shall blossom and bud, and fill the face of the world with fruit.","words":[["H0935","He shall cause them that come",0,29],["H3290","of Jacob",30,38],["H8327","to take root",39,51],["H3478","Israel",53,59],["H6692","shall blossom",60,73],["H6524","and bud",74,81],["H4390","and fill",83,91],["H6440","the face",92,100],["H8398","of the world",101,113],["H8570","with fruit",114,124]]},"27:7":{"text":"Hath he smitten him, as he smote those that smote him? or is he slain according to the slaughter of them that are slain by him?","words":[["H5221","Hath he smitten",0,15],["H4347","him, as he smote",16,32],["H5221","those that smote",33,49],["H2026","him? or is he slain",50,69],["H2027","according to the slaughter",70,96],["H2026","of them that are slain",97,119]]},"27:8":{"text":"In measure, when it shooteth forth, thou wilt debate with it: he stayeth his rough wind in the day of the east wind.","words":[["H5432","In measure",0,10],["H7971","when it shooteth forth",12,34],["H7378","thou wilt debate",36,52],["H1898","with it: he stayeth",53,72],["H7186","his rough",73,82],["H7307","wind",83,87],["H3117","in the day",88,98],["H6921","of the east wind",99,115]]},"27:9":{"text":"By this therefore shall the iniquity of Jacob be purged; and this is all the fruit to take away his sin; when he maketh all the stones of the altar as chalkstones that are beaten in sunder, the groves and images shall not stand up.","words":[["H2063","By this",0,7],["H5771","therefore shall the iniquity",8,36],["H3290","of Jacob",37,45],["H3722","be purged",46,55],["H6529","and this is all the fruit",57,82],["H5493","to take away",83,95],["H2403","his sin",96,103],["H7760","when he maketh",105,119],["H0068","all the stones",120,134],["H4196","of the altar",135,147],["H1615","as chalkstones",148,162],["H5310","that are beaten in sunder",163,188],["H0842","the groves",190,200],["H2553","and images",201,211],["H6965","shall not stand up",212,230]]},"27:10":{"text":"Yet the defenced city shall be desolate, and the habitation forsaken, and left like a wilderness: there shall the calf feed, and there shall he lie down, and consume the branches thereof.","words":[["H1219","Yet the defenced",0,16],["H5892","city",17,21],["H0910","shall be desolate",22,39],["H5116","and the habitation",41,59],["H7971","forsaken",60,68],["H5800","and left",70,78],["H4057","like a wilderness",79,96],["H5695","there shall the calf",98,118],["H7462","feed",119,123],["H7257","and there shall he lie down",125,152],["H3615","and consume",154,165],["H5585","the branches",166,178]]},"27:11":{"text":"When the boughs thereof are withered, they shall be broken off: the women come, and set them on fire: for it is a people of no understanding: therefore he that made them will not have mercy on them, and he that formed them will shew them no favour.","words":[["H7105","When the boughs",0,15],["H3001","thereof are withered",16,36],["H7665","they shall be broken off",38,62],["H0802","the women",64,73],["H0935","come",74,78],["H0215","and set them on fire",80,100],["H5971","for it is a people",102,120],["H0998","of no understanding",121,140],["H6213","therefore he that made",142,164],["H7355","them will not have mercy",165,189],["H3335","on them, and he that formed",190,217],["H2603","them will shew them no favour",218,247]]},"27:12":{"text":"And it shall come to pass in that day, that the LORD shall beat off from the channel of the river unto the stream of Egypt, and ye shall be gathered one by one, O ye children of Israel.","words":[["H3117","And it shall come to pass in that day",0,37],["H3068","that the LORD",39,52],["H2251","shall beat off",53,67],["H7641","from the channel",68,84],["H5104","of the river",85,97],["H5158","unto the stream",98,113],["H4714","of Egypt",114,122],["H3950","and ye shall be gathered",124,148],["H0259","one",149,152],["H0259","by one",153,159],["H1121","O ye children",161,174],["H3478","of Israel",175,184]]},"27:13":{"text":"And it shall come to pass in that day, that the great trumpet shall be blown, and they shall come which were ready to perish in the land of Assyria, and the outcasts in the land of Egypt, and shall worship the LORD in the holy mount at Jerusalem.","words":[["H3117","And it shall come to pass in that day",0,37],["H1419","that the great",39,53],["H7782","trumpet",54,61],["H8628","shall be blown",62,76],["H0935","and they shall come",78,97],["H0006","which were ready to perish",98,124],["H0776","in the land",125,136],["H0804","of Assyria",137,147],["H5080","and the outcasts",149,165],["H0776","in the land",166,177],["H4714","of Egypt",178,186],["H7812","and shall worship",188,205],["H3068","the LORD",206,214],["H6944","in the holy",215,226],["H2022","mount",227,232],["H3389","at Jerusalem",233,245]]},"28:1":{"text":"Woe to the crown of pride, to the drunkards of Ephraim, whose glorious beauty is a fading flower, which are on the head of the fat valleys of them that are overcome with wine!","words":[["H1945","Woe",0,3],["H5850","to the crown",4,16],["H1348","of pride",17,25],["H7910","to the drunkards",27,43],["H0669","of Ephraim",44,54],["H6643","whose glorious",56,70],["H8597","beauty",71,77],["H5034","is a fading",78,89],["H6731","flower",90,96],["H7218","which are on the head",98,119],["H8081","of the fat",120,130],["H1516","valleys",131,138],["H1986","of them that are overcome",139,164],["H3196","with wine",165,174]]},"28:2":{"text":"Behold, the Lord hath a mighty and strong one, which as a tempest of hail and a destroying storm, as a flood of mighty waters overflowing, shall cast down to the earth with the hand.","words":[["H0136","Behold, the Lord",0,16],["H2389","hath a mighty",17,30],["H0533","and strong one",31,45],["H2230","which as a tempest",47,65],["H1259","of hail",66,73],["H6986","and a destroying",74,90],["H8178","storm",91,96],["H2230","as a flood",98,108],["H3524","of mighty",109,118],["H4325","waters",119,125],["H7857","overflowing",126,137],["H3240","shall cast down",139,154],["H0776","to the earth",155,167],["H3027","with the hand",168,181]]},"28:3":{"text":"The crown of pride, the drunkards of Ephraim, shall be trodden under feet:","words":[["H5850","The crown",0,9],["H1348","of pride",10,18],["H7910","the drunkards",20,33],["H0669","of Ephraim",34,44],["H7429","shall be trodden",46,62],["H7272","under feet",63,73]]},"28:4":{"text":"And the glorious beauty, which is on the head of the fat valley, shall be a fading flower, and as the hasty fruit before the summer; which when he that looketh upon it seeth, while it is yet in his hand he eateth it up.","words":[["H6643","And the glorious",0,16],["H8597","beauty",17,23],["H7218","which is on the head",25,45],["H8081","of the fat",46,56],["H1516","valley",57,63],["H5034","shall be a fading",65,82],["H6733","flower",83,89],["H1061","and as the hasty fruit",91,113],["H7019","before the summer",114,131],["H7200","which when he that looketh",133,159],["H7200","upon it seeth",160,173],["H3709","while it is yet in his hand",175,202],["H1104","he eateth it up",203,218]]},"28:5":{"text":"In that day shall the LORD of hosts be for a crown of glory, and for a diadem of beauty, unto the residue of his people,","words":[["H3117","In that day",0,11],["H3068","shall the LORD",12,26],["H6635","of hosts",27,35],["H5850","be for a crown",36,50],["H6643","of glory",51,59],["H6843","and for a diadem",61,77],["H8597","of beauty",78,87],["H7605","unto the residue",89,105],["H5971","of his people",106,119]]},"28:6":{"text":"And for a spirit of judgment to him that sitteth in judgment, and for strength to them that turn the battle to the gate.","words":[["H7307","And for a spirit",0,16],["H4941","of judgment",17,28],["H3427","to him that sitteth",29,48],["H4941","in judgment",49,60],["H1369","and for strength",62,78],["H7725","to them that turn",79,96],["H4421","the battle",97,107],["H8179","to the gate",108,119]]},"28:7":{"text":"But they also have erred through wine, and through strong drink are out of the way; the priest and the prophet have erred through strong drink, they are swallowed up of wine, they are out of the way through strong drink; they err in vision, they stumble in judgment.","words":[["H0428","But they",0,8],["H7686","also have erred",9,24],["H3196","through wine",25,37],["H7941","and through strong drink",39,63],["H8582","are out of the way",64,82],["H3548","the priest",84,94],["H5030","and the prophet",95,110],["H7686","have erred",111,121],["H7941","through strong drink",122,142],["H1104","they are swallowed up",144,165],["H4480","of",166,168],["H3196","wine",169,173],["H8582","they are out of the way",175,198],["H7941","through strong drink",199,219],["H7686","they err",221,229],["H7203","in vision",230,239],["H6328","they stumble",241,253],["H6417","in judgment",254,265]]},"28:8":{"text":"For all tables are full of vomit and filthiness, so that there is no place clean.","words":[["H7979","For all tables",0,14],["H4390","are full",15,23],["H6892","of vomit",24,32],["H6675","and filthiness",33,47],["H4725","so that there is no place",49,74]]},"28:9":{"text":"Whom shall he teach knowledge? and whom shall he make to understand doctrine? them that are weaned from the milk, and drawn from the breasts.","words":[["H3384","Whom shall he teach",0,19],["H1844","knowledge",20,29],["H0995","and whom shall he make to understand",31,67],["H8052","doctrine",68,76],["H1580","them that are weaned",78,98],["H2461","from the milk",99,112],["H6267","and drawn",114,123],["H7699","from the breasts",124,140]]},"28:10":{"text":"For precept must be upon precept, precept upon precept; line upon line, line upon line; here a little, and there a little:","words":[["H6673","For precept",0,11],["H6673","must be upon precept",12,32],["H6673","precept",34,41],["H6673","upon precept",42,54],["H6957","line",56,60],["H6957","upon line",61,70],["H6957","line",72,76],["H6957","upon line",77,86],["H2191","here a little",88,101],["H2191","and there a little",103,121]]},"28:11":{"text":"For with stammering lips and another tongue will he speak to this people.","words":[["H3934","For with stammering",0,19],["H8193","lips",20,24],["H0312","and another",25,36],["H3956","tongue",37,43],["H1696","will he speak",44,57],["H5971","to this people",58,72]]},"28:12":{"text":"To whom he said, This is the rest wherewith ye may cause the weary to rest; and this is the refreshing: yet they would not hear.","words":[["H0559","To whom he said",0,15],["H4496","This is the rest",17,33],["H5889","wherewith ye may cause the weary",34,66],["H5117","to rest",67,74],["H4774","and this is the refreshing",76,102],["H0014","yet they would",104,118],["H8085","not hear",119,127]]},"28:13":{"text":"But the word of the LORD was unto them precept upon precept, precept upon precept; line upon line, line upon line; here a little, and there a little; that they might go, and fall backward, and be broken, and snared, and taken.","words":[["H1697","But the word",0,12],["H3068","of the LORD",13,24],["H6673","was unto them precept",25,46],["H6673","upon precept",47,59],["H6673","precept",61,68],["H6673","upon precept",69,81],["H6957","line",83,87],["H6957","upon line",88,97],["H6957","line",99,103],["H6957","upon line",104,113],["H2191","here a little",115,128],["H2191","and there a little",130,148],["H3212","that they might go",150,168],["H3782","and fall",170,178],["H0268","backward",179,187],["H7665","and be broken",189,202],["H3369","and snared",204,214],["H3920","and taken",216,225]]},"28:14":{"text":"Wherefore hear the word of the LORD, ye scornful men, that rule this people which is in Jerusalem.","words":[["H8085","Wherefore hear",0,14],["H1697","the word",15,23],["H3068","of the LORD",24,35],["H3944","ye scornful",37,48],["H0582","men",49,52],["H4910","that rule",54,63],["H5971","this people",64,75],["H3389","which is in Jerusalem",76,97]]},"28:15":{"text":"Because ye have said, We have made a covenant with death, and with hell are we at agreement; when the overflowing scourge shall pass through, it shall not come unto us: for we have made lies our refuge, and under falsehood have we hid ourselves:","words":[["H0559","Because ye have said",0,20],["H3772","We have made",22,34],["H1285","a covenant",35,45],["H4194","with death",46,56],["H7585","and with hell",58,71],["H6213","are we",72,78],["H2374","at agreement",79,91],["H7857","when the overflowing",93,113],["H7752","scourge",114,121],["H7885","scourge",114,121],["H5674","shall pass through",122,140],["H5674","shall pass through",122,140],["H0935","it shall not come",142,159],["H7760","unto us: for we have made",160,185],["H3577","lies",186,190],["H4268","our refuge",191,201],["H8267","and under falsehood",203,222],["H5641","have we hid",223,234]]},"28:16":{"text":"Therefore thus saith the Lord GOD, Behold, I lay in Zion for a foundation a stone, a tried stone, a precious corner stone, a sure foundation: he that believeth shall not make haste.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H3245","Behold, I lay",35,48],["H6726","in Zion",49,56],["H0068","for a foundation a stone",57,81],["H0976","a tried",83,90],["H0068","stone",91,96],["H3368","a precious",98,108],["H6438","corner",109,115],["H3245","stone, a sure",116,129],["H4143","foundation",130,140],["H0539","he that believeth",142,159],["H2363","shall not make haste",160,180]]},"28:17":{"text":"Judgment also will I lay to the line, and righteousness to the plummet: and the hail shall sweep away the refuge of lies, and the waters shall overflow the hiding place.","words":[["H4941","Judgment",0,8],["H7760","also will I lay",9,24],["H6957","to the line",25,36],["H6666","and righteousness",38,55],["H4949","to the plummet",56,70],["H1259","and the hail",72,84],["H3261","shall sweep away",85,101],["H4268","the refuge",102,112],["H3577","of lies",113,120],["H4325","and the waters",122,136],["H7857","shall overflow",137,151],["H5643","the hiding place",152,168]]},"28:18":{"text":"And your covenant with death shall be disannulled, and your agreement with hell shall not stand; when the overflowing scourge shall pass through, then ye shall be trodden down by it.","words":[["H1285","And your covenant",0,17],["H4194","with death",18,28],["H3722","shall be disannulled",29,49],["H2380","and your agreement",51,69],["H7585","with hell",70,79],["H6965","shall not stand",80,95],["H7857","when the overflowing",97,117],["H7752","scourge",118,125],["H5674","shall pass through",126,144],["H4823","then ye shall be trodden down",146,175]]},"28:19":{"text":"From the time that it goeth forth it shall take you: for morning by morning shall it pass over, by day and by night: and it shall be a vexation only to understand the report.","words":[["H1767","From the time",0,13],["H5674","that it goeth forth",14,33],["H3947","it shall take",34,47],["H1242","you: for morning",48,64],["H1242","by morning",65,75],["H5674","shall it pass over",76,94],["H3117","by day",96,102],["H3915","and by night",103,115],["H2113","and it shall be a vexation",117,143],["H0995","only to understand",144,162],["H8052","the report",163,173]]},"28:20":{"text":"For the bed is shorter than that a man can stretch himself on it: and the covering narrower than that he can wrap himself in it.","words":[["H4702","For the bed",0,11],["H7114","is shorter",12,22],["H8311","than that a man can stretch",23,50],["H4541","himself on it: and the covering",51,82],["H6887","narrower",83,91],["H3664","than that he can wrap",92,113]]},"28:21":{"text":"For the LORD shall rise up as in mount Perazim, he shall be wroth as in the valley of Gibeon, that he may do his work, his strange work; and bring to pass his act, his strange act.","words":[["H3068","For the LORD",0,12],["H6965","shall rise up",13,26],["H2022","as in mount",27,38],["H6559","Perazim",39,46],["H7264","he shall be wroth",48,65],["H6010","as in the valley",66,82],["H1391","of Gibeon",83,92],["H6213","that he may do",94,108],["H4639","his work",109,117],["H2114","his strange",119,130],["H4639","work",131,135],["H5647","and bring to pass",137,154],["H5656","his act",155,162],["H5237","his strange",164,175],["H5656","act",176,179]]},"28:22":{"text":"Now therefore be ye not mockers, lest your bands be made strong: for I have heard from the Lord GOD of hosts a consumption, even determined upon the whole earth.","words":[["H3887","Now therefore be ye not mockers",0,31],["H4147","lest your bands",33,48],["H2388","be made strong",49,63],["H8085","for I have heard",65,81],["H0136","from the Lord",82,95],["H3069","GOD",96,99],["H6635","of hosts",100,108],["H3617","a consumption",109,122],["H2782","even determined",124,139],["H0776","upon the whole earth",140,160]]},"28:23":{"text":"Give ye ear, and hear my voice; hearken, and hear my speech.","words":[["H0238","Give ye ear",0,11],["H8085","and hear",13,21],["H6963","my voice",22,30],["H7181","hearken",32,39],["H8085","and hear",41,49],["H0565","my speech",50,59]]},"28:24":{"text":"Doth the plowman plow all day to sow? doth he open and break the clods of his ground?","words":[["H2790","Doth the plowman",0,16],["H2790","plow",17,21],["H3117","all day",22,29],["H2232","to sow",30,36],["H6605","doth he open",38,50],["H7702","and break the clods",51,70],["H0127","of his ground",71,84]]},"28:25":{"text":"When he hath made plain the face thereof, doth he not cast abroad the fitches, and scatter the cummin, and cast in the principal wheat and the appointed barley and the rie in their place?","words":[["H7737","When he hath made plain",0,23],["H6440","the face",24,32],["H6327","thereof, doth he not cast abroad",33,65],["H7100","the fitches",66,77],["H2236","and scatter",79,90],["H3646","the cummin",91,101],["H7760","and cast",103,111],["H7795","in the principal",112,128],["H2406","wheat",129,134],["H5567","and the appointed",135,152],["H8184","barley",153,159],["H3698","and the rie",160,171],["H1367","in their place",172,186]]},"28:26":{"text":"For his God doth instruct him to discretion, and doth teach him.","words":[["H0430","For his God",0,11],["H3256","doth instruct",12,25],["H4941","him to discretion",26,43],["H3384","and doth teach",45,59]]},"28:27":{"text":"For the fitches are not threshed with a threshing instrument, neither is a cart wheel turned about upon the cummin; but the fitches are beaten out with a staff, and the cummin with a rod.","words":[["H7100","For the fitches",0,15],["H1758","are not threshed",16,32],["H2742","with a threshing instrument",33,60],["H5699","neither is a cart",62,79],["H0212","wheel",80,85],["H5437","turned about",86,98],["H3646","upon the cummin",99,114],["H7100","but the fitches",116,131],["H2251","are beaten out",132,146],["H4294","with a staff",147,159],["H3646","and the cummin",161,175],["H7626","with a rod",176,186]]},"28:28":{"text":"Bread corn is bruised; because he will not ever be threshing it, nor break it with the wheel of his cart, nor bruise it with his horsemen.","words":[["H3899","Bread",0,5],["H1854","corn is bruised",6,21],["H5331","because he will not ever",23,47],["H0156","be threshing",48,60],["H1758","be threshing",48,60],["H2000","it, nor break",61,74],["H1536","it with the wheel",75,92],["H5699","of his cart",93,104],["H1854","nor bruise",106,116],["H6571","it with his horsemen",117,137]]},"28:29":{"text":"This also cometh forth from the LORD of hosts, which is wonderful in counsel, and excellent in working.","words":[["H3318","This also cometh forth",0,22],["H3068","from the LORD",23,36],["H6635","of hosts",37,45],["H6381","which is wonderful",47,65],["H6098","in counsel",66,76],["H1431","and excellent",78,91],["H8454","in working",92,102]]},"29:1":{"text":"Woe to Ariel, to Ariel, the city where David dwelt! add ye year to year; let them kill sacrifices.","words":[["H1945","Woe",0,3],["H0740","to Ariel",4,12],["H0740","to Ariel",14,22],["H7151","the city",24,32],["H1732","where David",33,44],["H2583","dwelt",45,50],["H5595","add",52,55],["H8141","ye year",56,63],["H8141","to year",64,71],["H5362","let them kill",73,86],["H2282","sacrifices",87,97]]},"29:2":{"text":"Yet I will distress Ariel, and there shall be heaviness and sorrow: and it shall be unto me as Ariel.","words":[["H6693","Yet I will distress",0,19],["H0740","Ariel",20,25],["H8386","and there shall be heaviness",27,55],["H0592","and sorrow",56,66],["H0740","and it shall be unto me as Ariel",68,100]]},"29:3":{"text":"And I will camp against thee round about, and will lay siege against thee with a mount, and I will raise forts against thee.","words":[["H2583","And I will camp",0,15],["H1754","against thee round about",16,40],["H6696","and will lay siege",42,60],["H4674","against thee with a mount",61,86],["H6965","and I will raise",88,104],["H4694","forts",105,110]]},"29:4":{"text":"And thou shalt be brought down, and shalt speak out of the ground, and thy speech shall be low out of the dust, and thy voice shall be, as of one that hath a familiar spirit, out of the ground, and thy speech shall whisper out of the dust.","words":[["H8213","And thou shalt be brought down",0,30],["H1696","and shalt speak",32,47],["H0776","out of the ground",48,65],["H0565","and thy speech",67,81],["H7817","shall be low",82,94],["H6083","out of the dust",95,110],["H6963","and thy voice",112,125],["H0178","shall be, as of one that hath a familiar spirit",126,173],["H0776","out of the ground",175,192],["H0565","and thy speech",194,208],["H6850","shall whisper",209,222],["H6083","out of the dust",223,238]]},"29:5":{"text":"Moreover the multitude of thy strangers shall be like small dust, and the multitude of the terrible ones shall be as chaff that passeth away: yea, it shall be at an instant suddenly.","words":[["H1995","Moreover the multitude",0,22],["H2114","of thy strangers",23,39],["H1851","shall be like small",40,59],["H0080","dust",60,64],["H1995","and the multitude",66,83],["H6184","of the terrible ones",84,104],["H4671","shall be as chaff",105,122],["H5674","that passeth away",123,140],["H6621","yea, it shall be at an instant",142,172],["H6597","suddenly",173,181]]},"29:6":{"text":"Thou shalt be visited of the LORD of hosts with thunder, and with earthquake, and great noise, with storm and tempest, and the flame of devouring fire.","words":[["H6485","Thou shalt be visited",0,21],["H3068","of the LORD",22,33],["H6635","of hosts",34,42],["H7482","with thunder",43,55],["H7494","and with earthquake",57,76],["H1419","and great",78,87],["H6963","noise",88,93],["H5492","with storm",95,105],["H5591","and tempest",106,117],["H3851","and the flame",119,132],["H0398","of devouring",133,145],["H0784","fire",146,150]]},"29:7":{"text":"And the multitude of all the nations that fight against Ariel, even all that fight against her and her munition, and that distress her, shall be as a dream of a night vision.","words":[["H1995","And the multitude",0,17],["H1471","of all the nations",18,36],["H6633","that fight",37,47],["H0740","against Ariel",48,61],["H6638","even all that fight",63,82],["H4685","against her and her munition",83,111],["H6693","and that distress",113,130],["H2472","her, shall be as a dream",131,155],["H3915","of a night",156,166],["H2377","vision",167,173]]},"29:8":{"text":"It shall even be as when an hungry man dreameth, and, behold, he eateth; but he awaketh, and his soul is empty: or as when a thirsty man dreameth, and, behold, he drinketh; but he awaketh, and, behold, he is faint, and his soul hath appetite: so shall the multitude of all the nations be, that fight against mount Zion.","words":[["H7457","It shall even be as when an hungry",0,34],["H2492","man dreameth",35,47],["H0398","and, behold, he eateth",49,71],["H6974","but he awaketh",73,87],["H5315","and his soul",89,101],["H7386","is empty",102,110],["H0834","or as when",112,122],["H6771","a thirsty man",123,136],["H2492","dreameth",137,145],["H8354","and, behold, he drinketh",147,171],["H6974","but he awaketh",173,187],["H5889","and, behold, he is faint",189,213],["H5315","and his soul",215,227],["H8264","hath appetite",228,241],["H1995","so shall the multitude",243,265],["H1471","of all the nations",266,284],["H6633","be, that fight",285,299],["H2022","against mount",300,313],["H6726","Zion",314,318]]},"29:9":{"text":"Stay yourselves, and wonder; cry ye out, and cry: they are drunken, but not with wine; they stagger, but not with strong drink.","words":[["H4102","Stay",0,4],["H8539","yourselves, and wonder",5,27],["H8173","cry ye out",29,39],["H8173","and cry",41,48],["H7937","they are drunken",50,66],["H3196","but not with wine",68,85],["H5128","they stagger",87,99],["H7941","but not with strong drink",101,126]]},"29:10":{"text":"For the LORD hath poured out upon you the spirit of deep sleep, and hath closed your eyes: the prophets and your rulers, the seers hath he covered.","words":[["H3068","For the LORD",0,12],["H5258","hath poured out",13,28],["H7307","upon you the spirit",29,48],["H8639","of deep sleep",49,62],["H6105","and hath closed",64,79],["H5869","your eyes",80,89],["H5030","the prophets",91,103],["H7218","and your rulers",104,119],["H2374","the seers",121,130],["H3680","hath he covered",131,146]]},"29:11":{"text":"And the vision of all is become unto you as the words of a book that is sealed, which men deliver to one that is learned, saying, Read this, I pray thee: and he saith, I cannot; for it is sealed:","words":[["H2380","And the vision",0,14],["H1697","of all is become unto you as the words",15,53],["H5612","of a book",54,63],["H2856","that is sealed",64,78],["H5414","which men deliver",80,97],["H3045","to one that is learned",98,120],["H0559","saying",122,128],["H7121","Read",130,134],["H0559","this, I pray thee: and he saith",135,166],["H3201","I cannot",168,176],["H2856","for it is sealed",178,194]]},"29:12":{"text":"And the book is delivered to him that is not learned, saying, Read this, I pray thee: and he saith, I am not learned.","words":[["H5612","And the book",0,12],["H5414","is delivered",13,25],["H3045","to him that is not learned",26,52],["H5612","to him that is not learned",26,52],["H0559","saying",54,60],["H7121","Read",62,66],["H0559","this, I pray thee: and he saith",67,98],["H3045","I am not learned",100,116]]},"29:13":{"text":"Wherefore the Lord said, Forasmuch as this people draw near me with their mouth, and with their lips do honour me, but have removed their heart far from me, and their fear toward me is taught by the precept of men:","words":[["H0136","Wherefore the Lord",0,18],["H0559","said",19,23],["H3282","Forasmuch",25,34],["H5971","as this people",35,49],["H5066","draw near",50,59],["H6310","me with their mouth",60,79],["H8193","and with their lips",81,100],["H3513","do honour",101,110],["H7368","me, but have removed",111,131],["H3820","their heart",132,143],["H7368","far",144,147],["H3374","from me, and their fear",148,171],["H3925","toward me is taught",172,191],["H4687","by the precept",192,206],["H0582","of men",207,213]]},"29:14":{"text":"Therefore, behold, I will proceed to do a marvellous work among this people, even a marvellous work and a wonder: for the wisdom of their wise men shall perish, and the understanding of their prudent men shall be hid.","words":[["H3254","Therefore, behold, I will proceed",0,33],["H6381","to do a marvellous work",34,57],["H5971","among this people",58,75],["H6381","even a marvellous work",77,99],["H6382","and a wonder",100,112],["H2451","for the wisdom",114,128],["H2450","of their wise",129,142],["H0006","men shall perish",143,159],["H0998","and the understanding",161,182],["H0995","of their prudent",183,199],["H5641","men shall be hid",200,216]]},"29:15":{"text":"Woe unto them that seek deep to hide their counsel from the LORD, and their works are in the dark, and they say, Who seeth us? and who knoweth us?","words":[["H1945","Woe",0,3],["H6009","unto them that seek deep",4,28],["H5641","to hide",29,36],["H6098","their counsel",37,50],["H3068","from the LORD",51,64],["H4639","and their works",66,81],["H4285","are in the dark",82,97],["H0559","and they say",99,111],["H7200","Who seeth",113,122],["H3045","us? and who knoweth",123,142]]},"29:16":{"text":"Surely your turning of things upside down shall be esteemed as the potter's clay: for shall the work say of him that made it, He made me not? or shall the thing framed say of him that framed it, He had no understanding?","words":[["H2017","Surely your turning of things upside down",0,41],["H2803","shall be esteemed",42,59],["H3335","as the potter's",60,75],["H2563","clay",76,80],["H4639","for shall the work",82,100],["H0559","say",101,104],["H6213","of him that made",105,121],["H6213","it, He made",122,133],["H3336","me not? or shall the thing framed",134,167],["H0559","say",168,171],["H3335","of him that framed",172,190],["H0995","it, He had no understanding",191,218]]},"29:17":{"text":"Is it not yet a very little while, and Lebanon shall be turned into a fruitful field, and the fruitful field shall be esteemed as a forest?","words":[["H4213","Is it not yet a very",0,20],["H4592","little while",21,33],["H3844","and Lebanon",35,46],["H7725","shall be turned",47,62],["H3759","into a fruitful field",63,84],["H3759","and the fruitful field",86,108],["H2803","shall be esteemed",109,126],["H3293","as a forest",127,138]]},"29:18":{"text":"And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity, and out of darkness.","words":[["H3117","And in that day",0,15],["H2795","shall the deaf",16,30],["H8085","hear",31,35],["H1697","the words",36,45],["H5612","of the book",46,57],["H5869","and the eyes",59,71],["H5787","of the blind",72,84],["H7200","shall see",85,94],["H0652","out of obscurity",95,111],["H2822","and out of darkness",113,132]]},"29:19":{"text":"The meek also shall increase their joy in the LORD, and the poor among men shall rejoice in the Holy One of Israel.","words":[["H6035","The meek",0,8],["H3254","also shall increase",9,28],["H8057","their joy",29,38],["H3068","in the LORD",39,50],["H0034","and the poor",52,64],["H0120","among men",65,74],["H1523","shall rejoice",75,88],["H6918","in the Holy One",89,104],["H3478","of Israel",105,114]]},"29:20":{"text":"For the terrible one is brought to nought, and the scorner is consumed, and all that watch for iniquity are cut off:","words":[["H6184","For the terrible one",0,20],["H0656","is brought to nought",21,41],["H3887","and the scorner",43,58],["H3615","is consumed",59,70],["H8245","and all that watch",72,90],["H0205","for iniquity",91,103],["H3772","are cut off",104,115]]},"29:21":{"text":"That make a man an offender for a word, and lay a snare for him that reproveth in the gate, and turn aside the just for a thing of nought.","words":[["H0120","That make a man",0,15],["H2398","an offender",16,27],["H1697","for a word",28,38],["H6983","and lay a snare",40,55],["H3198","for him that reproveth",56,78],["H8179","in the gate",79,90],["H5186","and turn aside",92,106],["H6662","the just",107,115],["H8414","for a thing of nought",116,137]]},"29:22":{"text":"Therefore thus saith the LORD, who redeemed Abraham, concerning the house of Jacob, Jacob shall not now be ashamed, neither shall his face now wax pale.","words":[["H0559","Therefore thus saith",0,20],["H3068","the LORD",21,29],["H6299","who redeemed",31,43],["H0085","Abraham",44,51],["H1004","concerning the house",53,73],["H3290","of Jacob",74,82],["H3290","Jacob",84,89],["H0954","shall not now be ashamed",90,114],["H6440","neither shall his face",116,138],["H2357","now wax pale",139,151]]},"29:23":{"text":"But when he seeth his children, the work of mine hands, in the midst of him, they shall sanctify my name, and sanctify the Holy One of Jacob, and shall fear the God of Israel.","words":[["H7200","But when he seeth",0,17],["H3206","his children",18,30],["H4639","the work",32,40],["H3027","of mine hands",41,54],["H7130","in the midst",56,68],["H6942","of him, they shall sanctify",69,96],["H8034","my name",97,104],["H6942","and sanctify",106,118],["H6918","the Holy One",119,131],["H3290","of Jacob",132,140],["H6206","and shall fear",142,156],["H0430","the God",157,164],["H3478","of Israel",165,174]]},"29:24":{"text":"They also that erred in spirit shall come to understanding, and they that murmured shall learn doctrine.","words":[["H8582","They also that erred",0,20],["H7307","in spirit",21,30],["H3045","shall come",31,41],["H0998","to understanding",42,58],["H7279","and they that murmured",60,82],["H3925","shall learn",83,94],["H3948","doctrine",95,103]]},"30:1":{"text":"Woe to the rebellious children, saith the LORD, that take counsel, but not of me; and that cover with a covering, but not of my spirit, that they may add sin to sin:","words":[["H1945","Woe",0,3],["H5637","to the rebellious",4,21],["H1121","children",22,30],["H5002","saith",32,37],["H3068","the LORD",38,46],["H6213","that take",48,57],["H6098","counsel",58,65],["H5258","but not of me; and that cover",67,96],["H4541","with a covering",97,112],["H7307","but not of my spirit",114,134],["H5595","that they may add",136,153],["H2403","sin",154,157],["H2403","to sin",158,164]]},"30:2":{"text":"That walk to go down into Egypt, and have not asked at my mouth; to strengthen themselves in the strength of Pharaoh, and to trust in the shadow of Egypt!","words":[["H1980","That walk",0,9],["H3381","to go down",10,20],["H4714","into Egypt",21,31],["H7592","and have not asked",33,51],["H6310","at my mouth",52,63],["H5810","to strengthen",65,78],["H4581","themselves in the strength",79,105],["H6547","of Pharaoh",106,116],["H2620","and to trust",118,130],["H6738","in the shadow",131,144],["H4714","of Egypt",145,153]]},"30:3":{"text":"Therefore shall the strength of Pharaoh be your shame, and the trust in the shadow of Egypt your confusion.","words":[["H4581","Therefore shall the strength",0,28],["H6547","of Pharaoh",29,39],["H1322","be your shame",40,53],["H2622","and the trust",55,68],["H6738","in the shadow",69,82],["H4714","of Egypt",83,91],["H3639","your confusion",92,106]]},"30:4":{"text":"For his princes were at Zoan, and his ambassadors came to Hanes.","words":[["H8269","For his princes",0,15],["H6814","were at Zoan",16,28],["H4397","and his ambassadors",30,49],["H5060","came",50,54],["H2609","to Hanes",55,63]]},"30:5":{"text":"They were all ashamed of a people that could not profit them, nor be an help nor profit, but a shame, and also a reproach.","words":[["H3001","They were all ashamed",0,21],["H5971","of a people",22,33],["H3276","that could not profit",34,55],["H5828","them, nor be an help",56,76],["H3276","nor profit",77,87],["H1322","but a shame",89,100],["H2781","and also a reproach",102,121]]},"30:6":{"text":"The burden of the beasts of the south: into the land of trouble and anguish, from whence come the young and old lion, the viper and fiery flying serpent, they will carry their riches upon the shoulders of young asses, and their treasures upon the bunches of camels, to a people that shall not profit them.","words":[["H4853","The burden",0,10],["H0929","of the beasts",11,24],["H5045","of the south",25,37],["H0776","into the land",39,52],["H6869","of trouble",53,63],["H6695","and anguish",64,75],["H3833","from whence come the young",77,103],["H3918","and old lion",104,116],["H0660","the viper",118,127],["H8314","and fiery",128,137],["H5774","flying",138,144],["H8314","serpent",145,152],["H5375","they will carry",154,169],["H2428","their riches",170,182],["H3802","upon the shoulders",183,201],["H5895","of young asses",202,216],["H0214","and their treasures",218,237],["H1707","upon the bunches",238,254],["H1581","of camels",255,264],["H5971","to a people",266,277],["H3276","that shall not profit",278,299]]},"30:7":{"text":"For the Egyptians shall help in vain, and to no purpose: therefore have I cried concerning this, Their strength is to sit still.","words":[["H4714","For the Egyptians",0,17],["H5826","shall help",18,28],["H1892","in vain",29,36],["H7385","and to no purpose",38,55],["H7121","therefore have I cried",57,79],["H2063","concerning this",80,95],["H1992","Their",97,102],["H7293","strength",103,111],["H7674","is to sit still",112,127]]},"30:8":{"text":"Now go, write it before them in a table, and note it in a book, that it may be for the time to come for ever and ever:","words":[["H0935","Now go",0,6],["H3789","write",8,13],["H3871","it before them in a table",14,39],["H2710","and note",41,49],["H5612","it in a book",50,62],["H3117","that it may be for the time",64,91],["H0314","to come",92,99],["H5704","for",100,103],["H5703","ever",104,108],["H5769","and ever",109,117]]},"30:9":{"text":"That this is a rebellious people, lying children, children that will not hear the law of the LORD:","words":[["H4805","That this is a rebellious",0,25],["H5971","people",26,32],["H3586","lying",34,39],["H1121","children",40,48],["H1121","children",50,58],["H0014","that will",59,68],["H8085","not hear",69,77],["H8451","the law",78,85],["H3068","of the LORD",86,97]]},"30:10":{"text":"Which say to the seers, See not; and to the prophets, Prophesy not unto us right things, speak unto us smooth things, prophesy deceits:","words":[["H0559","Which say",0,9],["H7200","to the seers",10,22],["H7200","See",24,27],["H2374","not; and to the prophets",28,52],["H2372","Prophesy",54,62],["H5229","not unto us right things",63,87],["H1696","speak",89,94],["H2513","unto us smooth things",95,116],["H2372","prophesy",118,126],["H4123","deceits",127,134]]},"30:11":{"text":"Get you out of the way, turn aside out of the path, cause the Holy One of Israel to cease from before us.","words":[["H5493","Get you out",0,11],["H1870","of the way",12,22],["H5186","turn aside",24,34],["H0734","out of the path",35,50],["H6918","cause the Holy One",52,70],["H3478","of Israel",71,80],["H7673","to cease",81,89],["H6440","from before",90,101]]},"30:12":{"text":"Wherefore thus saith the Holy One of Israel, Because ye despise this word, and trust in oppression and perverseness, and stay thereon:","words":[["H0559","Wherefore thus saith",0,20],["H6918","the Holy One",21,33],["H3478","of Israel",34,43],["H3988","Because ye despise",45,63],["H1697","this word",64,73],["H0982","and trust",75,84],["H6233","in oppression",85,98],["H3868","and perverseness",99,115],["H8172","and stay",117,125]]},"30:13":{"text":"Therefore this iniquity shall be to you as a breach ready to fall, swelling out in a high wall, whose breaking cometh suddenly at an instant.","words":[["H5771","Therefore this iniquity",0,23],["H6556","shall be to you as a breach",24,51],["H5307","ready to fall",52,65],["H1158","swelling out",67,79],["H7682","in a high",80,89],["H2346","wall",90,94],["H7667","whose breaking",96,110],["H0935","cometh",111,117],["H6597","suddenly",118,126],["H6621","at an instant",127,140]]},"30:14":{"text":"And he shall break it as the breaking of the potters' vessel that is broken in pieces; he shall not spare: so that there shall not be found in the bursting of it a sherd to take fire from the hearth, or to take water withal out of the pit.","words":[["H7665","And he shall break",0,18],["H7667","it as the breaking",19,37],["H3335","of the potters'",38,53],["H5035","vessel",54,60],["H3807","that is broken in pieces",61,85],["H2550","he shall not spare",87,105],["H4672","so that there shall not be found",107,139],["H4386","in the bursting",140,155],["H2789","of it a sherd",156,169],["H2846","to take",170,177],["H0784","fire",178,182],["H3344","from the hearth",183,198],["H2834","or to take",200,210],["H4325","water",211,216],["H1360","withal out of the pit",217,238]]},"30:15":{"text":"For thus saith the Lord GOD, the Holy One of Israel; In returning and rest shall ye be saved; in quietness and in confidence shall be your strength: and ye would not.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H6918","the Holy One",29,41],["H3478","of Israel",42,51],["H7729","In returning",53,65],["H5183","and rest",66,74],["H3467","shall ye be saved",75,92],["H8252","in quietness",94,106],["H0985","and in confidence",107,124],["H1369","shall be your strength",125,147],["H0014","and ye would",149,161]]},"30:16":{"text":"But ye said, No; for we will flee upon horses; therefore shall ye flee: and, We will ride upon the swift; therefore shall they that pursue you be swift.","words":[["H0559","But ye said",0,11],["H5127","No; for we will flee",13,33],["H5483","upon horses",34,45],["H5127","therefore shall ye flee",47,70],["H7392","and, We will ride",72,89],["H7031","upon the swift",90,104],["H7291","therefore shall they that pursue",106,138],["H7043","you be swift",139,151]]},"30:17":{"text":"One thousand shall flee at the rebuke of one; at the rebuke of five shall ye flee: till ye be left as a beacon upon the top of a mountain, and as an ensign on an hill.","words":[["H0259","One",0,3],["H0505","thousand",4,12],["H6440","shall flee at",13,26],["H1606","the rebuke",27,37],["H0259","of one",38,44],["H6440","at",46,48],["H1606","the rebuke",49,59],["H2568","of five",60,67],["H5127","shall ye flee",68,81],["H3498","till ye be left",83,98],["H8650","as a beacon",99,110],["H7218","upon the top",111,123],["H2022","of a mountain",124,137],["H5251","and as an ensign",139,155],["H1389","on an hill",156,166]]},"30:18":{"text":"And therefore will the LORD wait, that he may be gracious unto you, and therefore will he be exalted, that he may have mercy upon you: for the LORD is a God of judgment: blessed are all they that wait for him.","words":[["H3068","And therefore will the LORD",0,27],["H2442","wait",28,32],["H2603","that he may be gracious",34,57],["H7311","unto you, and therefore will he be exalted",58,100],["H7355","that he may have mercy",102,124],["H3068","upon you: for the LORD",125,147],["H0430","is a God",148,156],["H4941","of judgment",157,168],["H0835","blessed",170,177],["H2442","are all they that wait",178,200]]},"30:19":{"text":"For the people shall dwell in Zion at Jerusalem: thou shalt weep no more: he will be very gracious unto thee at the voice of thy cry; when he shall hear it, he will answer thee.","words":[["H5971","For the people",0,14],["H3427","shall dwell",15,26],["H6726","in Zion",27,34],["H3389","at Jerusalem",35,47],["H1058","thou shalt weep",49,64],["H1058","no more",65,72],["H2603","he will be very",74,89],["H2603","gracious",90,98],["H6963","unto thee at the voice",99,121],["H2199","of thy cry",122,132],["H8085","when he shall hear",134,152],["H6030","it, he will answer",153,171]]},"30:20":{"text":"And though the Lord give you the bread of adversity, and the water of affliction, yet shall not thy teachers be removed into a corner any more, but thine eyes shall see thy teachers:","words":[["H0136","And though the Lord",0,19],["H5414","give",20,24],["H3899","you the bread",25,38],["H6862","of adversity",39,51],["H4325","and the water",53,66],["H3906","of affliction",67,80],["H3384","yet shall not thy teachers",82,108],["H3670","be removed into a corner",109,133],["H5869","any more, but thine eyes",134,158],["H7200","shall see",159,168],["H3384","thy teachers",169,181]]},"30:21":{"text":"And thine ears shall hear a word behind thee, saying, This is the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.","words":[["H0241","And thine ears",0,14],["H8085","shall hear",15,25],["H1697","a word",26,32],["H0310","behind",33,39],["H0559","thee, saying",40,52],["H1870","This is the way",54,69],["H3212","walk ye in it",71,84],["H0541","when ye turn to the right hand",86,116],["H8041","and when ye turn to the left",118,146]]},"30:22":{"text":"Ye shall defile also the covering of thy graven images of silver, and the ornament of thy molten images of gold: thou shalt cast them away as a menstruous cloth; thou shalt say unto it, Get thee hence.","words":[["H2930","Ye shall defile",0,15],["H6826","also the covering",16,33],["H6456","of thy graven images",34,54],["H3701","of silver",55,64],["H0642","and the ornament",66,82],["H4541","of thy molten images",83,103],["H2091","of gold",104,111],["H2219","thou shalt cast them away",113,138],["H1739","as a menstruous cloth",139,160],["H0559","thou shalt say",162,176],["H3318","unto it, Get thee hence",177,200]]},"30:23":{"text":"Then shall he give the rain of thy seed, that thou shalt sow the ground withal; and bread of the increase of the earth, and it shall be fat and plenteous: in that day shall thy cattle feed in large pastures.","words":[["H5414","Then shall he give",0,18],["H4306","the rain",19,27],["H2233","of thy seed",28,39],["H2232","that thou shalt sow",41,60],["H0127","the ground",61,71],["H3899","withal; and bread",72,89],["H8393","of the increase",90,105],["H0127","of the earth",106,118],["H1879","and it shall be fat",120,139],["H8082","and plenteous",140,153],["H3117","in that day",155,166],["H4735","shall thy cattle",167,183],["H7462","feed",184,188],["H7337","in large",189,197],["H3733","pastures",198,206]]},"30:24":{"text":"The oxen likewise and the young asses that ear the ground shall eat clean provender, which hath been winnowed with the shovel and with the fan.","words":[["H0504","The oxen",0,8],["H5895","likewise and the young asses",9,37],["H5647","that ear",38,46],["H0127","the ground",47,57],["H0398","shall eat",58,67],["H2548","clean",68,73],["H1098","provender",74,83],["H2219","which hath been winnowed",85,109],["H7371","with the shovel",110,125],["H4214","and with the fan",126,142]]},"30:25":{"text":"And there shall be upon every high mountain, and upon every high hill, rivers and streams of waters in the day of the great slaughter, when the towers fall.","words":[["H1364","And there shall be upon every high",0,34],["H2022","mountain",35,43],["H5375","and upon every high",45,64],["H1389","hill",65,69],["H6388","rivers",71,77],["H2988","and streams",78,89],["H4325","of waters",90,99],["H3117","in the day",100,110],["H7227","of the great",111,123],["H2027","slaughter",124,133],["H4026","when the towers",135,150],["H5307","fall",151,155]]},"30:26":{"text":"Moreover the light of the moon shall be as the light of the sun, and the light of the sun shall be sevenfold, as the light of seven days, in the day that the LORD bindeth up the breach of his people, and healeth the stroke of their wound.","words":[["H0216","Moreover the light",0,18],["H3842","of the moon",19,30],["H0216","shall be as the light",31,52],["H2535","of the sun",53,63],["H0216","and the light",65,78],["H2535","of the sun",79,89],["H7659","shall be sevenfold",90,108],["H0216","as the light",110,122],["H7651","of seven",123,131],["H3117","days",132,136],["H3117","in the day",138,148],["H3068","that the LORD",149,162],["H2280","bindeth up",163,173],["H7667","the breach",174,184],["H5971","of his people",185,198],["H7495","and healeth",200,211],["H4273","the stroke",212,222],["H4347","of their wound",223,237]]},"30:27":{"text":"Behold, the name of the LORD cometh from far, burning with his anger, and the burden thereof is heavy: his lips are full of indignation, and his tongue as a devouring fire:","words":[["H8034","Behold, the name",0,16],["H3068","of the LORD",17,28],["H0935","cometh",29,35],["H4801","from far",36,44],["H1197","burning",46,53],["H0639","with his anger",54,68],["H4858","and the burden",70,84],["H3514","thereof is heavy",85,101],["H8193","his lips",103,111],["H4390","are full",112,120],["H2195","of indignation",121,135],["H3956","and his tongue",137,151],["H0398","as a devouring",152,166],["H0784","fire",167,171]]},"30:28":{"text":"And his breath, as an overflowing stream, shall reach to the midst of the neck, to sift the nations with the sieve of vanity: and there shall be a bridle in the jaws of the people, causing them to err.","words":[["H7307","And his breath",0,14],["H7857","as an overflowing",16,33],["H5158","stream",34,40],["H2673","shall reach to the midst",42,66],["H6677","of the neck",67,78],["H5130","to sift",80,87],["H1471","the nations",88,99],["H5299","with the sieve",100,114],["H7723","of vanity",115,124],["H7448","and there shall be a bridle",126,153],["H3895","in the jaws",154,165],["H5971","of the people",166,179],["H8582","causing them to err",181,200]]},"30:29":{"text":"Ye shall have a song, as in the night when a holy solemnity is kept; and gladness of heart, as when one goeth with a pipe to come into the mountain of the LORD, to the mighty One of Israel.","words":[["H7892","Ye shall have a song",0,20],["H3915","as in the night",22,37],["H6942","when a holy",38,49],["H2282","solemnity",50,59],["H6942","is kept",60,67],["H8057","and gladness",69,81],["H3824","of heart",82,90],["H1980","as when one goeth",92,109],["H2485","with a pipe",110,121],["H0935","to come",122,129],["H2022","into the mountain",130,147],["H3068","of the LORD",148,159],["H6697","to the mighty One",161,178],["H3478","of Israel",179,188]]},"30:30":{"text":"And the LORD shall cause his glorious voice to be heard, and shall shew the lighting down of his arm, with the indignation of his anger, and with the flame of a devouring fire, with scattering, and tempest, and hailstones.","words":[["H3068","And the LORD",0,12],["H1935","shall cause his glorious",13,37],["H6963","voice",38,43],["H8085","to be heard",44,55],["H7200","and shall shew",57,71],["H5183","the lighting down",72,89],["H2220","of his arm",90,100],["H2197","with the indignation",102,122],["H0639","of his anger",123,135],["H3851","and with the flame",137,155],["H0398","of a devouring",156,170],["H0784","fire",171,175],["H5311","with scattering",177,192],["H2230","and tempest",194,205],["H0068","and hailstones",207,221],["H1259","and hailstones",207,221]]},"30:31":{"text":"For through the voice of the LORD shall the Assyrian be beaten down, which smote with a rod.","words":[["H6963","For through the voice",0,21],["H3068","of the LORD",22,33],["H0804","shall the Assyrian",34,52],["H2865","be beaten down",53,67],["H5221","which smote",69,80],["H7626","with a rod",81,91]]},"30:32":{"text":"And in every place where the grounded staff shall pass, which the LORD shall lay upon him, it shall be with tabrets and harps: and in battles of shaking will he fight with it.","words":[["H3605","And in every place",0,18],["H4145","where the grounded",19,37],["H4294","staff",38,43],["H4569","shall pass",44,54],["H3068","which the LORD",56,70],["H5117","shall lay",71,80],["H8596","upon him, it shall be with tabrets",81,115],["H3658","and harps",116,125],["H4421","and in battles",127,141],["H8573","of shaking",142,152],["H3898","will he fight",153,166]]},"30:33":{"text":"For Tophet is ordained of old; yea, for the king it is prepared; he hath made it deep and large: the pile thereof is fire and much wood; the breath of the LORD, like a stream of brimstone, doth kindle it.","words":[["H8613","For Tophet",0,10],["H6186","is ordained",11,22],["H0865","of old",23,29],["H4428","yea, for the king",31,48],["H3559","it is prepared",49,63],["H6009","he hath made it deep",65,85],["H7337","and large",86,95],["H4071","the pile",97,105],["H0784","thereof is fire",106,121],["H7235","and much",122,130],["H6086","wood",131,135],["H5397","the breath",137,147],["H3068","of the LORD",148,159],["H5158","like a stream",161,174],["H1614","of brimstone",175,187],["H1197","doth kindle",189,200]]},"31:1":{"text":"Woe to them that go down to Egypt for help; and stay on horses, and trust in chariots, because they are many; and in horsemen, because they are very strong; but they look not unto the Holy One of Israel, neither seek the LORD!","words":[["H1945","Woe",0,3],["H3381","to them that go down",4,24],["H4714","to Egypt",25,33],["H5833","for help",34,42],["H8172","and stay",44,52],["H5483","on horses",53,62],["H0982","and trust",64,73],["H7393","in chariots",74,85],["H7227","because they are many",87,108],["H6571","and in horsemen",110,125],["H3966","because they are very",127,148],["H6105","strong",149,155],["H8159","but they look",157,170],["H6918","not unto the Holy One",171,192],["H3478","of Israel",193,202],["H1875","neither seek",204,216],["H3068","the LORD",217,225]]},"31:2":{"text":"Yet he also is wise, and will bring evil, and will not call back his words: but will arise against the house of the evildoers, and against the help of them that work iniquity.","words":[["H2450","Yet he also is wise",0,19],["H0935","and will bring",21,35],["H7451","evil",36,40],["H5493","and will not call back",42,64],["H1697","his words",65,74],["H6965","but will arise",76,90],["H1004","against the house",91,108],["H7489","of the evildoers",109,125],["H5833","and against the help",127,147],["H6466","of them that work",148,165],["H0205","iniquity",166,174]]},"31:3":{"text":"Now the Egyptians are men, and not God; and their horses flesh, and not spirit. When the LORD shall stretch out his hand, both he that helpeth shall fall, and he that is holpen shall fall down, and they all shall fail together.","words":[["H4714","Now the Egyptians",0,17],["H0120","are men",18,25],["H0410","and not God",27,38],["H5483","and their horses",40,56],["H1320","flesh",57,62],["H7307","and not spirit",64,78],["H3068","When the LORD",80,93],["H5186","shall stretch out",94,111],["H3027","his hand",112,120],["H5826","both he that helpeth",122,142],["H3782","shall fall",143,153],["H5826","and he that is holpen",155,176],["H5307","shall fall down",177,192],["H3615","and they all shall fail",194,217],["H3162","together",218,226]]},"31:4":{"text":"For thus hath the LORD spoken unto me, Like as the lion and the young lion roaring on his prey, when a multitude of shepherds is called forth against him, he will not be afraid of their voice, nor abase himself for the noise of them: so shall the LORD of hosts come down to fight for mount Zion, and for the hill thereof.","words":[["H3068","For thus hath the LORD",0,22],["H0559","spoken",23,29],["H0738","unto me, Like as the lion",30,55],["H3715","and the young lion",56,74],["H1897","roaring",75,82],["H2964","on his prey",83,94],["H4393","when a multitude",96,112],["H7462","of shepherds",113,125],["H7121","is called forth",126,141],["H2865","against him, he will not be afraid",142,176],["H6963","of their voice",177,191],["H6031","nor abase",193,202],["H1995","himself for the noise",203,224],["H3068","of them: so shall the LORD",225,251],["H6635","of hosts",252,260],["H3381","come down",261,270],["H6633","to fight",271,279],["H2022","for mount",280,289],["H6726","Zion",290,294],["H1389","and for the hill",296,312]]},"31:5":{"text":"As birds flying, so will the LORD of hosts defend Jerusalem; defending also he will deliver it; and passing over he will preserve it.","words":[["H6833","As birds",0,8],["H5774","flying",9,15],["H3068","so will the LORD",17,33],["H6635","of hosts",34,42],["H1598","defend",43,49],["H3389","Jerusalem",50,59],["H1598","defending",61,70],["H5337","also he will deliver",71,91],["H6452","it; and passing over",92,112],["H4422","he will preserve",113,129]]},"31:6":{"text":"Turn ye unto him from whom the children of Israel have deeply revolted.","words":[["H7725","Turn",0,4],["H1121","ye unto him from whom the children",5,39],["H3478","of Israel",40,49],["H6009","have deeply",50,61],["H5627","revolted",62,70]]},"31:7":{"text":"For in that day every man shall cast away his idols of silver, and his idols of gold, which your own hands have made unto you for a sin.","words":[["H3117","For in that day",0,15],["H0376","every man",16,25],["H3988","shall cast away",26,41],["H0457","his idols",42,51],["H3701","of silver",52,61],["H0457","and his idols",63,76],["H2091","of gold",77,84],["H3027","which your own hands",86,106],["H6213","have made",107,116],["H2399","unto you for a sin",117,135]]},"31:8":{"text":"Then shall the Assyrian fall with the sword, not of a mighty man; and the sword, not of a mean man, shall devour him: but he shall flee from the sword, and his young men shall be discomfited.","words":[["H0804","Then shall the Assyrian",0,23],["H5307","fall",24,28],["H2719","with the sword",29,43],["H0376","not of a mighty man",45,64],["H2719","and the sword",66,79],["H0120","not of a mean man",81,98],["H0398","shall devour",100,112],["H5127","him: but he shall flee",113,135],["H6440","from",136,140],["H2719","the sword",141,150],["H0970","and his young men",152,169],["H4522","shall be discomfited",170,190]]},"31:9":{"text":"And he shall pass over to his strong hold for fear, and his princes shall be afraid of the ensign, saith the LORD, whose fire is in Zion, and his furnace in Jerusalem.","words":[["H5674","And he shall pass over",0,22],["H5553","to his strong hold",23,41],["H4032","for fear",42,50],["H8269","and his princes",52,67],["H2865","shall be afraid",68,83],["H5251","of the ensign",84,97],["H5002","saith",99,104],["H3068","the LORD",105,113],["H0217","whose fire",115,125],["H6726","is in Zion",126,136],["H8574","and his furnace",138,153],["H3389","in Jerusalem",154,166]]},"32:1":{"text":"Behold, a king shall reign in righteousness, and princes shall rule in judgment.","words":[["H4428","Behold, a king",0,14],["H4427","shall reign",15,26],["H6664","in righteousness",27,43],["H8269","and princes",45,56],["H8323","shall rule",57,67],["H4941","in judgment",68,79]]},"32:2":{"text":"And a man shall be as an hiding place from the wind, and a covert from the tempest; as rivers of water in a dry place, as the shadow of a great rock in a weary land.","words":[["H0376","And a man",0,9],["H4224","shall be as an hiding place",10,37],["H7307","from the wind",38,51],["H5643","and a covert",53,65],["H2230","from the tempest",66,82],["H6388","as rivers",84,93],["H4325","of water",94,102],["H6724","in a dry place",103,117],["H6738","as the shadow",119,132],["H3515","of a great",133,143],["H5553","rock",144,148],["H5889","in a weary",149,159],["H0776","land",160,164]]},"32:3":{"text":"And the eyes of them that see shall not be dim, and the ears of them that hear shall hearken.","words":[["H5869","And the eyes",0,12],["H7200","of them that see",13,29],["H8159","shall not be dim",30,46],["H0241","and the ears",48,60],["H8085","of them that hear",61,78],["H7181","shall hearken",79,92]]},"32:4":{"text":"The heart also of the rash shall understand knowledge, and the tongue of the stammerers shall be ready to speak plainly.","words":[["H3824","The heart",0,9],["H4116","also of the rash",10,26],["H0995","shall understand",27,43],["H1847","knowledge",44,53],["H3956","and the tongue",55,69],["H5926","of the stammerers",70,87],["H4116","shall be ready",88,102],["H1696","to speak",103,111],["H6703","plainly",112,119]]},"32:5":{"text":"The vile person shall be no more called liberal, nor the churl said to be bountiful.","words":[["H5036","The vile person",0,15],["H7121","shall be no more called",16,39],["H5081","liberal",40,47],["H3596","nor the churl",49,62],["H0559","said",63,67],["H7771","to be bountiful",68,83]]},"32:6":{"text":"For the vile person will speak villany, and his heart will work iniquity, to practise hypocrisy, and to utter error against the LORD, to make empty the soul of the hungry, and he will cause the drink of the thirsty to fail.","words":[["H5036","For the vile person",0,19],["H1696","will speak",20,30],["H5039","villany",31,38],["H3820","and his heart",40,53],["H6213","will work",54,63],["H0205","iniquity",64,72],["H6213","to practise",74,85],["H2612","hypocrisy",86,95],["H1696","and to utter",97,109],["H8442","error",110,115],["H3068","against the LORD",116,132],["H7324","to make empty",134,147],["H5315","the soul",148,156],["H7457","of the hungry",157,170],["H4945","and he will cause the drink",172,199],["H6771","of the thirsty",200,214],["H2637","to fail",215,222]]},"32:7":{"text":"The instruments also of the churl are evil: he deviseth wicked devices to destroy the poor with lying words, even when the needy speaketh right.","words":[["H3627","The instruments",0,15],["H3596","also of the churl",16,33],["H7451","are evil",34,42],["H3289","he deviseth",44,55],["H2154","wicked devices",56,70],["H2254","to destroy",71,81],["H6041","the poor",82,90],["H6035","the poor",82,90],["H8267","with lying",91,101],["H0561","words",102,107],["H0034","even when the needy",109,128],["H1696","speaketh",129,137],["H4941","right",138,143]]},"32:8":{"text":"But the liberal deviseth liberal things; and by liberal things shall he stand.","words":[["H5081","But the liberal",0,15],["H3289","deviseth",16,24],["H5081","liberal things",25,39],["H5081","and by liberal things",41,62],["H6965","shall he stand",63,77]]},"32:9":{"text":"Rise up, ye women that are at ease; hear my voice, ye careless daughters; give ear unto my speech.","words":[["H6965","Rise up",0,7],["H0802","ye women",9,17],["H7600","that are at ease",18,34],["H8085","hear",36,40],["H6963","my voice",41,49],["H0982","ye careless",51,62],["H1323","daughters",63,72],["H0238","give ear",74,82],["H0565","unto my speech",83,97]]},"32:10":{"text":"Many days and years shall ye be troubled, ye careless women: for the vintage shall fail, the gathering shall not come.","words":[["H3117","Many days",0,9],["H8141","and years",10,19],["H7264","shall ye be troubled",20,40],["H0982","ye careless women",42,59],["H1210","for the vintage",61,76],["H3615","shall fail",77,87],["H0625","the gathering",89,102],["H0935","shall not come",103,117]]},"32:11":{"text":"Tremble, ye women that are at ease; be troubled, ye careless ones: strip you, and make you bare, and gird sackcloth upon your loins.","words":[["H2729","Tremble",0,7],["H7600","ye women that are at ease",9,34],["H7264","be troubled",36,47],["H0982","ye careless ones",49,65],["H6584","strip",67,72],["H6209","you, and make you bare",73,95],["H2290","and gird",97,105],["H2504","sackcloth upon your loins",106,131]]},"32:12":{"text":"They shall lament for the teats, for the pleasant fields, for the fruitful vine.","words":[["H5594","They shall lament",0,17],["H7699","for the teats",18,31],["H2531","for the pleasant",33,49],["H7704","fields",50,56],["H6509","for the fruitful",58,74],["H1612","vine",75,79]]},"32:13":{"text":"Upon the land of my people shall come up thorns and briers; yea, upon all the houses of joy in the joyous city:","words":[["H0127","Upon the land",0,13],["H5971","of my people",14,26],["H5927","shall come up",27,40],["H6975","thorns",41,47],["H8068","and briers",48,58],["H1004","yea, upon all the houses",60,84],["H4885","of joy",85,91],["H5947","in the joyous",92,105],["H7151","city",106,110]]},"32:14":{"text":"Because the palaces shall be forsaken; the multitude of the city shall be left; the forts and towers shall be for dens for ever, a joy of wild asses, a pasture of flocks;","words":[["H0759","Because the palaces",0,19],["H5203","shall be forsaken",20,37],["H1995","the multitude",39,52],["H5892","of the city",53,64],["H5800","shall be left",65,78],["H6076","the forts",80,89],["H0975","and towers",90,100],["H4631","shall be for dens",101,118],["H5704","for",119,122],["H5769","ever",123,127],["H4885","a joy",129,134],["H6501","of wild asses",135,148],["H4829","a pasture",150,159],["H5739","of flocks",160,169]]},"32:15":{"text":"Until the spirit be poured upon us from on high, and the wilderness be a fruitful field, and the fruitful field be counted for a forest.","words":[["H7307","Until the spirit",0,16],["H6168","be poured",17,26],["H4791","upon us from on high",27,47],["H4057","and the wilderness",49,67],["H3759","be a fruitful field",68,87],["H3759","and the fruitful field",89,111],["H2803","be counted",112,122],["H3293","for a forest",123,135]]},"32:16":{"text":"Then judgment shall dwell in the wilderness, and righteousness remain in the fruitful field.","words":[["H4941","Then judgment",0,13],["H7931","shall dwell",14,25],["H4057","in the wilderness",26,43],["H6666","and righteousness",45,62],["H3427","remain",63,69],["H3759","in the fruitful field",70,91]]},"32:17":{"text":"And the work of righteousness shall be peace; and the effect of righteousness quietness and assurance for ever.","words":[["H4639","And the work",0,12],["H6666","of righteousness",13,29],["H7965","shall be peace",30,44],["H5656","and the effect",46,60],["H6666","of righteousness",61,77],["H8252","quietness",78,87],["H0983","and assurance",88,101],["H5704","for",102,105],["H5769","ever",106,110]]},"32:18":{"text":"And my people shall dwell in a peaceable habitation, and in sure dwellings, and in quiet resting places;","words":[["H5971","And my people",0,13],["H3427","shall dwell",14,25],["H7965","in a peaceable",26,40],["H5116","habitation",41,51],["H4009","and in sure",53,64],["H4908","dwellings",65,74],["H7600","and in quiet",76,88],["H4496","resting places",89,103]]},"32:19":{"text":"When it shall hail, coming down on the forest; and the city shall be low in a low place.","words":[["H1258","When it shall hail",0,18],["H3381","coming down",20,31],["H3293","on the forest",32,45],["H5892","and the city",47,59],["H8213","shall be low",60,72],["H8218","in a low place",73,87]]},"32:20":{"text":"Blessed are ye that sow beside all waters, that send forth thither the feet of the ox and the ass.","words":[["H0835","Blessed",0,7],["H2232","are ye that sow",8,23],["H4325","beside all waters",24,41],["H7971","that send forth",43,58],["H7272","thither the feet",59,75],["H7794","of the ox",76,85],["H2543","and the ass",86,97]]},"33:1":{"text":"Woe to thee that spoilest, and thou wast not spoiled; and dealest treacherously, and they dealt not treacherously with thee! when thou shalt cease to spoil, thou shalt be spoiled; and when thou shalt make an end to deal treacherously, they shall deal treacherously with thee.","words":[["H1945","Woe",0,3],["H7703","to thee that spoilest",4,25],["H7703","and thou wast not spoiled",27,52],["H0898","and dealest treacherously",54,79],["H0898","and they dealt not treacherously",81,113],["H8552","with thee! when thou shalt cease",114,146],["H7703","to spoil",147,155],["H7703","thou shalt be spoiled",157,178],["H5239","and when thou shalt make an end",180,211],["H0898","to deal treacherously",212,233],["H0898","they shall deal treacherously",235,264]]},"33:2":{"text":"O LORD, be gracious unto us; we have waited for thee: be thou their arm every morning, our salvation also in the time of trouble.","words":[["H3068","O LORD",0,6],["H2603","be gracious",8,19],["H6960","unto us; we have waited",20,43],["H2220","for thee: be thou their arm",44,71],["H1242","every morning",72,85],["H3444","our salvation",87,100],["H6256","also in the time",101,117],["H6869","of trouble",118,128]]},"33:3":{"text":"At the noise of the tumult the people fled; at the lifting up of thyself the nations were scattered.","words":[["H6963","At the noise",0,12],["H1995","of the tumult",13,26],["H5971","the people",27,37],["H5074","fled",38,42],["H7427","at the lifting up",44,61],["H1471","of thyself the nations",62,84],["H5310","were scattered",85,99]]},"33:4":{"text":"And your spoil shall be gathered like the gathering of the caterpiller: as the running to and fro of locusts shall he run upon them.","words":[["H7998","And your spoil",0,14],["H0622","shall be gathered",15,32],["H0625","like the gathering",33,51],["H2625","of the caterpiller",52,70],["H4944","as the running to and fro",72,97],["H1357","of locusts",98,108],["H8264","shall he run",109,121]]},"33:5":{"text":"The LORD is exalted; for he dwelleth on high: he hath filled Zion with judgment and righteousness.","words":[["H3068","The LORD",0,8],["H7682","is exalted",9,19],["H7931","for he dwelleth",21,36],["H4791","on high",37,44],["H4390","he hath filled",46,60],["H6726","Zion",61,65],["H4941","with judgment",66,79],["H6666","and righteousness",80,97]]},"33:6":{"text":"And wisdom and knowledge shall be the stability of thy times, and strength of salvation: the fear of the LORD is his treasure.","words":[["H2451","And wisdom",0,10],["H1847","and knowledge",11,24],["H0530","shall be the stability",25,47],["H6256","of thy times",48,60],["H2633","and strength",62,74],["H3444","of salvation",75,87],["H3374","the fear",89,97],["H3068","of the LORD",98,109],["H0214","is his treasure",110,125]]},"33:7":{"text":"Behold, their valiant ones shall cry without: the ambassadors of peace shall weep bitterly.","words":[["H0691","Behold, their valiant ones",0,26],["H6817","shall cry",27,36],["H2351","without",37,44],["H4397","the ambassadors",46,61],["H7965","of peace",62,70],["H1058","shall weep",71,81],["H4751","bitterly",82,90]]},"33:8":{"text":"The highways lie waste, the wayfaring man ceaseth: he hath broken the covenant, he hath despised the cities, he regardeth no man.","words":[["H4546","The highways",0,12],["H8074","lie waste",13,22],["H5674","the wayfaring man",24,41],["H0734","the wayfaring man",24,41],["H7673","ceaseth",42,49],["H6565","he hath broken",51,65],["H1285","the covenant",66,78],["H3988","he hath despised",80,96],["H5892","the cities",97,107],["H2803","he regardeth",109,121],["H0582","no man",122,128]]},"33:9":{"text":"The earth mourneth and languisheth: Lebanon is ashamed and hewn down: Sharon is like a wilderness; and Bashan and Carmel shake off their fruits.","words":[["H0776","The earth",0,9],["H0056","mourneth",10,18],["H0535","and languisheth",19,34],["H3844","Lebanon",36,43],["H2659","is ashamed",44,54],["H7060","and hewn down",55,68],["H8289","Sharon",70,76],["H6160","is like a wilderness",77,97],["H1316","and Bashan",99,109],["H3760","and Carmel",110,120],["H5287","shake off",121,130]]},"33:10":{"text":"Now will I rise, saith the LORD; now will I be exalted; now will I lift up myself.","words":[["H6965","Now will I rise",0,15],["H0559","saith",17,22],["H3068","the LORD",23,31],["H7426","now will I be exalted",33,54],["H5375","now will I lift up",56,74]]},"33:11":{"text":"Ye shall conceive chaff, ye shall bring forth stubble: your breath, as fire, shall devour you.","words":[["H2029","Ye shall conceive",0,17],["H2842","chaff",18,23],["H3205","ye shall bring forth",25,45],["H7179","stubble",46,53],["H7307","your breath",55,66],["H0784","as fire",68,75],["H0398","shall devour",77,89]]},"33:12":{"text":"And the people shall be as the burnings of lime: as thorns cut up shall they be burned in the fire.","words":[["H5971","And the people",0,14],["H4955","shall be as the burnings",15,39],["H7875","of lime",40,47],["H6975","as thorns",49,58],["H3683","cut up",59,65],["H3341","shall they be burned",66,86],["H0784","in the fire",87,98]]},"33:13":{"text":"Hear, ye that are far off, what I have done; and, ye that are near, acknowledge my might.","words":[["H8085","Hear",0,4],["H7350","ye that are far off",6,25],["H6213","what I have done",27,43],["H7138","and, ye that are near",45,66],["H3045","acknowledge",68,79],["H1369","my might",80,88]]},"33:14":{"text":"The sinners in Zion are afraid; fearfulness hath surprised the hypocrites. Who among us shall dwell with the devouring fire? who among us shall dwell with everlasting burnings?","words":[["H2400","The sinners",0,11],["H6726","in Zion",12,19],["H6342","are afraid",20,30],["H7461","fearfulness",32,43],["H0270","hath surprised",44,58],["H2611","the hypocrites",59,73],["H1481","Who among us shall dwell",75,99],["H0398","with the devouring",100,118],["H0784","fire",119,123],["H1481","who among us shall dwell",125,149],["H5769","with everlasting",150,166],["H4168","burnings",167,175]]},"33:15":{"text":"He that walketh righteously, and speaketh uprightly; he that despiseth the gain of oppressions, that shaketh his hands from holding of bribes, that stoppeth his ears from hearing of blood, and shutteth his eyes from seeing evil;","words":[["H1980","He that walketh",0,15],["H6666","righteously",16,27],["H1696","and speaketh",29,41],["H4339","uprightly",42,51],["H3988","he that despiseth",53,70],["H1215","the gain",71,79],["H4642","of oppressions",80,94],["H5287","that shaketh",96,108],["H3709","his hands",109,118],["H8551","from holding",119,131],["H7810","of bribes",132,141],["H0331","that stoppeth",143,156],["H0241","his ears",157,165],["H8085","from hearing",166,178],["H1818","of blood",179,187],["H6105","and shutteth",189,201],["H5869","his eyes",202,210],["H7200","from seeing",211,222],["H7451","evil",223,227]]},"33:16":{"text":"He shall dwell on high: his place of defence shall be the munitions of rocks: bread shall be given him; his waters shall be sure.","words":[["H7931","He shall dwell",0,14],["H4791","on high",15,22],["H4869","his place of defence",24,44],["H4679","shall be the munitions",45,67],["H5553","of rocks",68,76],["H3899","bread",78,83],["H5414","shall be given",84,98],["H4325","him; his waters",99,114],["H0539","shall be sure",115,128]]},"33:17":{"text":"Thine eyes shall see the king in his beauty: they shall behold the land that is very far off.","words":[["H5869","Thine eyes",0,10],["H2372","shall see",11,20],["H4428","the king",21,29],["H3308","in his beauty",30,43],["H7200","they shall behold",45,62],["H0776","the land",63,71],["H4801","that is very far off",72,92]]},"33:18":{"text":"Thine heart shall meditate terror. Where is the scribe? where is the receiver? where is he that counted the towers?","words":[["H3820","Thine heart",0,11],["H1897","shall meditate",12,26],["H0367","terror",27,33],["H5608","Where is the scribe",35,54],["H8254","where is the receiver",56,77],["H5608","where is he that counted",79,103],["H4026","the towers",104,114]]},"33:19":{"text":"Thou shalt not see a fierce people, a people of a deeper speech than thou canst perceive; of a stammering tongue, that thou canst not understand.","words":[["H7200","Thou shalt not see",0,18],["H3267","a fierce",19,27],["H5971","people",28,34],["H5971","a people",36,44],["H6012","of a deeper",45,56],["H8193","speech",57,63],["H8085","than thou canst perceive",64,88],["H3932","of a stammering",90,105],["H3956","tongue",106,112],["H0998","that thou canst not understand",114,144]]},"33:20":{"text":"Look upon Zion, the city of our solemnities: thine eyes shall see Jerusalem a quiet habitation, a tabernacle that shall not be taken down; not one of the stakes thereof shall ever be removed, neither shall any of the cords thereof be broken.","words":[["H2372","Look",0,4],["H6726","upon Zion",5,14],["H7151","the city",16,24],["H4150","of our solemnities",25,43],["H5869","thine eyes",45,55],["H7200","shall see",56,65],["H3389","Jerusalem",66,75],["H7600","a quiet",76,83],["H5116","habitation",84,94],["H0168","a tabernacle",96,108],["H6813","that shall not be taken down",109,137],["H3489","not one of the stakes",139,160],["H5331","thereof shall ever",161,179],["H5265","be removed",180,190],["H2256","neither shall any of the cords",192,222],["H5423","thereof be broken",223,240]]},"33:21":{"text":"But there the glorious LORD will be unto us a place of broad rivers and streams; wherein shall go no galley with oars, neither shall gallant ship pass thereby.","words":[["H0117","But there the glorious",0,22],["H3068","LORD",23,27],["H4725","will be unto us a place",28,51],["H7342","of broad",52,60],["H3027","of broad",52,60],["H5104","rivers",61,67],["H2975","and streams",68,79],["H3212","wherein shall go",81,97],["H1077","no",98,100],["H0590","galley",101,107],["H7885","with oars",108,117],["H0117","neither shall gallant",119,140],["H6716","ship",141,145],["H5674","pass",146,150]]},"33:22":{"text":"For the LORD is our judge, the LORD is our lawgiver, the LORD is our king; he will save us.","words":[["H3068","For the LORD",0,12],["H8199","is our judge",13,25],["H3068","the LORD",27,35],["H2710","is our lawgiver",36,51],["H3068","the LORD",53,61],["H4428","is our king",62,73],["H3467","he will save",75,87]]},"33:23":{"text":"Thy tacklings are loosed; they could not well strengthen their mast, they could not spread the sail: then is the prey of a great spoil divided; the lame take the prey.","words":[["H2256","Thy tacklings",0,13],["H5203","are loosed",14,24],["H3653","they could not well",26,45],["H2388","strengthen",46,56],["H8650","their mast",57,67],["H6566","they could not spread",69,90],["H5251","the sail",91,99],["H5706","then is the prey",101,117],["H4766","of a great",118,128],["H7998","spoil",129,134],["H2505","divided",135,142],["H6455","the lame",144,152],["H0962","take",153,157],["H0957","the prey",158,166]]},"33:24":{"text":"And the inhabitant shall not say, I am sick: the people that dwell therein shall be forgiven their iniquity.","words":[["H7934","And the inhabitant",0,18],["H0559","shall not say",19,32],["H2470","I am sick",34,43],["H5971","the people",45,55],["H3427","that dwell",56,66],["H5375","therein shall be forgiven",67,92],["H5771","their iniquity",93,107]]},"34:1":{"text":"Come near, ye nations, to hear; and hearken, ye people: let the earth hear, and all that is therein; the world, and all things that come forth of it.","words":[["H7126","Come near",0,9],["H1471","ye nations",11,21],["H8085","to hear",23,30],["H7181","and hearken",32,43],["H3816","ye people",45,54],["H0776","let the earth",56,69],["H8085","hear",70,74],["H4393","and all that is therein",76,99],["H8398","the world",101,110],["H6631","and all things that come forth",112,142]]},"34:2":{"text":"For the indignation of the LORD is upon all nations, and his fury upon all their armies: he hath utterly destroyed them, he hath delivered them to the slaughter.","words":[["H7110","For the indignation",0,19],["H3068","of the LORD",20,31],["H1471","is upon all nations",32,51],["H2534","and his fury",53,65],["H6635","upon all their armies",66,87],["H2763","he hath utterly destroyed",89,114],["H5414","them, he hath delivered",115,138],["H2874","them to the slaughter",139,160]]},"34:3":{"text":"Their slain also shall be cast out, and their stink shall come up out of their carcases, and the mountains shall be melted with their blood.","words":[["H2491","Their slain",0,11],["H7993","also shall be cast out",12,34],["H0889","and their stink",36,51],["H5927","shall come up",52,65],["H6297","out of their carcases",66,87],["H2022","and the mountains",89,106],["H4549","shall be melted",107,122],["H1818","with their blood",123,139]]},"34:4":{"text":"And all the host of heaven shall be dissolved, and the heavens shall be rolled together as a scroll: and all their host shall fall down, as the leaf falleth off from the vine, and as a falling fig from the fig tree.","words":[["H6635","And all the host",0,16],["H8064","of heaven",17,26],["H4743","shall be dissolved",27,45],["H8064","and the heavens",47,62],["H1556","shall be rolled together",63,87],["H5612","as a scroll",88,99],["H6635","and all their host",101,119],["H5034","shall fall down",120,135],["H5929","as the leaf",137,148],["H5034","falleth off",149,160],["H1612","from the vine",161,174],["H5034","and as a falling",176,192],["H8384","fig from the fig tree",193,214]]},"34:5":{"text":"For my sword shall be bathed in heaven: behold, it shall come down upon Idumea, and upon the people of my curse, to judgment.","words":[["H2719","For my sword",0,12],["H7301","shall be bathed",13,28],["H8064","in heaven",29,38],["H3381","behold, it shall come down",40,66],["H0123","upon Idumea",67,78],["H5971","and upon the people",80,99],["H2764","of my curse",100,111],["H4941","to judgment",113,124]]},"34:6":{"text":"The sword of the LORD is filled with blood, it is made fat with fatness, and with the blood of lambs and goats, with the fat of the kidneys of rams: for the LORD hath a sacrifice in Bozrah, and a great slaughter in the land of Idumea.","words":[["H2719","The sword",0,9],["H3068","of the LORD",10,21],["H4390","is filled",22,31],["H1818","with blood",32,42],["H1878","it is made fat",44,58],["H2459","with fatness",59,71],["H1818","and with the blood",73,91],["H3733","of lambs",92,100],["H6260","and goats",101,110],["H2459","with the fat",112,124],["H3629","of the kidneys",125,139],["H0352","of rams",140,147],["H3068","for the LORD",149,161],["H2077","hath a sacrifice",162,178],["H1224","in Bozrah",179,188],["H1419","and a great",190,201],["H2874","slaughter",202,211],["H0776","in the land",212,223],["H0123","of Idumea",224,233]]},"34:7":{"text":"And the unicorns shall come down with them, and the bullocks with the bulls; and their land shall be soaked with blood, and their dust made fat with fatness.","words":[["H7214","And the unicorns",0,16],["H3381","shall come down",17,32],["H6499","with them, and the bullocks",33,60],["H0047","with the bulls",61,75],["H0776","and their land",77,91],["H7301","shall be soaked",92,107],["H1818","with blood",108,118],["H6083","and their dust",120,134],["H1878","made fat",135,143],["H2459","with fatness",144,156]]},"34:8":{"text":"For it is the day of the LORD'S vengeance, and the year of recompences for the controversy of Zion.","words":[["H3117","For it is the day",0,17],["H3068","of the LORD'S",18,31],["H5359","vengeance",32,41],["H8141","and the year",43,55],["H7966","of recompences",56,70],["H7379","for the controversy",71,90],["H6726","of Zion",91,98]]},"34:9":{"text":"And the streams thereof shall be turned into pitch, and the dust thereof into brimstone, and the land thereof shall become burning pitch.","words":[["H5158","And the streams",0,15],["H2015","thereof shall be turned",16,39],["H2203","into pitch",40,50],["H6083","and the dust",52,64],["H1614","thereof into brimstone",65,87],["H0776","and the land",89,101],["H1197","thereof shall become burning",102,130],["H2203","pitch",131,136]]},"34:10":{"text":"It shall not be quenched night nor day; the smoke thereof shall go up for ever: from generation to generation it shall lie waste; none shall pass through it for ever and ever.","words":[["H3518","It shall not be quenched",0,24],["H3915","night",25,30],["H3119","nor day",31,38],["H6227","the smoke",40,49],["H5927","thereof shall go up",50,69],["H5769","for ever",70,78],["H1755","from generation",80,95],["H1755","to generation",96,109],["H2717","it shall lie waste",110,128],["H5674","none shall pass through",130,153],["H5331","it for ever",154,165],["H5331","and ever",166,174]]},"34:11":{"text":"But the cormorant and the bittern shall possess it; the owl also and the raven shall dwell in it: and he shall stretch out upon it the line of confusion, and the stones of emptiness.","words":[["H6893","But the cormorant",0,17],["H7090","and the bittern",18,33],["H3423","shall possess",34,47],["H3244","it; the owl",48,59],["H6158","also and the raven",60,78],["H7931","shall dwell",79,90],["H5186","in it: and he shall stretch out",91,122],["H6957","upon it the line",123,139],["H8414","of confusion",140,152],["H0068","and the stones",154,168],["H0922","of emptiness",169,181]]},"34:12":{"text":"They shall call the nobles thereof to the kingdom, but none shall be there, and all her princes shall be nothing.","words":[["H7121","They shall call",0,15],["H2715","the nobles",16,26],["H4410","thereof to the kingdom",27,49],["H8269","but none shall be there, and all her princes",51,95],["H0657","shall be nothing",96,112]]},"34:13":{"text":"And thorns shall come up in her palaces, nettles and brambles in the fortresses thereof: and it shall be an habitation of dragons, and a court for owls.","words":[["H5518","And thorns",0,10],["H5927","shall come up",11,24],["H0759","in her palaces",25,39],["H7057","nettles",41,48],["H2336","and brambles",49,61],["H4013","in the fortresses",62,79],["H5116","thereof: and it shall be an habitation",80,118],["H8577","of dragons",119,129],["H2681","and a court",131,142],["H1323","for owls",143,151],["H3284","for owls",143,151]]},"34:14":{"text":"The wild beasts of the desert shall also meet with the wild beasts of the island, and the satyr shall cry to his fellow; the screech owl also shall rest there, and find for herself a place of rest.","words":[["H6728","The wild beasts of the desert",0,29],["H6298","shall also meet",30,45],["H0338","with the wild beasts of the island",46,80],["H8163","and the satyr",82,95],["H7121","shall cry",96,105],["H7453","to his fellow",106,119],["H3917","the screech owl",121,136],["H7280","also shall rest",137,152],["H4672","there, and find",153,168],["H4494","for herself a place of rest",169,196]]},"34:15":{"text":"There shall the great owl make her nest, and lay, and hatch, and gather under her shadow: there shall the vultures also be gathered, every one with her mate.","words":[["H7091","There shall the great owl",0,25],["H7077","make her nest",26,39],["H4422","and lay",41,48],["H1234","and hatch",50,59],["H1716","and gather",61,71],["H6738","under her shadow",72,88],["H1772","there shall the vultures",90,114],["H6908","also be gathered",115,131],["H0802","every one",133,142],["H7468","with her mate",143,156]]},"34:16":{"text":"Seek ye out of the book of the LORD, and read: no one of these shall fail, none shall want her mate: for my mouth it hath commanded, and his spirit it hath gathered them.","words":[["H1875","Seek ye out",0,11],["H5612","of the book",12,23],["H3068","of the LORD",24,35],["H7121","and read",37,45],["H0259","no one",47,53],["H2007","of these",54,62],["H5737","shall fail",63,73],["H0802","none",75,79],["H6485","shall want",80,90],["H7468","her mate",91,99],["H6310","for my mouth",101,113],["H6680","it hath commanded",114,131],["H7307","and his spirit",133,147],["H6908","it hath gathered",148,164]]},"34:17":{"text":"And he hath cast the lot for them, and his hand hath divided it unto them by line: they shall possess it for ever, from generation to generation shall they dwell therein.","words":[["H5307","And he hath cast",0,16],["H1486","the lot",17,24],["H3027","for them, and his hand",25,47],["H2505","hath divided",48,60],["H6957","it unto them by line",61,81],["H3423","they shall possess",83,101],["H5704","it for",102,108],["H5769","ever",109,113],["H1755","from generation",115,130],["H1755","to generation",131,144],["H7931","shall they dwell",145,161]]},"35:1":{"text":"The wilderness and the solitary place shall be glad for them; and the desert shall rejoice, and blossom as the rose.","words":[["H4057","The wilderness",0,14],["H6723","and the solitary place",15,37],["H7797","shall be glad",38,51],["H6160","for them; and the desert",52,76],["H1523","shall rejoice",77,90],["H6524","and blossom",92,103],["H2261","as the rose",104,115]]},"35:2":{"text":"It shall blossom abundantly, and rejoice even with joy and singing: the glory of Lebanon shall be given unto it, the excellency of Carmel and Sharon, they shall see the glory of the LORD, and the excellency of our God.","words":[["H6524","It shall blossom",0,16],["H6524","abundantly",17,27],["H1523","and rejoice",29,40],["H1525","even with joy",41,54],["H7444","and singing",55,66],["H3519","the glory",68,77],["H3844","of Lebanon",78,88],["H5414","shall be given",89,103],["H1926","unto it, the excellency",104,127],["H3760","of Carmel",128,137],["H8289","and Sharon",138,148],["H7200","they shall see",150,164],["H3519","the glory",165,174],["H3068","of the LORD",175,186],["H1926","and the excellency",188,206],["H0430","of our God",207,217]]},"35:3":{"text":"Strengthen ye the weak hands, and confirm the feeble knees.","words":[["H2388","Strengthen",0,10],["H7504","ye the weak",11,22],["H3027","hands",23,28],["H0553","and confirm",30,41],["H3782","the feeble",42,52],["H1290","knees",53,58]]},"35:4":{"text":"Say to them that are of a fearful heart, Be strong, fear not: behold, your God will come with vengeance, even God with a recompence; he will come and save you.","words":[["H0559","Say",0,3],["H4116","to them that are of a fearful",4,33],["H3820","heart",34,39],["H2388","Be strong",41,50],["H3372","fear",52,56],["H0430","not: behold, your God",57,78],["H0935","will come",79,88],["H5359","with vengeance",89,103],["H0430","even God",105,113],["H1576","with a recompence",114,131],["H0935","he will come",133,145],["H3467","and save",146,154]]},"35:5":{"text":"Then the eyes of the blind shall be opened, and the ears of the deaf shall be unstopped.","words":[["H5869","Then the eyes",0,13],["H5787","of the blind",14,26],["H6491","shall be opened",27,42],["H0241","and the ears",44,56],["H2795","of the deaf",57,68],["H6605","shall be unstopped",69,87]]},"35:6":{"text":"Then shall the lame man leap as an hart, and the tongue of the dumb sing: for in the wilderness shall waters break out, and streams in the desert.","words":[["H6455","Then shall the lame",0,19],["H1801","man leap",20,28],["H0354","as an hart",29,39],["H3956","and the tongue",41,55],["H0483","of the dumb",56,67],["H7442","sing",68,72],["H4057","for in the wilderness",74,95],["H4325","shall waters",96,108],["H1234","break out",109,118],["H5158","and streams",120,131],["H6160","in the desert",132,145]]},"35:7":{"text":"And the parched ground shall become a pool, and the thirsty land springs of water: in the habitation of dragons, where each lay, shall be grass with reeds and rushes.","words":[["H8273","And the parched ground",0,22],["H0098","shall become a pool",23,42],["H6774","and the thirsty land",44,64],["H4002","springs",65,72],["H4325","of water",73,81],["H5116","in the habitation",83,100],["H8577","of dragons",101,111],["H7258","where each lay",113,127],["H2682","shall be grass",129,143],["H7070","with reeds",144,154],["H1573","and rushes",155,165]]},"35:8":{"text":"And an highway shall be there, and a way, and it shall be called The way of holiness; the unclean shall not pass over it; but it shall be for those: the wayfaring men, though fools, shall not err therein.","words":[["H4547","And an highway",0,14],["H1870","shall be there, and a way",15,40],["H7121","and it shall be called",42,64],["H1870","The way",65,72],["H6944","of holiness",73,84],["H2931","the unclean",86,97],["H5674","shall not pass over",98,117],["H1980","it; but it shall be for those: the wayfaring men",118,166],["H0191","though fools",168,180],["H8582","shall not err",182,195]]},"35:9":{"text":"No lion shall be there, nor any ravenous beast shall go up thereon, it shall not be found there; but the redeemed shall walk there:","words":[["H0738","No lion",0,7],["H6530","shall be there, nor any ravenous",8,40],["H2416","beast",41,46],["H5927","shall go up",47,58],["H4672","thereon, it shall not be found",59,89],["H1350","there; but the redeemed",90,113],["H1980","shall walk",114,124]]},"35:10":{"text":"And the ransomed of the LORD shall return, and come to Zion with songs and everlasting joy upon their heads: they shall obtain joy and gladness, and sorrow and sighing shall flee away.","words":[["H6299","And the ransomed",0,16],["H3068","of the LORD",17,28],["H7725","shall return",29,41],["H0935","and come",43,51],["H6726","to Zion",52,59],["H7440","with songs",60,70],["H5769","and everlasting",71,86],["H8057","joy",87,90],["H7218","upon their heads",91,107],["H5381","they shall obtain",109,126],["H8057","joy",127,130],["H8342","and gladness",131,143],["H3015","and sorrow",145,155],["H0585","and sighing",156,167],["H5127","shall flee away",168,183]]},"36:1":{"text":"Now it came to pass in the fourteenth year of king Hezekiah, that Sennacherib king of Assyria came up against all the defenced cities of Judah, and took them.","words":[["H0702","Now it came to pass in the fourteenth",0,37],["H6240","Now it came to pass in the fourteenth",0,37],["H8141","year",38,42],["H4428","of king",43,50],["H2396","Hezekiah",51,59],["H5576","that Sennacherib",61,77],["H4428","king",78,82],["H0804","of Assyria",83,93],["H5927","came up",94,101],["H1219","against all the defenced",102,126],["H5892","cities",127,133],["H3063","of Judah",134,142],["H8610","and took",144,152]]},"36:2":{"text":"And the king of Assyria sent Rabshakeh from Lachish to Jerusalem unto king Hezekiah with a great army. And he stood by the conduit of the upper pool in the highway of the fuller's field.","words":[["H4428","And the king",0,12],["H0804","of Assyria",13,23],["H7971","sent",24,28],["H7262","Rabshakeh",29,38],["H3923","from Lachish",39,51],["H3389","to Jerusalem",52,64],["H4428","unto king",65,74],["H2396","Hezekiah",75,83],["H3515","with a great",84,96],["H2426","army",97,101],["H5975","And he stood",103,115],["H8585","by the conduit",116,130],["H5945","of the upper",131,143],["H1295","pool",144,148],["H4546","in the highway",149,163],["H3526","of the fuller's",164,179],["H7704","field",180,185]]},"36:3":{"text":"Then came forth unto him Eliakim, Hilkiah's son, which was over the house, and Shebna the scribe, and Joah, Asaph's son, the recorder.","words":[["H3318","Then came forth",0,15],["H0471","unto him Eliakim",16,32],["H2518","Hilkiah's",34,43],["H1121","son",44,47],["H1004","which was over the house",49,73],["H7644","and Shebna",75,85],["H5608","the scribe",86,96],["H3098","and Joah",98,106],["H0623","Asaph's",108,115],["H1121","son",116,119],["H2142","the recorder",121,133]]},"36:4":{"text":"And Rabshakeh said unto them, Say ye now to Hezekiah, Thus saith the great king, the king of Assyria, What confidence is this wherein thou trustest?","words":[["H7262","And Rabshakeh",0,13],["H0559","said",14,18],["H0559","unto them, Say",19,33],["H2396","ye now to Hezekiah",34,52],["H0559","Thus saith",54,64],["H1419","the great",65,74],["H4428","king",75,79],["H4428","the king",81,89],["H0804","of Assyria",90,100],["H0986","What confidence",102,117],["H0982","is this wherein thou trustest",118,147]]},"36:5":{"text":"I say, sayest thou, (but they are but vain words) I have counsel and strength for war: now on whom dost thou trust, that thou rebellest against me?","words":[["H0559","I say",0,5],["H8193","sayest thou, (but they are but vain",7,42],["H1697","words",43,48],["H6098","I have counsel",50,64],["H1369","and strength",65,77],["H4421","for war",78,85],["H0982","now on whom dost thou trust",87,114],["H4775","that thou rebellest",116,135]]},"36:6":{"text":"Lo, thou trustest in the staff of this broken reed, on Egypt; whereon if a man lean, it will go into his hand, and pierce it: so is Pharaoh king of Egypt to all that trust in him.","words":[["H0982","Lo, thou trustest",0,17],["H4938","in the staff",18,30],["H7533","of this broken",31,45],["H7070","reed",46,50],["H4714","on Egypt",52,60],["H0376","whereon if a man",62,78],["H5564","lean",79,83],["H0935","it will go",85,95],["H3709","into his hand",96,109],["H5344","and pierce",111,121],["H6547","it: so is Pharaoh",122,139],["H4428","king",140,144],["H4714","of Egypt",145,153],["H0982","to all that trust",154,171]]},"36:7":{"text":"But if thou say to me, We trust in the LORD our God: is it not he, whose high places and whose altars Hezekiah hath taken away, and said to Judah and to Jerusalem, Ye shall worship before this altar?","words":[["H0559","But if thou say",0,15],["H0982","to me, We trust",16,31],["H3068","in the LORD",32,43],["H0430","our God",44,51],["H1116","is it not he, whose high places",53,84],["H4196","and whose altars",85,101],["H2396","Hezekiah",102,110],["H5493","hath taken away",111,126],["H0559","and said",128,136],["H3063","to Judah",137,145],["H3389","and to Jerusalem",146,162],["H7812","Ye shall worship",164,180],["H6440","before",181,187],["H4196","this altar",188,198]]},"36:8":{"text":"Now therefore give pledges, I pray thee, to my master the king of Assyria, and I will give thee two thousand horses, if thou be able on thy part to set riders upon them.","words":[["H6148","Now therefore give pledges",0,26],["H0113","I pray thee, to my master",28,53],["H4428","the king",54,62],["H0804","of Assyria",63,73],["H5414","and I will give",75,90],["H0505","thee two thousand",91,108],["H5483","horses",109,115],["H3201","if thou be able",117,132],["H5414","on thy part to set",133,151],["H7392","riders",152,158]]},"36:9":{"text":"How then wilt thou turn away the face of one captain of the least of my master's servants, and put thy trust on Egypt for chariots and for horsemen?","words":[["H7725","How then wilt thou turn away",0,28],["H6440","the face",29,37],["H0259","of one",38,44],["H6346","captain",45,52],["H6996","of the least",53,65],["H0113","of my master's",66,80],["H5650","servants",81,89],["H0982","and put thy trust",91,108],["H4714","on Egypt",109,117],["H7393","for chariots",118,130],["H6571","and for horsemen",131,147]]},"36:10":{"text":"And am I now come up without the LORD against this land to destroy it? the LORD said unto me, Go up against this land, and destroy it.","words":[["H5927","And am I now come up",0,20],["H1107","without",21,28],["H3068","the LORD",29,37],["H0776","against this land",38,55],["H7843","to destroy",56,66],["H3068","it? the LORD",67,79],["H0559","said",80,84],["H5927","unto me, Go up",85,99],["H0776","against this land",100,117],["H7843","and destroy",119,130]]},"36:11":{"text":"Then said Eliakim and Shebna and Joah unto Rabshakeh, Speak, I pray thee, unto thy servants in the Syrian language; for we understand it: and speak not to us in the Jews' language, in the ears of the people that are on the wall.","words":[["H0559","Then said",0,9],["H0471","Eliakim",10,17],["H7644","and Shebna",18,28],["H3098","and Joah",29,37],["H7262","unto Rabshakeh",38,52],["H1696","Speak",54,59],["H5650","I pray thee, unto thy servants",61,91],["H0762","in the Syrian language",92,114],["H8085","for we understand",116,133],["H1696","it: and speak",134,147],["H3066","not to us in the Jews' language",148,179],["H0241","in the ears",181,192],["H5971","of the people",193,206],["H2346","that are on the wall",207,227]]},"36:12":{"text":"But Rabshakeh said, Hath my master sent me to thy master and to thee to speak these words? hath he not sent me to the men that sit upon the wall, that they may eat their own dung, and drink their own piss with you?","words":[["H7262","But Rabshakeh",0,13],["H0559","said",14,18],["H0113","Hath my master",20,34],["H7971","sent",35,39],["H0113","me to thy master",40,56],["H1696","and to thee to speak",57,77],["H1697","these words",78,89],["H0582","hath he not sent me to the men",91,121],["H3427","that sit",122,130],["H2346","upon the wall",131,144],["H0398","that they may eat",146,163],["H2716","their own dung",164,178],["H6675","their own dung",164,178],["H8354","and drink",180,189],["H4325","their own piss",190,204],["H7272","their own piss",190,204],["H7890","their own piss",190,204]]},"36:13":{"text":"Then Rabshakeh stood, and cried with a loud voice in the Jews' language, and said, Hear ye the words of the great king, the king of Assyria.","words":[["H7262","Then Rabshakeh",0,14],["H5975","stood",15,20],["H7121","and cried",22,31],["H1419","with a loud",32,43],["H6963","voice",44,49],["H3066","in the Jews' language",50,71],["H0559","and said",73,81],["H8085","Hear",83,87],["H1697","ye the words",88,100],["H1419","of the great",101,113],["H4428","king",114,118],["H4428","the king",120,128],["H0804","of Assyria",129,139]]},"36:14":{"text":"Thus saith the king, Let not Hezekiah deceive you: for he shall not be able to deliver you.","words":[["H0559","Thus saith",0,10],["H4428","the king",11,19],["H2396","Let not Hezekiah",21,37],["H5377","deceive",38,45],["H3201","you: for he shall not be able",46,75],["H5337","to deliver",76,86]]},"36:15":{"text":"Neither let Hezekiah make you trust in the LORD, saying, The LORD will surely deliver us: this city shall not be delivered into the hand of the king of Assyria.","words":[["H2396","Neither let Hezekiah",0,20],["H0982","make you trust",21,35],["H3068","in the LORD",36,47],["H0559","saying",49,55],["H3068","The LORD",57,65],["H5337","will surely",66,77],["H5337","deliver",78,85],["H5892","us: this city",86,99],["H5414","shall not be delivered",100,122],["H3027","into the hand",123,136],["H4428","of the king",137,148],["H0804","of Assyria",149,159]]},"36:16":{"text":"Hearken not to Hezekiah: for thus saith the king of Assyria, Make an agreement with me by a present, and come out to me: and eat ye every one of his vine, and every one of his fig tree, and drink ye every one the waters of his own cistern;","words":[["H8085","Hearken",0,7],["H2396","not to Hezekiah",8,23],["H0559","for thus saith",25,39],["H4428","the king",40,48],["H0804","of Assyria",49,59],["H6213","Make",61,65],["H1293","an agreement with me by a present",66,99],["H3318","and come out",101,113],["H0398","to me: and eat",114,128],["H0376","ye every one",129,141],["H1612","of his vine",142,153],["H0376","and every one",155,168],["H8384","of his fig tree",169,184],["H8354","and drink",186,195],["H0376","ye every one",196,208],["H4325","the waters",209,219],["H0953","of his own cistern",220,238]]},"36:17":{"text":"Until I come and take you away to a land like your own land, a land of corn and wine, a land of bread and vineyards.","words":[["H0935","Until I come",0,12],["H3947","and take you away",13,30],["H0776","to a land",31,40],["H0776","like your own land",41,59],["H0776","a land",61,67],["H1715","of corn",68,75],["H8492","and wine",76,84],["H0776","a land",86,92],["H3899","of bread",93,101],["H3754","and vineyards",102,115]]},"36:18":{"text":"Beware lest Hezekiah persuade you, saying, The LORD will deliver us. Hath any of the gods of the nations delivered his land out of the hand of the king of Assyria?","words":[["H2396","Beware lest Hezekiah",0,20],["H5496","persuade",21,29],["H0559","you, saying",30,41],["H3068","The LORD",43,51],["H5337","will deliver",52,64],["H0376","us. Hath any",65,77],["H0430","of the gods",78,89],["H1471","of the nations",90,104],["H5337","delivered",105,114],["H0776","his land",115,123],["H3027","out of the hand",124,139],["H4428","of the king",140,151],["H0804","of Assyria",152,162]]},"36:19":{"text":"Where are the gods of Hamath and Arphad? where are the gods of Sepharvaim? and have they delivered Samaria out of my hand?","words":[["H0430","Where are the gods",0,18],["H2574","of Hamath",19,28],["H0774","and Arphad",29,39],["H0430","where are the gods",41,59],["H5617","of Sepharvaim",60,73],["H5337","and have they delivered",75,98],["H8111","Samaria",99,106],["H3027","out of my hand",107,121]]},"36:20":{"text":"Who are they among all the gods of these lands, that have delivered their land out of my hand, that the LORD should deliver Jerusalem out of my hand?","words":[["H0430","Who are they among all the gods",0,31],["H0776","of these lands",32,46],["H5337","that have delivered",48,67],["H0776","their land",68,78],["H3027","out of my hand",79,93],["H3068","that the LORD",95,108],["H5337","should deliver",109,123],["H3389","Jerusalem",124,133],["H3027","out of my hand",134,148]]},"36:21":{"text":"But they held their peace, and answered him not a word: for the king's commandment was, saying, Answer him not.","words":[["H2790","But they held their peace",0,25],["H6030","and answered",27,39],["H1697","him not a word",40,54],["H4428","for the king's",56,70],["H4687","commandment",71,82],["H0559","was, saying",83,94],["H6030","Answer",96,102]]},"36:22":{"text":"Then came Eliakim, the son of Hilkiah, that was over the household, and Shebna the scribe, and Joah, the son of Asaph, the recorder, to Hezekiah with their clothes rent, and told him the words of Rabshakeh.","words":[["H0935","Then came",0,9],["H0471","Eliakim",10,17],["H1121","the son",19,26],["H2518","of Hilkiah",27,37],["H1004","that was over the household",39,66],["H7644","and Shebna",68,78],["H5608","the scribe",79,89],["H3098","and Joah",91,99],["H1121","the son",101,108],["H0623","of Asaph",109,117],["H2142","the recorder",119,131],["H2396","to Hezekiah",133,144],["H0899","with their clothes",145,163],["H7167","rent",164,168],["H5046","and told",170,178],["H1697","him the words",179,192],["H7262","of Rabshakeh",193,205]]},"37:1":{"text":"And it came to pass, when king Hezekiah heard it, that he rent his clothes, and covered himself with sackcloth, and went into the house of the LORD.","words":[["H4428","And it came to pass, when king",0,30],["H2396","Hezekiah",31,39],["H8085","heard",40,45],["H7167","it, that he rent",46,62],["H0899","his clothes",63,74],["H3680","and covered",76,87],["H8242","himself with sackcloth",88,110],["H0935","and went",112,120],["H1004","into the house",121,135],["H3068","of the LORD",136,147]]},"37:2":{"text":"And he sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests covered with sackcloth, unto Isaiah the prophet the son of Amoz.","words":[["H7971","And he sent",0,11],["H0471","Eliakim",12,19],["H1004","who was over the household",21,47],["H7644","and Shebna",49,59],["H5608","the scribe",60,70],["H2205","and the elders",72,86],["H3548","of the priests",87,101],["H3680","covered",102,109],["H8242","with sackcloth",110,124],["H3470","unto Isaiah",126,137],["H5030","the prophet",138,149],["H1121","the son",150,157],["H0531","of Amoz",158,165]]},"37:3":{"text":"And they said unto him, Thus saith Hezekiah, This day is a day of trouble, and of rebuke, and of blasphemy: for the children are come to the birth, and there is not strength to bring forth.","words":[["H0559","And they said",0,13],["H0559","unto him, Thus saith",14,34],["H2396","Hezekiah",35,43],["H3117","This day",45,53],["H3117","is a day",54,62],["H6869","of trouble",63,73],["H8433","and of rebuke",75,88],["H5007","and of blasphemy",90,106],["H1121","for the children",108,124],["H0935","are come",125,133],["H4866","to the birth",134,146],["H3581","and there is not strength",148,173],["H3205","to bring forth",174,188]]},"37:4":{"text":"It may be the LORD thy God will hear the words of Rabshakeh, whom the king of Assyria his master hath sent to reproach the living God, and will reprove the words which the LORD thy God hath heard: wherefore lift up thy prayer for the remnant that is left.","words":[["H3068","It may be the LORD",0,18],["H0430","thy God",19,26],["H8085","will hear",27,36],["H1697","the words",37,46],["H7262","of Rabshakeh",47,59],["H4428","whom the king",61,74],["H0804","of Assyria",75,85],["H0113","his master",86,96],["H7971","hath sent",97,106],["H2778","to reproach",107,118],["H2416","the living",119,129],["H0430","God",130,133],["H3198","and will reprove",135,151],["H1697","the words",152,161],["H3068","which the LORD",162,176],["H0430","thy God",177,184],["H8085","hath heard",185,195],["H5375","wherefore lift up",197,214],["H8605","thy prayer",215,225],["H7611","for the remnant",226,241],["H4672","that is left",242,254]]},"37:5":{"text":"So the servants of king Hezekiah came to Isaiah.","words":[["H5650","So the servants",0,15],["H4428","of king",16,23],["H2396","Hezekiah",24,32],["H0935","came",33,37],["H3470","to Isaiah",38,47]]},"37:6":{"text":"And Isaiah said unto them, Thus shall ye say unto your master, Thus saith the LORD, Be not afraid of the words that thou hast heard, wherewith the servants of the king of Assyria have blasphemed me.","words":[["H3470","And Isaiah",0,10],["H0559","said",11,15],["H0559","unto them, Thus shall ye say",16,44],["H0113","unto your master",45,61],["H0559","Thus saith",63,73],["H3068","the LORD",74,82],["H3372","Be not afraid",84,97],["H6440","of",98,100],["H1697","the words",101,110],["H8085","that thou hast heard",111,131],["H5288","wherewith the servants",133,155],["H4428","of the king",156,167],["H0804","of Assyria",168,178],["H1442","have blasphemed",179,194]]},"37:7":{"text":"Behold, I will send a blast upon him, and he shall hear a rumour, and return to his own land; and I will cause him to fall by the sword in his own land.","words":[["H5414","Behold, I will send",0,19],["H7307","a blast",20,27],["H8085","upon him, and he shall hear",28,55],["H8052","a rumour",56,64],["H7725","and return",66,76],["H0776","to his own land",77,92],["H5307","and I will cause him to fall",94,122],["H2719","by the sword",123,135],["H0776","in his own land",136,151]]},"37:8":{"text":"So Rabshakeh returned, and found the king of Assyria warring against Libnah: for he had heard that he was departed from Lachish.","words":[["H7262","So Rabshakeh",0,12],["H7725","returned",13,21],["H4672","and found",23,32],["H4428","the king",33,41],["H0804","of Assyria",42,52],["H3898","warring",53,60],["H3841","against Libnah",61,75],["H8085","for he had heard",77,93],["H5265","that he was departed",94,114],["H3923","from Lachish",115,127]]},"37:9":{"text":"And he heard say concerning Tirhakah king of Ethiopia, He is come forth to make war with thee. And when he heard it, he sent messengers to Hezekiah, saying,","words":[["H8085","And he heard",0,12],["H0559","say",13,16],["H8640","concerning Tirhakah",17,36],["H4428","king",37,41],["H3568","of Ethiopia",42,53],["H3318","He is come forth",55,71],["H3898","to make war",72,83],["H8085","with thee. And when he heard",84,112],["H7971","it, he sent",113,124],["H4397","messengers",125,135],["H2396","to Hezekiah",136,147],["H0559","saying",149,155]]},"37:10":{"text":"Thus shall ye speak to Hezekiah king of Judah, saying, Let not thy God, in whom thou trustest, deceive thee, saying, Jerusalem shall not be given into the hand of the king of Assyria.","words":[["H0559","Thus shall ye speak",0,19],["H2396","to Hezekiah",20,31],["H4428","king",32,36],["H3063","of Judah",37,45],["H0559","saying",47,53],["H0430","Let not thy God",55,70],["H0982","in whom thou trustest",72,93],["H5377","deceive",95,102],["H0559","thee, saying",103,115],["H3389","Jerusalem",117,126],["H5414","shall not be given",127,145],["H3027","into the hand",146,159],["H4428","of the king",160,171],["H0804","of Assyria",172,182]]},"37:11":{"text":"Behold, thou hast heard what the kings of Assyria have done to all lands by destroying them utterly; and shalt thou be delivered?","words":[["H8085","Behold, thou hast heard",0,23],["H4428","what the kings",24,38],["H0804","of Assyria",39,49],["H6213","have done",50,59],["H0776","to all lands",60,72],["H2763","by destroying them utterly",73,99],["H5337","and shalt thou be delivered",101,128]]},"37:12":{"text":"Have the gods of the nations delivered them which my fathers have destroyed, as Gozan, and Haran, and Rezeph, and the children of Eden which were in Telassar?","words":[["H0430","Have the gods",0,13],["H1471","of the nations",14,28],["H5337","delivered",29,38],["H0001","them which my fathers",39,60],["H7843","have destroyed",61,75],["H1470","as Gozan",77,85],["H2771","and Haran",87,96],["H7530","and Rezeph",98,108],["H1121","and the children",110,126],["H5729","of Eden",127,134],["H8515","which were in Telassar",135,157]]},"37:13":{"text":"Where is the king of Hamath, and the king of Arphad, and the king of the city of Sepharvaim, Hena, and Ivah?","words":[["H4428","Where is the king",0,17],["H2574","of Hamath",18,27],["H4428","and the king",29,41],["H0774","of Arphad",42,51],["H4428","and the king",53,65],["H5892","of the city",66,77],["H5617","of Sepharvaim",78,91],["H2012","Hena",93,97],["H5755","and Ivah",99,107]]},"37:14":{"text":"And Hezekiah received the letter from the hand of the messengers, and read it: and Hezekiah went up unto the house of the LORD, and spread it before the LORD.","words":[["H2396","And Hezekiah",0,12],["H3947","received",13,21],["H5612","the letter",22,32],["H3027","from the hand",33,46],["H4397","of the messengers",47,64],["H7121","and read",66,74],["H2396","it: and Hezekiah",75,91],["H5927","went up",92,99],["H1004","unto the house",100,114],["H3068","of the LORD",115,126],["H6566","and spread",128,138],["H6440","it before",139,148],["H3068","the LORD",149,157]]},"37:15":{"text":"And Hezekiah prayed unto the LORD, saying,","words":[["H2396","And Hezekiah",0,12],["H6419","prayed",13,19],["H3068","unto the LORD",20,33],["H0559","saying",35,41]]},"37:16":{"text":"O LORD of hosts, God of Israel, that dwellest between the cherubims, thou art the God, even thou alone, of all the kingdoms of the earth: thou hast made heaven and earth.","words":[["H3068","O LORD",0,6],["H6635","of hosts",7,15],["H0430","God",17,20],["H3478","of Israel",21,30],["H3427","that dwellest",32,45],["H3742","between the cherubims",46,67],["H0430","thou art the God",69,85],["H4467","even thou alone, of all the kingdoms",87,123],["H0776","of the earth",124,136],["H6213","thou hast made",138,152],["H8064","heaven",153,159],["H0776","and earth",160,169]]},"37:17":{"text":"Incline thine ear, O LORD, and hear; open thine eyes, O LORD, and see: and hear all the words of Sennacherib, which hath sent to reproach the living God.","words":[["H5186","Incline",0,7],["H0241","thine ear",8,17],["H3068","O LORD",19,25],["H8085","and hear",27,35],["H6491","open",37,41],["H5869","thine eyes",42,52],["H3068","O LORD",54,60],["H7200","and see",62,69],["H8085","and hear",71,79],["H1697","all the words",80,93],["H5576","of Sennacherib",94,108],["H7971","which hath sent",110,125],["H2778","to reproach",126,137],["H2416","the living",138,148],["H0430","God",149,152]]},"37:18":{"text":"Of a truth, LORD, the kings of Assyria have laid waste all the nations, and their countries,","words":[["H0551","Of a truth",0,10],["H3068","LORD",12,16],["H4428","the kings",18,27],["H0804","of Assyria",28,38],["H2717","have laid waste",39,54],["H0776","all the nations",55,70],["H0776","and their countries",72,91]]},"37:19":{"text":"And have cast their gods into the fire: for they were no gods, but the work of men's hands, wood and stone: therefore they have destroyed them.","words":[["H5414","And have cast",0,13],["H0430","their gods",14,24],["H0784","into the fire",25,38],["H0430","for they were no gods",40,61],["H4639","but the work",63,75],["H0120","of men's",76,84],["H3027","hands",85,90],["H6086","wood",92,96],["H0068","and stone",97,106],["H0006","therefore they have destroyed",108,137]]},"37:20":{"text":"Now therefore, O LORD our God, save us from his hand, that all the kingdoms of the earth may know that thou art the LORD, even thou only.","words":[["H3068","Now therefore, O LORD",0,21],["H0430","our God",22,29],["H3467","save",31,35],["H3027","us from his hand",36,52],["H4467","that all the kingdoms",54,75],["H0776","of the earth",76,88],["H3045","may know",89,97],["H3068","that thou art the LORD",98,120]]},"37:21":{"text":"Then Isaiah the son of Amoz sent unto Hezekiah, saying, Thus saith the LORD God of Israel, Whereas thou hast prayed to me against Sennacherib king of Assyria:","words":[["H3470","Then Isaiah",0,11],["H1121","the son",12,19],["H0531","of Amoz",20,27],["H7971","sent",28,32],["H2396","unto Hezekiah",33,46],["H0559","saying",48,54],["H0559","Thus saith",56,66],["H3068","the LORD",67,75],["H0430","God",76,79],["H3478","of Israel",80,89],["H6419","Whereas thou hast prayed",91,115],["H5576","to me against Sennacherib",116,141],["H4428","king",142,146],["H0804","of Assyria",147,157]]},"37:22":{"text":"This is the word which the LORD hath spoken concerning him; The virgin, the daughter of Zion, hath despised thee, and laughed thee to scorn; the daughter of Jerusalem hath shaken her head at thee.","words":[["H1697","This is the word",0,16],["H3068","which the LORD",17,31],["H1696","hath spoken",32,43],["H1330","concerning him; The virgin",44,70],["H1323","the daughter",72,84],["H6726","of Zion",85,92],["H0959","hath despised",94,107],["H3932","thee, and laughed thee to scorn;",108,140],["H1323","the daughter",141,153],["H3389","of Jerusalem",154,166],["H5128","hath shaken",167,178],["H7218","her head",179,187],["H0310","at thee",188,195]]},"37:23":{"text":"Whom hast thou reproached and blasphemed? and against whom hast thou exalted thy voice, and lifted up thine eyes on high? even against the Holy One of Israel.","words":[["H2778","Whom hast thou reproached",0,25],["H1442","and blasphemed",26,40],["H7311","and against whom hast thou exalted",42,76],["H6963","thy voice",77,86],["H5375","and lifted up",88,101],["H5869","thine eyes",102,112],["H4791","on high",113,120],["H6918","even against the Holy One",122,147],["H3478","of Israel",148,157]]},"37:24":{"text":"By thy servants hast thou reproached the Lord, and hast said, By the multitude of my chariots am I come up to the height of the mountains, to the sides of Lebanon; and I will cut down the tall cedars thereof, and the choice fir trees thereof: and I will enter into the height of his border, and the forest of his Carmel.","words":[["H3027","By",0,2],["H5650","thy servants",3,15],["H2778","hast thou reproached",16,36],["H0136","the Lord",37,45],["H0559","and hast said",47,60],["H7230","By the multitude",62,78],["H7393","of my chariots",79,93],["H5927","am I come up",94,106],["H4791","to the height",107,120],["H2022","of the mountains",121,137],["H3411","to the sides",139,151],["H3844","of Lebanon",152,162],["H3772","and I will cut down",164,183],["H6967","the tall",184,192],["H0730","cedars",193,199],["H4005","thereof, and the choice",200,223],["H1265","fir trees",224,233],["H0935","thereof: and I will enter",234,259],["H4791","into the height",260,275],["H7093","of his border",276,289],["H3293","and the forest",291,305],["H3760","of his Carmel",306,319]]},"37:25":{"text":"I have digged, and drunk water; and with the sole of my feet have I dried up all the rivers of the besieged places.","words":[["H6979","I have digged",0,13],["H8354","and drunk",15,24],["H4325","water",25,30],["H3709","and with the sole",32,49],["H6471","of my feet",50,60],["H2717","have I dried up",61,76],["H2975","all the rivers",77,91],["H4693","of the besieged places",92,114]]},"37:26":{"text":"Hast thou not heard long ago, how I have done it; and of ancient times, that I have formed it? now have I brought it to pass, that thou shouldest be to lay waste defenced cities into ruinous heaps.","words":[["H8085","Hast thou not heard",0,19],["H7350","long ago",20,28],["H6213","how I have done",30,45],["H6924","it; and of ancient",46,64],["H3117","times",65,70],["H3335","that I have formed",72,90],["H0935","it? now have I brought",91,113],["H7582","it to pass, that thou shouldest be to lay waste",114,161],["H1219","defenced",162,170],["H5892","cities",171,177],["H5327","into ruinous",178,190],["H1530","heaps",191,196]]},"37:27":{"text":"Therefore their inhabitants were of small power, they were dismayed and confounded: they were as the grass of the field, and as the green herb, as the grass on the housetops, and as corn blasted before it be grown up.","words":[["H3427","Therefore their inhabitants",0,27],["H7116","were of small",28,41],["H3027","power",42,47],["H2865","they were dismayed",49,67],["H0954","and confounded",68,82],["H6212","they were as the grass",84,106],["H7704","of the field",107,119],["H3419","and as the green",121,137],["H1877","herb",138,142],["H2682","as the grass",144,156],["H1406","on the housetops",157,173],["H7709","and as corn blasted",175,194],["H6440","before",195,201],["H7054","it be grown up",202,216]]},"37:28":{"text":"But I know thy abode, and thy going out, and thy coming in, and thy rage against me.","words":[["H3045","But I know",0,10],["H3427","thy abode",11,20],["H3318","and thy going out",22,39],["H0935","and thy coming in",41,58],["H7264","and thy rage",60,72]]},"37:29":{"text":"Because thy rage against me, and thy tumult, is come up into mine ears, therefore will I put my hook in thy nose, and my bridle in thy lips, and I will turn thee back by the way by which thou camest.","words":[["H7264","Because thy rage",0,16],["H7600","against me, and thy tumult",17,43],["H5927","is come up",45,55],["H0241","into mine ears",56,70],["H7760","therefore will I put",72,92],["H2397","my hook",93,100],["H0639","in thy nose",101,112],["H4964","and my bridle",114,127],["H8193","in thy lips",128,139],["H7725","and I will turn thee back",141,166],["H1870","by the way",167,177],["H0935","by which thou camest",178,198]]},"37:30":{"text":"And this shall be a sign unto thee, Ye shall eat this year such as groweth of itself; and the second year that which springeth of the same: and in the third year sow ye, and reap, and plant vineyards, and eat the fruit thereof.","words":[["H0226","And this shall be a sign",0,24],["H0398","unto thee, Ye shall eat",25,48],["H8141","this year",49,58],["H5599","such as groweth",59,74],["H8145","of itself; and the second",75,100],["H8141","year",101,105],["H7823","that which springeth",106,126],["H7992","of the same: and in the third",127,156],["H8141","year",157,161],["H2232","sow",162,165],["H7114","ye, and reap",166,178],["H5193","and plant",180,189],["H3754","vineyards",190,199],["H0398","and eat",201,208],["H6529","the fruit",209,218]]},"37:31":{"text":"And the remnant that is escaped of the house of Judah shall again take root downward, and bear fruit upward:","words":[["H7604","And the remnant",0,15],["H6413","that is escaped",16,31],["H1004","of the house",32,44],["H3063","of Judah",45,53],["H3254","shall again",54,65],["H8328","take root",66,75],["H4295","downward",76,84],["H6213","and bear",86,94],["H6529","fruit",95,100],["H4605","upward",101,107]]},"37:32":{"text":"For out of Jerusalem shall go forth a remnant, and they that escape out of mount Zion: the zeal of the LORD of hosts shall do this.","words":[["H3389","For out of Jerusalem",0,20],["H3318","shall go forth",21,35],["H7611","a remnant",36,45],["H6413","and they that escape",47,67],["H2022","out of mount",68,80],["H6726","Zion",81,85],["H7068","the zeal",87,95],["H3068","of the LORD",96,107],["H6635","of hosts",108,116],["H6213","shall do",117,125]]},"37:33":{"text":"Therefore thus saith the LORD concerning the king of Assyria, He shall not come into this city, nor shoot an arrow there, nor come before it with shields, nor cast a bank against it.","words":[["H0559","Therefore thus saith",0,20],["H3068","the LORD",21,29],["H4428","concerning the king",30,49],["H0804","of Assyria",50,60],["H0935","He shall not come",62,79],["H5892","into this city",80,94],["H3384","nor shoot",96,105],["H2671","an arrow",106,114],["H6923","there, nor come before",115,137],["H4043","it with shields",138,153],["H8210","nor cast",155,163],["H5550","a bank",164,170]]},"37:34":{"text":"By the way that he came, by the same shall he return, and shall not come into this city, saith the LORD.","words":[["H1870","By the way",0,10],["H0935","that he came",11,23],["H7725","by the same shall he return",25,52],["H0935","and shall not come",54,72],["H5892","into this city",73,87],["H5002","saith",89,94],["H3068","the LORD",95,103]]},"37:35":{"text":"For I will defend this city to save it for mine own sake, and for my servant David's sake.","words":[["H1598","For I will defend",0,17],["H5892","this city",18,27],["H3467","to save",28,35],["H5650","it for mine own sake, and for my servant",36,76],["H1732","David's",77,84]]},"37:36":{"text":"Then the angel of the LORD went forth, and smote in the camp of the Assyrians a hundred and fourscore and five thousand: and when they arose early in the morning, behold, they were all dead corpses.","words":[["H4397","Then the angel",0,14],["H3068","of the LORD",15,26],["H3318","went forth",27,37],["H5221","and smote",39,48],["H4264","in the camp",49,60],["H0804","of the Assyrians",61,77],["H3967","a hundred",78,87],["H8084","and fourscore",88,101],["H2568","and five",102,110],["H0505","thousand",111,119],["H7925","and when they arose early",121,146],["H1242","in the morning",147,161],["H4191","behold, they were all dead",163,189],["H6297","corpses",190,197]]},"37:37":{"text":"So Sennacherib king of Assyria departed, and went and returned, and dwelt at Nineveh.","words":[["H5576","So Sennacherib",0,14],["H4428","king",15,19],["H0804","of Assyria",20,30],["H5265","departed",31,39],["H3212","and went",41,49],["H7725","and returned",50,62],["H3427","and dwelt",64,73],["H5210","at Nineveh",74,84]]},"37:38":{"text":"And it came to pass, as he was worshipping in the house of Nisroch his god, that Adrammelech and Sharezer his sons smote him with the sword; and they escaped into the land of Armenia: and Esarhaddon his son reigned in his stead.","words":[["H7812","And it came to pass, as he was worshipping",0,42],["H1004","in the house",43,55],["H5268","of Nisroch",56,66],["H0430","his god",67,74],["H0152","that Adrammelech",76,92],["H8272","and Sharezer",93,105],["H1121","his sons",106,114],["H5221","smote",115,120],["H2719","him with the sword",121,139],["H4422","and they escaped",141,157],["H0776","into the land",158,171],["H0780","of Armenia",172,182],["H0634","and Esarhaddon",184,198],["H1121","his son",199,206],["H4427","reigned",207,214]]},"38:1":{"text":"In those days was Hezekiah sick unto death. And Isaiah the prophet the son of Amoz came unto him, and said unto him, Thus saith the LORD, Set thine house in order: for thou shalt die, and not live.","words":[["H3117","In those days",0,13],["H2396","was Hezekiah",14,26],["H2470","sick",27,31],["H4191","unto death",32,42],["H3470","And Isaiah",44,54],["H5030","the prophet",55,66],["H1121","the son",67,74],["H0531","of Amoz",75,82],["H0935","came",83,87],["H0559","unto him, and said",88,106],["H0559","unto him, Thus saith",107,127],["H3068","the LORD",128,136],["H1004","Set thine house",138,153],["H6680","in order",154,162],["H4191","for thou shalt die",164,182],["H2421","and not live",184,196]]},"38:2":{"text":"Then Hezekiah turned his face toward the wall, and prayed unto the LORD,","words":[["H2396","Then Hezekiah",0,13],["H5437","turned",14,20],["H6440","his face",21,29],["H7023","toward the wall",30,45],["H6419","and prayed",47,57],["H3068","unto the LORD",58,71]]},"38:3":{"text":"And said, Remember now, O LORD, I beseech thee, how I have walked before thee in truth and with a perfect heart, and have done that which is good in thy sight. And Hezekiah wept sore.","words":[["H0559","And said",0,8],["H2142","Remember",10,18],["H3068","now, O LORD",19,30],["H0577","I beseech",32,41],["H1980","thee, how I have walked",42,65],["H6440","before",66,72],["H0571","thee in truth",73,86],["H8003","and with a perfect",87,105],["H3820","heart",106,111],["H6213","and have done",113,126],["H2896","that which is good",127,145],["H5869","in thy sight",146,158],["H2396","And Hezekiah",160,172],["H1058","wept",173,177],["H1065","wept",173,177],["H1419","sore",178,182]]},"38:4":{"text":"Then came the word of the LORD to Isaiah, saying,","words":[["H1697","Then came the word",0,18],["H3068","of the LORD",19,30],["H3470","to Isaiah",31,40],["H0559","saying",42,48]]},"38:5":{"text":"Go, and say to Hezekiah, Thus saith the LORD, the God of David thy father, I have heard thy prayer, I have seen thy tears: behold, I will add unto thy days fifteen years.","words":[["H1980","Go",0,2],["H0559","and say",4,11],["H2396","to Hezekiah",12,23],["H0559","Thus saith",25,35],["H3068","the LORD",36,44],["H0430","the God",46,53],["H1732","of David",54,62],["H0001","thy father",63,73],["H8085","I have heard",75,87],["H8605","thy prayer",88,98],["H7200","I have seen",100,111],["H1832","thy tears",112,121],["H3254","behold, I will add",123,141],["H3117","unto thy days",142,155],["H2568","fifteen",156,163],["H6240","fifteen",156,163],["H8141","years",164,169]]},"38:6":{"text":"And I will deliver thee and this city out of the hand of the king of Assyria: and I will defend this city.","words":[["H5337","And I will deliver",0,18],["H5892","thee and this city",19,37],["H3709","out of the hand",38,53],["H4428","of the king",54,65],["H0804","of Assyria",66,76],["H1598","and I will defend",78,95],["H5892","this city",96,105]]},"38:7":{"text":"And this shall be a sign unto thee from the LORD, that the LORD will do this thing that he hath spoken;","words":[["H0226","And this shall be a sign",0,24],["H3068","unto thee from the LORD",25,48],["H3068","that the LORD",50,63],["H6213","will do",64,71],["H1697","this thing",72,82],["H1696","that he hath spoken",83,102]]},"38:8":{"text":"Behold, I will bring again the shadow of the degrees, which is gone down in the sun dial of Ahaz, ten degrees backward. So the sun returned ten degrees, by which degrees it was gone down.","words":[["H7725","Behold, I will bring again",0,26],["H6738","the shadow",27,37],["H4609","of the degrees",38,52],["H3381","which is gone down",54,72],["H8121","in the sun",73,83],["H4609","dial",84,88],["H0271","of Ahaz",89,96],["H6235","ten",98,101],["H4609","degrees",102,109],["H0322","backward",110,118],["H8121","So the sun",120,130],["H7725","returned",131,139],["H6235","ten",140,143],["H4609","degrees",144,151],["H4609","by which degrees",153,169],["H3381","it was gone down",170,186]]},"38:9":{"text":"The writing of Hezekiah king of Judah, when he had been sick, and was recovered of his sickness:","words":[["H4385","The writing",0,11],["H2396","of Hezekiah",12,23],["H4428","king",24,28],["H3063","of Judah",29,37],["H2470","when he had been sick",39,60],["H2421","and was recovered",62,79],["H2483","of his sickness",80,95]]},"38:10":{"text":"I said in the cutting off of my days, I shall go to the gates of the grave: I am deprived of the residue of my years.","words":[["H0559","I said",0,6],["H1824","in the cutting off",7,25],["H3117","of my days",26,36],["H3212","I shall go",38,48],["H8179","to the gates",49,61],["H7585","of the grave",62,74],["H6485","I am deprived",76,89],["H3499","of the residue",90,104],["H8141","of my years",105,116]]},"38:11":{"text":"I said, I shall not see the LORD, even the LORD, in the land of the living: I shall behold man no more with the inhabitants of the world.","words":[["H0559","I said",0,6],["H7200","I shall not see",8,23],["H3050","the LORD",24,32],["H3050","even the LORD",34,47],["H0776","in the land",49,60],["H2416","of the living",61,74],["H5027","I shall behold",76,90],["H0120","man",91,94],["H3427","no more with the inhabitants",95,123],["H2309","of the world",124,136]]},"38:12":{"text":"Mine age is departed, and is removed from me as a shepherd's tent: I have cut off like a weaver my life: he will cut me off with pining sickness: from day even to night wilt thou make an end of me.","words":[["H1755","Mine age",0,8],["H5265","is departed",9,20],["H1540","and is removed",22,36],["H7473","from me as a shepherd's",37,60],["H0168","tent",61,65],["H7088","I have cut off",67,81],["H0707","like a weaver",82,95],["H2416","my life",96,103],["H1214","he will cut me off",105,123],["H1803","with pining sickness",124,144],["H3117","from day",146,154],["H3915","even to night",155,168],["H7999","wilt thou make an end",169,190]]},"38:13":{"text":"I reckoned till morning, that, as a lion, so will he break all my bones: from day even to night wilt thou make an end of me.","words":[["H7737","I reckoned",0,10],["H1242","till morning",11,23],["H0738","that, as a lion",25,40],["H7665","so will he break",42,58],["H6106","all my bones",59,71],["H3117","from day",73,81],["H3915","even to night",82,95],["H7999","wilt thou make an end",96,117]]},"38:14":{"text":"Like a crane or a swallow, so did I chatter: I did mourn as a dove: mine eyes fail with looking upward: O LORD, I am oppressed; undertake for me.","words":[["H5483","Like a crane",0,12],["H5693","or a swallow",13,25],["H6850","so did I chatter",27,43],["H1897","I did mourn",45,56],["H3123","as a dove",57,66],["H5869","mine eyes",68,77],["H1809","fail",78,82],["H4791","with looking upward",83,102],["H3068","O LORD",104,110],["H6234","I am oppressed",112,126],["H6148","undertake",128,137]]},"38:15":{"text":"What shall I say? he hath both spoken unto me, and himself hath done it: I shall go softly all my years in the bitterness of my soul.","words":[["H1696","What shall I say",0,16],["H0559","he hath both spoken",18,37],["H6213","unto me, and himself hath done",38,68],["H1718","it: I shall go softly",69,90],["H8141","all my years",91,103],["H4751","in the bitterness",104,121],["H5315","of my soul",122,132]]},"38:16":{"text":"O Lord, by these things men live, and in all these things is the life of my spirit: so wilt thou recover me, and make me to live.","words":[["H0136","O Lord",0,6],["H2421","by these things men live",8,32],["H2416","and in all these things is the life",34,69],["H7307","of my spirit",70,82],["H2492","so wilt thou recover",84,104],["H2421","me, and make me to live",105,128]]},"38:17":{"text":"Behold, for peace I had great bitterness: but thou hast in love to my soul delivered it from the pit of corruption: for thou hast cast all my sins behind thy back.","words":[["H7965","Behold, for peace",0,17],["H4751","I had great bitterness",18,40],["H4843","I had great bitterness",18,40],["H2836","but thou hast in love",42,63],["H5315","to my soul",64,74],["H7845","delivered it from the pit",75,100],["H1097","of corruption",101,114],["H7993","for thou hast cast",116,134],["H2399","all my sins",135,146],["H0310","behind",147,153],["H1460","thy back",154,162]]},"38:18":{"text":"For the grave cannot praise thee, death can not celebrate thee: they that go down into the pit cannot hope for thy truth.","words":[["H7585","For the grave",0,13],["H3034","cannot praise",14,27],["H4194","thee, death",28,39],["H1984","can not celebrate",40,57],["H3381","thee: they that go down",58,81],["H0953","into the pit",82,94],["H7663","cannot hope",95,106],["H0571","for thy truth",107,120]]},"38:19":{"text":"The living, the living, he shall praise thee, as I do this day: the father to the children shall make known thy truth.","words":[["H2416","The living",0,10],["H2416","the living",12,22],["H3034","he shall praise",24,39],["H3117","thee, as I do this day",40,62],["H0001","the father",64,74],["H1121","to the children",75,90],["H3045","shall make known",91,107],["H0571","thy truth",108,117]]},"38:20":{"text":"The LORD was ready to save me: therefore we will sing my songs to the stringed instruments all the days of our life in the house of the LORD.","words":[["H3068","The LORD",0,8],["H3467","was ready to save",9,26],["H5058","me: therefore we will sing my songs",27,62],["H5059","to the stringed instruments",63,90],["H3117","all the days",91,103],["H2416","of our life",104,115],["H1004","in the house",116,128],["H3068","of the LORD",129,140]]},"38:21":{"text":"For Isaiah had said, Let them take a lump of figs, and lay it for a plaister upon the boil, and he shall recover.","words":[["H3470","For Isaiah",0,10],["H0559","had said",11,19],["H5375","Let them take",21,34],["H1690","a lump",35,41],["H8384","of figs",42,49],["H4799","and lay it for a plaister",51,76],["H7822","upon the boil",77,90],["H2421","and he shall recover",92,112]]},"38:22":{"text":"Hezekiah also had said, What is the sign that I shall go up to the house of the LORD?","words":[["H2396","Hezekiah",0,8],["H0559","also had said",9,22],["H0226","What is the sign",24,40],["H5927","that I shall go up",41,59],["H1004","to the house",60,72],["H3068","of the LORD",73,84]]},"39:1":{"text":"At that time Merodachbaladan, the son of Baladan, king of Babylon, sent letters and a present to Hezekiah: for he had heard that he had been sick, and was recovered.","words":[["H6256","At that time",0,12],["H4757","Merodachbaladan",13,28],["H1121","the son",30,37],["H1081","of Baladan",38,48],["H4428","king",50,54],["H0894","of Babylon",55,65],["H7971","sent",67,71],["H5612","letters",72,79],["H4503","and a present",80,93],["H2396","to Hezekiah",94,105],["H8085","for he had heard",107,123],["H2470","that he had been sick",124,145],["H2388","and was recovered",147,164]]},"39:2":{"text":"And Hezekiah was glad of them, and shewed them the house of his precious things, the silver, and the gold, and the spices, and the precious ointment, and all the house of his armour, and all that was found in his treasures: there was nothing in his house, nor in all his dominion, that Hezekiah shewed them not.","words":[["H2396","And Hezekiah",0,12],["H8055","was glad",13,21],["H7200","of them, and shewed",22,41],["H1004","them the house",42,56],["H5238","of his precious things",57,79],["H3701","the silver",81,91],["H2091","and the gold",93,105],["H1314","and the spices",107,121],["H2896","and the precious",123,139],["H8081","ointment",140,148],["H1004","and all the house",150,167],["H3627","of his armour",168,181],["H4672","and all that was found",183,205],["H0214","in his treasures",206,222],["H1697","there was nothing",224,241],["H1004","in his house",242,254],["H4475","nor in all his dominion",256,279],["H2396","that Hezekiah",281,294],["H7200","shewed",295,301]]},"39:3":{"text":"Then came Isaiah the prophet unto king Hezekiah, and said unto him, What said these men? and from whence came they unto thee? And Hezekiah said, They are come from a far country unto me, even from Babylon.","words":[["H0935","Then came",0,9],["H3470","Isaiah",10,16],["H5030","the prophet",17,28],["H4428","unto king",29,38],["H2396","Hezekiah",39,47],["H0559","and said",49,57],["H0559","unto him, What said",58,77],["H0582","these men",78,87],["H0370","and from whence",89,104],["H0935","came",105,109],["H2396","they unto thee? And Hezekiah",110,138],["H0559","said",139,143],["H0935","They are come",145,158],["H7350","from a far",159,169],["H0776","country",170,177],["H0894","unto me, even from Babylon",178,204]]},"39:4":{"text":"Then said he, What have they seen in thine house? And Hezekiah answered, All that is in mine house have they seen: there is nothing among my treasures that I have not shewed them.","words":[["H0559","Then said",0,9],["H7200","he, What have they seen",10,33],["H1004","in thine house",34,48],["H2396","And Hezekiah",50,62],["H0559","answered",63,71],["H1004","All that is in mine house",73,98],["H7200","have they seen",99,113],["H1697","there is nothing",115,131],["H0214","among my treasures",132,150],["H7200","that I have not shewed",151,173]]},"39:5":{"text":"Then said Isaiah to Hezekiah, Hear the word of the LORD of hosts:","words":[["H0559","Then said",0,9],["H3470","Isaiah",10,16],["H2396","to Hezekiah",17,28],["H8085","Hear",30,34],["H1697","the word",35,43],["H3068","of the LORD",44,55],["H6635","of hosts",56,64]]},"39:6":{"text":"Behold, the days come, that all that is in thine house, and that which thy fathers have laid up in store until this day, shall be carried to Babylon: nothing shall be left, saith the LORD.","words":[["H3117","Behold, the days",0,16],["H0935","come",17,21],["H1004","that all that is in thine house",23,54],["H0001","and that which thy fathers",56,82],["H0686","have laid up in store",83,104],["H3117","until this day",105,119],["H5375","shall be carried",121,137],["H0894","to Babylon",138,148],["H1697","nothing",150,157],["H3498","shall be left",158,171],["H0559","saith",173,178],["H3068","the LORD",179,187]]},"39:7":{"text":"And of thy sons that shall issue from thee, which thou shalt beget, shall they take away; and they shall be eunuchs in the palace of the king of Babylon.","words":[["H1121","And of thy sons",0,15],["H3318","that shall issue",16,32],["H3205","from thee, which thou shalt beget",33,66],["H3947","shall they take away",68,88],["H5631","and they shall be eunuchs",90,115],["H1964","in the palace",116,129],["H4428","of the king",130,141],["H0894","of Babylon",142,152]]},"39:8":{"text":"Then said Hezekiah to Isaiah, Good is the word of the LORD which thou hast spoken. He said moreover, For there shall be peace and truth in my days.","words":[["H0559","Then said",0,9],["H2396","Hezekiah",10,18],["H3470","to Isaiah",19,28],["H2896","Good",30,34],["H1697","is the word",35,46],["H3068","of the LORD",47,58],["H1696","which thou hast spoken",59,81],["H0559","He said",83,90],["H7965","moreover, For there shall be peace",91,125],["H0571","and truth",126,135],["H3117","in my days",136,146]]},"40:1":{"text":"Comfort ye, comfort ye my people, saith your God.","words":[["H5162","Comfort",0,7],["H5162","ye, comfort",8,19],["H5971","ye my people",20,32],["H0559","saith",34,39],["H0430","your God",40,48]]},"40:2":{"text":"Speak ye comfortably to Jerusalem, and cry unto her, that her warfare is accomplished, that her iniquity is pardoned: for she hath received of the LORD'S hand double for all her sins.","words":[["H1696","Speak",0,5],["H3820","ye comfortably",6,20],["H3389","to Jerusalem",21,33],["H7121","and cry",35,42],["H6635","unto her, that her warfare",43,69],["H4390","is accomplished",70,85],["H5771","that her iniquity",87,104],["H7521","is pardoned",105,116],["H3947","for she hath received",118,139],["H3068","of the LORD'S",140,153],["H3027","hand",154,158],["H3718","double",159,165],["H2403","for all her sins",166,182]]},"40:3":{"text":"The voice of him that crieth in the wilderness, Prepare ye the way of the LORD, make straight in the desert a highway for our God.","words":[["H6963","The voice",0,9],["H7121","of him that crieth",10,28],["H4057","in the wilderness",29,46],["H6437","Prepare",48,55],["H1870","ye the way",56,66],["H3068","of the LORD",67,78],["H3474","make straight",80,93],["H6160","in the desert",94,107],["H4546","a highway",108,117],["H0430","for our God",118,129]]},"40:4":{"text":"Every valley shall be exalted, and every mountain and hill shall be made low: and the crooked shall be made straight, and the rough places plain:","words":[["H1516","Every valley",0,12],["H5375","shall be exalted",13,29],["H2022","and every mountain",31,49],["H1389","and hill",50,58],["H8213","shall be made low",59,76],["H6121","and the crooked",78,93],["H4334","shall be made straight",94,116],["H7406","and the rough places",118,138],["H1237","plain",139,144]]},"40:5":{"text":"And the glory of the LORD shall be revealed, and all flesh shall see it together: for the mouth of the LORD hath spoken it.","words":[["H3519","And the glory",0,13],["H3068","of the LORD",14,25],["H1540","shall be revealed",26,43],["H1320","and all flesh",45,58],["H7200","shall see",59,68],["H3162","it together",69,80],["H6310","for the mouth",82,95],["H3068","of the LORD",96,107],["H1696","hath spoken",108,119]]},"40:6":{"text":"The voice said, Cry. And he said, What shall I cry? All flesh is grass, and all the goodliness thereof is as the flower of the field:","words":[["H6963","The voice",0,9],["H0559","said",10,14],["H7121","Cry",16,19],["H0559","And he said",21,32],["H7121","What shall I cry",34,50],["H1320","All flesh",52,61],["H2682","is grass",62,70],["H2617","and all the goodliness",72,94],["H6731","thereof is as the flower",95,119],["H7704","of the field",120,132]]},"40:7":{"text":"The grass withereth, the flower fadeth: because the spirit of the LORD bloweth upon it: surely the people is grass.","words":[["H2682","The grass",0,9],["H3001","withereth",10,19],["H6731","the flower",21,31],["H5034","fadeth",32,38],["H7307","because the spirit",40,58],["H3068","of the LORD",59,70],["H5380","bloweth",71,78],["H0403","upon it: surely",79,94],["H5971","the people",95,105],["H2682","is grass",106,114]]},"40:8":{"text":"The grass withereth, the flower fadeth: but the word of our God shall stand for ever.","words":[["H2682","The grass",0,9],["H3001","withereth",10,19],["H6731","the flower",21,31],["H5034","fadeth",32,38],["H1697","but the word",40,52],["H0430","of our God",53,63],["H6965","shall stand",64,75],["H5769","for ever",76,84]]},"40:9":{"text":"O Zion, that bringest good tidings, get thee up into the high mountain; O Jerusalem, that bringest good tidings, lift up thy voice with strength; lift it up, be not afraid; say unto the cities of Judah, Behold your God!","words":[["H6726","O Zion",0,6],["H1319","that bringest good tidings",8,34],["H5927","get thee up",36,47],["H1364","into the high",48,61],["H2022","mountain",62,70],["H3389","O Jerusalem",72,83],["H1319","that bringest good tidings",85,111],["H7311","lift up",113,120],["H6963","thy voice",121,130],["H3581","with strength",131,144],["H7311","lift it up",146,156],["H3372","be not afraid",158,171],["H0559","say",173,176],["H5892","unto the cities",177,192],["H3063","of Judah",193,201],["H0430","Behold your God",203,218]]},"40:10":{"text":"Behold, the Lord GOD will come with strong hand, and his arm shall rule for him: behold, his reward is with him, and his work before him.","words":[["H0136","Behold, the Lord",0,16],["H3069","GOD",17,20],["H0935","will come",21,30],["H2389","with strong",31,42],["H2220","hand, and his arm",43,60],["H4910","shall rule",61,71],["H7939","for him: behold, his reward",72,99],["H6468","is with him, and his work",100,125],["H6440","before",126,132]]},"40:11":{"text":"He shall feed his flock like a shepherd: he shall gather the lambs with his arm, and carry them in his bosom, and shall gently lead those that are with young.","words":[["H7462","He shall feed",0,13],["H5739","his flock",14,23],["H7462","like a shepherd",24,39],["H6908","he shall gather",41,56],["H2922","the lambs",57,66],["H2220","with his arm",67,79],["H5375","and carry",81,90],["H2436","them in his bosom",91,108],["H5095","and shall gently lead",110,131],["H5763","those that are with young",132,157]]},"40:12":{"text":"Who hath measured the waters in the hollow of his hand, and meted out heaven with the span, and comprehended the dust of the earth in a measure, and weighed the mountains in scales, and the hills in a balance?","words":[["H4058","Who hath measured",0,17],["H4325","the waters",18,28],["H8168","in the hollow of his hand",29,54],["H8505","and meted out",56,69],["H8064","heaven",70,76],["H2239","with the span",77,90],["H3557","and comprehended",92,108],["H6083","the dust",109,117],["H0776","of the earth",118,130],["H7991","in a measure",131,143],["H8254","and weighed",145,156],["H2022","the mountains",157,170],["H6425","in scales",171,180],["H1389","and the hills",182,195],["H3976","in a balance",196,208]]},"40:13":{"text":"Who hath directed the Spirit of the LORD, or being his counsellor hath taught him?","words":[["H8505","Who hath directed",0,17],["H7307","the Spirit",18,28],["H3068","of the LORD",29,40],["H0376","or being his counsellor",42,65],["H6098","or being his counsellor",42,65],["H3045","hath taught",66,77]]},"40:14":{"text":"With whom took he counsel, and who instructed him, and taught him in the path of judgment, and taught him knowledge, and shewed to him the way of understanding?","words":[["H3289","With whom took he counsel",0,25],["H0995","and who instructed",27,45],["H3925","him, and taught",46,61],["H0734","him in the path",62,77],["H4941","of judgment",78,89],["H3925","and taught",91,101],["H1847","him knowledge",102,115],["H3045","and shewed",117,127],["H1870","to him the way",128,142],["H8394","of understanding",143,159]]},"40:15":{"text":"Behold, the nations are as a drop of a bucket, and are counted as the small dust of the balance: behold, he taketh up the isles as a very little thing.","words":[["H1471","Behold, the nations",0,19],["H4752","are as a drop",20,33],["H1805","of a bucket",34,45],["H2803","and are counted",47,62],["H7834","as the small dust",63,80],["H3976","of the balance",81,95],["H5190","behold, he taketh up",97,117],["H0339","the isles",118,127],["H1851","as a very little thing",128,150]]},"40:16":{"text":"And Lebanon is not sufficient to burn, nor the beasts thereof sufficient for a burnt offering.","words":[["H3844","And Lebanon",0,11],["H0369","is not",12,18],["H1767","sufficient",19,29],["H1197","to burn",30,37],["H2416","nor the beasts",39,53],["H1767","thereof sufficient",54,72],["H5930","for a burnt offering",73,93]]},"40:17":{"text":"All nations before him are as nothing; and they are counted to him less than nothing, and vanity.","words":[["H1471","All nations",0,11],["H2803","before him are as nothing; and they are counted",12,59],["H0657","to him less than nothing",60,84],["H8414","and vanity",86,96]]},"40:18":{"text":"To whom then will ye liken God? or what likeness will ye compare unto him?","words":[["H1819","To whom then will ye liken",0,26],["H0410","God",27,30],["H1823","or what likeness",32,48],["H6186","will ye compare",49,64]]},"40:19":{"text":"The workman melteth a graven image, and the goldsmith spreadeth it over with gold, and casteth silver chains.","words":[["H2796","The workman",0,11],["H5258","melteth",12,19],["H6459","a graven image",20,34],["H6884","and the goldsmith",36,53],["H7554","spreadeth",54,63],["H2091","it over with gold",64,81],["H6884","and casteth",83,94],["H3701","silver",95,101],["H7577","chains",102,108]]},"40:20":{"text":"He that is so impoverished that he hath no oblation chooseth a tree that will not rot; he seeketh unto him a cunning workman to prepare a graven image, that shall not be moved.","words":[["H5533","He that is so impoverished",0,26],["H5534","He that is so impoverished",0,26],["H8641","that he hath no oblation",27,51],["H0977","chooseth",52,60],["H6086","a tree",61,67],["H7537","that will not rot",68,85],["H1245","he seeketh",87,97],["H2450","unto him a cunning",98,116],["H2796","workman",117,124],["H3559","to prepare",125,135],["H6459","a graven image",136,150],["H4131","that shall not be moved",152,175]]},"40:21":{"text":"Have ye not known? have ye not heard? hath it not been told you from the beginning? have ye not understood from the foundations of the earth?","words":[["H3045","Have ye not known",0,17],["H8085","have ye not heard",19,36],["H5046","hath it not been told",38,59],["H7218","you from the beginning",60,82],["H0995","have ye not understood",84,106],["H4146","from the foundations",107,127],["H0776","of the earth",128,140]]},"40:22":{"text":"It is he that sitteth upon the circle of the earth, and the inhabitants thereof are as grasshoppers; that stretcheth out the heavens as a curtain, and spreadeth them out as a tent to dwell in:","words":[["H3427","It is he that sitteth",0,21],["H2329","upon the circle",22,37],["H0776","of the earth",38,50],["H3427","and the inhabitants",52,71],["H2284","thereof are as grasshoppers",72,99],["H5186","that stretcheth out",101,120],["H8064","the heavens",121,132],["H1852","as a curtain",133,145],["H4969","and spreadeth them out",147,169],["H0168","as a tent",170,179],["H3427","to dwell in",180,191]]},"40:23":{"text":"That bringeth the princes to nothing; he maketh the judges of the earth as vanity.","words":[["H5414","That bringeth",0,13],["H7336","the princes",14,25],["H6213","to nothing; he maketh",26,47],["H8199","the judges",48,58],["H0776","of the earth",59,71],["H8414","as vanity",72,81]]},"40:24":{"text":"Yea, they shall not be planted; yea, they shall not be sown: yea, their stock shall not take root in the earth: and he shall also blow upon them, and they shall wither, and the whirlwind shall take them away as stubble.","words":[["H5193","Yea, they shall not be planted",0,30],["H2232","yea, they shall not be sown",32,59],["H1503","yea, their stock",61,77],["H8327","shall not take root",78,97],["H0776","in the earth",98,110],["H5398","and he shall also blow",112,134],["H3001","upon them, and they shall wither",135,167],["H5591","and the whirlwind",169,186],["H5375","shall take",187,197],["H7179","them away as stubble",198,218]]},"40:25":{"text":"To whom then will ye liken me, or shall I be equal? saith the Holy One.","words":[["H1819","To whom then will ye liken",0,26],["H7737","me, or shall I be equal",27,50],["H0559","saith",52,57],["H6918","the Holy One",58,70]]},"40:26":{"text":"Lift up your eyes on high, and behold who hath created these things, that bringeth out their host by number: he calleth them all by names by the greatness of his might, for that he is strong in power; not one faileth.","words":[["H5375","Lift up",0,7],["H5869","your eyes",8,17],["H4791","on high",18,25],["H7200","and behold",27,37],["H1254","who hath created",38,54],["H3318","these things, that bringeth out",55,86],["H6635","their host",87,97],["H4557","by number",98,107],["H7121","he calleth",109,119],["H8034","them all by names",120,137],["H7230","by the greatness",138,154],["H0202","of his might",155,167],["H0533","for that he is strong",169,190],["H3581","in power",191,199],["H0376","not one",201,208],["H5737","faileth",209,216]]},"40:27":{"text":"Why sayest thou, O Jacob, and speakest, O Israel, My way is hid from the LORD, and my judgment is passed over from my God?","words":[["H0559","Why sayest",0,10],["H3290","thou, O Jacob",11,24],["H1696","and speakest",26,38],["H3478","O Israel",40,48],["H1870","My way",50,56],["H5641","is hid",57,63],["H3068","from the LORD",64,77],["H4941","and my judgment",79,94],["H5674","is passed over",95,109],["H0430","from my God",110,121]]},"40:28":{"text":"Hast thou not known? hast thou not heard, that the everlasting God, the LORD, the Creator of the ends of the earth, fainteth not, neither is weary? there is no searching of his understanding.","words":[["H3045","Hast thou not known",0,19],["H8085","hast thou not heard",21,40],["H5769","that the everlasting",42,62],["H0430","God",63,66],["H3068","the LORD",68,76],["H1254","the Creator",78,89],["H7098","of the ends",90,101],["H0776","of the earth",102,114],["H3286","fainteth",116,124],["H3021","not, neither is weary",125,146],["H2714","there is no searching",148,169],["H8394","of his understanding",170,190]]},"40:29":{"text":"He giveth power to the faint; and to them that have no might he increaseth strength.","words":[["H5414","He giveth",0,9],["H3581","power",10,15],["H3287","to the faint",16,28],["H0202","and to them that have no might",30,60],["H7235","he increaseth",61,74],["H6109","strength",75,83]]},"40:30":{"text":"Even the youths shall faint and be weary, and the young men shall utterly fall:","words":[["H5288","Even the youths",0,15],["H3286","shall faint",16,27],["H3021","and be weary",28,40],["H0970","and the young men",42,59],["H3782","shall utterly",60,73],["H3782","fall",74,78]]},"40:31":{"text":"But they that wait upon the LORD shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","words":[["H6960","But they that wait",0,18],["H3068","upon the LORD",19,32],["H2498","shall renew",33,44],["H3581","their strength",45,59],["H5927","they shall mount up",61,80],["H0083","with wings",81,91],["H5404","as eagles",92,101],["H7323","they shall run",103,117],["H3021","and not be weary",119,135],["H3212","and they shall walk",137,156],["H3286","and not faint",158,171]]},"41:1":{"text":"Keep silence before me, O islands; and let the people renew their strength: let them come near; then let them speak: let us come near together to judgment.","words":[["H2790","Keep silence",0,12],["H0339","before me, O islands",13,33],["H3816","and let the people",35,53],["H2498","renew",54,59],["H3581","their strength",60,74],["H5066","let them come near",76,94],["H1696","then let them speak",96,115],["H7126","let us come near",117,133],["H3162","together",134,142],["H4941","to judgment",143,154]]},"41:2":{"text":"Who raised up the righteous man from the east, called him to his foot, gave the nations before him, and made him rule over kings? he gave them as the dust to his sword, and as driven stubble to his bow.","words":[["H5782","Who raised up",0,13],["H6664","the righteous",14,27],["H4217","man from the east",28,45],["H7121","called",47,53],["H7272","him to his foot",54,69],["H5414","gave",71,75],["H1471","the nations",76,87],["H6440","before",88,94],["H7287","him, and made him rule",95,117],["H4428","over kings",118,128],["H5414","he gave",130,137],["H6083","them as the dust",138,154],["H2719","to his sword",155,167],["H5086","and as driven",169,182],["H7179","stubble",183,190],["H7198","to his bow",191,201]]},"41:3":{"text":"He pursued them, and passed safely; even by the way that he had not gone with his feet.","words":[["H7291","He pursued",0,10],["H5674","them, and passed",11,27],["H7965","safely",28,34],["H0734","even by the way",36,51],["H0935","that he had not gone",52,72],["H7272","with his feet",73,86]]},"41:4":{"text":"Who hath wrought and done it, calling the generations from the beginning? I the LORD, the first, and with the last; I am he.","words":[["H6466","Who hath wrought",0,16],["H6213","and done",17,25],["H7121","it, calling",26,37],["H1755","the generations",38,53],["H7218","from the beginning",54,72],["H3068","I the LORD",74,84],["H7223","the first",86,95],["H0314","and with the last",97,114]]},"41:5":{"text":"The isles saw it, and feared; the ends of the earth were afraid, drew near, and came.","words":[["H0339","The isles",0,9],["H7200","saw",10,13],["H3372","it, and feared",14,28],["H7098","the ends",30,38],["H0776","of the earth",39,51],["H2729","were afraid",52,63],["H7126","drew near",65,74],["H0857","and came",76,84]]},"41:6":{"text":"They helped every one his neighbour; and every one said to his brother, Be of good courage.","words":[["H5826","They helped",0,11],["H0376","every one",12,21],["H7453","his neighbour",22,35],["H0559","and every one said",37,55],["H0251","to his brother",56,70],["H2388","Be of good courage",72,90]]},"41:7":{"text":"So the carpenter encouraged the goldsmith, and he that smootheth with the hammer him that smote the anvil, saying, It is ready for the sodering: and he fastened it with nails, that it should not be moved.","words":[["H2796","So the carpenter",0,16],["H2388","encouraged",17,27],["H6884","the goldsmith",28,41],["H2505","and he that smootheth",43,64],["H6360","with the hammer",65,80],["H1986","him that smote",81,95],["H6471","the anvil",96,105],["H0559","saying",107,113],["H2896","It is ready",115,126],["H1694","for the sodering",127,143],["H2388","and he fastened",145,160],["H4548","it with nails",161,174],["H4131","that it should not be moved",176,203]]},"41:8":{"text":"But thou, Israel, art my servant, Jacob whom I have chosen, the seed of Abraham my friend.","words":[["H3478","But thou, Israel",0,16],["H5650","art my servant",18,32],["H3290","Jacob",34,39],["H0977","whom I have chosen",40,58],["H2233","the seed",60,68],["H0085","of Abraham",69,79],["H0157","my friend",80,89]]},"41:9":{"text":"Thou whom I have taken from the ends of the earth, and called thee from the chief men thereof, and said unto thee, Thou art my servant; I have chosen thee, and not cast thee away.","words":[["H2388","Thou whom I have taken",0,22],["H7098","from the ends",23,36],["H0776","of the earth",37,49],["H7121","and called",51,61],["H0678","thee from the chief men",62,85],["H0559","thereof, and said",86,103],["H5650","unto thee, Thou art my servant",104,134],["H0977","I have chosen",136,149],["H3988","thee, and not cast thee away",150,178]]},"41:10":{"text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","words":[["H3372","Fear",0,4],["H8159","thou not; for I am with thee: be not dismayed",5,50],["H0430","for I am thy God",52,68],["H0553","I will strengthen",70,87],["H5826","thee; yea, I will help",88,110],["H8551","thee; yea, I will uphold",111,135],["H3225","thee with the right hand",136,160],["H6664","of my righteousness",161,180]]},"41:11":{"text":"Behold, all they that were incensed against thee shall be ashamed and confounded: they shall be as nothing; and they that strive with thee shall perish.","words":[["H2734","Behold, all they that were incensed",0,35],["H0954","against thee shall be ashamed",36,65],["H3637","and confounded",66,80],["H0582","they shall be as nothing; and they",82,116],["H7379","that strive",117,128],["H0006","with thee shall perish",129,151]]},"41:12":{"text":"Thou shalt seek them, and shalt not find them, even them that contended with thee: they that war against thee shall be as nothing, and as a thing of nought.","words":[["H1245","Thou shalt seek",0,15],["H4672","them, and shalt not find",16,40],["H0582","them, even them",41,56],["H4695","that contended",57,71],["H4421","with thee: they that war",72,96],["H0657","against thee shall be as nothing, and as a thing of nought",97,155]]},"41:13":{"text":"For I the LORD thy God will hold thy right hand, saying unto thee, Fear not; I will help thee.","words":[["H3068","For I the LORD",0,14],["H0430","thy God",15,22],["H2388","will hold",23,32],["H3225","thy right hand",33,47],["H0559","saying",49,55],["H3372","unto thee, Fear",56,71],["H5826","not; I will help",72,88]]},"41:14":{"text":"Fear not, thou worm Jacob, and ye men of Israel; I will help thee, saith the LORD, and thy redeemer, the Holy One of Israel.","words":[["H3372","Fear",0,4],["H8438","not, thou worm",5,19],["H3290","Jacob",20,25],["H4962","and ye men",27,37],["H3478","of Israel",38,47],["H5826","I will help",49,60],["H5002","thee, saith",61,72],["H3068","the LORD",73,81],["H1350","and thy redeemer",83,99],["H6918","the Holy One",101,113],["H3478","of Israel",114,123]]},"41:15":{"text":"Behold, I will make thee a new sharp threshing instrument having teeth: thou shalt thresh the mountains, and beat them small, and shalt make the hills as chaff.","words":[["H7760","Behold, I will make",0,19],["H2319","thee a new",20,30],["H2742","sharp",31,36],["H4173","threshing",37,46],["H1167","instrument having",47,64],["H6374","teeth",65,70],["H1758","thou shalt thresh",72,89],["H2022","the mountains",90,103],["H1854","and beat them small",105,124],["H7760","and shalt make",126,140],["H1389","the hills",141,150],["H4671","as chaff",151,159]]},"41:16":{"text":"Thou shalt fan them, and the wind shall carry them away, and the whirlwind shall scatter them: and thou shalt rejoice in the LORD, and shalt glory in the Holy One of Israel.","words":[["H2219","Thou shalt fan",0,14],["H7307","them, and the wind",15,33],["H5375","shall carry them away",34,55],["H5591","and the whirlwind",57,74],["H6327","shall scatter",75,88],["H1523","them: and thou shalt rejoice",89,117],["H3068","in the LORD",118,129],["H1984","and shalt glory",131,146],["H6918","in the Holy One",147,162],["H3478","of Israel",163,172]]},"41:17":{"text":"When the poor and needy seek water, and there is none, and their tongue faileth for thirst, I the LORD will hear them, I the God of Israel will not forsake them.","words":[["H6041","When the poor",0,13],["H0034","and needy",14,23],["H1245","seek",24,28],["H4325","water",29,34],["H3956","and there is none, and their tongue",36,71],["H5405","faileth",72,79],["H6772","for thirst",80,90],["H3068","I the LORD",92,102],["H6030","will hear",103,112],["H0430","them, I the God",113,128],["H3478","of Israel",129,138],["H5800","will not forsake",139,155]]},"41:18":{"text":"I will open rivers in high places, and fountains in the midst of the valleys: I will make the wilderness a pool of water, and the dry land springs of water.","words":[["H6605","I will open",0,11],["H5104","rivers",12,18],["H8205","in high places",19,33],["H4599","and fountains",35,48],["H8432","in the midst",49,61],["H1237","of the valleys",62,76],["H7760","I will make",78,89],["H4057","the wilderness",90,104],["H0098","a pool",105,111],["H4325","of water",112,120],["H6723","and the dry",122,133],["H0776","land",134,138],["H4161","springs",139,146],["H4325","of water",147,155]]},"41:19":{"text":"I will plant in the wilderness the cedar, the shittah tree, and the myrtle, and the oil tree; I will set in the desert the fir tree, and the pine, and the box tree together:","words":[["H5414","I will plant",0,12],["H4057","in the wilderness",13,30],["H0730","the cedar",31,40],["H7848","the shittah tree",42,58],["H1918","and the myrtle",60,74],["H8081","and the oil",76,87],["H6086","tree",88,92],["H7760","I will set",94,104],["H6160","in the desert",105,118],["H1265","the fir tree",119,131],["H8410","and the pine",133,145],["H8391","and the box tree",147,163],["H3162","together",164,172]]},"41:20":{"text":"That they may see, and know, and consider, and understand together, that the hand of the LORD hath done this, and the Holy One of Israel hath created it.","words":[["H7200","That they may see",0,17],["H3045","and know",19,27],["H7760","and consider",29,41],["H7919","and understand",43,57],["H3162","together",58,66],["H3027","that the hand",68,81],["H3068","of the LORD",82,93],["H6213","hath done",94,103],["H6918","this, and the Holy One",104,126],["H3478","of Israel",127,136],["H1254","hath created",137,149]]},"41:21":{"text":"Produce your cause, saith the LORD; bring forth your strong reasons, saith the King of Jacob.","words":[["H7126","Produce",0,7],["H7379","your cause",8,18],["H0559","saith",20,25],["H3068","the LORD",26,34],["H5066","bring forth",36,47],["H6110","your strong",48,59],["H0559","reasons, saith",60,74],["H4428","the King",75,83],["H3290","of Jacob",84,92]]},"41:22":{"text":"Let them bring them forth, and shew us what shall happen: let them shew the former things, what they be, that we may consider them, and know the latter end of them; or declare us things for to come.","words":[["H5066","Let them bring them forth",0,25],["H5046","and shew",27,35],["H7136","us what shall happen",36,56],["H5046","let them shew",58,71],["H7223","the former things",72,89],["H7760","what they be, that we may consider",91,125],["H3820","what they be, that we may consider",91,125],["H3045","them, and know",126,140],["H0319","the latter end",141,155],["H8085","of them; or declare",156,175],["H0935","us things for to come",176,197]]},"41:23":{"text":"Shew the things that are to come hereafter, that we may know that ye are gods: yea, do good, or do evil, that we may be dismayed, and behold it together.","words":[["H5046","Shew",0,4],["H0857","the things that are to come",5,32],["H0268","hereafter",33,42],["H3045","that we may know",44,60],["H0430","that ye are gods",61,77],["H3190","yea, do good",79,91],["H7489","or do evil",93,103],["H8159","that we may be dismayed",105,128],["H7200","and behold",130,140],["H3162","it together",141,152]]},"41:24":{"text":"Behold, ye are of nothing, and your work of nought: an abomination is he that chooseth you.","words":[["H0369","Behold, ye are of nothing",0,25],["H6467","and your work",27,40],["H0659","of nought",41,50],["H8441","an abomination",52,66],["H0977","is he that chooseth",67,86]]},"41:25":{"text":"I have raised up one from the north, and he shall come: from the rising of the sun shall he call upon my name: and he shall come upon princes as upon morter, and as the potter treadeth clay.","words":[["H5782","I have raised up",0,16],["H6828","one from the north",17,35],["H0857","and he shall come",37,54],["H4217","from the rising",56,71],["H8121","of the sun",72,82],["H7121","shall he call",83,96],["H8034","upon my name",97,109],["H0935","and he shall come",111,128],["H5461","upon princes",129,141],["H2563","as upon morter",142,156],["H3335","and as the potter",158,175],["H7429","treadeth",176,184],["H2916","clay",185,189]]},"41:26":{"text":"Who hath declared from the beginning, that we may know? and beforetime, that we may say, He is righteous? yea, there is none that sheweth, yea, there is none that declareth, yea, there is none that heareth your words.","words":[["H5046","Who hath declared",0,17],["H7218","from the beginning",18,36],["H3045","that we may know",38,54],["H6440","and beforetime",56,70],["H0559","that we may say",72,87],["H6662","He is righteous",89,104],["H5046","yea, there is none that sheweth",106,137],["H8085","yea, there is none that declareth",139,172],["H8085","yea, there is none that heareth",174,205],["H0561","your words",206,216]]},"41:27":{"text":"The first shall say to Zion, Behold, behold them: and I will give to Jerusalem one that bringeth good tidings.","words":[["H7223","The first",0,9],["H6726","shall say to Zion",10,27],["H2009","Behold",29,35],["H2009","behold",37,43],["H5414","them: and I will give",44,65],["H3389","to Jerusalem",66,78],["H1319","one that bringeth good tidings",79,109]]},"41:28":{"text":"For I beheld, and there was no man; even among them, and there was no counsellor, that, when I asked of them, could answer a word.","words":[["H7200","For I beheld",0,12],["H0376","and there was no man",14,34],["H3289","even among them, and there was no counsellor",36,80],["H7592","that, when I asked",82,100],["H7725","of them, could answer",101,122],["H1697","a word",123,129]]},"41:29":{"text":"Behold, they are all vanity; their works are nothing: their molten images are wind and confusion.","words":[["H0205","Behold, they are all vanity",0,27],["H4639","their works",29,40],["H0657","are nothing",41,52],["H5262","their molten images",54,73],["H7307","are wind",74,82],["H8414","and confusion",83,96]]},"42:1":{"text":"Behold my servant, whom I uphold; mine elect, in whom my soul delighteth; I have put my spirit upon him: he shall bring forth judgment to the Gentiles.","words":[["H5650","Behold my servant",0,17],["H8551","whom I uphold",19,32],["H0972","mine elect",34,44],["H5315","in whom my soul",46,61],["H7521","delighteth",62,72],["H5414","I have put",74,84],["H7307","my spirit",85,94],["H3318","upon him: he shall bring forth",95,125],["H4941","judgment",126,134],["H1471","to the Gentiles",135,150]]},"42:2":{"text":"He shall not cry, nor lift up, nor cause his voice to be heard in the street.","words":[["H6817","He shall not cry",0,16],["H5375","nor lift up",18,29],["H6963","nor cause his voice",31,50],["H8085","to be heard",51,62],["H2351","in the street",63,76]]},"42:3":{"text":"A bruised reed shall he not break, and the smoking flax shall he not quench: he shall bring forth judgment unto truth.","words":[["H7533","A bruised",0,9],["H7070","reed",10,14],["H7665","shall he not break",15,33],["H3544","and the smoking",35,50],["H6594","flax",51,55],["H3518","shall he not quench",56,75],["H3318","he shall bring forth",77,97],["H4941","judgment",98,106],["H0571","unto truth",107,117]]},"42:4":{"text":"He shall not fail nor be discouraged, till he have set judgment in the earth: and the isles shall wait for his law.","words":[["H3543","He shall not fail",0,17],["H7533","nor be discouraged",18,36],["H7760","till he have set",38,54],["H4941","judgment",55,63],["H0776","in the earth",64,76],["H0339","and the isles",78,91],["H3176","shall wait",92,102],["H8451","for his law",103,114]]},"42:5":{"text":"Thus saith God the LORD, he that created the heavens, and stretched them out; he that spread forth the earth, and that which cometh out of it; he that giveth breath unto the people upon it, and spirit to them that walk therein:","words":[["H0559","Thus saith",0,10],["H0410","God",11,14],["H3068","the LORD",15,23],["H1254","he that created",25,40],["H8064","the heavens",41,52],["H5186","and stretched them out",54,76],["H7554","he that spread forth",78,98],["H0776","the earth",99,108],["H6631","and that which cometh out",110,135],["H5414","of it; he that giveth",136,157],["H5397","breath",158,164],["H5971","unto the people",165,180],["H7307","upon it, and spirit",181,200],["H1980","to them that walk",201,218]]},"42:6":{"text":"I the LORD have called thee in righteousness, and will hold thine hand, and will keep thee, and give thee for a covenant of the people, for a light of the Gentiles;","words":[["H3068","I the LORD",0,10],["H7121","have called",11,22],["H6664","thee in righteousness",23,44],["H2388","and will hold",46,59],["H3027","thine hand",60,70],["H5341","and will keep",72,85],["H5414","thee, and give",86,100],["H1285","thee for a covenant",101,120],["H5971","of the people",121,134],["H0216","for a light",136,147],["H1471","of the Gentiles",148,163]]},"42:7":{"text":"To open the blind eyes, to bring out the prisoners from the prison, and them that sit in darkness out of the prison house.","words":[["H6491","To open",0,7],["H5787","the blind",8,17],["H5869","eyes",18,22],["H3318","to bring out",24,36],["H0616","the prisoners",37,50],["H4525","from the prison",51,66],["H3427","and them that sit",68,85],["H2822","in darkness",86,97],["H3608","out of the prison",98,115],["H1004","house",116,121]]},"42:8":{"text":"I am the LORD: that is my name: and my glory will I not give to another, neither my praise to graven images.","words":[["H3068","I am the LORD",0,13],["H8034","that is my name",15,30],["H3519","and my glory",32,44],["H5414","will I not give",45,60],["H0312","to another",61,71],["H8416","neither my praise",73,90],["H6456","to graven images",91,107]]},"42:9":{"text":"Behold, the former things are come to pass, and new things do I declare: before they spring forth I tell you of them.","words":[["H7223","Behold, the former things",0,25],["H0935","are come to pass",26,42],["H2319","and new things",44,58],["H5046","do I declare",59,71],["H6779","before they spring forth",73,97],["H8085","I tell",98,104]]},"42:10":{"text":"Sing unto the LORD a new song, and his praise from the end of the earth, ye that go down to the sea, and all that is therein; the isles, and the inhabitants thereof.","words":[["H7891","Sing",0,4],["H3068","unto the LORD",5,18],["H2319","a new",19,24],["H7892","song",25,29],["H8416","and his praise",31,45],["H7097","from the end",46,58],["H0776","of the earth",59,71],["H3381","ye that go down",73,88],["H3220","to the sea",89,99],["H4393","and all that is therein",101,124],["H0339","the isles",126,135],["H3427","and the inhabitants",137,156]]},"42:11":{"text":"Let the wilderness and the cities thereof lift up their voice, the villages that Kedar doth inhabit: let the inhabitants of the rock sing, let them shout from the top of the mountains.","words":[["H4057","Let the wilderness",0,18],["H5892","and the cities",19,33],["H5375","thereof lift up",34,49],["H2691","their voice, the villages",50,75],["H6938","that Kedar",76,86],["H3427","doth inhabit",87,99],["H3427","let the inhabitants",101,120],["H5553","of the rock",121,132],["H7442","sing",133,137],["H6681","let them shout",139,153],["H7218","from the top",154,166],["H2022","of the mountains",167,183]]},"42:12":{"text":"Let them give glory unto the LORD, and declare his praise in the islands.","words":[["H7760","Let them give",0,13],["H3519","glory",14,19],["H3068","unto the LORD",20,33],["H5046","and declare",35,46],["H8416","his praise",47,57],["H0339","in the islands",58,72]]},"42:13":{"text":"The LORD shall go forth as a mighty man, he shall stir up jealousy like a man of war: he shall cry, yea, roar; he shall prevail against his enemies.","words":[["H3068","The LORD",0,8],["H3318","shall go forth",9,23],["H1368","as a mighty man",24,39],["H5782","he shall stir up",41,57],["H7068","jealousy",58,66],["H0376","like a man",67,77],["H4421","of war",78,84],["H7321","he shall cry",86,98],["H6873","yea, roar",100,109],["H1396","he shall prevail",111,127],["H0341","against his enemies",128,147]]},"42:14":{"text":"I have long time holden my peace; I have been still, and refrained myself: now will I cry like a travailing woman; I will destroy and devour at once.","words":[["H5769","I have long time",0,16],["H2814","holden my peace",17,32],["H2790","I have been still",34,51],["H0662","and refrained",53,66],["H6463","myself: now will I cry",67,89],["H3205","like a travailing woman",90,113],["H5395","I will destroy",115,129],["H8074","I will destroy",115,129],["H7602","and devour",130,140],["H3162","at once",141,148]]},"42:15":{"text":"I will make waste mountains and hills, and dry up all their herbs; and I will make the rivers islands, and I will dry up the pools.","words":[["H2717","I will make waste",0,17],["H2022","mountains",18,27],["H1389","and hills",28,37],["H3001","and dry up",39,49],["H6212","all their herbs",50,65],["H7760","and I will make",67,82],["H5104","the rivers",83,93],["H0339","islands",94,101],["H3001","and I will dry up",103,120],["H0098","the pools",121,130]]},"42:16":{"text":"And I will bring the blind by a way that they knew not; I will lead them in paths that they have not known: I will make darkness light before them, and crooked things straight. These things will I do unto them, and not forsake them.","words":[["H3212","And I will bring",0,16],["H5787","the blind",17,26],["H1870","by a way",27,35],["H3045","that they knew",36,50],["H1869","not; I will lead",51,67],["H5410","them in paths",68,81],["H3045","that they have not known",82,106],["H7760","I will make",108,119],["H4285","darkness",120,128],["H0216","light",129,134],["H6440","before",135,141],["H4625","them, and crooked things",142,166],["H4334","straight",167,175],["H1697","These things",177,189],["H6213","will I do",190,199],["H5800","unto them, and not forsake",200,226]]},"42:17":{"text":"They shall be turned back, they shall be greatly ashamed, that trust in graven images, that say to the molten images, Ye are our gods.","words":[["H5472","They shall be turned",0,20],["H0268","back",21,25],["H1322","they shall be greatly",27,48],["H0954","ashamed",49,56],["H0982","that trust",58,68],["H6459","in graven images",69,85],["H0559","that say",87,95],["H4541","to the molten images",96,116],["H0430","Ye are our gods",118,133]]},"42:18":{"text":"Hear, ye deaf; and look, ye blind, that ye may see.","words":[["H8085","Hear",0,4],["H2795","ye deaf",6,13],["H5027","and look",15,23],["H5787","ye blind",25,33],["H7200","that ye may see",35,50]]},"42:19":{"text":"Who is blind, but my servant? or deaf, as my messenger that I sent? who is blind as he that is perfect, and blind as the LORD'S servant?","words":[["H5787","Who is blind",0,12],["H5650","but my servant",14,28],["H2795","or deaf",30,37],["H4397","as my messenger",39,54],["H7971","that I sent",55,66],["H5787","who is blind",68,80],["H7999","as he that is perfect",81,102],["H5787","and blind",104,113],["H3068","as the LORD'S",114,127],["H5650","servant",128,135]]},"42:20":{"text":"Seeing many things, but thou observest not; opening the ears, but he heareth not.","words":[["H7200","Seeing",0,6],["H7200","Seeing",0,6],["H7227","many things",7,18],["H8104","but thou observest",20,38],["H6491","not; opening",39,51],["H0241","the ears",52,60],["H8085","but he heareth",62,76]]},"42:21":{"text":"The LORD is well pleased for his righteousness' sake; he will magnify the law, and make it honourable.","words":[["H3068","The LORD",0,8],["H2654","is well pleased",9,24],["H6664","for his righteousness'",25,47],["H1431","sake; he will magnify",48,69],["H8451","the law",70,77],["H0142","and make it honourable",79,101]]},"42:22":{"text":"But this is a people robbed and spoiled; they are all of them snared in holes, and they are hid in prison houses: they are for a prey, and none delivereth; for a spoil, and none saith, Restore.","words":[["H5971","But this is a people",0,20],["H0962","robbed",21,27],["H8154","and spoiled",28,39],["H6351","they are all of them snared",41,68],["H2352","in holes",69,77],["H0970","in holes",69,77],["H2244","and they are hid",79,95],["H3608","in prison",96,105],["H1004","houses",106,112],["H0957","they are for a prey",114,133],["H5337","and none delivereth",135,154],["H4933","for a spoil",156,167],["H0559","and none saith",169,183],["H7725","Restore",185,192]]},"42:23":{"text":"Who among you will give ear to this? who will hearken and hear for the time to come?","words":[["H0238","Who among you will give ear",0,27],["H7181","to this? who will hearken",28,53],["H8085","and hear",54,62],["H0268","for the time to come",63,83]]},"42:24":{"text":"Who gave Jacob for a spoil, and Israel to the robbers? did not the LORD, he against whom we have sinned? for they would not walk in his ways, neither were they obedient unto his law.","words":[["H5414","Who gave",0,8],["H3290","Jacob",9,14],["H4933","for a spoil",15,26],["H4882","for a spoil",15,26],["H3478","and Israel",28,38],["H0962","to the robbers",39,53],["H3068","did not the LORD",55,71],["H2098","he against whom",73,88],["H2398","we have sinned",89,103],["H0014","for they would",105,119],["H1980","not walk",120,128],["H1870","in his ways",129,140],["H8085","neither were they obedient",142,168],["H8451","unto his law",169,181]]},"42:25":{"text":"Therefore he hath poured upon him the fury of his anger, and the strength of battle: and it hath set him on fire round about, yet he knew not; and it burned him, yet he laid it not to heart.","words":[["H8210","Therefore he hath poured",0,24],["H2534","upon him the fury",25,42],["H0639","of his anger",43,55],["H5807","and the strength",57,73],["H4421","of battle",74,83],["H3857","and it hath set him on fire",85,112],["H5439","round about",113,124],["H3045","yet he knew",126,137],["H1197","not; and it burned",138,156],["H7760","him, yet he laid",157,173],["H3820","it not to heart",174,189]]},"43:1":{"text":"But now thus saith the LORD that created thee, O Jacob, and he that formed thee, O Israel, Fear not: for I have redeemed thee, I have called thee by thy name; thou art mine.","words":[["H0559","But now thus saith",0,18],["H3068","the LORD",19,27],["H1254","that created",28,40],["H3290","thee, O Jacob",41,54],["H3335","and he that formed",56,74],["H3478","thee, O Israel",75,89],["H3372","Fear",91,95],["H1350","not: for I have redeemed",96,120],["H7121","thee, I have called",121,140],["H8034","thee by thy name",141,157]]},"43:2":{"text":"When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee.","words":[["H5674","When thou passest through",0,25],["H4325","the waters",26,36],["H5104","I will be with thee; and through the rivers",38,81],["H7857","they shall not overflow",83,106],["H3212","thee: when thou walkest",107,130],["H1119","through",131,138],["H0784","the fire",139,147],["H3554","thou shalt not be burned",149,173],["H3852","neither shall the flame",175,198],["H1197","kindle",199,205]]},"43:3":{"text":"For I am the LORD thy God, the Holy One of Israel, thy Saviour: I gave Egypt for thy ransom, Ethiopia and Seba for thee.","words":[["H3068","For I am the LORD",0,17],["H0430","thy God",18,25],["H6918","the Holy One",27,39],["H3478","of Israel",40,49],["H3467","thy Saviour",51,62],["H5414","I gave",64,70],["H4714","Egypt",71,76],["H3724","for thy ransom",77,91],["H3568","Ethiopia",93,101],["H5434","and Seba",102,110]]},"43:4":{"text":"Since thou wast precious in my sight, thou hast been honourable, and I have loved thee: therefore will I give men for thee, and people for thy life.","words":[["H3365","Since thou wast precious",0,24],["H5869","in my sight",25,36],["H3513","thou hast been honourable",38,63],["H0157","and I have loved",65,81],["H5414","thee: therefore will I give",82,109],["H0120","men",110,113],["H3816","for thee, and people",114,134],["H5315","for thy life",135,147]]},"43:5":{"text":"Fear not: for I am with thee: I will bring thy seed from the east, and gather thee from the west;","words":[["H3372","Fear",0,4],["H0935","not: for I am with thee: I will bring",5,42],["H2233","thy seed",43,51],["H4217","from the east",52,65],["H6908","and gather",67,77],["H4628","thee from the west",78,96]]},"43:6":{"text":"I will say to the north, Give up; and to the south, Keep not back: bring my sons from far, and my daughters from the ends of the earth;","words":[["H0559","I will say",0,10],["H6828","to the north",11,23],["H5414","Give up",25,32],["H8486","and to the south",34,50],["H3607","Keep not back",52,65],["H0935","bring",67,72],["H1121","my sons",73,80],["H7350","from far",81,89],["H1323","and my daughters",91,107],["H7097","from the ends",108,121],["H0776","of the earth",122,134]]},"43:7":{"text":"Even every one that is called by my name: for I have created him for my glory, I have formed him; yea, I have made him.","words":[["H3605","Even every one",0,14],["H7121","that is called",15,29],["H8034","by my name",30,40],["H1254","for I have created",42,60],["H3519","him for my glory",61,77],["H3335","I have formed",79,92],["H6213","him; yea, I have made",93,114]]},"43:8":{"text":"Bring forth the blind people that have eyes, and the deaf that have ears.","words":[["H3318","Bring forth",0,11],["H5787","the blind",12,21],["H5971","people",22,28],["H3426","that have",29,38],["H5869","eyes",39,43],["H2795","and the deaf",45,57],["H0241","that have ears",58,72]]},"43:9":{"text":"Let all the nations be gathered together, and let the people be assembled: who among them can declare this, and shew us former things? let them bring forth their witnesses, that they may be justified: or let them hear, and say, It is truth.","words":[["H1471","Let all the nations",0,19],["H6908","be gathered",20,31],["H3162","together",32,40],["H3816","and let the people",42,60],["H0622","be assembled",61,73],["H5046","who among them can declare",75,101],["H8085","this, and shew",102,116],["H7223","us former things",117,133],["H5414","let them bring forth",135,155],["H5707","their witnesses",156,171],["H6663","that they may be justified",173,199],["H8085","or let them hear",201,217],["H0559","and say",219,226],["H0571","It is truth",228,239]]},"43:10":{"text":"Ye are my witnesses, saith the LORD, and my servant whom I have chosen: that ye may know and believe me, and understand that I am he: before me there was no God formed, neither shall there be after me.","words":[["H5707","Ye are my witnesses",0,19],["H5002","saith",21,26],["H3068","the LORD",27,35],["H5650","and my servant",37,51],["H0977","whom I have chosen",52,70],["H3045","that ye may know",72,88],["H0539","and believe",89,100],["H0995","me, and understand",101,119],["H6440","that I am he: before",120,140],["H0410","me there was no God",141,160],["H3335","formed",161,167],["H0310","neither shall there be after",169,197]]},"43:11":{"text":"I, even I, am the LORD; and beside me there is no saviour.","words":[["H3068","I, even I, am the LORD",0,22],["H1107","and beside",24,34],["H3467","me there is no saviour",35,57]]},"43:12":{"text":"I have declared, and have saved, and I have shewed, when there was no strange god among you: therefore ye are my witnesses, saith the LORD, that I am God.","words":[["H5046","I have declared",0,15],["H3467","and have saved",17,31],["H8085","and I have shewed",33,50],["H2114","when there was no strange",52,77],["H5707","god among you: therefore ye are my witnesses",78,122],["H5002","saith",124,129],["H3068","the LORD",130,138],["H0410","that I am God",140,153]]},"43:13":{"text":"Yea, before the day was I am he; and there is none that can deliver out of my hand: I will work, and who shall let it?","words":[["H3117","Yea, before the day",0,19],["H5337","was I am he; and there is none that can deliver",20,67],["H3027","out of my hand",68,82],["H6466","I will work",84,95],["H7725","and who shall let",97,114]]},"43:14":{"text":"Thus saith the LORD, your redeemer, the Holy One of Israel; For your sake I have sent to Babylon, and have brought down all their nobles, and the Chaldeans, whose cry is in the ships.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H1350","your redeemer",21,34],["H6918","the Holy One",36,48],["H3478","of Israel",49,58],["H7971","For your sake I have sent",60,85],["H0894","to Babylon",86,96],["H3381","and have brought down",98,119],["H1281","all their nobles",120,136],["H3778","and the Chaldeans",138,155],["H7440","whose cry",157,166],["H0591","is in the ships",167,182]]},"43:15":{"text":"I am the LORD, your Holy One, the creator of Israel, your King.","words":[["H3068","I am the LORD",0,13],["H6918","your Holy One",15,28],["H1254","the creator",30,41],["H3478","of Israel",42,51],["H4428","your King",53,62]]},"43:16":{"text":"Thus saith the LORD, which maketh a way in the sea, and a path in the mighty waters;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H5414","which maketh",21,33],["H1870","a way",34,39],["H3220","in the sea",40,50],["H5410","and a path",52,62],["H5794","in the mighty",63,76],["H4325","waters",77,83]]},"43:17":{"text":"Which bringeth forth the chariot and horse, the army and the power; they shall lie down together, they shall not rise: they are extinct, they are quenched as tow.","words":[["H3318","Which bringeth forth",0,20],["H7393","the chariot",21,32],["H5483","and horse",33,42],["H2428","the army",44,52],["H5808","and the power",53,66],["H7901","they shall lie down",68,87],["H3162","together",88,96],["H6965","they shall not rise",98,117],["H1846","they are extinct",119,135],["H3518","they are quenched",137,154],["H6594","as tow",155,161]]},"43:18":{"text":"Remember ye not the former things, neither consider the things of old.","words":[["H2142","Remember",0,8],["H7223","ye not the former things",9,33],["H0995","neither consider",35,51],["H6931","the things of old",52,69]]},"43:19":{"text":"Behold, I will do a new thing; now it shall spring forth; shall ye not know it? I will even make a way in the wilderness, and rivers in the desert.","words":[["H6213","Behold, I will do",0,17],["H2319","a new thing",18,29],["H6779","now it shall spring forth",31,56],["H3045","shall ye not know",58,75],["H7760","it? I will even make",76,96],["H1870","a way",97,102],["H4057","in the wilderness",103,120],["H5104","and rivers",122,132],["H3452","in the desert",133,146]]},"43:20":{"text":"The beast of the field shall honour me, the dragons and the owls: because I give waters in the wilderness, and rivers in the desert, to give drink to my people, my chosen.","words":[["H2416","The beast",0,9],["H7704","of the field",10,22],["H3513","shall honour",23,35],["H8577","me, the dragons",36,51],["H1323","and the owls",52,64],["H3284","and the owls",52,64],["H5414","because I give",66,80],["H4325","waters",81,87],["H4057","in the wilderness",88,105],["H5104","and rivers",107,117],["H3452","in the desert",118,131],["H8248","to give drink",133,146],["H5971","to my people",147,159],["H0972","my chosen",161,170]]},"43:21":{"text":"This people have I formed for myself; they shall shew forth my praise.","words":[["H2098","This",0,4],["H5971","people",5,11],["H3335","have I formed",12,25],["H5608","for myself; they shall shew forth",26,59],["H8416","my praise",60,69]]},"43:22":{"text":"But thou hast not called upon me, O Jacob; but thou hast been weary of me, O Israel.","words":[["H7121","But thou hast not called",0,24],["H3290","upon me, O Jacob",25,41],["H3021","but thou hast been weary",43,67],["H3478","of me, O Israel",68,83]]},"43:23":{"text":"Thou hast not brought me the small cattle of thy burnt offerings; neither hast thou honoured me with thy sacrifices. I have not caused thee to serve with an offering, nor wearied thee with incense.","words":[["H0935","Thou hast not brought",0,21],["H7716","me the small cattle",22,41],["H5930","of thy burnt offerings",42,64],["H3513","neither hast thou honoured",66,92],["H2077","me with thy sacrifices",93,115],["H5647","I have not caused thee to serve",117,148],["H4503","with an offering",149,165],["H3021","nor wearied",167,178],["H3828","thee with incense",179,196]]},"43:24":{"text":"Thou hast bought me no sweet cane with money, neither hast thou filled me with the fat of thy sacrifices: but thou hast made me to serve with thy sins, thou hast wearied me with thine iniquities.","words":[["H7069","Thou hast bought",0,16],["H7070","me no sweet cane",17,33],["H3701","with money",34,44],["H7301","neither hast thou filled",46,70],["H2459","me with the fat",71,86],["H2077","of thy sacrifices",87,104],["H5647","but thou hast made me to serve",106,136],["H2403","with thy sins",137,150],["H3021","thou hast wearied",152,169],["H5771","me with thine iniquities",170,194]]},"43:25":{"text":"I, even I, am he that blotteth out thy transgressions for mine own sake, and will not remember thy sins.","words":[["H4229","I, even I, am he that blotteth out",0,34],["H6588","thy transgressions",35,53],["H2142","for mine own sake, and will not remember",54,94],["H2403","thy sins",95,103]]},"43:26":{"text":"Put me in remembrance: let us plead together: declare thou, that thou mayest be justified.","words":[["H2142","Put me in remembrance",0,21],["H8199","let us plead",23,35],["H3162","together",36,44],["H5608","declare",46,53],["H6663","thou, that thou mayest be justified",54,89]]},"43:27":{"text":"Thy first father hath sinned, and thy teachers have transgressed against me.","words":[["H7223","Thy first",0,9],["H0001","father",10,16],["H2398","hath sinned",17,28],["H3887","and thy teachers",30,46],["H6586","have transgressed",47,64]]},"43:28":{"text":"Therefore I have profaned the princes of the sanctuary, and have given Jacob to the curse, and Israel to reproaches.","words":[["H2490","Therefore I have profaned",0,25],["H8269","the princes",26,37],["H6944","of the sanctuary",38,54],["H5414","and have given",56,70],["H3290","Jacob",71,76],["H2764","to the curse",77,89],["H3478","and Israel",91,101],["H1421","to reproaches",102,115]]},"44:1":{"text":"Yet now hear, O Jacob my servant; and Israel, whom I have chosen:","words":[["H8085","Yet now hear",0,12],["H3290","O Jacob",14,21],["H5650","my servant",22,32],["H3478","and Israel",34,44],["H0977","whom I have chosen",46,64]]},"44:2":{"text":"Thus saith the LORD that made thee, and formed thee from the womb, which will help thee; Fear not, O Jacob, my servant; and thou, Jesurun, whom I have chosen.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6213","that made",20,29],["H3335","thee, and formed",30,46],["H0990","thee from the womb",47,65],["H5826","which will help",67,82],["H3372","thee; Fear",83,93],["H3290","not, O Jacob",94,106],["H5650","my servant",108,118],["H3484","and thou, Jesurun",120,137],["H0977","whom I have chosen",139,157]]},"44:3":{"text":"For I will pour water upon him that is thirsty, and floods upon the dry ground: I will pour my spirit upon thy seed, and my blessing upon thine offspring:","words":[["H3332","For I will pour",0,15],["H4325","water",16,21],["H6771","upon him that is thirsty",22,46],["H5140","and floods",48,58],["H3004","upon the dry ground",59,78],["H3332","I will pour",80,91],["H7307","my spirit",92,101],["H2233","upon thy seed",102,115],["H1293","and my blessing",117,132],["H6631","upon thine offspring",133,153]]},"44:4":{"text":"And they shall spring up as among the grass, as willows by the water courses.","words":[["H6779","And they shall spring up",0,24],["H0996","as among",25,33],["H2682","the grass",34,43],["H6155","as willows",45,55],["H4325","by the water",56,68],["H2988","courses",69,76]]},"44:5":{"text":"One shall say, I am the LORD'S; and another shall call himself by the name of Jacob; and another shall subscribe with his hand unto the LORD, and surname himself by the name of Israel.","words":[["H0559","One shall say",0,13],["H3068","I am the LORD'S",15,30],["H7121","and another shall call",32,54],["H8034","himself by the name",55,74],["H3290","of Jacob",75,83],["H3789","and another shall subscribe",85,112],["H3027","with his hand",113,126],["H3068","unto the LORD",127,140],["H3655","and surname",142,153],["H8034","himself by the name",154,173],["H3478","of Israel",174,183]]},"44:6":{"text":"Thus saith the LORD the King of Israel, and his redeemer the LORD of hosts; I am the first, and I am the last; and beside me there is no God.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H4428","the King",20,28],["H3478","of Israel",29,38],["H1350","and his redeemer",40,56],["H3068","the LORD",57,65],["H6635","of hosts",66,74],["H7223","I am the first",76,90],["H0314","and I am the last",92,109],["H1107","and beside",111,121],["H0430","me there is no God",122,140]]},"44:7":{"text":"And who, as I, shall call, and shall declare it, and set it in order for me, since I appointed the ancient people? and the things that are coming, and shall come, let them shew unto them.","words":[["H7121","And who, as I, shall call",0,25],["H5046","and shall declare",27,44],["H6186","it, and set it in order",45,68],["H7760","for me, since I appointed",69,94],["H5769","the ancient",95,106],["H5971","people",107,113],["H0857","and the things that are coming",115,145],["H0935","and shall come",147,161],["H5046","let them shew",163,176]]},"44:8":{"text":"Fear ye not, neither be afraid: have not I told thee from that time, and have declared it? ye are even my witnesses. Is there a God beside me? yea, there is no God; I know not any.","words":[["H6342","Fear",0,4],["H7297","ye not, neither be afraid",5,30],["H7297","ye not, neither be afraid",5,30],["H8085","have not I told",32,47],["H0227","thee from that time",48,67],["H5046","and have declared",69,86],["H5707","it? ye are even my witnesses",87,115],["H3426","Is there",117,125],["H0433","a God",126,131],["H1107","beside",132,138],["H6697","me? yea, there is no God",139,163],["H3045","I know",165,171]]},"44:9":{"text":"They that make a graven image are all of them vanity; and their delectable things shall not profit; and they are their own witnesses; they see not, nor know; that they may be ashamed.","words":[["H3335","They that make",0,14],["H6459","a graven image",15,29],["H8414","are all of them vanity",30,52],["H2530","and their delectable things",54,81],["H3276","shall not profit",82,98],["H5707","and they are their own witnesses",100,132],["H7200","they see",134,142],["H3045","not, nor know",143,156],["H0954","that they may be ashamed",158,182]]},"44:10":{"text":"Who hath formed a god, or molten a graven image that is profitable for nothing?","words":[["H3335","Who hath formed",0,15],["H0410","a god",16,21],["H5258","or molten",23,32],["H6459","a graven image",33,47],["H3276","that is profitable",48,66],["H1115","for nothing",67,78]]},"44:11":{"text":"Behold, all his fellows shall be ashamed: and the workmen, they are of men: let them all be gathered together, let them stand up; yet they shall fear, and they shall be ashamed together.","words":[["H2270","Behold, all his fellows",0,23],["H0954","shall be ashamed",24,40],["H2796","and the workmen",42,57],["H0120","they are of men",59,74],["H6908","let them all be gathered together",76,109],["H5975","let them stand up",111,128],["H6342","yet they shall fear",130,149],["H0954","and they shall be ashamed",151,176],["H3162","together",177,185]]},"44:12":{"text":"The smith with the tongs both worketh in the coals, and fashioneth it with hammers, and worketh it with the strength of his arms: yea, he is hungry, and his strength faileth: he drinketh no water, and is faint.","words":[["H1270","The smith",0,9],["H2796","The smith",0,9],["H4621","with the tongs",10,24],["H6466","both worketh",25,37],["H6352","in the coals",38,50],["H3335","and fashioneth",52,66],["H4717","it with hammers",67,82],["H6466","and worketh",84,95],["H3581","it with the strength",96,116],["H2220","of his arms",117,128],["H7457","yea, he is hungry",130,147],["H3581","and his strength",149,165],["H0369","faileth",166,173],["H8354","he drinketh",175,186],["H4325","no water",187,195],["H3286","and is faint",197,209]]},"44:13":{"text":"The carpenter stretcheth out his rule; he marketh it out with a line; he fitteth it with planes, and he marketh it out with the compass, and maketh it after the figure of a man, according to the beauty of a man; that it may remain in the house.","words":[["H2796","The carpenter",0,13],["H6086","The carpenter",0,13],["H5186","stretcheth out",14,28],["H6957","his rule",29,37],["H8388","he marketh it out",39,56],["H8279","with a line",57,68],["H6213","he fitteth",70,80],["H4741","it with planes",81,95],["H8388","and he marketh it out",97,118],["H4230","with the compass",119,135],["H6213","and maketh",137,147],["H8403","it after the figure",148,167],["H0376","of a man",168,176],["H8597","according to the beauty",178,201],["H0120","of a man",202,210],["H3427","that it may remain",212,230],["H1004","in the house",231,243]]},"44:14":{"text":"He heweth him down cedars, and taketh the cypress and the oak, which he strengtheneth for himself among the trees of the forest: he planteth an ash, and the rain doth nourish it.","words":[["H3772","He heweth him down",0,18],["H0730","cedars",19,25],["H3947","and taketh",27,37],["H8645","the cypress",38,49],["H0437","and the oak",50,61],["H0553","which he strengtheneth",63,85],["H6086","for himself among the trees",86,113],["H3293","of the forest",114,127],["H5193","he planteth",129,140],["H0766","an ash",141,147],["H1653","and the rain",149,161],["H1431","doth nourish",162,174]]},"44:15":{"text":"Then shall it be for a man to burn: for he will take thereof, and warm himself; yea, he kindleth it, and baketh bread; yea, he maketh a god, and worshippeth it; he maketh it a graven image, and falleth down thereto.","words":[["H0120","Then shall it be for a man",0,26],["H1197","to burn",27,34],["H3947","for he will take",36,52],["H2552","thereof, and warm",53,70],["H5400","himself; yea, he kindleth",71,96],["H0644","it, and baketh",97,111],["H3899","bread",112,117],["H6466","yea, he maketh",119,133],["H0410","a god",134,139],["H7812","and worshippeth",141,156],["H6213","it; he maketh",157,170],["H6459","it a graven image",171,188],["H5456","and falleth down",190,206]]},"44:16":{"text":"He burneth part thereof in the fire; with part thereof he eateth flesh; he roasteth roast, and is satisfied: yea, he warmeth himself, and saith, Aha, I am warm, I have seen the fire:","words":[["H8313","He burneth",0,10],["H2677","part",11,15],["H1119","thereof in",16,26],["H0784","the fire",27,35],["H2677","with part",37,46],["H0398","thereof he eateth",47,64],["H1320","flesh",65,70],["H6740","he roasteth",72,83],["H6748","roast",84,89],["H7646","and is satisfied",91,107],["H2552","yea, he warmeth",109,124],["H0559","himself, and saith",125,143],["H1889","Aha",145,148],["H2552","I am warm",150,159],["H7200","I have seen",161,172],["H0217","the fire",173,181]]},"44:17":{"text":"And the residue thereof he maketh a god, even his graven image: he falleth down unto it, and worshippeth it, and prayeth unto it, and saith, Deliver me; for thou art my god.","words":[["H7611","And the residue",0,15],["H6213","thereof he maketh",16,33],["H0410","a god",34,39],["H6459","even his graven image",41,62],["H5456","he falleth down",64,79],["H7812","unto it, and worshippeth",80,104],["H6419","it, and prayeth",105,120],["H0559","unto it, and saith",121,139],["H5337","Deliver",141,148],["H0410","me; for thou art my god",149,172]]},"44:18":{"text":"They have not known nor understood: for he hath shut their eyes, that they cannot see; and their hearts, that they cannot understand.","words":[["H3045","They have not known",0,19],["H0995","nor understood",20,34],["H2902","for he hath shut",36,52],["H5869","their eyes",53,63],["H7200","that they cannot see",65,85],["H3826","and their hearts",87,103],["H7919","that they cannot understand",105,132]]},"44:19":{"text":"And none considereth in his heart, neither is there knowledge nor understanding to say, I have burned part of it in the fire; yea, also I have baked bread upon the coals thereof; I have roasted flesh, and eaten it: and shall I make the residue thereof an abomination? shall I fall down to the stock of a tree?","words":[["H7725","And none considereth",0,20],["H3820","in his heart",21,33],["H1847","neither is there knowledge",35,61],["H8394","nor understanding",62,79],["H0559","to say",80,86],["H8313","I have burned",88,101],["H2677","part",102,106],["H1119","of it in",107,115],["H0784","the fire",116,124],["H0644","yea, also I have baked",126,148],["H3899","bread",149,154],["H1513","upon the coals",155,169],["H6740","thereof; I have roasted",170,193],["H1320","flesh",194,199],["H0398","and eaten",201,210],["H6213","it: and shall I make",211,231],["H3499","the residue",232,243],["H8441","thereof an abomination",244,266],["H5456","shall I fall down",268,285],["H0944","to the stock",286,298],["H6086","of a tree",299,308]]},"44:20":{"text":"He feedeth on ashes: a deceived heart hath turned him aside, that he cannot deliver his soul, nor say, Is there not a lie in my right hand?","words":[["H7462","He feedeth",0,10],["H0665","on ashes",11,19],["H2048","a deceived",21,31],["H3820","heart",32,37],["H5186","hath turned him aside",38,59],["H5337","that he cannot deliver",61,83],["H5315","his soul",84,92],["H0559","nor say",94,101],["H8267","Is there not a lie",103,121],["H3225","in my right hand",122,138]]},"44:21":{"text":"Remember these, O Jacob and Israel; for thou art my servant: I have formed thee; thou art my servant: O Israel, thou shalt not be forgotten of me.","words":[["H2142","Remember",0,8],["H3290","these, O Jacob",9,23],["H3478","and Israel",24,34],["H5650","for thou art my servant",36,59],["H3335","I have formed",61,74],["H5650","thee; thou art my servant",75,100],["H3478","O Israel",102,110],["H5382","thou shalt not be forgotten",112,139]]},"44:22":{"text":"I have blotted out, as a thick cloud, thy transgressions, and, as a cloud, thy sins: return unto me; for I have redeemed thee.","words":[["H4229","I have blotted out",0,18],["H5645","as a thick cloud",20,36],["H6588","thy transgressions",38,56],["H6051","and, as a cloud",58,73],["H2403","thy sins",75,83],["H7725","return",85,91],["H1350","unto me; for I have redeemed",92,120]]},"44:23":{"text":"Sing, O ye heavens; for the LORD hath done it: shout, ye lower parts of the earth: break forth into singing, ye mountains, O forest, and every tree therein: for the LORD hath redeemed Jacob, and glorified himself in Israel.","words":[["H7442","Sing",0,4],["H8064","O ye heavens",6,18],["H3068","for the LORD",20,32],["H6213","hath done",33,42],["H7321","it: shout",43,52],["H8482","ye lower parts",54,68],["H0776","of the earth",69,81],["H6476","break forth",83,94],["H7440","into singing",95,107],["H2022","ye mountains",109,121],["H3293","O forest",123,131],["H6086","and every tree",133,147],["H3068","therein: for the LORD",148,169],["H1350","hath redeemed",170,183],["H3290","Jacob",184,189],["H6286","and glorified",191,204],["H3478","himself in Israel",205,222]]},"44:24":{"text":"Thus saith the LORD, thy redeemer, and he that formed thee from the womb, I am the LORD that maketh all things; that stretcheth forth the heavens alone; that spreadeth abroad the earth by myself;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H1350","thy redeemer",21,33],["H3335","and he that formed",35,53],["H0990","thee from the womb",54,72],["H3068","I am the LORD",74,87],["H6213","that maketh",88,99],["H5186","all things; that stretcheth forth",100,133],["H8064","the heavens",134,145],["H7554","alone; that spreadeth abroad",146,174],["H0776","the earth",175,184]]},"44:25":{"text":"That frustrateth the tokens of the liars, and maketh diviners mad; that turneth wise men backward, and maketh their knowledge foolish;","words":[["H6565","That frustrateth",0,16],["H0226","the tokens",17,27],["H0907","of the liars",28,40],["H7080","and maketh diviners",42,61],["H1984","mad",62,65],["H7725","that turneth",67,79],["H2450","wise",80,84],["H0268","men backward",85,97],["H1847","and maketh their knowledge",99,125],["H5528","foolish",126,133]]},"44:26":{"text":"That confirmeth the word of his servant, and performeth the counsel of his messengers; that saith to Jerusalem, Thou shalt be inhabited; and to the cities of Judah, Ye shall be built, and I will raise up the decayed places thereof:","words":[["H6965","That confirmeth",0,15],["H1697","the word",16,24],["H5650","of his servant",25,39],["H7999","and performeth",41,55],["H6098","the counsel",56,67],["H4397","of his messengers",68,85],["H0559","that saith",87,97],["H3389","to Jerusalem",98,110],["H3427","Thou shalt be inhabited",112,135],["H5892","and to the cities",137,154],["H3063","of Judah",155,163],["H1129","Ye shall be built",165,182],["H6965","and I will raise up",184,203],["H2723","the decayed places",204,222]]},"44:27":{"text":"That saith to the deep, Be dry, and I will dry up thy rivers:","words":[["H0559","That saith",0,10],["H6683","to the deep",11,22],["H2717","Be dry",24,30],["H3001","and I will dry up",32,49],["H5104","thy rivers",50,60]]},"44:28":{"text":"That saith of Cyrus, He is my shepherd, and shall perform all my pleasure: even saying to Jerusalem, Thou shalt be built; and to the temple, Thy foundation shall be laid.","words":[["H0559","That saith",0,10],["H3566","of Cyrus",11,19],["H7462","He is my shepherd",21,38],["H7999","and shall perform",40,57],["H2656","all my pleasure",58,73],["H0559","even saying",75,86],["H3389","to Jerusalem",87,99],["H1129","Thou shalt be built",101,120],["H1964","and to the temple",122,139],["H3245","Thy foundation shall be laid",141,169]]},"45:1":{"text":"Thus saith the LORD to his anointed, to Cyrus, whose right hand I have holden, to subdue nations before him; and I will loose the loins of kings, to open before him the two leaved gates; and the gates shall not be shut;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H4899","to his anointed",20,35],["H3566","to Cyrus",37,45],["H3225","whose right hand",47,63],["H2388","I have holden",64,77],["H7286","to subdue",79,88],["H1471","nations",89,96],["H6440","before",97,103],["H6605","him; and I will loose",104,125],["H4975","the loins",126,135],["H4428","of kings",136,144],["H6605","to open",146,153],["H6440","before",154,160],["H1817","him the two leaved gates",161,185],["H8179","and the gates",187,200],["H5462","shall not be shut",201,218]]},"45:2":{"text":"I will go before thee, and make the crooked places straight: I will break in pieces the gates of brass, and cut in sunder the bars of iron:","words":[["H3212","I will go",0,9],["H6440","before",10,16],["H3474","thee, and make",17,31],["H1921","the crooked places",32,50],["H3474","straight",51,59],["H3474","straight",51,59],["H7665","I will break in pieces",61,83],["H1817","the gates",84,93],["H5154","of brass",94,102],["H1438","and cut in sunder",104,121],["H1280","the bars",122,130],["H1270","of iron",131,138]]},"45:3":{"text":"And I will give thee the treasures of darkness, and hidden riches of secret places, that thou mayest know that I, the LORD, which call thee by thy name, am the God of Israel.","words":[["H5414","And I will give",0,15],["H0214","thee the treasures",16,34],["H2822","of darkness",35,46],["H4301","and hidden riches",48,65],["H4565","of secret places",66,82],["H3045","that thou mayest know",84,105],["H3068","that I, the LORD",106,122],["H7121","which call",124,134],["H8034","thee by thy name",135,151],["H0430","am the God",153,163],["H3478","of Israel",164,173]]},"45:4":{"text":"For Jacob my servant's sake, and Israel mine elect, I have even called thee by thy name: I have surnamed thee, though thou hast not known me.","words":[["H3290","For Jacob",0,9],["H5650","my servant's",10,22],["H3478","sake, and Israel",23,39],["H0972","mine elect",40,50],["H7121","I have even called",52,70],["H8034","thee by thy name",71,87],["H3655","I have surnamed",89,104],["H3045","thee, though thou hast not known",105,137]]},"45:5":{"text":"I am the LORD, and there is none else, there is no God beside me: I girded thee, though thou hast not known me:","words":[["H3068","I am the LORD",0,13],["H0430","and there is none else, there is no God",15,54],["H2108","beside",55,61],["H0247","me: I girded",62,74],["H3045","thee, though thou hast not known",75,107]]},"45:6":{"text":"That they may know from the rising of the sun, and from the west, that there is none beside me. I am the LORD, and there is none else.","words":[["H3045","That they may know",0,18],["H4217","from the rising",19,34],["H8121","of the sun",35,45],["H4628","and from the west",47,64],["H0657","that there is none",66,84],["H1107","beside",85,91],["H3068","me. I am the LORD",92,109]]},"45:7":{"text":"I form the light, and create darkness: I make peace, and create evil: I the LORD do all these things.","words":[["H3335","I form",0,6],["H0216","the light",7,16],["H1254","and create",18,28],["H2822","darkness",29,37],["H6213","I make",39,45],["H7965","peace",46,51],["H1254","and create",53,63],["H7451","evil",64,68],["H3068","I the LORD",70,80],["H6213","do",81,83]]},"45:8":{"text":"Drop down, ye heavens, from above, and let the skies pour down righteousness: let the earth open, and let them bring forth salvation, and let righteousness spring up together; I the LORD have created it.","words":[["H7491","Drop down",0,9],["H8064","ye heavens",11,21],["H4605","from above",23,33],["H7834","and let the skies",35,52],["H5140","pour down",53,62],["H6664","righteousness",63,76],["H0776","let the earth",78,91],["H6605","open",92,96],["H6509","and let them bring forth",98,122],["H3468","salvation",123,132],["H6666","and let righteousness",134,155],["H6779","spring up",156,165],["H3162","together",166,174],["H3068","I the LORD",176,186],["H1254","have created",187,199]]},"45:9":{"text":"Woe unto him that striveth with his Maker! Let the potsherd strive with the potsherds of the earth. Shall the clay say to him that fashioneth it, What makest thou? or thy work, He hath no hands?","words":[["H1945","Woe",0,3],["H7378","unto him that striveth",4,26],["H3335","with his Maker",27,41],["H2789","Let the potsherd",43,59],["H2789","strive with the potsherds",60,85],["H0127","of the earth",86,98],["H2563","Shall the clay",100,114],["H0559","say",115,118],["H3335","to him that fashioneth",119,141],["H6213","it, What makest",142,157],["H6467","thou? or thy work",158,175],["H3027","He hath no hands",177,193]]},"45:10":{"text":"Woe unto him that saith unto his father, What begettest thou? or to the woman, What hast thou brought forth?","words":[["H1945","Woe",0,3],["H0559","unto him that saith",4,23],["H0001","unto his father",24,39],["H3205","What begettest",41,55],["H0802","thou? or to the woman",56,77],["H2342","What hast thou brought forth",79,107]]},"45:11":{"text":"Thus saith the LORD, the Holy One of Israel, and his Maker, Ask me of things to come concerning my sons, and concerning the work of my hands command ye me.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H6918","the Holy One",21,33],["H3478","of Israel",34,43],["H3335","and his Maker",45,58],["H7592","Ask",60,63],["H0857","me of things to come",64,84],["H1121","concerning my sons",85,103],["H6467","and concerning the work",105,128],["H3027","of my hands",129,140],["H6680","command",141,148]]},"45:12":{"text":"I have made the earth, and created man upon it: I, even my hands, have stretched out the heavens, and all their host have I commanded.","words":[["H6213","I have made",0,11],["H0776","the earth",12,21],["H1254","and created",23,34],["H0120","man",35,38],["H3027","upon it: I, even my hands",39,64],["H5186","have stretched out",66,84],["H8064","the heavens",85,96],["H6635","and all their host",98,116],["H6680","have I commanded",117,133]]},"45:13":{"text":"I have raised him up in righteousness, and I will direct all his ways: he shall build my city, and he shall let go my captives, not for price nor reward, saith the LORD of hosts.","words":[["H5782","I have raised him up",0,20],["H6664","in righteousness",21,37],["H3474","and I will direct",39,56],["H1870","all his ways",57,69],["H1129","he shall build",71,85],["H5892","my city",86,93],["H7971","and he shall let go",95,114],["H1546","my captives",115,126],["H4242","not for price",128,141],["H7810","nor reward",142,152],["H0559","saith",154,159],["H3068","the LORD",160,168],["H6635","of hosts",169,177]]},"45:14":{"text":"Thus saith the LORD, The labour of Egypt, and merchandise of Ethiopia and of the Sabeans, men of stature, shall come over unto thee, and they shall be thine: they shall come after thee; in chains they shall come over, and they shall fall down unto thee, they shall make supplication unto thee, saying, Surely God is in thee; and there is none else, there is no God.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H3018","The labour",21,31],["H4714","of Egypt",32,40],["H5505","and merchandise",42,57],["H3568","of Ethiopia",58,69],["H5436","and of the Sabeans",70,88],["H0582","men",90,93],["H4060","of stature",94,104],["H5674","shall come over",106,121],["H3212","unto thee, and they shall be thine: they shall come",122,173],["H0310","after",174,179],["H2131","thee; in chains",180,195],["H5674","they shall come over",196,216],["H7812","and they shall fall down",218,242],["H6419","unto thee, they shall make supplication",243,282],["H0410","unto thee, saying, Surely God",283,312],["H0657","is in thee; and there is none else, there is no",313,360],["H0430","God",361,364]]},"45:15":{"text":"Verily thou art a God that hidest thyself, O God of Israel, the Saviour.","words":[["H0403","Verily",0,6],["H0410","thou art a God",7,21],["H5641","that hidest",22,33],["H0430","thyself, O God",34,48],["H3478","of Israel",49,58],["H3467","the Saviour",60,71]]},"45:16":{"text":"They shall be ashamed, and also confounded, all of them: they shall go to confusion together that are makers of idols.","words":[["H0954","They shall be ashamed",0,21],["H3637","and also confounded",23,42],["H1980","all of them: they shall go",44,70],["H3639","to confusion",71,83],["H3162","together",84,92],["H2796","that are makers",93,108],["H6736","of idols",109,117]]},"45:17":{"text":"But Israel shall be saved in the LORD with an everlasting salvation: ye shall not be ashamed nor confounded world without end.","words":[["H3478","But Israel",0,10],["H3467","shall be saved",11,25],["H3068","in the LORD",26,37],["H5769","with an everlasting",38,57],["H8668","salvation",58,67],["H0954","ye shall not be ashamed",69,92],["H3637","nor confounded",93,107],["H5769","world",108,113],["H5703","without end",114,125]]},"45:18":{"text":"For thus saith the LORD that created the heavens; God himself that formed the earth and made it; he hath established it, he created it not in vain, he formed it to be inhabited: I am the LORD; and there is none else.","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H1254","that created",24,36],["H8064","the heavens",37,48],["H0430","God",50,53],["H3335","himself that formed",54,73],["H0776","the earth",74,83],["H6213","and made",84,92],["H3559","it; he hath established",93,116],["H1254","it, he created",117,131],["H8414","it not in vain",132,146],["H3335","he formed",148,157],["H3427","it to be inhabited",158,176],["H3068","I am the LORD",178,191]]},"45:19":{"text":"I have not spoken in secret, in a dark place of the earth: I said not unto the seed of Jacob, Seek ye me in vain: I the LORD speak righteousness, I declare things that are right.","words":[["H1696","I have not spoken",0,17],["H5643","in secret",18,27],["H2822","in a dark",29,38],["H4725","place",39,44],["H0776","of the earth",45,57],["H0559","I said",59,65],["H2233","not unto the seed",66,83],["H3290","of Jacob",84,92],["H1245","Seek",94,98],["H8414","ye me in vain",99,112],["H3068","I the LORD",114,124],["H1696","speak",125,130],["H6664","righteousness",131,144],["H5046","I declare",146,155],["H4339","things that are right",156,177]]},"45:20":{"text":"Assemble yourselves and come; draw near together, ye that are escaped of the nations: they have no knowledge that set up the wood of their graven image, and pray unto a god that cannot save.","words":[["H6908","Assemble",0,8],["H0935","yourselves and come",9,28],["H5066","draw near",30,39],["H3162","together",40,48],["H6412","ye that are escaped",50,69],["H1471","of the nations",70,84],["H3045","they have no knowledge",86,108],["H5375","that set up",109,120],["H6086","the wood",121,129],["H6459","of their graven image",130,151],["H6419","and pray",153,161],["H0410","unto a god",162,172],["H3467","that cannot save",173,189]]},"45:21":{"text":"Tell ye, and bring them near; yea, let them take counsel together: who hath declared this from ancient time? who hath told it from that time? have not I the LORD? and there is no God else beside me; a just God and a Saviour; there is none beside me.","words":[["H5046","Tell",0,4],["H5066","ye, and bring them near",5,28],["H3289","yea, let them take counsel",30,56],["H3162","together",57,65],["H8085","who hath declared",67,84],["H6924","this from ancient time",85,107],["H5046","who hath told",109,122],["H3068","it from that time? have not I the LORD",123,161],["H0430","and there is no God",163,182],["H1107","else beside",183,194],["H6662","me; a just",195,205],["H0410","God",206,209],["H3467","and a Saviour",210,223],["H0369","there is none",225,238],["H2108","beside",239,245]]},"45:22":{"text":"Look unto me, and be ye saved, all the ends of the earth: for I am God, and there is none else.","words":[["H6437","Look",0,4],["H3467","unto me, and be ye saved",5,29],["H0657","all the ends",31,43],["H0776","of the earth",44,56],["H0410","for I am God",58,70]]},"45:23":{"text":"I have sworn by myself, the word is gone out of my mouth in righteousness, and shall not return, That unto me every knee shall bow, every tongue shall swear.","words":[["H7650","I have sworn",0,12],["H1697","by myself, the word",13,32],["H3318","is gone out",33,44],["H6310","of my mouth",45,56],["H6666","in righteousness",57,73],["H7725","and shall not return",75,95],["H1290","That unto me every knee",97,120],["H3766","shall bow",121,130],["H3956","every tongue",132,144],["H7650","shall swear",145,156]]},"45:24":{"text":"Surely, shall one say, in the LORD have I righteousness and strength: even to him shall men come; and all that are incensed against him shall be ashamed.","words":[["H0559","Surely, shall one say",0,21],["H3068","in the LORD",23,34],["H6666","have I righteousness",35,55],["H5797","and strength",56,68],["H0935","even to him shall men come",70,96],["H2734","and all that are incensed",98,123],["H0954","against him shall be ashamed",124,152]]},"45:25":{"text":"In the LORD shall all the seed of Israel be justified, and shall glory.","words":[["H3068","In the LORD",0,11],["H2233","shall all the seed",12,30],["H3478","of Israel",31,40],["H6663","be justified",41,53],["H1984","and shall glory",55,70]]},"46:1":{"text":"Bel boweth down, Nebo stoopeth, their idols were upon the beasts, and upon the cattle: your carriages were heavy loaden; they are a burden to the weary beast.","words":[["H1078","Bel",0,3],["H3766","boweth down",4,15],["H5015","Nebo",17,21],["H7164","stoopeth",22,30],["H6091","their idols",32,43],["H2416","were upon the beasts",44,64],["H0929","and upon the cattle",66,85],["H5385","your carriages",87,101],["H6006","were heavy loaden",102,119],["H4853","they are a burden",121,138],["H5889","to the weary",139,151]]},"46:2":{"text":"They stoop, they bow down together; they could not deliver the burden, but themselves are gone into captivity.","words":[["H7164","They stoop",0,10],["H3766","they bow down",12,25],["H3162","together",26,34],["H3201","they could",36,46],["H4422","not deliver",47,58],["H4853","the burden",59,69],["H5315","but themselves",71,85],["H1980","are gone",86,94],["H7628","into captivity",95,109]]},"46:3":{"text":"Hearken unto me, O house of Jacob, and all the remnant of the house of Israel, which are borne by me from the belly, which are carried from the womb:","words":[["H8085","Hearken",0,7],["H1004","unto me, O house",8,24],["H3290","of Jacob",25,33],["H7611","and all the remnant",35,54],["H1004","of the house",55,67],["H3478","of Israel",68,77],["H6006","which are borne",79,94],["H0990","by me from the belly",95,115],["H5375","which are carried",117,134],["H7356","from the womb",135,148]]},"46:4":{"text":"And even to your old age I am he; and even to hoar hairs will I carry you: I have made, and I will bear; even I will carry, and will deliver you.","words":[["H2209","And even to your old age",0,24],["H7872","I am he; and even to hoar hairs",25,56],["H5445","will I carry",57,69],["H6213","you: I have made",70,86],["H5375","and I will bear",88,103],["H5445","even I will carry",105,122],["H4422","and will deliver",124,140]]},"46:5":{"text":"To whom will ye liken me, and make me equal, and compare me, that we may be like?","words":[["H1819","To whom will ye liken",0,21],["H7737","me, and make me equal",22,43],["H4911","and compare",45,56],["H1819","me, that we may be like",57,80]]},"46:6":{"text":"They lavish gold out of the bag, and weigh silver in the balance, and hire a goldsmith; and he maketh it a god: they fall down, yea, they worship.","words":[["H2107","They lavish",0,11],["H2091","gold",12,16],["H3599","out of the bag",17,31],["H8254","and weigh",33,42],["H3701","silver",43,49],["H7070","in the balance",50,64],["H7936","and hire",66,74],["H6884","a goldsmith",75,86],["H6213","and he maketh",88,101],["H0410","it a god",102,110],["H5456","they fall down",112,126],["H7812","yea, they worship",128,145]]},"46:7":{"text":"They bear him upon the shoulder, they carry him, and set him in his place, and he standeth; from his place shall he not remove: yea, one shall cry unto him, yet can he not answer, nor save him out of his trouble.","words":[["H5375","They bear",0,9],["H3802","him upon the shoulder",10,31],["H5445","they carry",33,43],["H3240","him, and set him in his place",44,73],["H5975","and he standeth",75,90],["H4725","from his place",92,106],["H4185","shall he not remove",107,126],["H6817","yea, one shall cry",128,146],["H6030","unto him, yet can he not answer",147,178],["H3467","nor save",180,188],["H6869","him out of his trouble",189,211]]},"46:8":{"text":"Remember this, and shew yourselves men: bring it again to mind, O ye transgressors.","words":[["H2142","Remember",0,8],["H0377","this, and shew yourselves men",9,38],["H7725","bring it again",40,54],["H3820","to mind",55,62],["H6586","O ye transgressors",64,82]]},"46:9":{"text":"Remember the former things of old: for I am God, and there is none else; I am God, and there is none like me,","words":[["H2142","Remember",0,8],["H7223","the former things",9,26],["H5769","of old",27,33],["H0410","for I am God",35,47],["H0430","and there is none else; I am God",49,81],["H0657","and there is none",83,100],["H3644","like",101,105]]},"46:10":{"text":"Declaring the end from the beginning, and from ancient times the things that are not yet done, saying, My counsel shall stand, and I will do all my pleasure:","words":[["H5046","Declaring",0,9],["H0319","the end",10,17],["H7225","from the beginning",18,36],["H6924","and from ancient times",38,60],["H6213","the things that are not yet done",61,93],["H0559","saying",95,101],["H6098","My counsel",103,113],["H6965","shall stand",114,125],["H6213","and I will do",127,140],["H2656","all my pleasure",141,156]]},"46:11":{"text":"Calling a ravenous bird from the east, the man that executeth my counsel from a far country: yea, I have spoken it, I will also bring it to pass; I have purposed it, I will also do it.","words":[["H7121","Calling",0,7],["H5861","a ravenous bird",8,23],["H4217","from the east",24,37],["H0376","the man",39,46],["H6098","that executeth my counsel",47,72],["H4801","from a far",73,83],["H0776","country",84,91],["H1696","yea, I have spoken",93,111],["H0935","it, I will also bring",112,133],["H3335","it to pass; I have purposed",134,161],["H6213","it, I will also do",162,180]]},"46:12":{"text":"Hearken unto me, ye stouthearted, that are far from righteousness:","words":[["H8085","Hearken",0,7],["H0047","unto me, ye stouthearted",8,32],["H3820","unto me, ye stouthearted",8,32],["H7350","that are far from",34,51],["H6666","righteousness",52,65]]},"46:13":{"text":"I bring near my righteousness; it shall not be far off, and my salvation shall not tarry: and I will place salvation in Zion for Israel my glory.","words":[["H7126","I bring near",0,12],["H6666","my righteousness",13,29],["H7368","it shall not be far off",31,54],["H8668","and my salvation",56,72],["H0309","shall not tarry",73,88],["H5414","and I will place",90,106],["H8668","salvation",107,116],["H6726","in Zion",117,124],["H3478","for Israel",125,135],["H8597","my glory",136,144]]},"47:1":{"text":"Come down, and sit in the dust, O virgin daughter of Babylon, sit on the ground: there is no throne, O daughter of the Chaldeans: for thou shalt no more be called tender and delicate.","words":[["H3381","Come down",0,9],["H3427","and sit",11,18],["H6083","in the dust",19,30],["H1330","O virgin",32,40],["H1323","daughter",41,49],["H0894","of Babylon",50,60],["H3427","sit",62,65],["H0776","on the ground",66,79],["H3678","there is no throne",81,99],["H1323","O daughter",101,111],["H3778","of the Chaldeans",112,128],["H3254","for thou shalt no more",130,152],["H7121","be called",153,162],["H7390","tender",163,169],["H6028","and delicate",170,182]]},"47:2":{"text":"Take the millstones, and grind meal: uncover thy locks, make bare the leg, uncover the thigh, pass over the rivers.","words":[["H3947","Take",0,4],["H7347","the millstones",5,19],["H2912","and grind",21,30],["H7058","meal",31,35],["H1540","uncover",37,44],["H6777","thy locks",45,54],["H2834","make bare",56,65],["H7640","the leg",66,73],["H1540","uncover",75,82],["H7785","the thigh",83,92],["H5674","pass over",94,103],["H5104","the rivers",104,114]]},"47:3":{"text":"Thy nakedness shall be uncovered, yea, thy shame shall be seen: I will take vengeance, and I will not meet thee as a man.","words":[["H6172","Thy nakedness",0,13],["H1540","shall be uncovered",14,32],["H2781","yea, thy shame",34,48],["H7200","shall be seen",49,62],["H3947","I will take",64,75],["H5359","vengeance",76,85],["H6293","and I will not meet",87,106],["H0120","thee as a man",107,120]]},"47:4":{"text":"As for our redeemer, the LORD of hosts is his name, the Holy One of Israel.","words":[["H1350","As for our redeemer",0,19],["H3068","the LORD",21,29],["H6635","of hosts",30,38],["H8034","is his name",39,50],["H6918","the Holy One",52,64],["H3478","of Israel",65,74]]},"47:5":{"text":"Sit thou silent, and get thee into darkness, O daughter of the Chaldeans: for thou shalt no more be called, The lady of kingdoms.","words":[["H3427","Sit",0,3],["H1748","thou silent",4,15],["H0935","and get",17,24],["H2822","thee into darkness",25,43],["H1323","O daughter",45,55],["H3778","of the Chaldeans",56,72],["H3254","for thou shalt no more",74,96],["H7121","be called",97,106],["H1404","The lady",108,116],["H4467","of kingdoms",117,128]]},"47:6":{"text":"I was wroth with my people, I have polluted mine inheritance, and given them into thine hand: thou didst shew them no mercy; upon the ancient hast thou very heavily laid thy yoke.","words":[["H7107","I was wroth",0,11],["H5971","with my people",12,26],["H2490","I have polluted",28,43],["H5159","mine inheritance",44,60],["H5414","and given",62,71],["H3027","them into thine hand",72,92],["H7760","thou didst shew",94,109],["H7356","them no mercy",110,123],["H2205","upon the ancient",125,141],["H3966","hast thou very",142,156],["H3513","heavily",157,164],["H5923","laid thy yoke",165,178]]},"47:7":{"text":"And thou saidst, I shall be a lady for ever: so that thou didst not lay these things to thy heart, neither didst remember the latter end of it.","words":[["H0559","And thou saidst",0,15],["H1404","I shall be a lady",17,34],["H5769","for ever",35,43],["H7760","so that thou didst not lay",45,71],["H3820","these things to thy heart",72,97],["H2142","neither didst remember",99,121],["H0319","the latter end",122,136]]},"47:8":{"text":"Therefore hear now this, thou that art given to pleasures, that dwellest carelessly, that sayest in thine heart, I am, and none else beside me; I shall not sit as a widow, neither shall I know the loss of children:","words":[["H8085","Therefore hear",0,14],["H5719","now this, thou that art given to pleasures",15,57],["H3427","that dwellest",59,72],["H0983","carelessly",73,83],["H0559","that sayest",85,96],["H3824","in thine heart",97,111],["H0657","I am, and none else",113,132],["H3427","beside me; I shall not sit",133,159],["H0490","as a widow",160,170],["H3045","neither shall I know",172,192],["H7908","the loss of children",193,213]]},"47:9":{"text":"But these two things shall come to thee in a moment in one day, the loss of children, and widowhood: they shall come upon thee in their perfection for the multitude of thy sorceries, and for the great abundance of thine enchantments.","words":[["H8147","But these two",0,13],["H0935","things shall come",14,31],["H7281","to thee in a moment",32,51],["H0259","in one",52,58],["H3117","day",59,62],["H7908","the loss of children",64,84],["H0489","and widowhood",86,99],["H0935","they shall come",101,116],["H8537","upon thee in their perfection",117,146],["H7230","for the multitude",147,164],["H3785","of thy sorceries",165,181],["H3966","and for the great",183,200],["H6109","abundance",201,210],["H2267","of thine enchantments",211,232]]},"47:10":{"text":"For thou hast trusted in thy wickedness: thou hast said, None seeth me. Thy wisdom and thy knowledge, it hath perverted thee; and thou hast said in thine heart, I am, and none else beside me.","words":[["H0982","For thou hast trusted",0,21],["H7451","in thy wickedness",22,39],["H0559","thou hast said",41,55],["H7200","None seeth",57,67],["H2451","me. Thy wisdom",68,82],["H1847","and thy knowledge",83,100],["H7725","it hath perverted",102,119],["H0559","thee; and thou hast said",120,144],["H3820","in thine heart",145,159],["H0657","I am, and none else",161,180]]},"47:11":{"text":"Therefore shall evil come upon thee; thou shalt not know from whence it riseth: and mischief shall fall upon thee; thou shalt not be able to put it off: and desolation shall come upon thee suddenly, which thou shalt not know.","words":[["H7451","Therefore shall evil",0,20],["H0935","come",21,25],["H3045","upon thee; thou shalt not know",26,56],["H7837","from whence it riseth",57,78],["H1943","and mischief",80,92],["H5307","shall fall",93,103],["H3201","upon thee; thou shalt not be able",104,137],["H3722","to put it off",138,151],["H7722","and desolation",153,167],["H0935","shall come",168,178],["H6597","upon thee suddenly",179,197],["H3045","which thou shalt not know",199,224]]},"47:12":{"text":"Stand now with thine enchantments, and with the multitude of thy sorceries, wherein thou hast laboured from thy youth; if so be thou shalt be able to profit, if so be thou mayest prevail.","words":[["H5975","Stand",0,5],["H2267","now with thine enchantments",6,33],["H7230","and with the multitude",35,57],["H3785","of thy sorceries",58,74],["H0834","wherein",76,83],["H3021","thou hast laboured",84,102],["H5271","from thy youth",103,117],["H3201","if so be thou shalt be able",119,146],["H3276","to profit",147,156],["H6206","if so be thou mayest prevail",158,186]]},"47:13":{"text":"Thou art wearied in the multitude of thy counsels. Let now the astrologers, the stargazers, the monthly prognosticators, stand up, and save thee from these things that shall come upon thee.","words":[["H3811","Thou art wearied",0,16],["H7230","in the multitude",17,33],["H6098","of thy counsels",34,49],["H1895","Let now the astrologers",51,74],["H8064","Let now the astrologers",51,74],["H2374","the stargazers",76,90],["H3556","the stargazers",76,90],["H2320","the monthly",92,103],["H3045","prognosticators",104,119],["H5975","stand up",121,129],["H3467","and save",131,139],["H0935","thee from these things that shall come",140,178]]},"47:14":{"text":"Behold, they shall be as stubble; the fire shall burn them; they shall not deliver themselves from the power of the flame: there shall not be a coal to warm at, nor fire to sit before it.","words":[["H7179","Behold, they shall be as stubble",0,32],["H0784","the fire",34,42],["H8313","shall burn",43,53],["H5337","them; they shall not deliver",54,82],["H5315","themselves",83,93],["H3027","from the power",94,108],["H3852","of the flame",109,121],["H1513","there shall not be a coal",123,148],["H2552","to warm",149,156],["H0217","at, nor fire",157,169],["H3427","to sit",170,176]]},"47:15":{"text":"Thus shall they be unto thee with whom thou hast laboured, even thy merchants, from thy youth: they shall wander every one to his quarter; none shall save thee.","words":[["H3021","Thus shall they be unto thee with whom thou hast laboured",0,57],["H5503","even thy merchants",59,77],["H5271","from thy youth",79,93],["H8582","they shall wander",95,112],["H0376","every one",113,122],["H5676","to his quarter",123,137],["H3467","none shall save",139,154]]},"48:1":{"text":"Hear ye this, O house of Jacob, which are called by the name of Israel, and are come forth out of the waters of Judah, which swear by the name of the LORD, and make mention of the God of Israel, but not in truth, nor in righteousness.","words":[["H8085","Hear",0,4],["H1004","ye this, O house",5,21],["H3290","of Jacob",22,30],["H7121","which are called",32,48],["H8034","by the name",49,60],["H3478","of Israel",61,70],["H3318","and are come forth",72,90],["H4325","out of the waters",91,108],["H3063","of Judah",109,117],["H7650","which swear",119,130],["H8034","by the name",131,142],["H3068","of the LORD",143,154],["H2142","and make mention",156,172],["H0430","of the God",173,183],["H3478","of Israel",184,193],["H0571","but not in truth",195,211],["H6666","nor in righteousness",213,233]]},"48:2":{"text":"For they call themselves of the holy city, and stay themselves upon the God of Israel; The LORD of hosts is his name.","words":[["H7121","For they call",0,13],["H6944","themselves of the holy",14,36],["H5892","city",37,41],["H5564","and stay",43,51],["H0430","themselves upon the God",52,75],["H3478","of Israel",76,85],["H3068","The LORD",87,95],["H6635","of hosts",96,104],["H8034","is his name",105,116]]},"48:3":{"text":"I have declared the former things from the beginning; and they went forth out of my mouth, and I shewed them; I did them suddenly, and they came to pass.","words":[["H5046","I have declared",0,15],["H7223","the former things",16,33],["H0227","from the beginning",34,52],["H3318","and they went forth",54,73],["H6310","out of my mouth",74,89],["H8085","and I shewed",91,103],["H6213","them; I did",104,115],["H6597","them suddenly",116,129],["H0935","and they came to pass",131,152]]},"48:4":{"text":"Because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass;","words":[["H1847","Because I knew",0,14],["H7186","that thou art obstinate",15,38],["H6203","and thy neck",40,52],["H1270","is an iron",53,63],["H1517","sinew",64,69],["H4696","and thy brow",71,83],["H5154","brass",84,89]]},"48:5":{"text":"I have even from the beginning declared it to thee; before it came to pass I shewed it thee: lest thou shouldest say, Mine idol hath done them, and my graven image, and my molten image, hath commanded them.","words":[["H0227","I have even from the beginning",0,30],["H5046","declared",31,39],["H0935","it to thee; before it came to pass",40,74],["H8085","I shewed",75,83],["H0559","it thee: lest thou shouldest say",84,116],["H6090","Mine idol",118,127],["H6213","hath done",128,137],["H6459","them, and my graven image",138,163],["H5262","and my molten image",165,184],["H6680","hath commanded",186,200]]},"48:6":{"text":"Thou hast heard, see all this; and will not ye declare it? I have shewed thee new things from this time, even hidden things, and thou didst not know them.","words":[["H8085","Thou hast heard",0,15],["H2372","see",17,20],["H5046","all this; and will not ye declare",21,54],["H8085","it? I have shewed",55,72],["H2319","thee new things",73,88],["H6258","from this time",89,103],["H5341","even hidden things",105,123],["H3045","and thou didst not know",125,148]]},"48:7":{"text":"They are created now, and not from the beginning; even before the day when thou heardest them not; lest thou shouldest say, Behold, I knew them.","words":[["H1254","They are created",0,16],["H6440","now, and not from the beginning; even before",17,61],["H3117","the day",62,69],["H8085","when thou heardest",70,88],["H0559","them not; lest thou shouldest say",89,122],["H3045","Behold, I knew",124,138]]},"48:8":{"text":"Yea, thou heardest not; yea, thou knewest not; yea, from that time that thine ear was not opened: for I knew that thou wouldest deal very treacherously, and wast called a transgressor from the womb.","words":[["H8085","Yea, thou heardest",0,18],["H3045","not; yea, thou knewest",19,41],["H0241","not; yea, from that time that thine ear",42,81],["H6605","was not opened",82,96],["H3045","for I knew",98,108],["H0898","that thou wouldest deal very",109,137],["H0898","treacherously",138,151],["H7121","and wast called",153,168],["H6586","a transgressor",169,183],["H0990","from the womb",184,197]]},"48:9":{"text":"For my name's sake will I defer mine anger, and for my praise will I refrain for thee, that I cut thee not off.","words":[["H8034","For my name's",0,13],["H0748","sake will I defer",14,31],["H0639","mine anger",32,42],["H8416","and for my praise",44,61],["H2413","will I refrain",62,76],["H3772","for thee, that I cut thee not off",77,110]]},"48:10":{"text":"Behold, I have refined thee, but not with silver; I have chosen thee in the furnace of affliction.","words":[["H6884","Behold, I have refined",0,22],["H3701","thee, but not with silver",23,48],["H0977","I have chosen",50,63],["H3564","thee in the furnace",64,83],["H6040","of affliction",84,97]]},"48:11":{"text":"For mine own sake, even for mine own sake, will I do it: for how should my name be polluted? and I will not give my glory unto another.","words":[["H6213","For mine own sake, even for mine own sake, will I do",0,52],["H2490","it: for how should my name be polluted",53,91],["H5414","and I will not give",93,112],["H3519","my glory",113,121],["H0312","unto another",122,134]]},"48:12":{"text":"Hearken unto me, O Jacob and Israel, my called; I am he; I am the first, I also am the last.","words":[["H8085","Hearken",0,7],["H3290","unto me, O Jacob",8,24],["H3478","and Israel",25,35],["H7121","my called",37,46],["H7223","I am he; I am the first",48,71],["H0314","I also am the last",73,91]]},"48:13":{"text":"Mine hand also hath laid the foundation of the earth, and my right hand hath spanned the heavens: when I call unto them, they stand up together.","words":[["H3027","Mine hand",0,9],["H3245","also hath laid the foundation",10,39],["H0776","of the earth",40,52],["H3225","and my right hand",54,71],["H2946","hath spanned",72,84],["H8064","the heavens",85,96],["H7121","when I call",98,109],["H5975","unto them, they stand up",110,134],["H3162","together",135,143]]},"48:14":{"text":"All ye, assemble yourselves, and hear; which among them hath declared these things? The LORD hath loved him: he will do his pleasure on Babylon, and his arm shall be on the Chaldeans.","words":[["H6908","All ye, assemble",0,16],["H8085","yourselves, and hear",17,37],["H5046","which among them hath declared",39,69],["H3068","these things? The LORD",70,92],["H0157","hath loved",93,103],["H6213","him: he will do",104,119],["H2656","his pleasure",120,132],["H0894","on Babylon",133,143],["H2220","and his arm",145,156],["H3778","shall be on the Chaldeans",157,182]]},"48:15":{"text":"I, even I, have spoken; yea, I have called him: I have brought him, and he shall make his way prosperous.","words":[["H1696","I, even I, have spoken",0,22],["H7121","yea, I have called",24,42],["H0935","him: I have brought",43,62],["H1870","him, and he shall make his way",63,93],["H6743","prosperous",94,104]]},"48:16":{"text":"Come ye near unto me, hear ye this; I have not spoken in secret from the beginning; from the time that it was, there am I: and now the Lord GOD, and his Spirit, hath sent me.","words":[["H7126","Come",0,4],["H7126","ye near",5,12],["H8085","unto me, hear",13,26],["H1696","ye this; I have not spoken",27,53],["H5643","in secret",54,63],["H7218","from the beginning",64,82],["H6256","from the time",84,97],["H0136","that it was, there am I: and now the Lord",98,139],["H3069","GOD",140,143],["H7307","and his Spirit",145,159],["H7971","hath sent",161,170]]},"48:17":{"text":"Thus saith the LORD, thy Redeemer, the Holy One of Israel; I am the LORD thy God which teacheth thee to profit, which leadeth thee by the way that thou shouldest go.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H1350","thy Redeemer",21,33],["H6918","the Holy One",35,47],["H3478","of Israel",48,57],["H3068","I am the LORD",59,72],["H0430","thy God",73,80],["H3925","which teacheth",81,95],["H3276","thee to profit",96,110],["H1869","which leadeth",112,125],["H1870","thee by the way",126,141],["H3212","that thou shouldest go",142,164]]},"48:18":{"text":"O that thou hadst hearkened to my commandments! then had thy peace been as a river, and thy righteousness as the waves of the sea:","words":[["H3863","O that",0,6],["H7181","thou hadst hearkened",7,27],["H4687","to my commandments",28,46],["H7965","then had thy peace",48,66],["H5104","been as a river",67,82],["H6666","and thy righteousness",84,105],["H1530","as the waves",106,118],["H3220","of the sea",119,129]]},"48:19":{"text":"Thy seed also had been as the sand, and the offspring of thy bowels like the gravel thereof; his name should not have been cut off nor destroyed from before me.","words":[["H2233","Thy seed",0,8],["H2344","also had been as the sand",9,34],["H6631","and the offspring",36,53],["H4578","of thy bowels",54,67],["H4579","like the gravel",68,83],["H8034","thereof; his name",84,101],["H3772","should not have been cut off",102,130],["H8045","nor destroyed",131,144],["H6440","from before",145,156]]},"48:20":{"text":"Go ye forth of Babylon, flee ye from the Chaldeans, with a voice of singing declare ye, tell this, utter it even to the end of the earth; say ye, The LORD hath redeemed his servant Jacob.","words":[["H3318","Go ye forth",0,11],["H0894","of Babylon",12,22],["H1272","flee",24,28],["H3778","ye from the Chaldeans",29,50],["H6963","with a voice",52,64],["H7440","of singing",65,75],["H5046","declare",76,83],["H8085","ye, tell",84,92],["H3318","this, utter",93,104],["H7097","it even to the end",105,123],["H0776","of the earth",124,136],["H0559","say",138,141],["H3068","ye, The LORD",142,154],["H1350","hath redeemed",155,168],["H5650","his servant",169,180],["H3290","Jacob",181,186]]},"48:21":{"text":"And they thirsted not when he led them through the deserts: he caused the waters to flow out of the rock for them: he clave the rock also, and the waters gushed out.","words":[["H6770","And they thirsted",0,17],["H3212","not when he led",18,33],["H2723","them through the deserts",34,58],["H4325","he caused the waters",60,80],["H5140","to flow",81,88],["H6697","out of the rock",89,104],["H1234","for them: he clave",105,123],["H6697","the rock",124,132],["H4325","also, and the waters",133,153],["H2100","gushed out",154,164]]},"48:22":{"text":"There is no peace, saith the LORD, unto the wicked.","words":[["H7965","There is no peace",0,17],["H0559","saith",19,24],["H3068","the LORD",25,33],["H7563","unto the wicked",35,50]]},"49:1":{"text":"Listen, O isles, unto me; and hearken, ye people, from far; The LORD hath called me from the womb; from the bowels of my mother hath he made mention of my name.","words":[["H8085","Listen",0,6],["H0339","O isles",8,15],["H7181","unto me; and hearken",17,37],["H3816","ye people",39,48],["H7350","from far",50,58],["H3068","The LORD",60,68],["H7121","hath called",69,80],["H0990","me from the womb",81,97],["H4578","from the bowels",99,114],["H0517","of my mother",115,127],["H2142","hath he made mention",128,148],["H8034","of my name",149,159]]},"49:2":{"text":"And he hath made my mouth like a sharp sword; in the shadow of his hand hath he hid me, and made me a polished shaft; in his quiver hath he hid me;","words":[["H7760","And he hath made",0,16],["H6310","my mouth",17,25],["H2299","like a sharp",26,38],["H2719","sword",39,44],["H6738","in the shadow",46,59],["H3027","of his hand",60,71],["H2244","hath he hid",72,83],["H7760","me, and made",84,96],["H1305","me a polished",97,110],["H2671","shaft",111,116],["H0827","in his quiver",118,131],["H5641","hath he hid",132,143]]},"49:3":{"text":"And said unto me, Thou art my servant, O Israel, in whom I will be glorified.","words":[["H0559","And said",0,8],["H5650","unto me, Thou art my servant",9,37],["H3478","O Israel",39,47],["H6286","in whom I will be glorified",49,76]]},"49:4":{"text":"Then I said, I have laboured in vain, I have spent my strength for nought, and in vain: yet surely my judgment is with the LORD, and my work with my God.","words":[["H0559","Then I said",0,11],["H3021","I have laboured",13,28],["H7385","in vain",29,36],["H3615","I have spent",38,50],["H3581","my strength",51,62],["H8414","for nought",63,73],["H1892","and in vain",75,86],["H0403","yet surely",88,98],["H4941","my judgment",99,110],["H3068","is with the LORD",111,127],["H6468","and my work",129,140],["H0430","with my God",141,152]]},"49:5":{"text":"And now, saith the LORD that formed me from the womb to be his servant, to bring Jacob again to him, Though Israel be not gathered, yet shall I be glorious in the eyes of the LORD, and my God shall be my strength.","words":[["H0559","And now, saith",0,14],["H3068","the LORD",15,23],["H3335","that formed",24,35],["H0990","me from the womb",36,52],["H5650","to be his servant",53,70],["H7725","to bring",72,80],["H3290","Jacob",81,86],["H7725","again",87,92],["H3478","to him, Though Israel",93,114],["H0622","be not gathered",115,130],["H3513","yet shall I be glorious",132,155],["H5869","in the eyes",156,167],["H3068","of the LORD",168,179],["H0430","and my God",181,191],["H5797","shall be my strength",192,212]]},"49:6":{"text":"And he said, It is a light thing that thou shouldest be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel: I will also give thee for a light to the Gentiles, that thou mayest be my salvation unto the end of the earth.","words":[["H0559","And he said",0,11],["H7043","It is a light thing",13,32],["H5650","that thou shouldest be my servant",33,66],["H6965","to raise up",67,78],["H7626","the tribes",79,89],["H3290","of Jacob",90,98],["H7725","and to restore",100,114],["H5341","the preserved",115,128],["H5336","the preserved",115,128],["H3478","of Israel",129,138],["H5414","I will also give",140,156],["H0216","thee for a light",157,173],["H1471","to the Gentiles",174,189],["H3444","that thou mayest be my salvation",191,223],["H7097","unto the end",224,236],["H0776","of the earth",237,249]]},"49:7":{"text":"Thus saith the LORD, the Redeemer of Israel, and his Holy One, to him whom man despiseth, to him whom the nation abhorreth, to a servant of rulers, Kings shall see and arise, princes also shall worship, because of the LORD that is faithful, and the Holy One of Israel, and he shall choose thee.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H1350","the Redeemer",21,33],["H3478","of Israel",34,43],["H6918","and his Holy One",45,61],["H5315","to him whom man",63,78],["H0960","despiseth",79,88],["H1471","to him whom the nation",90,112],["H8581","abhorreth",113,122],["H5650","to a servant",124,136],["H4910","of rulers",137,146],["H4428","Kings",148,153],["H7200","shall see",154,163],["H6965","and arise",164,173],["H8269","princes",175,182],["H7812","also shall worship",183,201],["H3068","because of the LORD",203,222],["H0539","that is faithful",223,239],["H6918","and the Holy One",241,257],["H3478","of Israel",258,267],["H0977","and he shall choose",269,288]]},"49:8":{"text":"Thus saith the LORD, In an acceptable time have I heard thee, and in a day of salvation have I helped thee: and I will preserve thee, and give thee for a covenant of the people, to establish the earth, to cause to inherit the desolate heritages;","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H7522","In an acceptable",21,37],["H6256","time",38,42],["H6030","have I heard",43,55],["H3117","thee, and in a day",56,74],["H3444","of salvation",75,87],["H5826","have I helped",88,101],["H5341","thee: and I will preserve",102,127],["H5414","thee, and give",128,142],["H1285","thee for a covenant",143,162],["H5971","of the people",163,176],["H6965","to establish",178,190],["H0776","the earth",191,200],["H5157","to cause to inherit",202,221],["H8074","the desolate",222,234],["H5159","heritages",235,244]]},"49:9":{"text":"That thou mayest say to the prisoners, Go forth; to them that are in darkness, Shew yourselves. They shall feed in the ways, and their pastures shall be in all high places.","words":[["H0559","That thou mayest say",0,20],["H0631","to the prisoners",21,37],["H3318","Go forth",39,47],["H2822","to them that are in darkness",49,77],["H1540","Shew",79,83],["H7462","yourselves. They shall feed",84,111],["H1870","in the ways",112,123],["H4830","and their pastures",125,143],["H8205","shall be in all high places",144,171]]},"49:10":{"text":"They shall not hunger nor thirst; neither shall the heat nor sun smite them: for he that hath mercy on them shall lead them, even by the springs of water shall he guide them.","words":[["H7456","They shall not hunger",0,21],["H6770","nor thirst",22,32],["H8273","neither shall the heat",34,56],["H8121","nor sun",57,64],["H5221","smite",65,70],["H7355","them: for he that hath mercy",71,99],["H5090","on them shall lead",100,118],["H4002","them, even by the springs",119,144],["H4325","of water",145,153],["H5095","shall he guide",154,168]]},"49:11":{"text":"And I will make all my mountains a way, and my highways shall be exalted.","words":[["H7760","And I will make",0,15],["H2022","all my mountains",16,32],["H1870","a way",33,38],["H4546","and my highways",40,55],["H7311","shall be exalted",56,72]]},"49:12":{"text":"Behold, these shall come from far: and, lo, these from the north and from the west; and these from the land of Sinim.","words":[["H0935","Behold, these shall come",0,24],["H7350","from far",25,33],["H6828","and, lo, these from the north",35,64],["H3220","and from the west",65,82],["H0776","and these from the land",84,107],["H5515","of Sinim",108,116]]},"49:13":{"text":"Sing, O heavens; and be joyful, O earth; and break forth into singing, O mountains: for the LORD hath comforted his people, and will have mercy upon his afflicted.","words":[["H7442","Sing",0,4],["H8064","O heavens",6,15],["H1523","and be joyful",17,30],["H0776","O earth",32,39],["H6476","and break forth",41,56],["H7440","into singing",57,69],["H2022","O mountains",71,82],["H3068","for the LORD",84,96],["H5162","hath comforted",97,111],["H5971","his people",112,122],["H7355","and will have mercy",124,143],["H6041","upon his afflicted",144,162]]},"49:14":{"text":"But Zion said, The LORD hath forsaken me, and my Lord hath forgotten me.","words":[["H6726","But Zion",0,8],["H0559","said",9,13],["H3068","The LORD",15,23],["H5800","hath forsaken",24,37],["H0136","me, and my Lord",38,53],["H7911","hath forgotten",54,68]]},"49:15":{"text":"Can a woman forget her sucking child, that she should not have compassion on the son of her womb? yea, they may forget, yet will I not forget thee.","words":[["H0802","Can a woman",0,11],["H7911","forget",12,18],["H5764","her sucking child",19,36],["H7355","that she should not have compassion",38,73],["H1121","on the son",74,84],["H0990","of her womb",85,96],["H7911","yea, they may forget",98,118],["H7911","yet will I not forget",120,141]]},"49:16":{"text":"Behold, I have graven thee upon the palms of my hands; thy walls are continually before me.","words":[["H2710","Behold, I have graven",0,21],["H3709","thee upon the palms of my hands",22,53],["H2346","thy walls",55,64],["H8548","are continually",65,80]]},"49:17":{"text":"Thy children shall make haste; thy destroyers and they that made thee waste shall go forth of thee.","words":[["H1121","Thy children",0,12],["H4116","shall make haste",13,29],["H2040","thy destroyers",31,45],["H2717","and they that made thee waste",46,75],["H3318","shall go forth",76,90]]},"49:18":{"text":"Lift up thine eyes round about, and behold: all these gather themselves together, and come to thee. As I live, saith the LORD, thou shalt surely clothe thee with them all, as with an ornament, and bind them on thee, as a bride doeth.","words":[["H5375","Lift up",0,7],["H5869","thine eyes",8,18],["H5439","round about",19,30],["H7200","and behold",32,42],["H6908","all these gather themselves together",44,80],["H0935","and come",82,90],["H2416","to thee. As I live",91,109],["H5002","saith",111,116],["H3068","the LORD",117,125],["H3847","thou shalt surely clothe",127,151],["H5716","thee with them all, as with an ornament",152,191],["H7194","and bind",193,201],["H3618","them on thee, as a bride",202,226]]},"49:19":{"text":"For thy waste and thy desolate places, and the land of thy destruction, shall even now be too narrow by reason of the inhabitants, and they that swallowed thee up shall be far away.","words":[["H2723","For thy waste",0,13],["H8074","and thy desolate places",14,37],["H0776","and the land",39,51],["H2035","of thy destruction",52,70],["H3334","shall even now be too narrow",72,100],["H3427","by reason of the inhabitants",101,129],["H1104","and they that swallowed thee up",131,162],["H7368","shall be far away",163,180]]},"49:20":{"text":"The children which thou shalt have, after thou hast lost the other, shall say again in thine ears, The place is too strait for me: give place to me that I may dwell.","words":[["H1121","The children",0,12],["H7923","which thou shalt have, after thou hast lost",13,56],["H0559","the other, shall say",57,77],["H0241","again in thine ears",78,97],["H4725","The place",99,108],["H6862","is too strait",109,122],["H5066","for me: give",123,135],["H4725","place",136,141],["H3427","to me that I may dwell",142,164]]},"49:21":{"text":"Then shalt thou say in thine heart, Who hath begotten me these, seeing I have lost my children, and am desolate, a captive, and removing to and fro? and who hath brought up these? Behold, I was left alone; these, where had they been?","words":[["H0559","Then shalt thou say",0,19],["H3824","in thine heart",20,34],["H3205","Who hath begotten",36,53],["H7921","me these, seeing I have lost my children",54,94],["H1565","and am desolate",96,111],["H1540","a captive",113,122],["H5493","and removing to and fro",124,147],["H1431","and who hath brought up",149,172],["H7604","these? Behold, I was left",173,198],["H0375","alone; these, where",199,218]]},"49:22":{"text":"Thus saith the Lord GOD, Behold, I will lift up mine hand to the Gentiles, and set up my standard to the people: and they shall bring thy sons in their arms, and thy daughters shall be carried upon their shoulders.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H5375","Behold, I will lift up",25,47],["H3027","mine hand",48,57],["H1471","to the Gentiles",58,73],["H7311","and set up",75,85],["H5251","my standard",86,97],["H5971","to the people",98,111],["H0935","and they shall bring",113,133],["H1121","thy sons",134,142],["H2684","in their arms",143,156],["H1323","and thy daughters",158,175],["H5375","shall be carried",176,192],["H3802","upon their shoulders",193,213]]},"49:23":{"text":"And kings shall be thy nursing fathers, and their queens thy nursing mothers: they shall bow down to thee with their face toward the earth, and lick up the dust of thy feet; and thou shalt know that I am the LORD: for they shall not be ashamed that wait for me.","words":[["H4428","And kings",0,9],["H0539","shall be thy nursing fathers",10,38],["H8282","and their queens",40,56],["H3243","thy nursing mothers",57,76],["H7812","they shall bow down",78,97],["H0639","to thee with their face",98,121],["H0776","toward the earth",122,138],["H3897","and lick up",140,151],["H6083","the dust",152,160],["H7272","of thy feet",161,172],["H3045","and thou shalt know",174,193],["H3068","that I am the LORD",194,212],["H0954","for they shall not be ashamed",214,243],["H6960","that wait",244,253]]},"49:24":{"text":"Shall the prey be taken from the mighty, or the lawful captive delivered?","words":[["H4455","Shall the prey",0,14],["H3947","be taken",15,23],["H1368","from the mighty",24,39],["H6662","or the lawful",41,54],["H7628","captive",55,62],["H4422","delivered",63,72]]},"49:25":{"text":"But thus saith the LORD, Even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered: for I will contend with him that contendeth with thee, and I will save thy children.","words":[["H0559","But thus saith",0,14],["H3068","the LORD",15,23],["H7628","Even the captives",25,42],["H1368","of the mighty",43,56],["H3947","shall be taken away",57,76],["H4455","and the prey",78,90],["H6184","of the terrible",91,106],["H4422","shall be delivered",107,125],["H7378","for I will contend",127,145],["H3401","with him that contendeth",146,170],["H3467","with thee, and I will save",171,197],["H1121","thy children",198,210]]},"49:26":{"text":"And I will feed them that oppress thee with their own flesh; and they shall be drunken with their own blood, as with sweet wine: and all flesh shall know that I the LORD am thy Saviour and thy Redeemer, the mighty One of Jacob.","words":[["H0398","And I will feed",0,15],["H3238","them that oppress",16,33],["H1320","thee with their own flesh",34,59],["H7937","and they shall be drunken",61,86],["H1818","with their own blood",87,107],["H6071","as with sweet wine",109,127],["H1320","and all flesh",129,142],["H3045","shall know",143,153],["H3068","that I the LORD",154,169],["H3467","am thy Saviour",170,184],["H1350","and thy Redeemer",185,201],["H0046","the mighty One",203,217],["H3290","of Jacob",218,226]]},"50:1":{"text":"Thus saith the LORD, Where is the bill of your mother's divorcement, whom I have put away? or which of my creditors is it to whom I have sold you? Behold, for your iniquities have ye sold yourselves, and for your transgressions is your mother put away.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H5612","Where is the bill",21,38],["H0517","of your mother's",39,55],["H3748","divorcement",56,67],["H7971","whom I have put away",69,89],["H5383","or which of my creditors",91,115],["H4376","is it to whom I have sold",116,141],["H5771","you? Behold, for your iniquities",142,174],["H4376","have ye sold",175,187],["H6588","yourselves, and for your transgressions",188,227],["H0517","is your mother",228,242],["H7971","put away",243,251]]},"50:2":{"text":"Wherefore, when I came, was there no man? when I called, was there none to answer? Is my hand shortened at all, that it cannot redeem? or have I no power to deliver? behold, at my rebuke I dry up the sea, I make the rivers a wilderness: their fish stinketh, because there is no water, and dieth for thirst.","words":[["H0935","Wherefore, when I came",0,22],["H0376","was there no man",24,40],["H7121","when I called",42,55],["H6030","was there none to answer",57,81],["H3027","Is my hand",83,93],["H7114","shortened",94,103],["H7114","at all",104,110],["H6304","that it cannot redeem",112,133],["H3581","or have I no power",135,153],["H5337","to deliver",154,164],["H1606","behold, at my rebuke",166,186],["H2717","I dry up",187,195],["H3220","the sea",196,203],["H7760","I make",205,211],["H5104","the rivers",212,222],["H4057","a wilderness",223,235],["H1710","their fish",237,247],["H0887","stinketh",248,256],["H4325","because there is no water",258,283],["H4191","and dieth",285,294],["H6772","for thirst",295,305]]},"50:3":{"text":"I clothe the heavens with blackness, and I make sackcloth their covering.","words":[["H3847","I clothe",0,8],["H8064","the heavens",9,20],["H6940","with blackness",21,35],["H7760","and I make",37,47],["H8242","sackcloth",48,57],["H3682","their covering",58,72]]},"50:4":{"text":"The Lord GOD hath given me the tongue of the learned, that I should know how to speak a word in season to him that is weary: he wakeneth morning by morning, he wakeneth mine ear to hear as the learned.","words":[["H0136","The Lord",0,8],["H3069","GOD",9,12],["H5414","hath given",13,23],["H3956","me the tongue",24,37],["H3928","of the learned",38,52],["H3045","that I should know",54,72],["H5790","how to speak",73,85],["H1697","a word",86,92],["H3287","in season to him that is weary",93,123],["H5782","he wakeneth",125,136],["H1242","morning",137,144],["H1242","by morning",145,155],["H5782","he wakeneth",157,168],["H0241","mine ear",169,177],["H8085","to hear",178,185],["H3928","as the learned",186,200]]},"50:5":{"text":"The Lord GOD hath opened mine ear, and I was not rebellious, neither turned away back.","words":[["H0136","The Lord",0,8],["H3069","GOD",9,12],["H6605","hath opened",13,24],["H0241","mine ear",25,33],["H4784","and I was not rebellious",35,59],["H5472","neither turned away",61,80],["H0268","back",81,85]]},"50:6":{"text":"I gave my back to the smiters, and my cheeks to them that plucked off the hair: I hid not my face from shame and spitting.","words":[["H5414","I gave",0,6],["H1460","my back",7,14],["H5221","to the smiters",15,29],["H3895","and my cheeks",31,44],["H4803","to them that plucked off",45,69],["H5641","the hair: I hid",70,85],["H6440","not my face",86,97],["H3639","from shame",98,108],["H7536","and spitting",109,121]]},"50:7":{"text":"For the Lord GOD will help me; therefore shall I not be confounded: therefore have I set my face like a flint, and I know that I shall not be ashamed.","words":[["H0136","For the Lord",0,12],["H3069","GOD",13,16],["H5826","will help",17,26],["H3637","me; therefore shall I not be confounded",27,66],["H7760","therefore have I set",68,88],["H6440","my face",89,96],["H2496","like a flint",97,109],["H3045","and I know",111,121],["H0954","that I shall not be ashamed",122,149]]},"50:8":{"text":"He is near that justifieth me; who will contend with me? let us stand together: who is mine adversary? let him come near to me.","words":[["H7138","He is near",0,10],["H6663","that justifieth",11,26],["H7378","me; who will contend",27,47],["H5975","with me? let us stand",48,69],["H3162","together",70,78],["H1167","who is mine adversary",80,101],["H4941","who is mine adversary",80,101],["H5066","let him come near",103,120]]},"50:9":{"text":"Behold, the Lord GOD will help me; who is he that shall condemn me? lo, they all shall wax old as a garment; the moth shall eat them up.","words":[["H0136","Behold, the Lord",0,16],["H3069","GOD",17,20],["H5826","will help",21,30],["H7561","me; who is he that shall condemn",31,63],["H1086","me? lo, they all shall wax old",64,94],["H0899","as a garment",95,107],["H6211","the moth",109,117],["H0398","shall eat them up",118,135]]},"50:10":{"text":"Who is among you that feareth the LORD, that obeyeth the voice of his servant, that walketh in darkness, and hath no light? let him trust in the name of the LORD, and stay upon his God.","words":[["H3373","Who is among you that feareth",0,29],["H3068","the LORD",30,38],["H8085","that obeyeth",40,52],["H6963","the voice",53,62],["H5650","of his servant",63,77],["H1980","that walketh",79,91],["H2825","in darkness",92,103],["H5051","and hath no light",105,122],["H0982","let him trust",124,137],["H8034","in the name",138,149],["H3068","of the LORD",150,161],["H8172","and stay",163,171],["H0430","upon his God",172,184]]},"50:11":{"text":"Behold, all ye that kindle a fire, that compass yourselves about with sparks: walk in the light of your fire, and in the sparks that ye have kindled. This shall ye have of mine hand; ye shall lie down in sorrow.","words":[["H6919","Behold, all ye that kindle",0,26],["H0784","a fire",27,33],["H0247","that compass yourselves about",35,64],["H2131","with sparks",65,76],["H3212","walk",78,82],["H0217","in the light",83,95],["H0784","of your fire",96,108],["H2131","and in the sparks",110,127],["H1197","that ye have kindled",128,148],["H3027","This shall ye have of mine hand",150,181],["H7901","ye shall lie down",183,200],["H4620","in sorrow",201,210]]},"51:1":{"text":"Hearken to me, ye that follow after righteousness, ye that seek the LORD: look unto the rock whence ye are hewn, and to the hole of the pit whence ye are digged.","words":[["H8085","Hearken",0,7],["H7291","to me, ye that follow after",8,35],["H6664","righteousness",36,49],["H1245","ye that seek",51,63],["H3068","the LORD",64,72],["H5027","look",74,78],["H6697","unto the rock",79,92],["H2672","whence ye are hewn",93,111],["H4718","and to the hole",113,128],["H0953","of the pit",129,139],["H5365","whence ye are digged",140,160]]},"51:2":{"text":"Look unto Abraham your father, and unto Sarah that bare you: for I called him alone, and blessed him, and increased him.","words":[["H5027","Look",0,4],["H0085","unto Abraham",5,17],["H0001","your father",18,29],["H8283","and unto Sarah",31,45],["H2342","that bare",46,55],["H7121","you: for I called",56,73],["H0259","him alone",74,83],["H1288","and blessed",85,96],["H7235","him, and increased",97,115]]},"51:3":{"text":"For the LORD shall comfort Zion: he will comfort all her waste places; and he will make her wilderness like Eden, and her desert like the garden of the LORD; joy and gladness shall be found therein, thanksgiving, and the voice of melody.","words":[["H3068","For the LORD",0,12],["H5162","shall comfort",13,26],["H6726","Zion",27,31],["H5162","he will comfort",33,48],["H2723","all her waste places",49,69],["H7760","and he will make",71,87],["H4057","her wilderness",88,102],["H5731","like Eden",103,112],["H6160","and her desert",114,128],["H1588","like the garden",129,144],["H3068","of the LORD",145,156],["H8342","joy",158,161],["H8057","and gladness",162,174],["H4672","shall be found",175,189],["H8426","therein, thanksgiving",190,211],["H6963","and the voice",213,226],["H2172","of melody",227,236]]},"51:4":{"text":"Hearken unto me, my people; and give ear unto me, O my nation: for a law shall proceed from me, and I will make my judgment to rest for a light of the people.","words":[["H7181","Hearken",0,7],["H5971","unto me, my people",8,26],["H0238","and give ear",28,40],["H3816","unto me, O my nation",41,61],["H8451","for a law",63,72],["H3318","shall proceed",73,86],["H4941","from me, and I will make my judgment",87,123],["H7280","to rest",124,131],["H0216","for a light",132,143],["H5971","of the people",144,157]]},"51:5":{"text":"My righteousness is near; my salvation is gone forth, and mine arms shall judge the people; the isles shall wait upon me, and on mine arm shall they trust.","words":[["H6664","My righteousness",0,16],["H7138","is near",17,24],["H3468","my salvation",26,38],["H3318","is gone forth",39,52],["H2220","and mine arms",54,67],["H8199","shall judge",68,79],["H5971","the people",80,90],["H0339","the isles",92,101],["H6960","shall wait",102,112],["H2220","upon me, and on mine arm",113,137],["H3176","shall they trust",138,154]]},"51:6":{"text":"Lift up your eyes to the heavens, and look upon the earth beneath: for the heavens shall vanish away like smoke, and the earth shall wax old like a garment, and they that dwell therein shall die in like manner: but my salvation shall be for ever, and my righteousness shall not be abolished.","words":[["H5375","Lift up",0,7],["H5869","your eyes",8,17],["H8064","to the heavens",18,32],["H5027","and look",34,42],["H0776","upon the earth",43,57],["H8064","beneath: for the heavens",58,82],["H4414","shall vanish away",83,100],["H6227","like smoke",101,111],["H0776","and the earth",113,126],["H1086","shall wax old",127,140],["H0899","like a garment",141,155],["H3427","and they that dwell",157,176],["H4191","therein shall die",177,194],["H3644","in like",195,202],["H3654","manner",203,209],["H3444","but my salvation",211,227],["H5769","shall be for ever",228,245],["H6666","and my righteousness",247,267],["H2865","shall not be abolished",268,290]]},"51:7":{"text":"Hearken unto me, ye that know righteousness, the people in whose heart is my law; fear ye not the reproach of men, neither be ye afraid of their revilings.","words":[["H8085","Hearken",0,7],["H3045","unto me, ye that know",8,29],["H6664","righteousness",30,43],["H5971","the people",45,55],["H3820","in whose heart",56,70],["H8451","is my law",71,80],["H3372","fear",82,86],["H2781","ye not the reproach",87,106],["H0582","of men",107,113],["H2865","neither be ye afraid",115,135],["H1421","of their revilings",136,154]]},"51:8":{"text":"For the moth shall eat them up like a garment, and the worm shall eat them like wool: but my righteousness shall be for ever, and my salvation from generation to generation.","words":[["H6211","For the moth",0,12],["H0398","shall eat them up",13,30],["H0899","like a garment",31,45],["H5580","and the worm",47,59],["H0398","shall eat",60,69],["H6785","them like wool",70,84],["H6666","but my righteousness",86,106],["H5769","shall be for ever",107,124],["H3444","and my salvation",126,142],["H1755","from generation",143,158],["H1755","to generation",159,172]]},"51:9":{"text":"Awake, awake, put on strength, O arm of the LORD; awake, as in the ancient days, in the generations of old. Art thou not it that hath cut Rahab, and wounded the dragon?","words":[["H5782","Awake",0,5],["H5782","awake",7,12],["H3847","put on",14,20],["H5797","strength",21,29],["H2220","O arm",31,36],["H3068","of the LORD",37,48],["H5782","awake",50,55],["H6924","as in the ancient",57,74],["H3117","days",75,79],["H1755","in the generations",81,99],["H5769","of old",100,106],["H2672","Art thou not it that hath cut",108,137],["H7294","Rahab",138,143],["H2490","and wounded",145,156],["H8577","the dragon",157,167]]},"51:10":{"text":"Art thou not it which hath dried the sea, the waters of the great deep; that hath made the depths of the sea a way for the ransomed to pass over?","words":[["H2717","Art thou not it which hath dried",0,32],["H3220","the sea",33,40],["H4325","the waters",42,52],["H7227","of the great",53,65],["H8415","deep",66,70],["H7760","that hath made",72,86],["H4615","the depths",87,97],["H3220","of the sea",98,108],["H1870","a way",109,114],["H1350","for the ransomed",115,131],["H5674","to pass over",132,144]]},"51:11":{"text":"Therefore the redeemed of the LORD shall return, and come with singing unto Zion; and everlasting joy shall be upon their head: they shall obtain gladness and joy; and sorrow and mourning shall flee away.","words":[["H6299","Therefore the redeemed",0,22],["H3068","of the LORD",23,34],["H7725","shall return",35,47],["H0935","and come",49,57],["H7440","with singing",58,70],["H6726","unto Zion",71,80],["H5769","and everlasting",82,97],["H8057","joy",98,101],["H7218","shall be upon their head",102,126],["H5381","they shall obtain",128,145],["H8342","gladness",146,154],["H8057","and joy",155,162],["H3015","and sorrow",164,174],["H0585","and mourning",175,187],["H5127","shall flee away",188,203]]},"51:12":{"text":"I, even I, am he that comforteth you: who art thou, that thou shouldest be afraid of a man that shall die, and of the son of man which shall be made as grass;","words":[["H5162","I, even I, am he that comforteth",0,32],["H3372","you: who art thou, that thou shouldest be afraid",33,81],["H0582","of a man",82,90],["H4191","that shall die",91,105],["H1121","and of the son",107,121],["H0120","of man",122,128],["H5414","which shall be made",129,148],["H2682","as grass",149,157]]},"51:13":{"text":"And forgettest the LORD thy maker, that hath stretched forth the heavens, and laid the foundations of the earth; and hast feared continually every day because of the fury of the oppressor, as if he were ready to destroy? and where is the fury of the oppressor?","words":[["H7911","And forgettest",0,14],["H3068","the LORD",15,23],["H6213","thy maker",24,33],["H5186","that hath stretched forth",35,60],["H8064","the heavens",61,72],["H3245","and laid the foundations",74,98],["H0776","of the earth",99,111],["H6342","and hast feared",113,128],["H8548","continually",129,140],["H3117","every day",141,150],["H6440","because",151,158],["H2534","of the fury",159,170],["H6693","of the oppressor",171,187],["H0834","as if",189,194],["H3559","he were ready",195,208],["H7843","to destroy",209,219],["H2534","and where is the fury",221,242],["H6693","of the oppressor",243,259]]},"51:14":{"text":"The captive exile hasteneth that he may be loosed, and that he should not die in the pit, nor that his bread should fail.","words":[["H6808","The captive exile",0,17],["H4116","hasteneth",18,27],["H6605","that he may be loosed",28,49],["H4191","and that he should not die",51,77],["H7845","in the pit",78,88],["H3899","nor that his bread",90,108],["H2637","should fail",109,120]]},"51:15":{"text":"But I am the LORD thy God, that divided the sea, whose waves roared: The LORD of hosts is his name.","words":[["H3068","But I am the LORD",0,17],["H0430","thy God",18,25],["H7280","that divided",27,39],["H3220","the sea",40,47],["H1530","whose waves",49,60],["H1993","roared",61,67],["H3068","The LORD",69,77],["H6635","of hosts",78,86],["H8034","is his name",87,98]]},"51:16":{"text":"And I have put my words in thy mouth, and I have covered thee in the shadow of mine hand, that I may plant the heavens, and lay the foundations of the earth, and say unto Zion, Thou art my people.","words":[["H7760","And I have put",0,14],["H1697","my words",15,23],["H6310","in thy mouth",24,36],["H3680","and I have covered",38,56],["H6738","thee in the shadow",57,75],["H3027","of mine hand",76,88],["H5193","that I may plant",90,106],["H8064","the heavens",107,118],["H3245","and lay the foundations",120,143],["H0776","of the earth",144,156],["H0559","and say",158,165],["H6726","unto Zion",166,175],["H5971","Thou art my people",177,195]]},"51:17":{"text":"Awake, awake, stand up, O Jerusalem, which hast drunk at the hand of the LORD the cup of his fury; thou hast drunken the dregs of the cup of trembling, and wrung them out.","words":[["H5782","Awake",0,5],["H5782","awake",7,12],["H6965","stand up",14,22],["H3389","O Jerusalem",24,35],["H8354","which hast drunk",37,53],["H3027","at the hand",54,65],["H3068","of the LORD",66,77],["H3563","the cup",78,85],["H2534","of his fury",86,97],["H8354","thou hast drunken",99,116],["H6907","the dregs",117,126],["H3563","of the cup",127,137],["H8653","of trembling",138,150],["H4680","and wrung them out",152,170]]},"51:18":{"text":"There is none to guide her among all the sons whom she hath brought forth; neither is there any that taketh her by the hand of all the sons that she hath brought up.","words":[["H5095","There is none to guide",0,22],["H1121","her among all the sons",23,45],["H3205","whom she hath brought forth",46,73],["H2388","neither is there any that taketh",75,107],["H3027","her by the hand",108,123],["H1121","of all the sons",124,139],["H1431","that she hath brought up",140,164]]},"51:19":{"text":"These two things are come unto thee; who shall be sorry for thee? desolation, and destruction, and the famine, and the sword: by whom shall I comfort thee?","words":[["H8147","These two",0,9],["H7122","things are come",10,25],["H5110","unto thee; who shall be sorry",26,55],["H7701","for thee? desolation",56,76],["H7667","and destruction",78,93],["H7458","and the famine",95,109],["H2719","and the sword",111,124],["H5162","by whom shall I comfort",126,149]]},"51:20":{"text":"Thy sons have fainted, they lie at the head of all the streets, as a wild bull in a net: they are full of the fury of the LORD, the rebuke of thy God.","words":[["H1121","Thy sons",0,8],["H5968","have fainted",9,21],["H7901","they lie",23,31],["H7218","at the head",32,43],["H2351","of all the streets",44,62],["H8377","as a wild bull",64,78],["H4364","in a net",79,87],["H4392","they are full",89,102],["H2534","of the fury",103,114],["H3068","of the LORD",115,126],["H1606","the rebuke",128,138],["H0430","of thy God",139,149]]},"51:21":{"text":"Therefore hear now this, thou afflicted, and drunken, but not with wine:","words":[["H8085","Therefore hear",0,14],["H6041","now this, thou afflicted",15,39],["H7937","and drunken",41,52],["H3196","but not with wine",54,71]]},"51:22":{"text":"Thus saith thy Lord the LORD, and thy God that pleadeth the cause of his people, Behold, I have taken out of thine hand the cup of trembling, even the dregs of the cup of my fury; thou shalt no more drink it again:","words":[["H0559","Thus saith",0,10],["H0113","thy Lord",11,19],["H3068","the LORD",20,28],["H0430","and thy God",30,41],["H7378","that pleadeth",42,55],["H5971","the cause of his people",56,79],["H3947","Behold, I have taken out",81,105],["H3027","of thine hand",106,119],["H3563","the cup",120,127],["H8653","of trembling",128,140],["H6907","even the dregs",142,156],["H3563","of the cup",157,167],["H2534","of my fury",168,178],["H3254","thou shalt no more",180,198],["H8354","drink it again",199,213]]},"51:23":{"text":"But I will put it into the hand of them that afflict thee; which have said to thy soul, Bow down, that we may go over: and thou hast laid thy body as the ground, and as the street, to them that went over.","words":[["H7760","But I will put",0,14],["H3027","it into the hand",15,31],["H3013","of them that afflict",32,52],["H0559","thee; which have said",53,74],["H5315","to thy soul",75,86],["H7812","Bow down",88,96],["H5674","that we may go over",98,117],["H7760","and thou hast laid",119,137],["H1460","thy body",138,146],["H0776","as the ground",147,160],["H2351","and as the street",162,179],["H5674","to them that went over",181,203]]},"52:1":{"text":"Awake, awake; put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city: for henceforth there shall no more come into thee the uncircumcised and the unclean.","words":[["H5782","Awake",0,5],["H5782","awake",7,12],["H3847","put on",14,20],["H5797","thy strength",21,33],["H6726","O Zion",35,41],["H3847","put on",43,49],["H8597","thy beautiful",50,63],["H0899","garments",64,72],["H3389","O Jerusalem",74,85],["H6944","the holy",87,95],["H5892","city",96,100],["H3254","for henceforth there shall no more",102,136],["H0935","come",137,141],["H6189","into thee the uncircumcised",142,169],["H2931","and the unclean",170,185]]},"52:2":{"text":"Shake thyself from the dust; arise, and sit down, O Jerusalem: loose thyself from the bands of thy neck, O captive daughter of Zion.","words":[["H5287","Shake",0,5],["H6083","thyself from the dust",6,27],["H6965","arise",29,34],["H3427","and sit down",36,48],["H3389","O Jerusalem",50,61],["H6605","loose",63,68],["H4147","thyself from the bands",69,91],["H6677","of thy neck",92,103],["H7628","O captive",105,114],["H1323","daughter",115,123],["H6726","of Zion",124,131]]},"52:3":{"text":"For thus saith the LORD, Ye have sold yourselves for nought; and ye shall be redeemed without money.","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H4376","Ye have sold",25,37],["H2600","yourselves for nought",38,59],["H1350","and ye shall be redeemed",61,85],["H3701","without money",86,99]]},"52:4":{"text":"For thus saith the Lord GOD, My people went down aforetime into Egypt to sojourn there; and the Assyrian oppressed them without cause.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H5971","My people",29,38],["H3381","went down",39,48],["H7223","aforetime",49,58],["H4714","into Egypt",59,69],["H1481","to sojourn",70,80],["H0804","there; and the Assyrian",81,104],["H6231","oppressed",105,114],["H0657","them without cause",115,133]]},"52:5":{"text":"Now therefore, what have I here, saith the LORD, that my people is taken away for nought? they that rule over them make them to howl, saith the LORD; and my name continually every day is blasphemed.","words":[["H5002","Now therefore, what have I here, saith",0,38],["H3068","the LORD",39,47],["H5971","that my people",49,63],["H3947","is taken away",64,77],["H2600","for nought",78,88],["H4910","they that rule",90,104],["H3213","over them make them to howl",105,132],["H5002","saith",134,139],["H3068","the LORD",140,148],["H8034","and my name",150,161],["H8548","continually",162,173],["H3117","every day",174,183],["H5006","is blasphemed",184,197]]},"52:6":{"text":"Therefore my people shall know my name: therefore they shall know in that day that I am he that doth speak: behold, it is I.","words":[["H5971","Therefore my people",0,19],["H3045","shall know",20,30],["H8034","my name",31,38],["H3117","therefore they shall know in that day",40,77],["H1696","that I am he that doth speak",78,106]]},"52:7":{"text":"How beautiful upon the mountains are the feet of him that bringeth good tidings, that publisheth peace; that bringeth good tidings of good, that publisheth salvation; that saith unto Zion, Thy God reigneth!","words":[["H4998","How beautiful",0,13],["H2022","upon the mountains",14,32],["H7272","are the feet",33,45],["H1319","of him that bringeth good tidings",46,79],["H8085","that publisheth",81,96],["H7965","peace",97,102],["H1319","that bringeth good tidings",104,130],["H2896","of good",131,138],["H8085","that publisheth",140,155],["H3444","salvation",156,165],["H0559","that saith",167,177],["H6726","unto Zion",178,187],["H0430","Thy God",189,196],["H4427","reigneth",197,205]]},"52:8":{"text":"Thy watchmen shall lift up the voice; with the voice together shall they sing: for they shall see eye to eye, when the LORD shall bring again Zion.","words":[["H6822","Thy watchmen",0,12],["H5375","shall lift up",13,26],["H6963","the voice",27,36],["H6963","with the voice",38,52],["H3162","together",53,61],["H7442","shall they sing",62,77],["H7200","for they shall see",79,97],["H5869","eye",98,101],["H5869","to eye",102,108],["H3068","when the LORD",110,123],["H7725","shall bring again",124,141],["H6726","Zion",142,146]]},"52:9":{"text":"Break forth into joy, sing together, ye waste places of Jerusalem: for the LORD hath comforted his people, he hath redeemed Jerusalem.","words":[["H6476","Break forth into joy",0,20],["H7442","sing",22,26],["H3162","together",27,35],["H2723","ye waste places",37,52],["H3389","of Jerusalem",53,65],["H3068","for the LORD",67,79],["H5162","hath comforted",80,94],["H5971","his people",95,105],["H1350","he hath redeemed",107,123],["H3389","Jerusalem",124,133]]},"52:10":{"text":"The LORD hath made bare his holy arm in the eyes of all the nations; and all the ends of the earth shall see the salvation of our God.","words":[["H3068","The LORD",0,8],["H2834","hath made bare",9,23],["H6944","his holy",24,32],["H2220","arm",33,36],["H5869","in the eyes",37,48],["H1471","of all the nations",49,67],["H0657","and all the ends",69,85],["H0776","of the earth",86,98],["H7200","shall see",99,108],["H3444","the salvation",109,122],["H0430","of our God",123,133]]},"52:11":{"text":"Depart ye, depart ye, go ye out from thence, touch no unclean thing; go ye out of the midst of her; be ye clean, that bear the vessels of the LORD.","words":[["H5493","Depart",0,6],["H5493","ye, depart",7,17],["H3318","ye, go ye out",18,31],["H5060","from thence, touch",32,50],["H2931","no unclean",51,61],["H3318","thing; go ye out",62,78],["H8432","of the midst",79,91],["H1305","of her; be ye clean",92,111],["H5375","that bear",113,122],["H3627","the vessels",123,134],["H3068","of the LORD",135,146]]},"52:12":{"text":"For ye shall not go out with haste, nor go by flight: for the LORD will go before you; and the God of Israel will be your rereward.","words":[["H3318","For ye shall not go out",0,23],["H2649","with haste",24,34],["H3212","nor go",36,42],["H4499","by flight",43,52],["H3068","for the LORD",54,66],["H1980","will go",67,74],["H6440","before",75,81],["H0430","you; and the God",82,98],["H3478","of Israel",99,108],["H0622","will be your rereward",109,130]]},"52:13":{"text":"Behold, my servant shall deal prudently, he shall be exalted and extolled, and be very high.","words":[["H5650","Behold, my servant",0,18],["H7919","shall deal prudently",19,39],["H7311","he shall be exalted",41,60],["H5375","and extolled",61,73],["H3966","and be very",75,86],["H1361","high",87,91]]},"52:14":{"text":"As many were astonied at thee; his visage was so marred more than any man, and his form more than the sons of men:","words":[["H7227","As many",0,7],["H8074","were astonied",8,21],["H4758","at thee; his visage",22,41],["H4893","was so marred",42,55],["H0376","more than any man",56,73],["H8389","and his form",75,87],["H1121","more than the sons",88,106],["H0120","of men",107,113]]},"52:15":{"text":"So shall he sprinkle many nations; the kings shall shut their mouths at him: for that which had not been told them shall they see; and that which they had not heard shall they consider.","words":[["H5137","So shall he sprinkle",0,20],["H7227","many",21,25],["H1471","nations",26,33],["H4428","the kings",35,44],["H7092","shall shut",45,55],["H6310","their mouths",56,68],["H5608","at him: for that which had not been told",69,109],["H7200","them shall they see",110,129],["H8085","and that which they had not heard",131,164],["H0995","shall they consider",165,184]]},"53:1":{"text":"Who hath believed our report? and to whom is the arm of the LORD revealed?","words":[["H0539","Who hath believed",0,17],["H8052","our report",18,28],["H2220","and to whom is the arm",30,52],["H3068","of the LORD",53,64],["H1540","revealed",65,73]]},"53:2":{"text":"For he shall grow up before him as a tender plant, and as a root out of a dry ground: he hath no form nor comeliness; and when we shall see him, there is no beauty that we should desire him.","words":[["H5927","For he shall grow up",0,20],["H6440","before",21,27],["H3126","him as a tender plant",28,49],["H8328","and as a root",51,64],["H6723","out of a dry",65,77],["H0776","ground",78,84],["H8389","he hath no form",86,101],["H1926","nor comeliness",102,116],["H7200","and when we shall see",118,139],["H4758","him, there is no beauty",140,163],["H2530","that we should desire",164,185]]},"53:3":{"text":"He is despised and rejected of men; a man of sorrows, and acquainted with grief: and we hid as it were our faces from him; he was despised, and we esteemed him not.","words":[["H0959","He is despised",0,14],["H2310","and rejected",15,27],["H0376","of men",28,34],["H0376","a man",36,41],["H4341","of sorrows",42,52],["H3045","and acquainted",54,68],["H2483","with grief",69,79],["H4564","and we hid as it were",81,102],["H6440","our faces",103,112],["H0959","from him; he was despised",113,138],["H2803","and we esteemed",140,155]]},"53:4":{"text":"Surely he hath borne our griefs, and carried our sorrows: yet we did esteem him stricken, smitten of God, and afflicted.","words":[["H0403","Surely",0,6],["H5375","he hath borne",7,20],["H2483","our griefs",21,31],["H5445","and carried",33,44],["H4341","our sorrows",45,56],["H2803","yet we did esteem",58,75],["H5060","him stricken",76,88],["H5221","smitten",90,97],["H0430","of God",98,104],["H6031","and afflicted",106,119]]},"53:5":{"text":"But he was wounded for our transgressions, he was bruised for our iniquities: the chastisement of our peace was upon him; and with his stripes we are healed.","words":[["H2490","But he was wounded",0,18],["H6588","for our transgressions",19,41],["H1792","he was bruised",43,57],["H5771","for our iniquities",58,76],["H4148","the chastisement",78,94],["H7965","of our peace",95,107],["H2250","was upon him; and with his stripes",108,142],["H7495","we are healed",143,156]]},"53:6":{"text":"All we like sheep have gone astray; we have turned every one to his own way; and the LORD hath laid on him the iniquity of us all.","words":[["H6629","All we like sheep",0,17],["H8582","have gone astray",18,34],["H6437","we have turned",36,50],["H0376","every one",51,60],["H1870","to his own way",61,75],["H3068","and the LORD",77,89],["H6293","hath laid",90,99],["H5771","on him the iniquity",100,119]]},"53:7":{"text":"He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth.","words":[["H5065","He was oppressed",0,16],["H6031","and he was afflicted",18,38],["H6605","yet he opened",40,53],["H6310","not his mouth",54,67],["H2986","he is brought",69,82],["H7716","as a lamb",83,92],["H2874","to the slaughter",93,109],["H7353","and as a sheep",111,125],["H6440","before",126,132],["H1494","her shearers",133,145],["H0481","is dumb",146,153],["H6605","so he openeth",155,168],["H6310","not his mouth",169,182]]},"53:8":{"text":"He was taken from prison and from judgment: and who shall declare his generation? for he was cut off out of the land of the living: for the transgression of my people was he stricken.","words":[["H3947","He was taken",0,12],["H6115","from prison",13,24],["H4941","and from judgment",25,42],["H7878","and who shall declare",44,65],["H1755","his generation",66,80],["H1504","for he was cut off",82,100],["H0776","out of the land",101,116],["H2416","of the living",117,130],["H6588","for the transgression",132,153],["H5971","of my people",154,166],["H5061","was he stricken",167,182]]},"53:9":{"text":"And he made his grave with the wicked, and with the rich in his death; because he had done no violence, neither was any deceit in his mouth.","words":[["H5414","And he made",0,11],["H6913","his grave",12,21],["H7563","with the wicked",22,37],["H6223","and with the rich",39,56],["H4194","in his death",57,69],["H6213","because he had done",71,90],["H2555","no violence",91,102],["H4820","neither was any deceit",104,126],["H6310","in his mouth",127,139]]},"53:10":{"text":"Yet it pleased the LORD to bruise him; he hath put him to grief: when thou shalt make his soul an offering for sin, he shall see his seed, he shall prolong his days, and the pleasure of the LORD shall prosper in his hand.","words":[["H2654","Yet it pleased",0,14],["H3068","the LORD",15,23],["H1792","to bruise",24,33],["H2470","him; he hath put him to grief",34,63],["H7760","when thou shalt make",65,85],["H5315","his soul",86,94],["H0817","an offering for sin",95,114],["H7200","he shall see",116,128],["H2233","his seed",129,137],["H0748","he shall prolong",139,155],["H3117","his days",156,164],["H2656","and the pleasure",166,182],["H3068","of the LORD",183,194],["H6743","shall prosper",195,208],["H3027","in his hand",209,220]]},"53:11":{"text":"He shall see of the travail of his soul, and shall be satisfied: by his knowledge shall my righteous servant justify many; for he shall bear their iniquities.","words":[["H7200","He shall see",0,12],["H5999","of the travail",13,27],["H5315","of his soul",28,39],["H7646","and shall be satisfied",41,63],["H1847","by his knowledge",65,81],["H6662","shall my righteous",82,100],["H5650","servant",101,108],["H6663","justify",109,116],["H7227","many",117,121],["H5445","for he shall bear",123,140],["H5771","their iniquities",141,157]]},"53:12":{"text":"Therefore will I divide him a portion with the great, and he shall divide the spoil with the strong; because he hath poured out his soul unto death: and he was numbered with the transgressors; and he bare the sin of many, and made intercession for the transgressors.","words":[["H2505","Therefore will I divide",0,23],["H7227","him a portion with the great",24,52],["H2505","and he shall divide",54,73],["H7998","the spoil",74,83],["H6099","with the strong",84,99],["H6168","because he hath poured out",101,127],["H5315","his soul",128,136],["H4194","unto death",137,147],["H4487","and he was numbered",149,168],["H6586","with the transgressors",169,191],["H5375","and he bare",193,204],["H2399","the sin",205,212],["H7227","of many",213,220],["H6293","and made intercession",222,243],["H6586","for the transgressors",244,265]]},"54:1":{"text":"Sing, O barren, thou that didst not bear; break forth into singing, and cry aloud, thou that didst not travail with child: for more are the children of the desolate than the children of the married wife, saith the LORD.","words":[["H7442","Sing",0,4],["H6135","O barren",6,14],["H3205","thou that didst not bear",16,40],["H6476","break forth",42,53],["H7440","into singing",54,66],["H6670","and cry aloud",68,81],["H2342","thou that didst not travail with child",83,121],["H7227","for more",123,131],["H1121","are the children",132,148],["H8074","of the desolate",149,164],["H1121","than the children",165,182],["H1166","of the married wife",183,202],["H0559","saith",204,209],["H3068","the LORD",210,218]]},"54:2":{"text":"Enlarge the place of thy tent, and let them stretch forth the curtains of thine habitations: spare not, lengthen thy cords, and strengthen thy stakes;","words":[["H7337","Enlarge",0,7],["H4725","the place",8,17],["H0168","of thy tent",18,29],["H5186","and let them stretch forth",31,57],["H3407","the curtains",58,70],["H4908","of thine habitations",71,91],["H2820","spare",93,98],["H0748","not, lengthen",99,112],["H4340","thy cords",113,122],["H2388","and strengthen",124,138],["H3489","thy stakes",139,149]]},"54:3":{"text":"For thou shalt break forth on the right hand and on the left; and thy seed shall inherit the Gentiles, and make the desolate cities to be inhabited.","words":[["H6555","For thou shalt break forth",0,26],["H3225","on the right hand",27,44],["H8040","and on the left",45,60],["H2233","and thy seed",62,74],["H3423","shall inherit",75,88],["H1471","the Gentiles",89,101],["H8074","and make the desolate",103,124],["H5892","cities",125,131],["H3427","to be inhabited",132,147]]},"54:4":{"text":"Fear not; for thou shalt not be ashamed: neither be thou confounded; for thou shalt not be put to shame: for thou shalt forget the shame of thy youth, and shalt not remember the reproach of thy widowhood any more.","words":[["H3372","Fear",0,4],["H0954","not; for thou shalt not be ashamed",5,39],["H3637","neither be thou confounded",41,67],["H2659","for thou shalt not be put to shame",69,103],["H7911","for thou shalt forget",105,126],["H1322","the shame",127,136],["H5934","of thy youth",137,149],["H2142","and shalt not remember",151,173],["H2781","the reproach",174,186],["H0491","of thy widowhood",187,203]]},"54:5":{"text":"For thy Maker is thine husband; the LORD of hosts is his name; and thy Redeemer the Holy One of Israel; The God of the whole earth shall he be called.","words":[["H6213","For thy Maker",0,13],["H1166","is thine husband",14,30],["H3068","the LORD",32,40],["H6635","of hosts",41,49],["H8034","is his name",50,61],["H1350","and thy Redeemer",63,79],["H6918","the Holy One",80,92],["H3478","of Israel",93,102],["H0430","The God",104,111],["H0776","of the whole earth",112,130],["H7121","shall he be called",131,149]]},"54:6":{"text":"For the LORD hath called thee as a woman forsaken and grieved in spirit, and a wife of youth, when thou wast refused, saith thy God.","words":[["H3068","For the LORD",0,12],["H7121","hath called",13,24],["H0802","thee as a woman",25,40],["H5800","forsaken",41,49],["H6087","and grieved",50,61],["H7307","in spirit",62,71],["H0802","and a wife",73,83],["H5271","of youth",84,92],["H3988","when thou wast refused",94,116],["H0559","saith",118,123],["H0430","thy God",124,131]]},"54:7":{"text":"For a small moment have I forsaken thee; but with great mercies will I gather thee.","words":[["H6996","For a small",0,11],["H7281","moment",12,18],["H5800","have I forsaken",19,34],["H1419","thee; but with great",35,55],["H7356","mercies",56,63],["H6908","will I gather",64,77]]},"54:8":{"text":"In a little wrath I hid my face from thee for a moment; but with everlasting kindness will I have mercy on thee, saith the LORD thy Redeemer.","words":[["H8241","In a little",0,11],["H7110","wrath",12,17],["H5641","I hid",18,23],["H6440","my face",24,31],["H7281","from thee for a moment",32,54],["H5769","but with everlasting",56,76],["H2617","kindness",77,85],["H7355","will I have mercy",86,103],["H0559","on thee, saith",104,118],["H3068","the LORD",119,127],["H1350","thy Redeemer",128,140]]},"54:9":{"text":"For this is as the waters of Noah unto me: for as I have sworn that the waters of Noah should no more go over the earth; so have I sworn that I would not be wroth with thee, nor rebuke thee.","words":[["H4325","For this is as the waters",0,25],["H5146","of Noah",26,33],["H7650","unto me: for as I have sworn",34,62],["H4325","that the waters",63,78],["H5146","of Noah",79,86],["H5674","should no more go over",87,109],["H0776","the earth",110,119],["H7650","so have I sworn",121,136],["H7107","that I would not be wroth",137,162],["H1605","with thee, nor rebuke",163,184]]},"54:10":{"text":"For the mountains shall depart, and the hills be removed; but my kindness shall not depart from thee, neither shall the covenant of my peace be removed, saith the LORD that hath mercy on thee.","words":[["H2022","For the mountains",0,17],["H4185","shall depart",18,30],["H1389","and the hills",32,45],["H4131","be removed",46,56],["H2617","but my kindness",58,73],["H4185","shall not depart",74,90],["H1285","from thee, neither shall the covenant",91,128],["H7965","of my peace",129,140],["H4131","be removed",141,151],["H0559","saith",153,158],["H3068","the LORD",159,167],["H7355","that hath mercy",168,183]]},"54:11":{"text":"O thou afflicted, tossed with tempest, and not comforted, behold, I will lay thy stones with fair colours, and lay thy foundations with sapphires.","words":[["H6041","O thou afflicted",0,16],["H5590","tossed with tempest",18,37],["H5162","and not comforted",39,56],["H7257","behold, I will lay",58,76],["H0068","thy stones",77,87],["H6320","with fair colours",88,105],["H3245","and lay thy foundations",107,130],["H5601","with sapphires",131,145]]},"54:12":{"text":"And I will make thy windows of agates, and thy gates of carbuncles, and all thy borders of pleasant stones.","words":[["H7760","And I will make",0,15],["H8121","thy windows",16,27],["H3539","of agates",28,37],["H8179","and thy gates",39,52],["H0068","of carbuncles",53,66],["H0688","of carbuncles",53,66],["H1366","and all thy borders",68,87],["H2656","of pleasant",88,99],["H0068","stones",100,106]]},"54:13":{"text":"And all thy children shall be taught of the LORD; and great shall be the peace of thy children.","words":[["H1121","And all thy children",0,20],["H3928","shall be taught",21,36],["H3068","of the LORD",37,48],["H7227","and great",50,59],["H7965","shall be the peace",60,78],["H1121","of thy children",79,94]]},"54:14":{"text":"In righteousness shalt thou be established: thou shalt be far from oppression; for thou shalt not fear: and from terror; for it shall not come near thee.","words":[["H6666","In righteousness",0,16],["H3559","shalt thou be established",17,42],["H7368","thou shalt be far",44,61],["H6233","from oppression",62,77],["H3372","for thou shalt not fear",79,102],["H4288","and from terror",104,119],["H7126","for it shall not come near",121,147]]},"54:15":{"text":"Behold, they shall surely gather together, but not by me: whosoever shall gather together against thee shall fall for thy sake.","words":[["H1481","Behold, they shall surely",0,25],["H1481","gather together",26,41],["H0657","but not",43,50],["H4310","by me: whosoever",51,67],["H1481","shall gather together",68,89],["H5307","against thee shall fall",90,113]]},"54:16":{"text":"Behold, I have created the smith that bloweth the coals in the fire, and that bringeth forth an instrument for his work; and I have created the waster to destroy.","words":[["H1254","Behold, I have created",0,22],["H2796","the smith",23,32],["H5301","that bloweth",33,45],["H6352","the coals",46,55],["H0784","in the fire",56,67],["H3318","and that bringeth forth",69,92],["H3627","an instrument",93,106],["H4639","for his work",107,119],["H1254","and I have created",121,139],["H7843","the waster",140,150],["H2254","to destroy",151,161]]},"54:17":{"text":"No weapon that is formed against thee shall prosper; and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of the LORD, and their righteousness is of me, saith the LORD.","words":[["H3627","No weapon",0,9],["H3335","that is formed",10,24],["H6743","against thee shall prosper",25,51],["H3956","and every tongue",53,69],["H6965","that shall rise",70,85],["H4941","against thee in judgment",86,110],["H7561","thou shalt condemn",111,129],["H5159","This is the heritage",131,151],["H5650","of the servants",152,167],["H3068","of the LORD",168,179],["H6666","and their righteousness",181,204],["H5002","is of me, saith",205,220],["H3068","the LORD",221,229]]},"55:1":{"text":"Ho, every one that thirsteth, come ye to the waters, and he that hath no money; come ye, buy, and eat; yea, come, buy wine and milk without money and without price.","words":[["H1945","Ho",0,2],["H6771","every one that thirsteth",4,28],["H3212","come",30,34],["H4325","ye to the waters",35,51],["H3701","and he that hath no money",53,78],["H3212","come",80,84],["H7666","ye, buy",85,92],["H0398","and eat",94,101],["H3212","yea, come",103,112],["H7666","buy",114,117],["H3196","wine",118,122],["H2461","and milk",123,131],["H3701","without money",132,145],["H4242","and without price",146,163]]},"55:2":{"text":"Wherefore do ye spend money for that which is not bread? and your labour for that which satisfieth not? hearken diligently unto me, and eat ye that which is good, and let your soul delight itself in fatness.","words":[["H8254","Wherefore do ye spend",0,21],["H3701","money",22,27],["H3899","for that which is not bread",28,55],["H3018","and your labour",57,72],["H7654","for that which satisfieth",73,98],["H3808","not",99,102],["H8085","hearken",104,111],["H8085","diligently",112,122],["H0398","unto me, and eat",123,139],["H2896","ye that which is good",140,161],["H5315","and let your soul",163,180],["H6026","delight",181,188],["H1880","itself in fatness",189,206]]},"55:3":{"text":"Incline your ear, and come unto me: hear, and your soul shall live; and I will make an everlasting covenant with you, even the sure mercies of David.","words":[["H5186","Incline",0,7],["H0241","your ear",8,16],["H3212","and come",18,26],["H8085","unto me: hear",27,40],["H5315","and your soul",42,55],["H2421","shall live",56,66],["H3772","and I will make",68,83],["H5769","an everlasting",84,98],["H1285","covenant",99,107],["H0539","with you, even the sure",108,131],["H2617","mercies",132,139],["H1732","of David",140,148]]},"55:4":{"text":"Behold, I have given him for a witness to the people, a leader and commander to the people.","words":[["H5414","Behold, I have given",0,20],["H5707","him for a witness",21,38],["H3816","to the people",39,52],["H5057","a leader",54,62],["H6680","and commander",63,76],["H3816","to the people",77,90]]},"55:5":{"text":"Behold, thou shalt call a nation that thou knowest not, and nations that knew not thee shall run unto thee because of the LORD thy God, and for the Holy One of Israel; for he hath glorified thee.","words":[["H7121","Behold, thou shalt call",0,23],["H1471","a nation",24,32],["H3045","that thou knowest",33,50],["H1471","not, and nations",51,67],["H3045","that knew",68,77],["H7323","not thee shall run",78,96],["H3068","unto thee because of the LORD",97,126],["H0430","thy God",127,134],["H6918","and for the Holy One",136,156],["H3478","of Israel",157,166],["H6286","for he hath glorified",168,189]]},"55:6":{"text":"Seek ye the LORD while he may be found, call ye upon him while he is near:","words":[["H1875","Seek",0,4],["H3068","ye the LORD",5,16],["H4672","while he may be found",17,38],["H7121","call",40,44],["H7138","ye upon him while he is near",45,73]]},"55:7":{"text":"Let the wicked forsake his way, and the unrighteous man his thoughts: and let him return unto the LORD, and he will have mercy upon him; and to our God, for he will abundantly pardon.","words":[["H7563","Let the wicked",0,14],["H5800","forsake",15,22],["H1870","his way",23,30],["H0205","and the unrighteous",32,51],["H0376","man",52,55],["H4284","his thoughts",56,68],["H7725","and let him return",70,88],["H3068","unto the LORD",89,102],["H7355","and he will have mercy",104,126],["H0430","upon him; and to our God",127,151],["H7235","for he will abundantly",153,175],["H5545","pardon",176,182]]},"55:8":{"text":"For my thoughts are not your thoughts, neither are your ways my ways, saith the LORD.","words":[["H4284","For my thoughts",0,15],["H4284","are not your thoughts",16,37],["H1870","neither are your ways",39,60],["H1870","my ways",61,68],["H5002","saith",70,75],["H3068","the LORD",76,84]]},"55:9":{"text":"For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.","words":[["H8064","For as the heavens",0,18],["H1361","are higher",19,29],["H0776","than the earth",30,44],["H1870","so are my ways",46,60],["H1361","higher",61,67],["H1870","than your ways",68,82],["H4284","and my thoughts",84,99],["H4284","than your thoughts",100,118]]},"55:10":{"text":"For as the rain cometh down, and the snow from heaven, and returneth not thither, but watereth the earth, and maketh it bring forth and bud, that it may give seed to the sower, and bread to the eater:","words":[["H1653","For as the rain",0,15],["H3381","cometh down",16,27],["H7950","and the snow",29,41],["H8064","from heaven",42,53],["H7725","and returneth",55,68],["H7301","not thither, but watereth",69,94],["H0776","the earth",95,104],["H3205","and maketh it bring forth",106,131],["H6779","and bud",132,139],["H5414","that it may give",141,157],["H2233","seed",158,162],["H2232","to the sower",163,175],["H3899","and bread",177,186],["H0398","to the eater",187,199]]},"55:11":{"text":"So shall my word be that goeth forth out of my mouth: it shall not return unto me void, but it shall accomplish that which I please, and it shall prosper in the thing whereto I sent it.","words":[["H1697","So shall my word",0,16],["H3318","be that goeth forth",17,36],["H6310","out of my mouth",37,52],["H7725","it shall not return",54,73],["H7387","unto me void",74,86],["H6213","but it shall accomplish",88,111],["H2654","that which I please",112,131],["H6743","and it shall prosper",133,153],["H7971","in the thing whereto I sent",154,181]]},"55:12":{"text":"For ye shall go out with joy, and be led forth with peace: the mountains and the hills shall break forth before you into singing, and all the trees of the field shall clap their hands.","words":[["H3318","For ye shall go out",0,19],["H8057","with joy",20,28],["H2986","and be led forth",30,46],["H7965","with peace",47,57],["H2022","the mountains",59,72],["H1389","and the hills",73,86],["H6476","shall break forth",87,104],["H6440","before",105,111],["H7440","you into singing",112,128],["H6086","and all the trees",130,147],["H7704","of the field",148,160],["H4222","shall clap",161,171],["H3709","their hands",172,183]]},"55:13":{"text":"Instead of the thorn shall come up the fir tree, and instead of the brier shall come up the myrtle tree: and it shall be to the LORD for a name, for an everlasting sign that shall not be cut off.","words":[["H5285","Instead of the thorn",0,20],["H5927","shall come up",21,34],["H1265","the fir tree",35,47],["H5636","and instead of the brier",49,73],["H5927","shall come up",74,87],["H1918","the myrtle tree",88,103],["H3068","and it shall be to the LORD",105,132],["H8034","for a name",133,143],["H5769","for an everlasting",145,163],["H0226","sign",164,168],["H3772","that shall not be cut off",169,194]]},"56:1":{"text":"Thus saith the LORD, Keep ye judgment, and do justice: for my salvation is near to come, and my righteousness to be revealed.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H8104","Keep",21,25],["H4941","ye judgment",26,37],["H6213","and do",39,45],["H6666","justice",46,53],["H3444","for my salvation",55,71],["H7138","is near",72,79],["H0935","to come",80,87],["H6666","and my righteousness",89,109],["H1540","to be revealed",110,124]]},"56:2":{"text":"Blessed is the man that doeth this, and the son of man that layeth hold on it; that keepeth the sabbath from polluting it, and keepeth his hand from doing any evil.","words":[["H0835","Blessed",0,7],["H0582","is the man",8,18],["H6213","that doeth",19,29],["H1121","this, and the son",30,47],["H0120","of man",48,54],["H2388","that layeth hold",55,71],["H8104","on it; that keepeth",72,91],["H7676","the sabbath",92,103],["H2490","from polluting",104,118],["H8104","it, and keepeth",119,134],["H3027","his hand",135,143],["H6213","from doing",144,154],["H7451","any evil",155,163]]},"56:3":{"text":"Neither let the son of the stranger, that hath joined himself to the LORD, speak, saying, The LORD hath utterly separated me from his people: neither let the eunuch say, Behold, I am a dry tree.","words":[["H1121","Neither let the son",0,19],["H5236","of the stranger",20,35],["H3867","that hath joined",37,53],["H3068","himself to the LORD",54,73],["H0559","speak",75,80],["H0559","saying",82,88],["H3068","The LORD",90,98],["H0914","hath utterly",99,111],["H0914","separated",112,121],["H5971","me from his people",122,140],["H5631","neither let the eunuch",142,164],["H0559","say",165,168],["H3002","Behold, I am a dry",170,188],["H6086","tree",189,193]]},"56:4":{"text":"For thus saith the LORD unto the eunuchs that keep my sabbaths, and choose the things that please me, and take hold of my covenant;","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H5631","unto the eunuchs",24,40],["H8104","that keep",41,50],["H7676","my sabbaths",51,62],["H0977","and choose",64,74],["H2654","the things that please",75,97],["H2388","me, and take hold",98,115],["H1285","of my covenant",116,130]]},"56:5":{"text":"Even unto them will I give in mine house and within my walls a place and a name better than of sons and of daughters: I will give them an everlasting name, that shall not be cut off.","words":[["H5414","Even unto them will I give",0,26],["H1004","in mine house",27,40],["H2346","and within my walls",41,60],["H3027","a place",61,68],["H8034","and a name",69,79],["H2896","better",80,86],["H1121","than of sons",87,99],["H1323","and of daughters",100,116],["H5414","I will give",118,129],["H5769","them an everlasting",130,149],["H8034","name",150,154],["H3772","that shall not be cut off",156,181]]},"56:6":{"text":"Also the sons of the stranger, that join themselves to the LORD, to serve him, and to love the name of the LORD, to be his servants, every one that keepeth the sabbath from polluting it, and taketh hold of my covenant;","words":[["H1121","Also the sons",0,13],["H5236","of the stranger",14,29],["H3867","that join",31,40],["H3068","themselves to the LORD",41,63],["H8334","to serve",65,73],["H0157","him, and to love",74,90],["H8034","the name",91,99],["H3068","of the LORD",100,111],["H5650","to be his servants",113,131],["H8104","every one that keepeth",133,155],["H7676","the sabbath",156,167],["H2490","from polluting",168,182],["H2388","it, and taketh hold",183,202],["H1285","of my covenant",203,217]]},"56:7":{"text":"Even them will I bring to my holy mountain, and make them joyful in my house of prayer: their burnt offerings and their sacrifices shall be accepted upon mine altar; for mine house shall be called an house of prayer for all people.","words":[["H0935","Even them will I bring",0,22],["H6944","to my holy",23,33],["H2022","mountain",34,42],["H8055","and make them joyful",44,64],["H1004","in my house",65,76],["H8605","of prayer",77,86],["H5930","their burnt offerings",88,109],["H2077","and their sacrifices",110,130],["H7522","shall be accepted",131,148],["H4196","upon mine altar",149,164],["H1004","for mine house",166,180],["H7121","shall be called",181,196],["H1004","an house",197,205],["H8605","of prayer",206,215],["H5971","for all people",216,230]]},"56:8":{"text":"The Lord GOD which gathereth the outcasts of Israel saith, Yet will I gather others to him, beside those that are gathered unto him.","words":[["H0136","The Lord",0,8],["H3069","GOD",9,12],["H6908","which gathereth",13,28],["H1760","the outcasts",29,41],["H3478","of Israel",42,51],["H5002","saith",52,57],["H6908","Yet will I gather",59,76],["H6908","others to him, beside those that are gathered",77,122]]},"56:9":{"text":"All ye beasts of the field, come to devour, yea, all ye beasts in the forest.","words":[["H2416","All ye beasts",0,13],["H7704","of the field",14,26],["H0857","come",28,32],["H0398","to devour",33,42],["H2416","yea, all ye beasts",44,62],["H3293","in the forest",63,76]]},"56:10":{"text":"His watchmen are blind: they are all ignorant, they are all dumb dogs, they cannot bark; sleeping, lying down, loving to slumber.","words":[["H6822","His watchmen",0,12],["H5787","are blind",13,22],["H3045","they are all ignorant",24,45],["H0483","they are all dumb",47,64],["H3611","dogs",65,69],["H3201","they cannot",71,82],["H5024","bark",83,87],["H1957","sleeping",89,97],["H7901","lying down",99,109],["H0157","loving",111,117],["H5123","to slumber",118,128]]},"56:11":{"text":"Yea, they are greedy dogs which can never have enough, and they are shepherds that cannot understand: they all look to their own way, every one for his gain, from his quarter.","words":[["H5794","Yea, they are greedy",0,20],["H5315","Yea, they are greedy",0,20],["H3611","dogs",21,25],["H3045","which can",26,35],["H3045","never have",36,46],["H7654","enough",47,53],["H7462","and they are shepherds",55,77],["H0995","that cannot understand",78,100],["H6437","they all look",102,115],["H1870","to their own way",116,132],["H0376","every one",134,143],["H1215","for his gain",144,156],["H7097","from his quarter",158,174]]},"56:12":{"text":"Come ye, say they, I will fetch wine, and we will fill ourselves with strong drink; and to morrow shall be as this day, and much more abundant.","words":[["H0857","Come",0,4],["H3947","ye, say they, I will fetch",5,31],["H3196","wine",32,36],["H5433","and we will fill",38,54],["H7941","ourselves with strong drink",55,82],["H4279","and to morrow",84,97],["H3117","shall be as this day",98,118],["H3966","and much",120,128],["H3499","more",129,133],["H1419","abundant",134,142]]},"57:1":{"text":"The righteous perisheth, and no man layeth it to heart: and merciful men are taken away, none considering that the righteous is taken away from the evil to come.","words":[["H6662","The righteous",0,13],["H0006","perisheth",14,23],["H0376","and no man",25,35],["H7760","layeth",36,42],["H3820","it to heart",43,54],["H2617","and merciful",56,68],["H0582","men",69,72],["H0622","are taken away",73,87],["H0995","none considering",89,105],["H6662","that the righteous",106,124],["H0622","is taken away",125,138],["H6440","from",139,143],["H7451","the evil",144,152]]},"57:2":{"text":"He shall enter into peace: they shall rest in their beds, each one walking in his uprightness.","words":[["H0935","He shall enter",0,14],["H7965","into peace",15,25],["H5117","they shall rest",27,42],["H4904","in their beds",43,56],["H1980","each one walking",58,74],["H5228","in his uprightness",75,93]]},"57:3":{"text":"But draw near hither, ye sons of the sorceress, the seed of the adulterer and the whore.","words":[["H7126","But draw near",0,13],["H1121","hither, ye sons",14,29],["H6049","of the sorceress",30,46],["H2233","the seed",48,56],["H5003","of the adulterer",57,73],["H2181","and the whore",74,87]]},"57:4":{"text":"Against whom do ye sport yourselves? against whom make ye a wide mouth, and draw out the tongue? are ye not children of transgression, a seed of falsehood,","words":[["H6026","Against whom do ye sport",0,24],["H7337","yourselves? against whom make ye a wide",25,64],["H6310","mouth",65,70],["H0748","and draw out",72,84],["H3956","the tongue",85,95],["H3206","are ye not children",97,116],["H6588","of transgression",117,133],["H2233","a seed",135,141],["H8267","of falsehood",142,154]]},"57:5":{"text":"Enflaming yourselves with idols under every green tree, slaying the children in the valleys under the clifts of the rocks?","words":[["H2552","Enflaming",0,9],["H0410","yourselves with idols",10,31],["H7488","under every green",32,49],["H6086","tree",50,54],["H7819","slaying",56,63],["H3206","the children",64,76],["H5158","in the valleys",77,91],["H5585","under the clifts",92,108],["H5553","of the rocks",109,121]]},"57:6":{"text":"Among the smooth stones of the stream is thy portion; they, they are thy lot: even to them hast thou poured a drink offering, thou hast offered a meat offering. Should I receive comfort in these?","words":[["H2511","Among the smooth",0,16],["H5158","stones of the stream",17,37],["H2506","is thy portion",38,52],["H1486","they, they are thy lot",54,76],["H8210","even to them hast thou poured",78,107],["H5262","a drink offering",108,124],["H5927","thou hast offered",126,143],["H4503","a meat offering",144,159],["H5162","Should I receive comfort",161,185]]},"57:7":{"text":"Upon a lofty and high mountain hast thou set thy bed: even thither wentest thou up to offer sacrifice.","words":[["H1364","Upon a lofty",0,12],["H5375","and high",13,21],["H2022","mountain",22,30],["H7760","hast thou set",31,44],["H4904","thy bed",45,52],["H5927","even thither wentest thou up",54,82],["H2076","to offer",83,91],["H2077","sacrifice",92,101]]},"57:8":{"text":"Behind the doors also and the posts hast thou set up thy remembrance: for thou hast discovered thyself to another than me, and art gone up; thou hast enlarged thy bed, and made thee a covenant with them; thou lovedst their bed where thou sawest it.","words":[["H0310","Behind",0,6],["H1817","the doors",7,16],["H4201","also and the posts",17,35],["H7760","hast thou set up",36,52],["H2146","thy remembrance",53,68],["H1540","for thou hast discovered",70,94],["H5927","thyself to another than me, and art gone up",95,138],["H7337","thou hast enlarged",140,158],["H4904","thy bed",159,166],["H3772","and made",168,176],["H0157","thee a covenant with them; thou lovedst",177,216],["H4904","their bed",217,226],["H3027","where",227,232],["H2372","thou sawest",233,244]]},"57:9":{"text":"And thou wentest to the king with ointment, and didst increase thy perfumes, and didst send thy messengers far off, and didst debase thyself even unto hell.","words":[["H7788","And thou wentest",0,16],["H4428","to the king",17,28],["H8081","with ointment",29,42],["H7235","and didst increase",44,62],["H7547","thy perfumes",63,75],["H7971","and didst send",77,91],["H6735","thy messengers",92,106],["H7350","far off",107,114],["H8213","and didst debase",116,132],["H7585","thyself even unto hell",133,155]]},"57:10":{"text":"Thou art wearied in the greatness of thy way; yet saidst thou not, There is no hope: thou hast found the life of thine hand; therefore thou wast not grieved.","words":[["H3021","Thou art wearied",0,16],["H7230","in the greatness",17,33],["H1870","of thy way",34,44],["H0559","yet saidst",46,56],["H2976","thou not, There is no hope",57,83],["H4672","thou hast found",85,100],["H2416","the life",101,109],["H3027","of thine hand",110,123],["H2470","therefore thou wast not grieved",125,156]]},"57:11":{"text":"And of whom hast thou been afraid or feared, that thou hast lied, and hast not remembered me, nor laid it to thy heart? have not I held my peace even of old, and thou fearest me not?","words":[["H1672","And of whom hast thou been afraid",0,33],["H3372","or feared",34,43],["H3576","that thou hast lied",45,64],["H2142","and hast not remembered",66,89],["H7760","me, nor laid",90,102],["H3820","it to thy heart",103,118],["H2814","have not I held my peace",120,144],["H5769","even of old",145,156],["H3372","and thou fearest",158,174]]},"57:12":{"text":"I will declare thy righteousness, and thy works; for they shall not profit thee.","words":[["H5046","I will declare",0,14],["H6666","thy righteousness",15,32],["H4639","and thy works",34,47],["H3276","for they shall not profit",49,74]]},"57:13":{"text":"When thou criest, let thy companies deliver thee; but the wind shall carry them all away; vanity shall take them: but he that putteth his trust in me shall possess the land, and shall inherit my holy mountain;","words":[["H2199","When thou criest",0,16],["H6899","let thy companies",18,35],["H5337","deliver",36,43],["H7307","thee; but the wind",44,62],["H5375","shall carry them all away",63,88],["H1892","vanity",90,96],["H3947","shall take",97,107],["H2620","them: but he that putteth his trust",108,143],["H5157","in me shall possess",144,163],["H0776","the land",164,172],["H3423","and shall inherit",174,191],["H6944","my holy",192,199],["H2022","mountain",200,208]]},"57:14":{"text":"And shall say, Cast ye up, cast ye up, prepare the way, take up the stumblingblock out of the way of my people.","words":[["H0559","And shall say",0,13],["H5549","Cast ye up",15,25],["H5549","cast ye up",27,37],["H6437","prepare",39,46],["H1870","the way",47,54],["H7311","take up",56,63],["H4383","the stumblingblock",64,82],["H1870","out of the way",83,97],["H5971","of my people",98,110]]},"57:15":{"text":"For thus saith the high and lofty One that inhabiteth eternity, whose name is Holy; I dwell in the high and holy place, with him also that is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite ones.","words":[["H0559","For thus saith",0,14],["H7311","the high",15,23],["H5375","and lofty One",24,37],["H7931","that inhabiteth",38,53],["H5703","eternity",54,62],["H8034","whose name",64,74],["H6918","is Holy",75,82],["H7931","I dwell",84,91],["H4791","in the high",92,103],["H6918","and holy",104,112],["H1793","place, with him also that is of a contrite",113,155],["H8217","and humble",156,166],["H7307","spirit",167,173],["H2421","to revive",175,184],["H7307","the spirit",185,195],["H8217","of the humble",196,209],["H2421","and to revive",211,224],["H3820","the heart",225,234],["H1792","of the contrite ones",235,255]]},"57:16":{"text":"For I will not contend for ever, neither will I be always wroth: for the spirit should fail before me, and the souls which I have made.","words":[["H7378","For I will not contend",0,22],["H5769","for ever",23,31],["H5331","neither will I be always",33,57],["H7107","wroth",58,63],["H7307","for the spirit",65,79],["H5848","should fail",80,91],["H6440","before",92,98],["H5397","me, and the souls",99,116],["H6213","which I have made",117,134]]},"57:17":{"text":"For the iniquity of his covetousness was I wroth, and smote him: I hid me, and was wroth, and he went on frowardly in the way of his heart.","words":[["H5771","For the iniquity",0,16],["H1215","of his covetousness",17,36],["H7107","was I wroth",37,48],["H5221","and smote",50,59],["H5641","him: I hid",60,70],["H7107","me, and was wroth",71,88],["H3212","and he went on",90,104],["H7726","frowardly",105,114],["H1870","in the way",115,125],["H3820","of his heart",126,138]]},"57:18":{"text":"I have seen his ways, and will heal him: I will lead him also, and restore comforts unto him and to his mourners.","words":[["H7200","I have seen",0,11],["H1870","his ways",12,20],["H7495","and will heal",22,35],["H5148","him: I will lead",36,52],["H7999","him also, and restore",53,74],["H5150","comforts",75,83],["H0057","unto him and to his mourners",84,112]]},"57:19":{"text":"I create the fruit of the lips; Peace, peace to him that is far off, and to him that is near, saith the LORD; and I will heal him.","words":[["H1254","I create",0,8],["H5108","the fruit",9,18],["H8193","of the lips",19,30],["H7965","Peace",32,37],["H7965","peace",39,44],["H7350","to him that is far off",45,67],["H7138","and to him that is near",69,92],["H0559","saith",94,99],["H3068","the LORD",100,108],["H7495","and I will heal",110,125]]},"57:20":{"text":"But the wicked are like the troubled sea, when it cannot rest, whose waters cast up mire and dirt.","words":[["H7563","But the wicked",0,14],["H1644","are like the troubled",15,36],["H3220","sea",37,40],["H3201","when it cannot",42,56],["H8252","rest",57,61],["H4325","whose waters",63,75],["H1644","cast up",76,83],["H7516","mire",84,88],["H2916","and dirt",89,97]]},"57:21":{"text":"There is no peace, saith my God, to the wicked.","words":[["H7965","There is no peace",0,17],["H0559","saith",19,24],["H0430","my God",25,31],["H7563","to the wicked",33,46]]},"58:1":{"text":"Cry aloud, spare not, lift up thy voice like a trumpet, and shew my people their transgression, and the house of Jacob their sins.","words":[["H7121","Cry",0,3],["H1627","aloud",4,9],["H2820","spare",11,16],["H7311","not, lift",17,26],["H6963","up thy voice",27,39],["H7782","like a trumpet",40,54],["H5046","and shew",56,64],["H5971","my people",65,74],["H6588","their transgression",75,94],["H1004","and the house",96,109],["H3290","of Jacob",110,118],["H2403","their sins",119,129]]},"58:2":{"text":"Yet they seek me daily, and delight to know my ways, as a nation that did righteousness, and forsook not the ordinance of their God: they ask of me the ordinances of justice; they take delight in approaching to God.","words":[["H1875","Yet they seek",0,13],["H3117","me daily",14,22],["H3117","me daily",14,22],["H2654","and delight",24,35],["H1847","to know",36,43],["H1870","my ways",44,51],["H1471","as a nation",53,64],["H6213","that did",65,73],["H6666","righteousness",74,87],["H5800","and forsook",89,100],["H4941","not the ordinance",101,118],["H0430","of their God",119,131],["H7592","they ask",133,141],["H4941","of me the ordinances",142,162],["H6664","of justice",163,173],["H2654","they take delight",175,192],["H7132","in approaching",193,207],["H0430","to God",208,214]]},"58:3":{"text":"Wherefore have we fasted, say they, and thou seest not? wherefore have we afflicted our soul, and thou takest no knowledge? Behold, in the day of your fast ye find pleasure, and exact all your labours.","words":[["H6684","Wherefore have we fasted",0,24],["H7200","say they, and thou seest",26,50],["H6031","not? wherefore have we afflicted",51,83],["H5315","our soul",84,92],["H3045","and thou takest no knowledge",94,122],["H3117","Behold, in the day",124,142],["H6685","of your fast",143,155],["H4672","ye find",156,163],["H2656","pleasure",164,172],["H5065","and exact",174,183],["H6092","all your labours",184,200]]},"58:4":{"text":"Behold, ye fast for strife and debate, and to smite with the fist of wickedness: ye shall not fast as ye do this day, to make your voice to be heard on high.","words":[["H6684","Behold, ye fast",0,15],["H7379","for strife",16,26],["H4683","and debate",27,37],["H5221","and to smite",39,51],["H0106","with the fist",52,65],["H7562","of wickedness",66,79],["H6684","ye shall not fast",81,98],["H3117","as ye do this day",99,116],["H6963","to make your voice",118,136],["H8085","to be heard",137,148],["H4791","on high",149,156]]},"58:5":{"text":"Is it such a fast that I have chosen? a day for a man to afflict his soul? is it to bow down his head as a bulrush, and to spread sackcloth and ashes under him? wilt thou call this a fast, and an acceptable day to the LORD?","words":[["H6685","Is it such a fast",0,17],["H0977","that I have chosen",18,36],["H3117","a day",38,43],["H0120","for a man",44,53],["H6031","to afflict",54,64],["H5315","his soul",65,73],["H3721","is it to bow down",75,92],["H7218","his head",93,101],["H0100","as a bulrush",102,114],["H3331","and to spread",116,129],["H8242","sackcloth",130,139],["H0665","and ashes",140,149],["H7121","under him? wilt thou call",150,175],["H2088","this",176,180],["H6685","a fast",181,187],["H7522","and an acceptable",189,206],["H3117","day",207,210],["H3068","to the LORD",211,222]]},"58:6":{"text":"Is not this the fast that I have chosen? to loose the bands of wickedness, to undo the heavy burdens, and to let the oppressed go free, and that ye break every yoke?","words":[["H6685","Is not this the fast",0,20],["H0977","that I have chosen",21,39],["H6605","to loose",41,49],["H2784","the bands",50,59],["H7562","of wickedness",60,73],["H5425","to undo",75,82],["H4133","the heavy",83,92],["H0092","burdens",93,100],["H7533","and to let the oppressed",102,126],["H7971","go",127,129],["H2670","free",130,134],["H5423","and that ye break",136,153],["H4133","every yoke",154,164]]},"58:7":{"text":"Is it not to deal thy bread to the hungry, and that thou bring the poor that are cast out to thy house? when thou seest the naked, that thou cover him; and that thou hide not thyself from thine own flesh?","words":[["H6536","Is it not to deal",0,17],["H3899","thy bread",18,27],["H7457","to the hungry",28,41],["H0935","and that thou bring",43,62],["H6041","the poor",63,71],["H4788","that are cast out",72,89],["H1004","to thy house",90,102],["H7200","when thou seest",104,119],["H6174","the naked",120,129],["H3680","that thou cover",131,146],["H5956","him; and that thou hide",147,170],["H1320","not thyself from thine own flesh",171,203]]},"58:8":{"text":"Then shall thy light break forth as the morning, and thine health shall spring forth speedily: and thy righteousness shall go before thee; the glory of the LORD shall be thy rereward.","words":[["H0216","Then shall thy light",0,20],["H1234","break forth",21,32],["H7837","as the morning",33,47],["H0724","and thine health",49,65],["H6779","shall spring forth",66,84],["H4120","speedily",85,93],["H6664","and thy righteousness",95,116],["H1980","shall go",117,125],["H6440","before",126,132],["H3519","thee; the glory",133,148],["H3068","of the LORD",149,160],["H0622","shall be thy rereward",161,182]]},"58:9":{"text":"Then shalt thou call, and the LORD shall answer; thou shalt cry, and he shall say, Here I am. If thou take away from the midst of thee the yoke, the putting forth of the finger, and speaking vanity;","words":[["H7121","Then shalt thou call",0,20],["H3068","and the LORD",22,34],["H6030","shall answer",35,47],["H7768","thou shalt cry",49,63],["H0559","and he shall say",65,81],["H5493","Here I am. If thou take away",83,111],["H8432","from the midst",112,126],["H4133","of thee the yoke",127,143],["H7971","the putting forth",145,162],["H0676","of the finger",163,176],["H1696","and speaking",178,190],["H0205","vanity",191,197]]},"58:10":{"text":"And if thou draw out thy soul to the hungry, and satisfy the afflicted soul; then shall thy light rise in obscurity, and thy darkness be as the noonday:","words":[["H6329","And if thou draw out",0,20],["H5315","thy soul",21,29],["H7457","to the hungry",30,43],["H7646","and satisfy",45,56],["H6031","the afflicted",57,70],["H5315","soul",71,75],["H0216","then shall thy light",77,97],["H2224","rise",98,102],["H2822","in obscurity",103,115],["H0653","and thy darkness",117,133],["H6672","be as the noonday",134,151]]},"58:11":{"text":"And the LORD shall guide thee continually, and satisfy thy soul in drought, and make fat thy bones: and thou shalt be like a watered garden, and like a spring of water, whose waters fail not.","words":[["H3068","And the LORD",0,12],["H5148","shall guide",13,24],["H8548","thee continually",25,41],["H7646","and satisfy",43,54],["H5315","thy soul",55,63],["H6710","in drought",64,74],["H2502","and make fat",76,88],["H6106","thy bones",89,98],["H7302","and thou shalt be like a watered",100,132],["H1588","garden",133,139],["H4161","and like a spring",141,158],["H4325","of water",159,167],["H4325","whose waters",169,181],["H3576","fail",182,186]]},"58:12":{"text":"And they that shall be of thee shall build the old waste places: thou shalt raise up the foundations of many generations; and thou shalt be called, The repairer of the breach, The restorer of paths to dwell in.","words":[["H1129","And they that shall be of thee shall build",0,42],["H5769","the old",43,50],["H2723","waste places",51,63],["H6965","thou shalt raise up",65,84],["H4146","the foundations",85,100],["H1755","of many",101,108],["H1755","generations",109,120],["H7121","and thou shalt be called",122,146],["H1443","The repairer",148,160],["H6556","of the breach",161,174],["H7725","The restorer",176,188],["H5410","of paths",189,197],["H3427","to dwell in",198,209]]},"58:13":{"text":"If thou turn away thy foot from the sabbath, from doing thy pleasure on my holy day; and call the sabbath a delight, the holy of the LORD, honourable; and shalt honour him, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words:","words":[["H7725","If thou turn away",0,17],["H7272","thy foot",18,26],["H7676","from the sabbath",27,43],["H6213","from doing",45,55],["H2656","thy pleasure",56,68],["H6944","on my holy",69,79],["H3117","day",80,83],["H7121","and call",85,93],["H7676","the sabbath",94,105],["H6027","a delight",106,115],["H6918","the holy",117,125],["H3068","of the LORD",126,137],["H3513","honourable",139,149],["H3513","and shalt honour",151,167],["H6213","him, not doing",168,182],["H1870","thine own ways",183,197],["H4672","nor finding",199,210],["H2656","thine own pleasure",211,229],["H1696","nor speaking",231,243],["H1697","thine own words",244,259]]},"58:14":{"text":"Then shalt thou delight thyself in the LORD; and I will cause thee to ride upon the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of the LORD hath spoken it.","words":[["H6026","Then shalt thou delight",0,23],["H3068","thyself in the LORD",24,43],["H7392","and I will cause thee to ride",45,74],["H1116","upon the high places",75,95],["H0776","of the earth",96,108],["H0398","and feed",110,118],["H5159","thee with the heritage",119,141],["H3290","of Jacob",142,150],["H0001","thy father",151,161],["H6310","for the mouth",163,176],["H3068","of the LORD",177,188],["H1696","hath spoken",189,200]]},"59:1":{"text":"Behold, the LORD'S hand is not shortened, that it cannot save; neither his ear heavy, that it cannot hear:","words":[["H2005","Behold",0,6],["H3068","the LORD'S",8,18],["H3027","hand",19,23],["H7114","is not shortened",24,40],["H3467","that it cannot save",42,61],["H0241","neither his ear",63,78],["H3513","heavy",79,84],["H8085","that it cannot hear",86,105]]},"59:2":{"text":"But your iniquities have separated between you and your God, and your sins have hid his face from you, that he will not hear.","words":[["H5771","But your iniquities",0,19],["H0914","have separated",20,34],["H0996","between",35,42],["H0430","you and your God",43,59],["H2403","and your sins",61,74],["H5641","have hid",75,83],["H6440","his face",84,92],["H8085","from you, that he will not hear",93,124]]},"59:3":{"text":"For your hands are defiled with blood, and your fingers with iniquity; your lips have spoken lies, your tongue hath muttered perverseness.","words":[["H3709","For your hands",0,14],["H1351","are defiled",15,26],["H1818","with blood",27,37],["H0676","and your fingers",39,55],["H5771","with iniquity",56,69],["H8193","your lips",71,80],["H1696","have spoken",81,92],["H8267","lies",93,97],["H3956","your tongue",99,110],["H1897","hath muttered",111,124],["H5766","perverseness",125,137]]},"59:4":{"text":"None calleth for justice, nor any pleadeth for truth: they trust in vanity, and speak lies; they conceive mischief, and bring forth iniquity.","words":[["H7121","None calleth",0,12],["H6664","for justice",13,24],["H8199","nor any pleadeth",26,42],["H0530","for truth",43,52],["H0982","they trust",54,64],["H8414","in vanity",65,74],["H1696","and speak",76,85],["H7723","lies",86,90],["H2029","they conceive",92,105],["H5999","mischief",106,114],["H3205","and bring forth",116,131],["H0205","iniquity",132,140]]},"59:5":{"text":"They hatch cockatrice' eggs, and weave the spider's web: he that eateth of their eggs dieth, and that which is crushed breaketh out into a viper.","words":[["H1234","They hatch",0,10],["H6848","cockatrice'",11,22],["H1000","eggs",23,27],["H0707","and weave",29,38],["H5908","the spider's",39,51],["H6980","web",52,55],["H0398","he that eateth",57,71],["H1000","of their eggs",72,85],["H4191","dieth",86,91],["H2116","and that which is crushed",93,118],["H1234","breaketh out",119,131],["H0660","into a viper",132,144]]},"59:6":{"text":"Their webs shall not become garments, neither shall they cover themselves with their works: their works are works of iniquity, and the act of violence is in their hands.","words":[["H6980","Their webs",0,10],["H0899","shall not become garments",11,36],["H3680","neither shall they cover",38,62],["H4639","themselves with their works",63,90],["H4639","their works",92,103],["H4639","are works",104,113],["H0205","of iniquity",114,125],["H6467","and the act",127,138],["H2555","of violence",139,150],["H3709","is in their hands",151,168]]},"59:7":{"text":"Their feet run to evil, and they make haste to shed innocent blood: their thoughts are thoughts of iniquity; wasting and destruction are in their paths.","words":[["H7272","Their feet",0,10],["H7323","run",11,14],["H7451","to evil",15,22],["H4116","and they make haste",24,43],["H8210","to shed",44,51],["H5355","innocent",52,60],["H1818","blood",61,66],["H4284","their thoughts",68,82],["H4284","are thoughts",83,95],["H0205","of iniquity",96,107],["H7701","wasting",109,116],["H7667","and destruction",117,132],["H4546","are in their paths",133,151]]},"59:8":{"text":"The way of peace they know not; and there is no judgment in their goings: they have made them crooked paths: whosoever goeth therein shall not know peace.","words":[["H1870","The way",0,7],["H7965","of peace",8,16],["H3045","they know",17,26],["H4941","not; and there is no judgment",27,56],["H4570","in their goings",57,72],["H6140","they have made them crooked",74,101],["H5410","paths",102,107],["H1869","whosoever goeth",109,124],["H3045","therein shall not know",125,147],["H7965","peace",148,153]]},"59:9":{"text":"Therefore is judgment far from us, neither doth justice overtake us: we wait for light, but behold obscurity; for brightness, but we walk in darkness.","words":[["H4941","Therefore is judgment",0,21],["H7368","far",22,25],["H6666","from us, neither doth justice",26,55],["H5381","overtake",56,64],["H6960","us: we wait",65,76],["H0216","for light",77,86],["H2822","but behold obscurity",88,108],["H5054","for brightness",110,124],["H1980","but we walk",126,137],["H0653","in darkness",138,149]]},"59:10":{"text":"We grope for the wall like the blind, and we grope as if we had no eyes: we stumble at noonday as in the night; we are in desolate places as dead men.","words":[["H1659","We grope",0,8],["H7023","for the wall",9,21],["H5787","like the blind",22,36],["H1659","and we grope",38,50],["H5869","as if we had no eyes",51,71],["H3782","we stumble",73,83],["H6672","at noonday",84,94],["H5399","as in the night",95,110],["H0820","we are in desolate",112,130],["H4191","places as dead",131,145]]},"59:11":{"text":"We roar all like bears, and mourn sore like doves: we look for judgment, but there is none; for salvation, but it is far off from us.","words":[["H1993","We roar",0,7],["H1677","all like bears",8,22],["H1897","and mourn",24,33],["H1897","sore",34,38],["H3123","like doves",39,49],["H6960","we look",51,58],["H4941","for judgment",59,71],["H3444","but there is none; for salvation",73,105],["H7368","but it is far off",107,124]]},"59:12":{"text":"For our transgressions are multiplied before thee, and our sins testify against us: for our transgressions are with us; and as for our iniquities, we know them;","words":[["H6588","For our transgressions",0,22],["H7231","are multiplied",23,37],["H2403","before thee, and our sins",38,63],["H6030","testify",64,71],["H6588","against us: for our transgressions",72,106],["H5771","are with us; and as for our iniquities",107,145],["H3045","we know",147,154]]},"59:13":{"text":"In transgressing and lying against the LORD, and departing away from our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.","words":[["H6586","In transgressing",0,16],["H3584","and lying",17,26],["H3068","against the LORD",27,43],["H5253","and departing away",45,63],["H0310","from",64,68],["H0430","our God",69,76],["H1696","speaking",78,86],["H6233","oppression",87,97],["H5627","and revolt",98,108],["H2029","conceiving",110,120],["H1897","and uttering",121,133],["H3820","from the heart",134,148],["H1697","words",149,154],["H8267","of falsehood",155,167]]},"59:14":{"text":"And judgment is turned away backward, and justice standeth afar off: for truth is fallen in the street, and equity cannot enter.","words":[["H4941","And judgment",0,12],["H5253","is turned away",13,27],["H0268","backward",28,36],["H6666","and justice",38,49],["H5975","standeth",50,58],["H7350","afar off",59,67],["H0571","for truth",69,78],["H3782","is fallen",79,88],["H7339","in the street",89,102],["H5229","and equity",104,114],["H3201","cannot",115,121],["H0935","enter",122,127]]},"59:15":{"text":"Yea, truth faileth; and he that departeth from evil maketh himself a prey: and the LORD saw it, and it displeased him that there was no judgment.","words":[["H0571","Yea, truth",0,10],["H5737","faileth",11,18],["H5493","and he that departeth",20,41],["H7451","from evil",42,51],["H7997","maketh himself a prey",52,73],["H3068","and the LORD",75,87],["H7200","saw",88,91],["H3415","it, and it displeased",92,113],["H5869","it, and it displeased",92,113],["H4941","him that there was no judgment",114,144]]},"59:16":{"text":"And he saw that there was no man, and wondered that there was no intercessor: therefore his arm brought salvation unto him; and his righteousness, it sustained him.","words":[["H7200","And he saw",0,10],["H0376","that there was no man",11,32],["H8074","and wondered",34,46],["H6293","that there was no intercessor",47,76],["H2220","therefore his arm",78,95],["H3467","brought salvation",96,113],["H6666","unto him; and his righteousness",114,145],["H5564","it sustained",147,159]]},"59:17":{"text":"For he put on righteousness as a breastplate, and an helmet of salvation upon his head; and he put on the garments of vengeance for clothing, and was clad with zeal as a cloke.","words":[["H3847","For he put on",0,13],["H6666","righteousness",14,27],["H8302","as a breastplate",28,44],["H3553","and an helmet",46,59],["H3444","of salvation",60,72],["H7218","upon his head",73,86],["H3847","and he put on",88,101],["H0899","the garments",102,114],["H5359","of vengeance",115,127],["H8516","for clothing",128,140],["H5844","and was clad",142,154],["H7068","with zeal",155,164],["H4598","as a cloke",165,175]]},"59:18":{"text":"According to their deeds, accordingly he will repay, fury to his adversaries, recompence to his enemies; to the islands he will repay recompence.","words":[["H5921","According to",0,12],["H1578","their deeds",13,24],["H7999","accordingly he will repay",26,51],["H2534","fury",53,57],["H6862","to his adversaries",58,76],["H1576","recompence",78,88],["H0341","to his enemies",89,103],["H0339","to the islands",105,119],["H7999","he will repay",120,133],["H1576","recompence",134,144]]},"59:19":{"text":"So shall they fear the name of the LORD from the west, and his glory from the rising of the sun. When the enemy shall come in like a flood, the Spirit of the LORD shall lift up a standard against him.","words":[["H3372","So shall they fear",0,18],["H8034","the name",19,27],["H3068","of the LORD",28,39],["H4628","from the west",40,53],["H3519","and his glory",55,68],["H4217","from the rising",69,84],["H8121","of the sun",85,95],["H6862","When the enemy",97,111],["H0935","shall come in",112,125],["H5104","like a flood",126,138],["H7307","the Spirit",140,150],["H3068","of the LORD",151,162],["H5127","shall lift up a standard",163,187]]},"59:20":{"text":"And the Redeemer shall come to Zion, and unto them that turn from transgression in Jacob, saith the LORD.","words":[["H1350","And the Redeemer",0,16],["H0935","shall come",17,27],["H6726","to Zion",28,35],["H7725","and unto them that turn",37,60],["H6588","from transgression",61,79],["H3290","in Jacob",80,88],["H5002","saith",90,95],["H3068","the LORD",96,104]]},"59:21":{"text":"As for me, this is my covenant with them, saith the LORD; My spirit that is upon thee, and my words which I have put in thy mouth, shall not depart out of thy mouth, nor out of the mouth of thy seed, nor out of the mouth of thy seed's seed, saith the LORD, from henceforth and for ever.","words":[["H1285","As for me, this is my covenant",0,30],["H0559","with them, saith",31,47],["H3068","the LORD",48,56],["H7307","My spirit",58,67],["H1697","that is upon thee, and my words",68,99],["H7760","which I have put",100,116],["H6310","in thy mouth",117,129],["H4185","shall not depart",131,147],["H6310","out of thy mouth",148,164],["H6310","nor out of the mouth",166,186],["H2233","of thy seed",187,198],["H6310","nor out of the mouth",200,220],["H2233","of thy seed's",221,234],["H2233","seed",235,239],["H0559","saith",241,246],["H3068","the LORD",247,255],["H5704","from henceforth and for",257,280],["H5769","ever",281,285]]},"60:1":{"text":"Arise, shine; for thy light is come, and the glory of the LORD is risen upon thee.","words":[["H6965","Arise",0,5],["H0215","shine",7,12],["H0216","for thy light",14,27],["H0935","is come",28,35],["H3519","and the glory",37,50],["H3068","of the LORD",51,62],["H2224","is risen",63,71]]},"60:2":{"text":"For, behold, the darkness shall cover the earth, and gross darkness the people: but the LORD shall arise upon thee, and his glory shall be seen upon thee.","words":[["H2822","For, behold, the darkness",0,25],["H3680","shall cover",26,37],["H0776","the earth",38,47],["H6205","and gross darkness",49,67],["H3816","the people",68,78],["H3068","but the LORD",80,92],["H2224","shall arise",93,104],["H3519","upon thee, and his glory",105,129],["H7200","shall be seen",130,143]]},"60:3":{"text":"And the Gentiles shall come to thy light, and kings to the brightness of thy rising.","words":[["H1471","And the Gentiles",0,16],["H1980","shall come",17,27],["H0216","to thy light",28,40],["H4428","and kings",42,51],["H5051","to the brightness",52,69],["H2225","of thy rising",70,83]]},"60:4":{"text":"Lift up thine eyes round about, and see: all they gather themselves together, they come to thee: thy sons shall come from far, and thy daughters shall be nursed at thy side.","words":[["H5375","Lift up",0,7],["H5869","thine eyes",8,18],["H5439","round about",19,30],["H7200","and see",32,39],["H6908","all they gather themselves together",41,76],["H0935","they come",78,87],["H1121","to thee: thy sons",88,105],["H0935","shall come",106,116],["H7350","from far",117,125],["H1323","and thy daughters",127,144],["H0539","shall be nursed",145,160],["H6654","at thy side",161,172]]},"60:5":{"text":"Then thou shalt see, and flow together, and thine heart shall fear, and be enlarged; because the abundance of the sea shall be converted unto thee, the forces of the Gentiles shall come unto thee.","words":[["H7200","Then thou shalt see",0,19],["H3372","Then thou shalt see",0,19],["H5102","and flow together",21,38],["H3824","and thine heart",40,55],["H6342","shall fear",56,66],["H7337","and be enlarged",68,83],["H1995","because the abundance",85,106],["H3220","of the sea",107,117],["H2015","shall be converted",118,136],["H2428","unto thee, the forces",137,158],["H1471","of the Gentiles",159,174],["H0935","shall come",175,185]]},"60:6":{"text":"The multitude of camels shall cover thee, the dromedaries of Midian and Ephah; all they from Sheba shall come: they shall bring gold and incense; and they shall shew forth the praises of the LORD.","words":[["H8229","The multitude",0,13],["H1581","of camels",14,23],["H3680","shall cover",24,35],["H1070","thee, the dromedaries",36,57],["H4080","of Midian",58,67],["H5891","and Ephah",68,77],["H7614","all they from Sheba",79,98],["H0935","shall come",99,109],["H5375","they shall bring",111,127],["H2091","gold",128,132],["H3828","and incense",133,144],["H1319","and they shall shew forth",146,171],["H8416","the praises",172,183],["H3068","of the LORD",184,195]]},"60:7":{"text":"All the flocks of Kedar shall be gathered together unto thee, the rams of Nebaioth shall minister unto thee: they shall come up with acceptance on mine altar, and I will glorify the house of my glory.","words":[["H6629","All the flocks",0,14],["H6938","of Kedar",15,23],["H6908","shall be gathered together",24,50],["H0352","unto thee, the rams",51,70],["H5032","of Nebaioth",71,82],["H8334","shall minister",83,97],["H5927","unto thee: they shall come up",98,127],["H7522","with acceptance",128,143],["H4196","on mine altar",144,157],["H6286","and I will glorify",159,177],["H1004","the house",178,187],["H8597","of my glory",188,199]]},"60:8":{"text":"Who are these that fly as a cloud, and as the doves to their windows?","words":[["H5774","Who are these that fly",0,22],["H5645","as a cloud",23,33],["H3123","and as the doves",35,51],["H0699","to their windows",52,68]]},"60:9":{"text":"Surely the isles shall wait for me, and the ships of Tarshish first, to bring thy sons from far, their silver and their gold with them, unto the name of the LORD thy God, and to the Holy One of Israel, because he hath glorified thee.","words":[["H0339","Surely the isles",0,16],["H6960","shall wait",17,27],["H0591","for me, and the ships",28,49],["H8659","of Tarshish",50,61],["H7223","first",62,67],["H0935","to bring",69,77],["H1121","thy sons",78,86],["H7350","from far",87,95],["H3701","their silver",97,109],["H2091","and their gold",110,124],["H8034","with them, unto the name",125,149],["H3068","of the LORD",150,161],["H0430","thy God",162,169],["H6918","and to the Holy One",171,190],["H3478","of Israel",191,200],["H6286","because he hath glorified",202,227]]},"60:10":{"text":"And the sons of strangers shall build up thy walls, and their kings shall minister unto thee: for in my wrath I smote thee, but in my favour have I had mercy on thee.","words":[["H1121","And the sons",0,12],["H5236","of strangers",13,25],["H1129","shall build up",26,40],["H2346","thy walls",41,50],["H4428","and their kings",52,67],["H8334","shall minister",68,82],["H7110","unto thee: for in my wrath",83,109],["H5221","I smote",110,117],["H7522","thee, but in my favour",118,140],["H7355","have I had mercy",141,157]]},"60:11":{"text":"Therefore thy gates shall be open continually; they shall not be shut day nor night; that men may bring unto thee the forces of the Gentiles, and that their kings may be brought.","words":[["H8179","Therefore thy gates",0,19],["H6605","shall be open",20,33],["H8548","continually",34,45],["H5462","they shall not be shut",47,69],["H3119","day",70,73],["H3915","nor night",74,83],["H0935","that men may bring",85,103],["H2428","unto thee the forces",104,124],["H1471","of the Gentiles",125,140],["H4428","and that their kings",142,162],["H5090","may be brought",163,177]]},"60:12":{"text":"For the nation and kingdom that will not serve thee shall perish; yea, those nations shall be utterly wasted.","words":[["H1471","For the nation",0,14],["H4467","and kingdom",15,26],["H5647","that will not serve",27,46],["H0006","thee shall perish",47,64],["H1471","yea, those nations",66,84],["H2717","shall be utterly",85,101],["H2717","wasted",102,108]]},"60:13":{"text":"The glory of Lebanon shall come unto thee, the fir tree, the pine tree, and the box together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.","words":[["H3519","The glory",0,9],["H3844","of Lebanon",10,20],["H0935","shall come",21,31],["H1265","unto thee, the fir tree",32,55],["H8410","the pine tree",57,70],["H8391","and the box",72,83],["H3162","together",84,92],["H6286","to beautify",94,105],["H4725","the place",106,115],["H4720","of my sanctuary",116,131],["H4725","and I will make the place",133,158],["H7272","of my feet",159,169],["H3513","glorious",170,178]]},"60:14":{"text":"The sons also of them that afflicted thee shall come bending unto thee; and all they that despised thee shall bow themselves down at the soles of thy feet; and they shall call thee, The city of the LORD, The Zion of the Holy One of Israel.","words":[["H1121","The sons",0,8],["H6031","also of them that afflicted",9,36],["H1980","thee shall come",37,52],["H7817","bending",53,60],["H5006","unto thee; and all they that despised",61,98],["H7812","thee shall bow themselves down",99,129],["H3709","at the soles",130,142],["H7272","of thy feet",143,154],["H7121","and they shall call",156,175],["H5892","thee, The city",176,190],["H3068","of the LORD",191,202],["H6726","The Zion",204,212],["H6918","of the Holy One",213,228],["H3478","of Israel",229,238]]},"60:15":{"text":"Whereas thou hast been forsaken and hated, so that no man went through thee, I will make thee an eternal excellency, a joy of many generations.","words":[["H8478","Whereas",0,7],["H5800","thou hast been forsaken",8,31],["H8130","and hated",32,41],["H5674","so that no man went through",43,70],["H7760","thee, I will make",71,88],["H5769","thee an eternal",89,104],["H1347","excellency",105,115],["H4885","a joy",117,122],["H1755","of many",123,130],["H1755","generations",131,142]]},"60:16":{"text":"Thou shalt also suck the milk of the Gentiles, and shalt suck the breast of kings: and thou shalt know that I the LORD am thy Saviour and thy Redeemer, the mighty One of Jacob.","words":[["H3243","Thou shalt also suck",0,20],["H2461","the milk",21,29],["H1471","of the Gentiles",30,45],["H3243","and shalt suck",47,61],["H7699","the breast",62,72],["H4428","of kings",73,81],["H3045","and thou shalt know",83,102],["H3068","that I the LORD",103,118],["H3467","am thy Saviour",119,133],["H1350","and thy Redeemer",134,150],["H0046","the mighty One",152,166],["H3290","of Jacob",167,175]]},"60:17":{"text":"For brass I will bring gold, and for iron I will bring silver, and for wood brass, and for stones iron: I will also make thy officers peace, and thine exactors righteousness.","words":[["H5178","For brass",0,9],["H0935","I will bring",10,22],["H2091","gold",23,27],["H1270","and for iron",29,41],["H0935","I will bring",42,54],["H3701","silver",55,61],["H6086","and for wood",63,75],["H5178","brass",76,81],["H0068","and for stones",83,97],["H1270","iron",98,102],["H7760","I will also make",104,120],["H6486","thy officers",121,133],["H7965","peace",134,139],["H5065","and thine exactors",141,159],["H6666","righteousness",160,173]]},"60:18":{"text":"Violence shall no more be heard in thy land, wasting nor destruction within thy borders; but thou shalt call thy walls Salvation, and thy gates Praise.","words":[["H2555","Violence",0,8],["H8085","shall no more be heard",9,31],["H0776","in thy land",32,43],["H7701","wasting",45,52],["H7667","nor destruction",53,68],["H1366","within thy borders",69,87],["H7121","but thou shalt call",89,108],["H2346","thy walls",109,118],["H3444","Salvation",119,128],["H8179","and thy gates",130,143],["H8416","Praise",144,150]]},"60:19":{"text":"The sun shall be no more thy light by day; neither for brightness shall the moon give light unto thee: but the LORD shall be unto thee an everlasting light, and thy God thy glory.","words":[["H8121","The sun",0,7],["H0216","shall be no more thy light",8,34],["H3119","by day",35,41],["H5051","neither for brightness",43,65],["H3394","shall the moon",66,80],["H0216","give light",81,91],["H3068","unto thee: but the LORD",92,115],["H5769","shall be unto thee an everlasting",116,149],["H0215","light",150,155],["H0430","and thy God",157,168],["H8597","thy glory",169,178]]},"60:20":{"text":"Thy sun shall no more go down; neither shall thy moon withdraw itself: for the LORD shall be thine everlasting light, and the days of thy mourning shall be ended.","words":[["H8121","Thy sun",0,7],["H0935","shall no more go down",8,29],["H3391","neither shall thy moon",31,53],["H0622","withdraw",54,62],["H3068","itself: for the LORD",63,83],["H5769","shall be thine everlasting",84,110],["H0216","light",111,116],["H3117","and the days",118,130],["H0060","of thy mourning",131,146],["H7999","shall be ended",147,161]]},"60:21":{"text":"Thy people also shall be all righteous: they shall inherit the land for ever, the branch of my planting, the work of my hands, that I may be glorified.","words":[["H5971","Thy people",0,10],["H6662","also shall be all righteous",11,38],["H3423","they shall inherit",40,58],["H0776","the land",59,67],["H5769","for ever",68,76],["H5342","the branch",78,88],["H4302","of my planting",89,103],["H4639","the work",105,113],["H3027","of my hands",114,125],["H6286","that I may be glorified",127,150]]},"60:22":{"text":"A little one shall become a thousand, and a small one a strong nation: I the LORD will hasten it in his time.","words":[["H6996","A little one",0,12],["H0505","shall become a thousand",13,36],["H6810","and a small one",38,53],["H6099","a strong",54,62],["H1471","nation",63,69],["H3068","I the LORD",71,81],["H2363","will hasten",82,93],["H6256","it in his time",94,108]]},"61:1":{"text":"The Spirit of the Lord GOD is upon me; because the LORD hath anointed me to preach good tidings unto the meek; he hath sent me to bind up the brokenhearted, to proclaim liberty to the captives, and the opening of the prison to them that are bound;","words":[["H7307","The Spirit",0,10],["H0136","of the Lord",11,22],["H3069","GOD",23,26],["H3068","is upon me; because the LORD",27,55],["H4886","hath anointed",56,69],["H1319","me to preach good tidings",70,95],["H6035","unto the meek",96,109],["H7971","he hath sent",111,123],["H2280","me to bind up",124,137],["H7665","the brokenhearted",138,155],["H3820","the brokenhearted",138,155],["H7121","to proclaim",157,168],["H1865","liberty",169,176],["H7617","to the captives",177,192],["H6495","and the opening of the prison",194,223],["H0631","to them that are bound",224,246]]},"61:2":{"text":"To proclaim the acceptable year of the LORD, and the day of vengeance of our God; to comfort all that mourn;","words":[["H7121","To proclaim",0,11],["H7522","the acceptable",12,26],["H8141","year",27,31],["H3068","of the LORD",32,43],["H3117","and the day",45,56],["H5359","of vengeance",57,69],["H0430","of our God",70,80],["H5162","to comfort",82,92],["H0057","all that mourn",93,107]]},"61:3":{"text":"To appoint unto them that mourn in Zion, to give unto them beauty for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness; that they might be called trees of righteousness, the planting of the LORD, that he might be glorified.","words":[["H7760","To appoint",0,10],["H0057","unto them that mourn",11,31],["H6726","in Zion",32,39],["H5414","to give",41,48],["H6287","unto them beauty",49,65],["H0665","for ashes",66,75],["H8081","the oil",77,84],["H8342","of joy",85,91],["H0060","for mourning",92,104],["H4594","the garment",106,117],["H8416","of praise",118,127],["H7307","for the spirit",128,142],["H3544","of heaviness",143,155],["H7121","that they might be called",157,182],["H0352","trees",183,188],["H6664","of righteousness",189,205],["H4302","the planting",207,219],["H3068","of the LORD",220,231],["H6286","that he might be glorified",233,259]]},"61:4":{"text":"And they shall build the old wastes, they shall raise up the former desolations, and they shall repair the waste cities, the desolations of many generations.","words":[["H1129","And they shall build",0,20],["H5769","the old",21,28],["H2723","wastes",29,35],["H6965","they shall raise up",37,56],["H7223","the former",57,67],["H8074","desolations",68,79],["H2318","and they shall repair",81,102],["H2721","the waste",103,112],["H5892","cities",113,119],["H8074","the desolations",121,136],["H1755","of many",137,144],["H1755","generations",145,156]]},"61:5":{"text":"And strangers shall stand and feed your flocks, and the sons of the alien shall be your plowmen and your vinedressers.","words":[["H2114","And strangers",0,13],["H5975","shall stand",14,25],["H7462","and feed",26,34],["H6629","your flocks",35,46],["H1121","and the sons",48,60],["H5236","of the alien",61,73],["H0406","shall be your plowmen",74,95],["H3755","and your vinedressers",96,117]]},"61:6":{"text":"But ye shall be named the Priests of the LORD: men shall call you the Ministers of our God: ye shall eat the riches of the Gentiles, and in their glory shall ye boast yourselves.","words":[["H7121","But ye shall be named",0,21],["H3548","the Priests",22,33],["H3068","of the LORD",34,45],["H0559","men shall call",47,61],["H8334","you the Ministers",62,79],["H0430","of our God",80,90],["H0398","ye shall eat",92,104],["H2428","the riches",105,115],["H1471","of the Gentiles",116,131],["H3519","and in their glory",133,151],["H3235","shall ye boast",152,166]]},"61:7":{"text":"For your shame ye shall have double; and for confusion they shall rejoice in their portion: therefore in their land they shall possess the double: everlasting joy shall be unto them.","words":[["H1322","For your shame",0,14],["H4932","ye shall have double",15,35],["H3639","and for confusion",37,54],["H7442","they shall rejoice",55,73],["H2506","in their portion",74,90],["H0776","therefore in their land",92,115],["H3423","they shall possess",116,134],["H4932","the double",135,145],["H5769","everlasting",147,158],["H8057","joy",159,162]]},"61:8":{"text":"For I the LORD love judgment, I hate robbery for burnt offering; and I will direct their work in truth, and I will make an everlasting covenant with them.","words":[["H3068","For I the LORD",0,14],["H0157","love",15,19],["H4941","judgment",20,28],["H8130","I hate",30,36],["H1498","robbery",37,44],["H5930","for burnt offering",45,63],["H5414","and I will direct",65,82],["H6468","their work",83,93],["H0571","in truth",94,102],["H3772","and I will make",104,119],["H5769","an everlasting",120,134],["H1285","covenant",135,143]]},"61:9":{"text":"And their seed shall be known among the Gentiles, and their offspring among the people: all that see them shall acknowledge them, that they are the seed which the LORD hath blessed.","words":[["H2233","And their seed",0,14],["H3045","shall be known",15,29],["H1471","among the Gentiles",30,48],["H6631","and their offspring",50,69],["H8432","among",70,75],["H5971","the people",76,86],["H7200","all that see",88,100],["H5234","them shall acknowledge",101,123],["H2233","them, that they are the seed",124,152],["H3068","which the LORD",153,167],["H1288","hath blessed",168,180]]},"61:10":{"text":"I will greatly rejoice in the LORD, my soul shall be joyful in my God; for he hath clothed me with the garments of salvation, he hath covered me with the robe of righteousness, as a bridegroom decketh himself with ornaments, and as a bride adorneth herself with her jewels.","words":[["H7797","I will greatly",0,14],["H7797","rejoice",15,22],["H3068","in the LORD",23,34],["H5315","my soul",36,43],["H1523","shall be joyful",44,59],["H0430","in my God",60,69],["H3847","for he hath clothed",71,90],["H0899","me with the garments",91,111],["H3468","of salvation",112,124],["H3271","he hath covered",126,141],["H4598","me with the robe",142,158],["H6666","of righteousness",159,175],["H2860","as a bridegroom",177,192],["H3547","decketh",193,200],["H6287","himself with ornaments",201,223],["H3618","and as a bride",225,239],["H5710","adorneth",240,248],["H3627","herself with her jewels",249,272]]},"61:11":{"text":"For as the earth bringeth forth her bud, and as the garden causeth the things that are sown in it to spring forth; so the Lord GOD will cause righteousness and praise to spring forth before all the nations.","words":[["H0776","For as the earth",0,16],["H3318","bringeth forth",17,31],["H6780","her bud",32,39],["H1593","and as the garden",41,58],["H2221","causeth the things that are sown",59,91],["H6779","in it to spring forth",92,113],["H0136","so the Lord",115,126],["H3069","GOD",127,130],["H6666","will cause righteousness",131,155],["H8416","and praise",156,166],["H6779","to spring forth",167,182],["H1471","before all the nations",183,205]]},"62:1":{"text":"For Zion's sake will I not hold my peace, and for Jerusalem's sake I will not rest, until the righteousness thereof go forth as brightness, and the salvation thereof as a lamp that burneth.","words":[["H6726","For Zion's",0,10],["H2814","sake will I not hold my peace",11,40],["H3389","and for Jerusalem's",42,61],["H8252","sake I will not rest",62,82],["H6664","until the righteousness",84,107],["H3318","thereof go forth",108,124],["H5051","as brightness",125,138],["H3444","and the salvation",140,157],["H3940","thereof as a lamp",158,175],["H1197","that burneth",176,188]]},"62:2":{"text":"And the Gentiles shall see thy righteousness, and all kings thy glory: and thou shalt be called by a new name, which the mouth of the LORD shall name.","words":[["H1471","And the Gentiles",0,16],["H7200","shall see",17,26],["H6664","thy righteousness",27,44],["H4428","and all kings",46,59],["H3519","thy glory",60,69],["H7121","and thou shalt be called",71,95],["H2319","by a new",96,104],["H5344","name",105,109],["H6310","which the mouth",111,126],["H3068","of the LORD",127,138],["H8034","shall name",139,149]]},"62:3":{"text":"Thou shalt also be a crown of glory in the hand of the LORD, and a royal diadem in the hand of thy God.","words":[["H5850","Thou shalt also be a crown",0,26],["H8597","of glory",27,35],["H3027","in the hand",36,47],["H3068","of the LORD",48,59],["H4410","and a royal",61,72],["H6797","diadem",73,79],["H6797","diadem",73,79],["H3709","in the hand",80,91],["H0430","of thy God",92,102]]},"62:4":{"text":"Thou shalt no more be termed Forsaken; neither shall thy land any more be termed Desolate: but thou shalt be called Hephzibah, and thy land Beulah: for the LORD delighteth in thee, and thy land shall be married.","words":[["H0559","Thou shalt no more be termed",0,28],["H5800","Forsaken",29,37],["H0776","neither shall thy land",39,61],["H0559","any more be termed",62,80],["H8077","Desolate",81,89],["H7121","but thou shalt be called",91,115],["H2657","Hephzibah",116,125],["H0776","and thy land",127,139],["H1166","Beulah",140,146],["H3068","for the LORD",148,160],["H2654","delighteth",161,171],["H0776","in thee, and thy land",172,193],["H1166","shall be married",194,210]]},"62:5":{"text":"For as a young man marrieth a virgin, so shall thy sons marry thee: and as the bridegroom rejoiceth over the bride, so shall thy God rejoice over thee.","words":[["H0970","For as a young man",0,18],["H1166","marrieth",19,27],["H1330","a virgin",28,36],["H1121","so shall thy sons",38,55],["H1166","marry",56,61],["H2860","thee: and as the bridegroom",62,89],["H4885","rejoiceth",90,99],["H3618","over the bride",100,114],["H0430","so shall thy God",116,132],["H7797","rejoice",133,140]]},"62:6":{"text":"I have set watchmen upon thy walls, O Jerusalem, which shall never hold their peace day nor night: ye that make mention of the LORD, keep not silence,","words":[["H6485","I have set",0,10],["H8104","watchmen",11,19],["H2346","upon thy walls",20,34],["H3389","O Jerusalem",36,47],["H8548","which shall never",49,66],["H2814","hold their peace",67,83],["H3117","day",84,87],["H3915","nor night",88,97],["H2142","ye that make mention",99,119],["H3068","of the LORD",120,131],["H1824","keep not silence",133,149]]},"62:7":{"text":"And give him no rest, till he establish, and till he make Jerusalem a praise in the earth.","words":[["H5414","And give",0,8],["H1824","him no rest",9,20],["H3559","till he establish",22,39],["H7760","and till he make",41,57],["H3389","Jerusalem",58,67],["H8416","a praise",68,76],["H0776","in the earth",77,89]]},"62:8":{"text":"The LORD hath sworn by his right hand, and by the arm of his strength, Surely I will no more give thy corn to be meat for thine enemies; and the sons of the stranger shall not drink thy wine, for the which thou hast laboured:","words":[["H3068","The LORD",0,8],["H7650","hath sworn",9,19],["H3225","by his right hand",20,37],["H2220","and by the arm",39,53],["H5797","of his strength",54,69],["H0518","Surely I will",71,84],["H5414","no more give",85,97],["H1715","thy corn",98,106],["H3978","to be meat",107,117],["H0341","for thine enemies",118,135],["H1121","and the sons",137,149],["H5236","of the stranger",150,165],["H8354","shall not drink",166,181],["H8492","thy wine",182,190],["H3021","for the which thou hast laboured",192,224]]},"62:9":{"text":"But they that have gathered it shall eat it, and praise the LORD; and they that have brought it together shall drink it in the courts of my holiness.","words":[["H0622","But they that have gathered",0,27],["H0398","it shall eat",28,40],["H1984","it, and praise",41,55],["H3068","the LORD",56,64],["H6908","and they that have brought it together",66,104],["H8354","shall drink",105,116],["H2691","it in the courts",117,133],["H6944","of my holiness",134,148]]},"62:10":{"text":"Go through, go through the gates; prepare ye the way of the people; cast up, cast up the highway; gather out the stones; lift up a standard for the people.","words":[["H5674","Go through",0,10],["H5674","go through",12,22],["H8179","the gates",23,32],["H6437","prepare",34,41],["H1870","ye the way",42,52],["H5971","of the people",53,66],["H5549","cast up",68,75],["H5549","cast up",77,84],["H4546","the highway",85,96],["H5619","gather out",98,108],["H0068","the stones",109,119],["H7311","lift up",121,128],["H5251","a standard",129,139],["H5971","for the people",140,154]]},"62:11":{"text":"Behold, the LORD hath proclaimed unto the end of the world, Say ye to the daughter of Zion, Behold, thy salvation cometh; behold, his reward is with him, and his work before him.","words":[["H3068","Behold, the LORD",0,16],["H8085","hath proclaimed",17,32],["H7097","unto the end",33,45],["H0776","of the world",46,58],["H0559","Say",60,63],["H1323","ye to the daughter",64,82],["H6726","of Zion",83,90],["H3468","Behold, thy salvation",92,113],["H0935","cometh",114,120],["H7939","behold, his reward",122,140],["H6468","is with him, and his work",141,166],["H6440","before",167,173]]},"62:12":{"text":"And they shall call them, The holy people, The redeemed of the LORD: and thou shalt be called, Sought out, A city not forsaken.","words":[["H7121","And they shall call",0,19],["H6944","them, The holy",20,34],["H5971","people",35,41],["H1350","The redeemed",43,55],["H3068","of the LORD",56,67],["H7121","and thou shalt be called",69,93],["H1875","Sought out",95,105],["H5892","A city",107,113],["H5800","not forsaken",114,126]]},"63:1":{"text":"Who is this that cometh from Edom, with dyed garments from Bozrah? this that is glorious in his apparel, travelling in the greatness of his strength? I that speak in righteousness, mighty to save.","words":[["H0935","Who is this that cometh",0,23],["H0123","from Edom",24,33],["H2556","with dyed",35,44],["H0899","garments",45,53],["H1224","from Bozrah",54,65],["H1921","this that is glorious",67,88],["H3830","in his apparel",89,103],["H6808","travelling",105,115],["H7230","in the greatness",116,132],["H3581","of his strength",133,148],["H1696","I that speak",150,162],["H6666","in righteousness",163,179],["H7227","mighty",181,187],["H3467","to save",188,195]]},"63:2":{"text":"Wherefore art thou red in thine apparel, and thy garments like him that treadeth in the winefat?","words":[["H0122","Wherefore art thou red",0,22],["H3830","in thine apparel",23,39],["H0899","and thy garments",41,57],["H1869","like him that treadeth",58,80],["H1660","in the winefat",81,95]]},"63:3":{"text":"I have trodden the winepress alone; and of the people there was none with me: for I will tread them in mine anger, and trample them in my fury; and their blood shall be sprinkled upon my garments, and I will stain all my raiment.","words":[["H1869","I have trodden",0,14],["H6333","the winepress",15,28],["H5971","alone; and of the people",29,53],["H0376","there was none",54,68],["H1869","with me: for I will tread",69,94],["H0639","them in mine anger",95,113],["H7429","and trample",115,126],["H2534","them in my fury",127,142],["H5332","and their blood",144,159],["H5137","shall be sprinkled",160,178],["H0899","upon my garments",179,195],["H1351","and I will stain",197,213],["H4403","all my raiment",214,228]]},"63:4":{"text":"For the day of vengeance is in mine heart, and the year of my redeemed is come.","words":[["H3117","For the day",0,11],["H5359","of vengeance",12,24],["H3820","is in mine heart",25,41],["H8141","and the year",43,55],["H1350","of my redeemed",56,70],["H0935","is come",71,78]]},"63:5":{"text":"And I looked, and there was none to help; and I wondered that there was none to uphold: therefore mine own arm brought salvation unto me; and my fury, it upheld me.","words":[["H5027","And I looked",0,12],["H5826","and there was none to help",14,40],["H8074","and I wondered",42,56],["H5564","that there was none to uphold",57,86],["H2220","therefore mine own arm",88,110],["H3467","brought salvation",111,128],["H2534","unto me; and my fury",129,149],["H5564","it upheld",151,160]]},"63:6":{"text":"And I will tread down the people in mine anger, and make them drunk in my fury, and I will bring down their strength to the earth.","words":[["H0947","And I will tread down",0,21],["H5971","the people",22,32],["H0639","in mine anger",33,46],["H7937","and make them drunk",48,67],["H2534","in my fury",68,78],["H3381","and I will bring down",80,101],["H5332","their strength",102,116],["H0776","to the earth",117,129]]},"63:7":{"text":"I will mention the lovingkindnesses of the LORD, and the praises of the LORD, according to all that the LORD hath bestowed on us, and the great goodness toward the house of Israel, which he hath bestowed on them according to his mercies, and according to the multitude of his lovingkindnesses.","words":[["H2142","I will mention",0,14],["H2617","the lovingkindnesses",15,35],["H3068","of the LORD",36,47],["H8416","and the praises",49,64],["H3068","of the LORD",65,76],["H3068","according to all that the LORD",78,108],["H1580","hath bestowed",109,122],["H7227","on us, and the great",123,143],["H2898","goodness",144,152],["H1004","toward the house",153,169],["H3478","of Israel",170,179],["H1580","which he hath bestowed",181,203],["H7356","on them according to his mercies",204,236],["H7230","and according to the multitude",238,268],["H2617","of his lovingkindnesses",269,292]]},"63:8":{"text":"For he said, Surely they are my people, children that will not lie: so he was their Saviour.","words":[["H0559","For he said",0,11],["H5971","Surely they are my people",13,38],["H1121","children",40,48],["H8266","that will not lie",49,66],["H3467","so he was their Saviour",68,91]]},"63:9":{"text":"In all their affliction he was afflicted, and the angel of his presence saved them: in his love and in his pity he redeemed them; and he bare them, and carried them all the days of old.","words":[["H6869","In all their affliction",0,23],["H6862","he was afflicted",24,40],["H4397","and the angel",42,55],["H6440","of his presence",56,71],["H3467","saved",72,77],["H0160","them: in his love",78,95],["H2551","and in his pity",96,111],["H1350","he redeemed",112,123],["H5190","them; and he bare",124,141],["H5375","them, and carried",142,159],["H3117","them all the days",160,177],["H5769","of old",178,184]]},"63:10":{"text":"But they rebelled, and vexed his holy Spirit: therefore he was turned to be their enemy, and he fought against them.","words":[["H4784","But they rebelled",0,17],["H6087","and vexed",19,28],["H6944","his holy",29,37],["H7307","Spirit",38,44],["H2015","therefore he was turned",46,69],["H0341","to be their enemy",70,87],["H3898","and he fought",89,102]]},"63:11":{"text":"Then he remembered the days of old, Moses, and his people, saying, Where is he that brought them up out of the sea with the shepherd of his flock? where is he that put his holy Spirit within him?","words":[["H2142","Then he remembered",0,18],["H3117","the days",19,27],["H5769","of old",28,34],["H4872","Moses",36,41],["H5971","and his people",43,57],["H5927","saying, Where is he that brought them up",59,99],["H3220","out of the sea",100,114],["H7462","with the shepherd",115,132],["H6629","of his flock",133,145],["H7760","where is he that put",147,167],["H6944","his holy",168,176],["H7307","Spirit",177,183],["H7130","within",184,190]]},"63:12":{"text":"That led them by the right hand of Moses with his glorious arm, dividing the water before them, to make himself an everlasting name?","words":[["H3212","That led",0,8],["H3225","them by the right hand",9,31],["H4872","of Moses",32,40],["H8597","with his glorious",41,58],["H2220","arm",59,62],["H1234","dividing",64,72],["H4325","the water",73,82],["H6440","before",83,89],["H6213","them, to make",90,103],["H5769","himself an everlasting",104,126],["H8034","name",127,131]]},"63:13":{"text":"That led them through the deep, as an horse in the wilderness, that they should not stumble?","words":[["H3212","That led",0,8],["H8415","them through the deep",9,30],["H5483","as an horse",32,43],["H4057","in the wilderness",44,61],["H3782","that they should not stumble",63,91]]},"63:14":{"text":"As a beast goeth down into the valley, the Spirit of the LORD caused him to rest: so didst thou lead thy people, to make thyself a glorious name.","words":[["H0929","As a beast",0,10],["H3381","goeth down",11,21],["H1237","into the valley",22,37],["H7307","the Spirit",39,49],["H3068","of the LORD",50,61],["H5117","caused him to rest",62,80],["H5090","so didst thou lead",82,100],["H5971","thy people",101,111],["H6213","to make",113,120],["H8597","thyself a glorious",121,139],["H8034","name",140,144]]},"63:15":{"text":"Look down from heaven, and behold from the habitation of thy holiness and of thy glory: where is thy zeal and thy strength, the sounding of thy bowels and of thy mercies toward me? are they restrained?","words":[["H5027","Look down",0,9],["H8064","from heaven",10,21],["H7200","and behold",23,33],["H2073","from the habitation",34,53],["H6944","of thy holiness",54,69],["H8597","and of thy glory",70,86],["H7068","where is thy zeal",88,105],["H1369","and thy strength",106,122],["H1995","the sounding",124,136],["H4578","of thy bowels",137,150],["H7356","and of thy mercies",151,169],["H0662","toward me? are they restrained",170,200]]},"63:16":{"text":"Doubtless thou art our father, though Abraham be ignorant of us, and Israel acknowledge us not: thou, O LORD, art our father, our redeemer; thy name is from everlasting.","words":[["H3588","Doubtless",0,9],["H0001","thou art our father",10,29],["H0085","though Abraham",31,45],["H3808","be ignorant",46,57],["H3045","be ignorant",46,57],["H3478","of us, and Israel",58,75],["H5234","acknowledge",76,87],["H3068","us not: thou, O LORD",88,108],["H0001","art our father",110,124],["H1350","our redeemer",126,138],["H8034","thy name",140,148],["H5769","is from everlasting",149,168]]},"63:17":{"text":"O LORD, why hast thou made us to err from thy ways, and hardened our heart from thy fear? Return for thy servants' sake, the tribes of thine inheritance.","words":[["H3068","O LORD",0,6],["H8582","why hast thou made us to err",8,36],["H1870","from thy ways",37,50],["H7188","and hardened",52,64],["H3820","our heart",65,74],["H3374","from thy fear",75,88],["H7725","Return",90,96],["H5650","for thy servants'",97,114],["H7626","sake, the tribes",115,131],["H5159","of thine inheritance",132,152]]},"63:18":{"text":"The people of thy holiness have possessed it but a little while: our adversaries have trodden down thy sanctuary.","words":[["H5971","The people",0,10],["H6944","of thy holiness",11,26],["H3423","have possessed",27,41],["H4705","it but a little while",42,63],["H6862","our adversaries",65,80],["H0947","have trodden down",81,98],["H4720","thy sanctuary",99,112]]},"63:19":{"text":"We are thine: thou never barest rule over them; they were not called by thy name.","words":[["H5769","We are thine: thou never",0,24],["H4910","barest rule",25,36],["H7121","over them; they were not called",37,68],["H8034","by thy name",69,80]]},"64:1":{"text":"Oh that thou wouldest rend the heavens, that thou wouldest come down, that the mountains might flow down at thy presence,","words":[["H3863","Oh",0,2],["H7167","that thou wouldest rend",3,26],["H8064","the heavens",27,38],["H3381","that thou wouldest come down",40,68],["H2022","that the mountains",70,88],["H2151","might flow down",89,104],["H6440","at thy presence",105,120]]},"64:2":{"text":"As when the melting fire burneth, the fire causeth the waters to boil, to make thy name known to thine adversaries, that the nations may tremble at thy presence!","words":[["H2003","As when the melting",0,19],["H0784","fire",20,24],["H6919","burneth",25,32],["H0784","the fire",34,42],["H4325","causeth the waters",43,61],["H1158","to boil",62,69],["H8034","to make thy name",71,87],["H3045","known",88,93],["H6862","to thine adversaries",94,114],["H1471","that the nations",116,132],["H7264","may tremble",133,144],["H6440","at thy presence",145,160]]},"64:3":{"text":"When thou didst terrible things which we looked not for, thou camest down, the mountains flowed down at thy presence.","words":[["H6213","When thou didst",0,15],["H3372","terrible things",16,31],["H6960","which we looked",32,47],["H3381","not for, thou camest down",48,73],["H2022","the mountains",75,88],["H2151","flowed down",89,100],["H6440","at thy presence",101,116]]},"64:4":{"text":"For since the beginning of the world men have not heard, nor perceived by the ear, neither hath the eye seen, O God, beside thee, what he hath prepared for him that waiteth for him.","words":[["H5769","For since the beginning of the world",0,36],["H8085","men have not heard",37,55],["H0238","nor perceived by the ear",57,81],["H5869","neither hath the eye",83,103],["H7200","seen",104,108],["H0430","O God",110,115],["H2108","beside",117,123],["H6213","thee, what he hath prepared",124,151],["H2442","for him that waiteth",152,172]]},"64:5":{"text":"Thou meetest him that rejoiceth and worketh righteousness, those that remember thee in thy ways: behold, thou art wroth; for we have sinned: in those is continuance, and we shall be saved.","words":[["H6293","Thou meetest",0,12],["H7797","him that rejoiceth",13,31],["H6213","and worketh",32,43],["H6664","righteousness",44,57],["H2142","those that remember",59,78],["H1870","thee in thy ways",79,95],["H7107","behold, thou art wroth",97,119],["H2398","for we have sinned",121,139],["H5769","in those is continuance",141,164],["H3467","and we shall be saved",166,187]]},"64:6":{"text":"But we are all as an unclean thing, and all our righteousnesses are as filthy rags; and we all do fade as a leaf; and our iniquities, like the wind, have taken us away.","words":[["H2931","But we are all as an unclean",0,28],["H6666","thing, and all our righteousnesses",29,63],["H5708","are as filthy",64,77],["H0899","rags",78,82],["H5034","and we all do fade",84,102],["H1101","and we all do fade",84,102],["H5929","as a leaf",103,112],["H5771","and our iniquities",114,132],["H7307","like the wind",134,147],["H5375","have taken us away",149,167]]},"64:7":{"text":"And there is none that calleth upon thy name, that stirreth up himself to take hold of thee: for thou hast hid thy face from us, and hast consumed us, because of our iniquities.","words":[["H7121","And there is none that calleth",0,30],["H8034","upon thy name",31,44],["H5782","that stirreth up",46,62],["H2388","himself to take hold",63,83],["H5641","of thee: for thou hast hid",84,110],["H6440","thy face",111,119],["H4127","from us, and hast consumed",120,146],["H3027","us, because",147,158],["H5771","of our iniquities",159,176]]},"64:8":{"text":"But now, O LORD, thou art our father; we are the clay, and thou our potter; and we all are the work of thy hand.","words":[["H3068","But now, O LORD",0,15],["H0001","thou art our father",17,36],["H2563","we are the clay",38,53],["H3335","and thou our potter",55,74],["H4639","and we all are the work",76,99],["H3027","of thy hand",100,111]]},"64:9":{"text":"Be not wroth very sore, O LORD, neither remember iniquity for ever: behold, see, we beseech thee, we are all thy people.","words":[["H7107","Be not wroth",0,12],["H3966","very sore",13,22],["H3068","O LORD",24,30],["H2142","neither remember",32,48],["H5771","iniquity",49,57],["H5703","for ever",58,66],["H5027","behold, see",68,79],["H5971","we beseech thee, we are all thy people",81,119]]},"64:10":{"text":"Thy holy cities are a wilderness, Zion is a wilderness, Jerusalem a desolation.","words":[["H6944","Thy holy",0,8],["H5892","cities",9,15],["H4057","are a wilderness",16,32],["H6726","Zion",34,38],["H4057","is a wilderness",39,54],["H3389","Jerusalem",56,65],["H8077","a desolation",66,78]]},"64:11":{"text":"Our holy and our beautiful house, where our fathers praised thee, is burned up with fire: and all our pleasant things are laid waste.","words":[["H6944","Our holy",0,8],["H8597","and our beautiful",9,26],["H1004","house",27,32],["H0001","where our fathers",34,51],["H1984","praised",52,59],["H8316","thee, is burned up",60,78],["H0784","with fire",79,88],["H4261","and all our pleasant things",90,117],["H2723","are laid waste",118,132]]},"64:12":{"text":"Wilt thou refrain thyself for these things, O LORD? wilt thou hold thy peace, and afflict us very sore?","words":[["H0662","Wilt thou refrain",0,17],["H3068","thyself for these things, O LORD",18,50],["H2814","wilt thou hold thy peace",52,76],["H6031","and afflict",78,89],["H3966","us very sore",90,102]]},"65:1":{"text":"I am sought of them that asked not for me; I am found of them that sought me not: I said, Behold me, behold me, unto a nation that was not called by my name.","words":[["H1875","I am sought",0,11],["H7592","of them that asked",12,30],["H3808","not",31,34],["H4672","for me; I am found",35,53],["H1245","of them that sought",54,73],["H3808","me not",74,80],["H0559","I said",82,88],["H1471","Behold me, behold me, unto a nation",90,125],["H7121","that was not called",126,145],["H8034","by my name",146,156]]},"65:2":{"text":"I have spread out my hands all the day unto a rebellious people, which walketh in a way that was not good, after their own thoughts;","words":[["H6566","I have spread out",0,17],["H3027","my hands",18,26],["H3117","all the day",27,38],["H5637","unto a rebellious",39,56],["H5971","people",57,63],["H1980","which walketh",65,78],["H1870","in a way",79,87],["H2896","that was not good",88,105],["H0310","after",107,112],["H4284","their own thoughts",113,131]]},"65:3":{"text":"A people that provoketh me to anger continually to my face; that sacrificeth in gardens, and burneth incense upon altars of brick;","words":[["H5971","A people",0,8],["H3707","that provoketh me to anger",9,35],["H8548","continually",36,47],["H6440","to my face",48,58],["H2076","that sacrificeth",60,76],["H1593","in gardens",77,87],["H6999","and burneth incense",89,108],["H3843","upon altars of brick",109,129]]},"65:4":{"text":"Which remain among the graves, and lodge in the monuments, which eat swine's flesh, and broth of abominable things is in their vessels;","words":[["H3427","Which remain",0,12],["H6913","among the graves",13,29],["H3885","and lodge",31,40],["H5341","in the monuments",41,57],["H0398","which eat",59,68],["H2386","swine's",69,76],["H1320","flesh",77,82],["H4839","and broth",84,93],["H6564","and broth",84,93],["H6292","of abominable",94,107],["H3627","things is in their vessels",108,134]]},"65:5":{"text":"Which say, Stand by thyself, come not near to me; for I am holier than thou. These are a smoke in my nose, a fire that burneth all the day.","words":[["H0559","Which say",0,9],["H7126","Stand",11,16],["H5066","by thyself, come not near",17,42],["H6942","to me; for I am holier",43,65],["H6227","than thou. These are a smoke",66,94],["H0639","in my nose",95,105],["H0784","a fire",107,113],["H3344","that burneth",114,126],["H3117","all the day",127,138]]},"65:6":{"text":"Behold, it is written before me: I will not keep silence, but will recompense, even recompense into their bosom,","words":[["H3789","Behold, it is written",0,21],["H6440","before",22,28],["H2814","me: I will not keep silence",29,56],["H7999","but will recompense",58,77],["H7999","even recompense",79,94],["H2436","into their bosom",95,111]]},"65:7":{"text":"Your iniquities, and the iniquities of your fathers together, saith the LORD, which have burned incense upon the mountains, and blasphemed me upon the hills: therefore will I measure their former work into their bosom.","words":[["H5771","Your iniquities",0,15],["H5771","and the iniquities",17,35],["H0001","of your fathers",36,51],["H3162","together",52,60],["H0559","saith",62,67],["H3068","the LORD",68,76],["H6999","which have burned incense",78,103],["H2022","upon the mountains",104,122],["H2778","and blasphemed",124,138],["H1389","me upon the hills",139,156],["H4058","therefore will I measure",158,182],["H7223","their former",183,195],["H6468","work",196,200],["H2436","into their bosom",201,217]]},"65:8":{"text":"Thus saith the LORD, As the new wine is found in the cluster, and one saith, Destroy it not; for a blessing is in it: so will I do for my servants' sakes, that I may not destroy them all.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H8492","As the new wine",21,36],["H4672","is found",37,45],["H0811","in the cluster",46,60],["H0559","and one saith",62,75],["H7843","Destroy",77,84],["H1293","it not; for a blessing",85,107],["H6213","is in it: so will I do",108,130],["H5650","for my servants'",131,147],["H7843","sakes, that I may not destroy",148,177]]},"65:9":{"text":"And I will bring forth a seed out of Jacob, and out of Judah an inheritor of my mountains: and mine elect shall inherit it, and my servants shall dwell there.","words":[["H3318","And I will bring forth",0,22],["H2233","a seed",23,29],["H3290","out of Jacob",30,42],["H3063","and out of Judah",44,60],["H3423","an inheritor",61,73],["H2022","of my mountains",74,89],["H0972","and mine elect",91,105],["H3423","shall inherit",106,119],["H5650","it, and my servants",120,139],["H7931","shall dwell",140,151]]},"65:10":{"text":"And Sharon shall be a fold of flocks, and the valley of Achor a place for the herds to lie down in, for my people that have sought me.","words":[["H8289","And Sharon",0,10],["H5116","shall be a fold",11,26],["H6629","of flocks",27,36],["H6010","and the valley",38,52],["H5911","of Achor",53,61],["H1241","a place for the herds",62,83],["H7258","to lie down in",84,98],["H5971","for my people",100,113],["H1875","that have sought",114,130]]},"65:11":{"text":"But ye are they that forsake the LORD, that forget my holy mountain, that prepare a table for that troop, and that furnish the drink offering unto that number.","words":[["H5800","But ye are they that forsake",0,28],["H3068","the LORD",29,37],["H7913","that forget",39,50],["H6944","my holy",51,58],["H2022","mountain",59,67],["H6186","that prepare",69,81],["H7979","a table",82,89],["H1409","for that troop",90,104],["H1408","for that troop",90,104],["H4390","and that furnish",106,122],["H4469","the drink offering",123,141],["H4507","unto that number",142,158]]},"65:12":{"text":"Therefore will I number you to the sword, and ye shall all bow down to the slaughter: because when I called, ye did not answer; when I spake, ye did not hear; but did evil before mine eyes, and did choose that wherein I delighted not.","words":[["H4487","Therefore will I number",0,23],["H2719","you to the sword",24,40],["H3766","and ye shall all bow down",42,67],["H2874","to the slaughter",68,84],["H7121","because when I called",86,107],["H6030","ye did not answer",109,126],["H1696","when I spake",128,140],["H8085","ye did not hear",142,157],["H6213","but did",159,166],["H7451","evil",167,171],["H5869","before mine eyes",172,188],["H0977","and did choose",190,204],["H2654","that wherein I delighted",205,229]]},"65:13":{"text":"Therefore thus saith the Lord GOD, Behold, my servants shall eat, but ye shall be hungry: behold, my servants shall drink, but ye shall be thirsty: behold, my servants shall rejoice, but ye shall be ashamed:","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5650","Behold, my servants",35,54],["H0398","shall eat",55,64],["H7456","but ye shall be hungry",66,88],["H5650","behold, my servants",90,109],["H8354","shall drink",110,121],["H6770","but ye shall be thirsty",123,146],["H5650","behold, my servants",148,167],["H8055","shall rejoice",168,181],["H0954","but ye shall be ashamed",183,206]]},"65:14":{"text":"Behold, my servants shall sing for joy of heart, but ye shall cry for sorrow of heart, and shall howl for vexation of spirit.","words":[["H5650","Behold, my servants",0,19],["H7442","shall sing",20,30],["H2898","for joy",31,38],["H3820","of heart",39,47],["H6817","but ye shall cry",49,65],["H3511","for sorrow",66,76],["H3820","of heart",77,85],["H3213","and shall howl",87,101],["H7667","for vexation",102,114],["H7307","of spirit",115,124]]},"65:15":{"text":"And ye shall leave your name for a curse unto my chosen: for the Lord GOD shall slay thee, and call his servants by another name:","words":[["H3240","And ye shall leave",0,18],["H8034","your name",19,28],["H7621","for a curse",29,40],["H0972","unto my chosen",41,55],["H0136","for the Lord",57,69],["H3069","GOD",70,73],["H4191","shall slay",74,84],["H7121","thee, and call",85,99],["H5650","his servants",100,112],["H0312","by another",113,123],["H8034","name",124,128]]},"65:16":{"text":"That he who blesseth himself in the earth shall bless himself in the God of truth; and he that sweareth in the earth shall swear by the God of truth; because the former troubles are forgotten, and because they are hid from mine eyes.","words":[["H1288","That he who blesseth",0,20],["H0776","himself in the earth",21,41],["H1288","shall bless",42,53],["H0430","himself in the God",54,72],["H0543","of truth",73,81],["H7650","and he that sweareth",83,103],["H0776","in the earth",104,116],["H7650","shall swear",117,128],["H0430","by the God",129,139],["H0543","of truth",140,148],["H7223","because the former",150,168],["H6869","troubles",169,177],["H7911","are forgotten",178,191],["H5641","and because they are hid",193,217],["H5869","from mine eyes",218,232]]},"65:17":{"text":"For, behold, I create new heavens and a new earth: and the former shall not be remembered, nor come into mind.","words":[["H1254","For, behold, I create",0,21],["H2319","new",22,25],["H8064","heavens",26,33],["H2319","and a new",34,43],["H0776","earth",44,49],["H7223","and the former",51,65],["H2142","shall not be remembered",66,89],["H5927","nor come",91,99],["H3820","into mind",100,109]]},"65:18":{"text":"But be ye glad and rejoice for ever in that which I create: for, behold, I create Jerusalem a rejoicing, and her people a joy.","words":[["H7797","But be ye glad",0,14],["H1523","and rejoice",15,26],["H5703","for ever",27,35],["H1254","in that which I create",36,58],["H1254","for, behold, I create",60,81],["H3389","Jerusalem",82,91],["H1525","a rejoicing",92,103],["H5971","and her people",105,119],["H4885","a joy",120,125]]},"65:19":{"text":"And I will rejoice in Jerusalem, and joy in my people: and the voice of weeping shall be no more heard in her, nor the voice of crying.","words":[["H1523","And I will rejoice",0,18],["H3389","in Jerusalem",19,31],["H7797","and joy",33,40],["H5971","in my people",41,53],["H6963","and the voice",55,68],["H1065","of weeping",69,79],["H8085","shall be no more heard",80,102],["H6963","in her, nor the voice",103,124],["H2201","of crying",125,134]]},"65:20":{"text":"There shall be no more thence an infant of days, nor an old man that hath not filled his days: for the child shall die an hundred years old; but the sinner being an hundred years old shall be accursed.","words":[["H5764","There shall be no more thence an infant",0,39],["H3117","of days",40,47],["H2205","nor an old man",49,63],["H4390","that hath not filled",64,84],["H3117","his days",85,93],["H5288","for the child",95,108],["H4191","shall die",109,118],["H3967","an hundred",119,129],["H8141","years",130,135],["H1121","old",136,139],["H2398","but the sinner",141,155],["H3967","being an hundred",156,172],["H8141","years",173,178],["H1121","old",179,182],["H7043","shall be accursed",183,200]]},"65:21":{"text":"And they shall build houses, and inhabit them; and they shall plant vineyards, and eat the fruit of them.","words":[["H1129","And they shall build",0,20],["H1004","houses",21,27],["H3427","and inhabit",29,40],["H5193","them; and they shall plant",41,67],["H3754","vineyards",68,77],["H0398","and eat",79,86],["H6529","the fruit",87,96]]},"65:22":{"text":"They shall not build, and another inhabit; they shall not plant, and another eat: for as the days of a tree are the days of my people, and mine elect shall long enjoy the work of their hands.","words":[["H1129","They shall not build",0,20],["H0312","and another",22,33],["H3427","inhabit",34,41],["H5193","they shall not plant",43,63],["H0312","and another",65,76],["H0398","eat",77,80],["H3117","for as the days",82,97],["H6086","of a tree",98,107],["H3117","are the days",108,120],["H5971","of my people",121,133],["H0972","and mine elect",135,149],["H1086","shall long enjoy",150,166],["H4639","the work",167,175],["H3027","of their hands",176,190]]},"65:23":{"text":"They shall not labour in vain, nor bring forth for trouble; for they are the seed of the blessed of the LORD, and their offspring with them.","words":[["H3021","They shall not labour",0,21],["H7385","in vain",22,29],["H3205","nor bring forth",31,46],["H0928","for trouble",47,58],["H2233","for they are the seed",60,81],["H1288","of the blessed",82,96],["H3068","of the LORD",97,108],["H6631","and their offspring",110,129]]},"65:24":{"text":"And it shall come to pass, that before they call, I will answer; and while they are yet speaking, I will hear.","words":[["H7121","And it shall come to pass, that before they call",0,48],["H6030","I will answer",50,63],["H1696","and while they are yet speaking",65,96],["H8085","I will hear",98,109]]},"65:25":{"text":"The wolf and the lamb shall feed together, and the lion shall eat straw like the bullock: and dust shall be the serpent's meat. They shall not hurt nor destroy in all my holy mountain, saith the LORD.","words":[["H2061","The wolf",0,8],["H2924","and the lamb",9,21],["H7462","shall feed",22,32],["H0259","together",33,41],["H0738","and the lion",43,55],["H0398","shall eat",56,65],["H8401","straw",66,71],["H1241","like the bullock",72,88],["H6083","and dust",90,98],["H5175","shall be the serpent's",99,121],["H3899","meat",122,126],["H7489","They shall not hurt",128,147],["H7843","nor destroy",148,159],["H6944","in all my holy",160,174],["H2022","mountain",175,183],["H0559","saith",185,190],["H3068","the LORD",191,199]]},"66:1":{"text":"Thus saith the LORD, The heaven is my throne, and the earth is my footstool: where is the house that ye build unto me? and where is the place of my rest?","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H8064","The heaven",21,31],["H3678","is my throne",32,44],["H0776","and the earth",46,59],["H7272","is my footstool",60,75],["H1916","is my footstool",60,75],["H1004","where is the house",77,95],["H1129","that ye build",96,109],["H4725","unto me? and where is the place",110,141],["H4496","of my rest",142,152]]},"66:2":{"text":"For all those things hath mine hand made, and all those things have been, saith the LORD: but to this man will I look, even to him that is poor and of a contrite spirit, and trembleth at my word.","words":[["H3027","For all those things hath mine hand",0,35],["H6213","made",36,40],["H5002","and all those things have been, saith",42,79],["H3068","the LORD",80,88],["H5027","but to this man will I look",90,117],["H6041","even to him that is poor",119,143],["H5223","and of a contrite",144,161],["H7307","spirit",162,168],["H2730","and trembleth",170,183],["H1697","at my word",184,194]]},"66:3":{"text":"He that killeth an ox is as if he slew a man; he that sacrificeth a lamb, as if he cut off a dog's neck; he that offereth an oblation, as if he offered swine's blood; he that burneth incense, as if he blessed an idol. Yea, they have chosen their own ways, and their soul delighteth in their abominations.","words":[["H7819","He that killeth",0,15],["H7794","an ox",16,21],["H5221","is as if he slew",22,38],["H0376","a man",39,44],["H2076","he that sacrificeth",46,65],["H7716","a lamb",66,72],["H6202","as if he cut off",74,90],["H3611","a dog's",91,98],["H6202","neck",99,103],["H5927","he that offereth",105,121],["H4503","an oblation",122,133],["H2386","as if he offered swine's",135,159],["H1818","blood",160,165],["H2142","he that burneth",167,182],["H3828","incense",183,190],["H1288","as if he blessed",192,208],["H0205","an idol",209,216],["H0977","Yea, they have chosen",218,239],["H1870","their own ways",240,254],["H5315","and their soul",256,270],["H2654","delighteth",271,281],["H8251","in their abominations",282,303]]},"66:4":{"text":"I also will choose their delusions, and will bring their fears upon them; because when I called, none did answer; when I spake, they did not hear: but they did evil before mine eyes, and chose that in which I delighted not.","words":[["H0977","I also will choose",0,18],["H8586","their delusions",19,34],["H0935","and will bring",36,50],["H4035","their fears",51,62],["H7121","upon them; because when I called",63,95],["H6030","none did answer",97,112],["H1696","when I spake",114,126],["H8085","they did not hear",128,145],["H6213","but they did",147,159],["H7451","evil",160,164],["H5869","before mine eyes",165,181],["H0977","and chose",183,192],["H2654","that in which I delighted",193,218]]},"66:5":{"text":"Hear the word of the LORD, ye that tremble at his word; Your brethren that hated you, that cast you out for my name's sake, said, Let the LORD be glorified: but he shall appear to your joy, and they shall be ashamed.","words":[["H8085","Hear",0,4],["H1697","the word",5,13],["H3068","of the LORD",14,25],["H2730","ye that tremble",27,42],["H1697","at his word",43,54],["H0251","Your brethren",56,69],["H8130","that hated",70,80],["H5077","you, that cast you out",81,103],["H8034","for my name's",104,117],["H0559","sake, said",118,128],["H3068","Let the LORD",130,142],["H3513","be glorified",143,155],["H7200","but he shall appear",157,176],["H8057","to your joy",177,188],["H0954","and they shall be ashamed",190,215]]},"66:6":{"text":"A voice of noise from the city, a voice from the temple, a voice of the LORD that rendereth recompence to his enemies.","words":[["H6963","A voice",0,7],["H7588","of noise",8,16],["H5892","from the city",17,30],["H6963","a voice",32,39],["H1964","from the temple",40,55],["H6963","a voice",57,64],["H3068","of the LORD",65,76],["H7999","that rendereth",77,91],["H1576","recompence",92,102],["H0341","to his enemies",103,117]]},"66:7":{"text":"Before she travailed, she brought forth; before her pain came, she was delivered of a man child.","words":[["H2342","Before she travailed",0,20],["H3205","she brought forth",22,39],["H2256","before her pain",41,56],["H0935","came",57,61],["H4422","she was delivered",63,80],["H2145","of a man child",81,95]]},"66:8":{"text":"Who hath heard such a thing? who hath seen such things? Shall the earth be made to bring forth in one day? or shall a nation be born at once? for as soon as Zion travailed, she brought forth her children.","words":[["H8085","Who hath heard",0,14],["H7200","such a thing? who hath seen",15,42],["H0776","such things? Shall the earth",43,71],["H2342","be made to bring forth",72,94],["H0259","in one",95,101],["H3117","day",102,105],["H1471","or shall a nation",107,124],["H3205","be born",125,132],["H6471","at once",133,140],["H1571","for as soon as",142,156],["H6726","Zion",157,161],["H2342","travailed",162,171],["H3205","she brought forth",173,190],["H1121","her children",191,203]]},"66:9":{"text":"Shall I bring to the birth, and not cause to bring forth? saith the LORD: shall I cause to bring forth, and shut the womb? saith thy God.","words":[["H7665","Shall I bring to the birth",0,26],["H3205","and not cause to bring forth",28,56],["H0559","saith",58,63],["H3068","the LORD",64,72],["H0589","shall I",74,81],["H3205","cause to bring forth",82,102],["H6113","and shut",104,112],["H0559","the womb? saith",113,128],["H0430","thy God",129,136]]},"66:10":{"text":"Rejoice ye with Jerusalem, and be glad with her, all ye that love her: rejoice for joy with her, all ye that mourn for her:","words":[["H8055","Rejoice",0,7],["H3389","ye with Jerusalem",8,25],["H1523","and be glad",27,38],["H0157","with her, all ye that love",39,65],["H7797","her: rejoice",66,78],["H4885","for joy",79,86],["H0056","with her, all ye that mourn",87,114]]},"66:11":{"text":"That ye may suck, and be satisfied with the breasts of her consolations; that ye may milk out, and be delighted with the abundance of her glory.","words":[["H3243","That ye may suck",0,16],["H7646","and be satisfied",18,34],["H7699","with the breasts",35,51],["H8575","of her consolations",52,71],["H4711","that ye may milk out",73,93],["H6026","and be delighted",95,111],["H2123","with the abundance",112,130],["H3519","of her glory",131,143]]},"66:12":{"text":"For thus saith the LORD, Behold, I will extend peace to her like a river, and the glory of the Gentiles like a flowing stream: then shall ye suck, ye shall be borne upon her sides, and be dandled upon her knees.","words":[["H0559","For thus saith",0,14],["H3068","the LORD",15,23],["H5186","Behold, I will extend",25,46],["H7965","peace",47,52],["H5104","to her like a river",53,72],["H3519","and the glory",74,87],["H1471","of the Gentiles",88,103],["H7857","like a flowing",104,118],["H5158","stream",119,125],["H3243","then shall ye suck",127,145],["H5375","ye shall be borne",147,164],["H6654","upon her sides",165,179],["H8173","and be dandled",181,195],["H1290","upon her knees",196,210]]},"66:13":{"text":"As one whom his mother comforteth, so will I comfort you; and ye shall be comforted in Jerusalem.","words":[["H0376","As one",0,6],["H0517","whom his mother",7,22],["H5162","comforteth",23,33],["H5162","so will I comfort",35,52],["H5162","you; and ye shall be comforted",53,83],["H3389","in Jerusalem",84,96]]},"66:14":{"text":"And when ye see this, your heart shall rejoice, and your bones shall flourish like an herb: and the hand of the LORD shall be known toward his servants, and his indignation toward his enemies.","words":[["H7200","And when ye see",0,15],["H3820","this, your heart",16,32],["H7797","shall rejoice",33,46],["H6106","and your bones",48,62],["H6524","shall flourish",63,77],["H1877","like an herb",78,90],["H3027","and the hand",92,104],["H3068","of the LORD",105,116],["H3045","shall be known",117,131],["H5650","toward his servants",132,151],["H2194","and his indignation",153,172],["H0341","toward his enemies",173,191]]},"66:15":{"text":"For, behold, the LORD will come with fire, and with his chariots like a whirlwind, to render his anger with fury, and his rebuke with flames of fire.","words":[["H3068","For, behold, the LORD",0,21],["H0935","will come",22,31],["H0784","with fire",32,41],["H4818","and with his chariots",43,64],["H5492","like a whirlwind",65,81],["H7725","to render",83,92],["H0639","his anger",93,102],["H2534","with fury",103,112],["H1606","and his rebuke",114,128],["H3851","with flames",129,140],["H0784","of fire",141,148]]},"66:16":{"text":"For by fire and by his sword will the LORD plead with all flesh: and the slain of the LORD shall be many.","words":[["H0784","For by fire",0,11],["H2719","and by his sword",12,28],["H3068","will the LORD",29,42],["H8199","plead",43,48],["H1320","with all flesh",49,63],["H2491","and the slain",65,78],["H3068","of the LORD",79,90],["H7231","shall be many",91,104]]},"66:17":{"text":"They that sanctify themselves, and purify themselves in the gardens behind one tree in the midst, eating swine's flesh, and the abomination, and the mouse, shall be consumed together, saith the LORD.","words":[["H6942","They that sanctify",0,18],["H2891","themselves, and purify",19,41],["H1593","themselves in the gardens",42,67],["H0310","behind",68,74],["H0259","one",75,78],["H8432","tree in the midst",79,96],["H0398","eating",98,104],["H2386","swine's",105,112],["H1320","flesh",113,118],["H8263","and the abomination",120,139],["H5909","and the mouse",141,154],["H5486","shall be consumed",156,173],["H3162","together",174,182],["H5002","saith",184,189],["H3068","the LORD",190,198]]},"66:18":{"text":"For I know their works and their thoughts: it shall come, that I will gather all nations and tongues; and they shall come, and see my glory.","words":[["H4639","For I know their works",0,22],["H4284","and their thoughts",23,41],["H0935","it shall come",43,56],["H6908","that I will gather",58,76],["H1471","all nations",77,88],["H3956","and tongues",89,100],["H0935","and they shall come",102,121],["H7200","and see",123,130],["H3519","my glory",131,139]]},"66:19":{"text":"And I will set a sign among them, and I will send those that escape of them unto the nations, to Tarshish, Pul, and Lud, that draw the bow, to Tubal, and Javan, to the isles afar off, that have not heard my fame, neither have seen my glory; and they shall declare my glory among the Gentiles.","words":[["H7760","And I will set",0,14],["H0226","a sign",15,21],["H7971","among them, and I will send",22,49],["H6412","those that escape",50,67],["H1471","of them unto the nations",68,92],["H8659","to Tarshish",94,105],["H6322","Pul",107,110],["H3865","and Lud",112,119],["H4900","that draw",121,130],["H7198","the bow",131,138],["H8422","to Tubal",140,148],["H3120","and Javan",150,159],["H0339","to the isles",161,173],["H7350","afar off",174,182],["H8085","that have not heard",184,203],["H8088","my fame",204,211],["H7200","neither have seen",213,230],["H3519","my glory",231,239],["H5046","and they shall declare",241,263],["H3519","my glory",264,272],["H1471","among the Gentiles",273,291]]},"66:20":{"text":"And they shall bring all your brethren for an offering unto the LORD out of all nations upon horses, and in chariots, and in litters, and upon mules, and upon swift beasts, to my holy mountain Jerusalem, saith the LORD, as the children of Israel bring an offering in a clean vessel into the house of the LORD.","words":[["H0935","And they shall bring",0,20],["H0251","all your brethren",21,38],["H4503","for an offering",39,54],["H3068","unto the LORD",55,68],["H1471","out of all nations",69,87],["H5483","upon horses",88,99],["H7393","and in chariots",101,116],["H6632","and in litters",118,132],["H6505","and upon mules",134,148],["H3753","and upon swift beasts",150,171],["H6944","to my holy",173,183],["H2022","mountain",184,192],["H3389","Jerusalem",193,202],["H0559","saith",204,209],["H3068","the LORD",210,218],["H1121","as the children",220,235],["H3478","of Israel",236,245],["H0935","bring",246,251],["H4503","an offering",252,263],["H2889","in a clean",264,274],["H3627","vessel",275,281],["H1004","into the house",282,296],["H3068","of the LORD",297,308]]},"66:21":{"text":"And I will also take of them for priests and for Levites, saith the LORD.","words":[["H3947","And I will also take",0,20],["H3548","of them for priests",21,40],["H3881","and for Levites",41,56],["H0559","saith",58,63],["H3068","the LORD",64,72]]},"66:22":{"text":"For as the new heavens and the new earth, which I will make, shall remain before me, saith the LORD, so shall your seed and your name remain.","words":[["H2319","For as the new",0,14],["H8064","heavens",15,22],["H2319","and the new",23,34],["H0776","earth",35,40],["H6213","which I will make",42,59],["H5975","shall remain",61,73],["H6440","before",74,80],["H5002","me, saith",81,90],["H3068","the LORD",91,99],["H2233","so shall your seed",101,119],["H8034","and your name",120,133],["H5975","remain",134,140]]},"66:23":{"text":"And it shall come to pass, that from one new moon to another, and from one sabbath to another, shall all flesh come to worship before me, saith the LORD.","words":[["H1767","And it shall come to pass, that from",0,36],["H2320","one new moon",37,49],["H2320","to another",50,60],["H1767","and from",62,70],["H7676","one sabbath",71,82],["H7676","to another",83,93],["H1320","shall all flesh",95,110],["H0935","come",111,115],["H7812","to worship",116,126],["H6440","before",127,133],["H0559","me, saith",134,143],["H3068","the LORD",144,152]]},"66:24":{"text":"And they shall go forth, and look upon the carcases of the men that have transgressed against me: for their worm shall not die, neither shall their fire be quenched; and they shall be an abhorring unto all flesh.","words":[["H3318","And they shall go forth",0,23],["H7200","and look",25,33],["H6297","upon the carcases",34,51],["H0582","of the men",52,62],["H6586","that have transgressed",63,85],["H8438","against me: for their worm",86,112],["H4191","shall not die",113,126],["H0784","neither shall their fire",128,152],["H3518","be quenched",153,164],["H1860","and they shall be an abhorring",166,196],["H1320","unto all flesh",197,211]]}}};
